def normalize_llm_backend(value: Any) -> str:
    normalized = str(value or "").strip().lower().replace("-", "_")
    aliases = {
        "openai": "openai_compatible",
        "openaicompat": "openai_compatible",
        "openai_compat": "openai_compatible",
        "openaicompatible": "openai_compatible",
    }
    return aliases.get(normalized, normalized or "ollama")


def normalize_grounding_profile(value: Any) -> str:
    normalized = str(value or "").strip().lower().replace("-", "_")
    if normalized in {"enterprise", "enterprise_strict", "strict", "strict_enterprise"}:
        return "enterprise_strict"
    return "standard"

