def coerce_positive_float(value: Any, default: float) -> float:
    try:
        parsed = float(value)
    except Exception:
        return float(default)
    if parsed <= 0:
        return float(default)
    return parsed

def coerce_optional_positive_int(value: Any, default: Optional[int]) -> Optional[int]:
    if value is None:
        return default
    try:
        parsed = int(value)
    except Exception:
        return default
    if parsed <= 0:
        return None
    return parsed

