    def _extract_airflow_dag_entry(call: ast.Call, line: int) -> Optional[dict[str, Any]]:
        constructor_name = _ast_get_call_name(call.func)
        constructor_full = _ast_get_full_name(call.func)
        is_dag_constructor = False
        if constructor_name == "DAG":
            is_dag_constructor = bool(has_airflow_import or constructor_name in airflow_dag_aliases or constructor_full.endswith(".DAG"))
        if constructor_name in airflow_dag_aliases:
            is_dag_constructor = True
        if not is_dag_constructor:
            return None

        dag_name = ""
        schedule = ""
        if call.args:
            dag_name = _resolve_python_string_expression(call.args[0], python_string_bindings)
        for kw in call.keywords or []:
            if kw.arg == "dag_id":
                dag_name = _resolve_python_string_expression(kw.value, python_string_bindings) or dag_name
            elif kw.arg in {"schedule", "schedule_interval"}:
                schedule = _resolve_python_string_expression(kw.value, python_string_bindings) or schedule
        if not dag_name:
            return None
        payload = {
            "kind": "airflow_dag",
            "name": dag_name,
            "file": rel,
            "line": int(line or 1),
            "evidence": make_evidence(rel, int(line or 1)),
        }
        if schedule:
            payload["schedule"] = schedule
        return payload

    def _extract_airflow_task_entry(call: ast.Call) -> Optional[dict[str, Any]]:
        constructor_name = _ast_get_call_name(call.func)
        constructor_full = _ast_get_full_name(call.func)
        if not constructor_name or not constructor_name.endswith("Operator"):
            return None
        is_airflow_operator = bool(
            constructor_name in airflow_operator_aliases
            or constructor_full.startswith("airflow.")
            or (has_airflow_import and constructor_name in airflow_operator_aliases)
        )
        if not is_airflow_operator:
            return None

        task_name = ""
        if call.args:
            task_name = _resolve_python_string_expression(call.args[0], python_string_bindings)
        for kw in call.keywords or []:
            if kw.arg == "task_id":
                task_name = _resolve_python_string_expression(kw.value, python_string_bindings) or task_name
        task_name = str(task_name or "").strip()
        if not task_name:
            return None
        line = int(getattr(call, "lineno", 1) or 1)
        return {
            "kind": "airflow_task",
            "name": task_name,
            "file": rel,
            "line": line,
            "evidence": make_evidence(rel, line),
        }

    def _extract_dagster_entry(fn: Any, decorator: Any) -> Optional[dict[str, Any]]:
        decorator_node = decorator.func if isinstance(decorator, ast.Call) else decorator
        decorator_name = _ast_get_call_name(decorator_node)
        decorator_full = _ast_get_full_name(decorator_node)
        if not decorator_name:
            return None

        is_dagster_job = decorator_name in dagster_job_aliases
        is_dagster_schedule = decorator_name in dagster_schedule_aliases
        is_dagster_asset = decorator_name in dagster_asset_aliases
        is_dagster_sensor = decorator_name in dagster_sensor_aliases
        is_dagster_repository = decorator_name in dagster_repository_aliases
        if not (
            is_dagster_job
            or is_dagster_schedule
            or is_dagster_asset
            or is_dagster_sensor
            or is_dagster_repository
        ):
            if "." in decorator_full:
                root_name = decorator_full.split(".", 1)[0].strip()
                tail_name = decorator_full.rsplit(".", 1)[-1].strip()
                if root_name in dagster_module_aliases and tail_name == "job":
                    is_dagster_job = True
                elif root_name in dagster_module_aliases and tail_name == "schedule":
                    is_dagster_schedule = True
                elif root_name in dagster_module_aliases and tail_name == "asset":
                    is_dagster_asset = True
                elif root_name in dagster_module_aliases and tail_name == "sensor":
                    is_dagster_sensor = True
                elif root_name in dagster_module_aliases and tail_name == "repository":
                    is_dagster_repository = True
        if not (
            is_dagster_job
            or is_dagster_schedule
            or is_dagster_asset
            or is_dagster_sensor
            or is_dagster_repository
        ):
            return None

        entry_name = str(getattr(fn, "name", "") or "").strip()
        schedule = ""
        if isinstance(decorator, ast.Call):
            for kw in decorator.keywords or []:
                if kw.arg == "name":
                    entry_name = _resolve_python_string_expression(kw.value, python_string_bindings) or entry_name
                elif kw.arg == "cron_schedule":
                    schedule = _resolve_python_string_expression(kw.value, python_string_bindings) or schedule
        if not entry_name:
            return None
        line = int(getattr(decorator, "lineno", getattr(fn, "lineno", 1)) or 1)
        entry_kind = "dagster_job"
        if is_dagster_schedule:
            entry_kind = "dagster_schedule"
        elif is_dagster_asset:
            entry_kind = "dagster_asset"
        elif is_dagster_sensor:
            entry_kind = "dagster_sensor"
        elif is_dagster_repository:
            entry_kind = "dagster_repository"
        payload = {
            "kind": entry_kind,
            "name": entry_name,
            "file": rel,
            "line": line,
            "evidence": make_evidence(rel, line),
        }
        if schedule:
            payload["schedule"] = schedule
        return payload

    def _extract_dagster_definitions_entry(node: Any, target_name: str, call: ast.Call) -> Optional[dict[str, Any]]:
        constructor_name = _ast_get_call_name(call.func)
        constructor_full = _ast_get_full_name(call.func)
        is_definitions_constructor = bool(constructor_name in dagster_definitions_aliases)
        if not is_definitions_constructor and constructor_name == "Definitions":
            is_definitions_constructor = bool(
                constructor_name in dagster_definitions_aliases
                or constructor_full.endswith(".Definitions")
                or "dagster" in constructor_full.split(".", 1)[0:1]
            )
        if not is_definitions_constructor and "." in constructor_full:
            root_name = constructor_full.split(".", 1)[0].strip()
            tail_name = constructor_full.rsplit(".", 1)[-1].strip()
            if root_name in dagster_module_aliases and tail_name == "Definitions":
                is_definitions_constructor = True
        if not is_definitions_constructor:
            return None

        entry_name = str(target_name or "").strip() or "definitions"
        line = int(getattr(call, "lineno", getattr(node, "lineno", 1)) or 1)
        payload = {
            "kind": "dagster_repository",
            "name": entry_name,
            "file": rel,
            "line": line,
            "evidence": make_evidence(rel, line),
        }
        counts: dict[str, int] = {}
        for kw in call.keywords or []:
            if kw.arg in {"assets", "jobs", "schedules", "sensors"} and isinstance(kw.value, (ast.List, ast.Tuple, ast.Set)):
                item_count = len(kw.value.elts)
                if item_count:
                    counts[f"{kw.arg}_count"] = item_count
        if counts:
            payload.update(counts)
        return payload

