    def _is_fastapi_background_tasks_annotation(annotation: Any) -> bool:
        annotation_name = _ast_get_full_name(annotation)
        canonical_name = _canonical_import_symbol(annotation_name)
        if canonical_name == "BackgroundTasks":
            return True
        normalized_name = str(annotation_name or "").strip()
        if not normalized_name:
            return False
        short_name = normalized_name.rsplit(".", 1)[-1].strip()
        if short_name != "BackgroundTasks":
            return False
        if normalized_name.startswith("fastapi."):
            return True
        return short_name in fastapi_background_tasks_aliases or normalized_name in fastapi_background_tasks_aliases

    def _extract_fastapi_background_task_entry(call: ast.Call) -> Optional[dict[str, Any]]:
        if not isinstance(call.func, ast.Attribute) or str(call.func.attr or "").strip() != "add_task":
            return None
        receiver_name = _ast_get_full_name(call.func.value)
        receiver_short = str(receiver_name or "").rsplit(".", 1)[-1].strip()
        if not receiver_short or receiver_short not in fastapi_background_task_receivers:
            return None
        if not call.args:
            return None
        task_target, _target_module, _dispatch_symbol = _resolve_fastapi_background_task_target(call.args[0])
        task_target = str(task_target or "").strip()
        if not task_target:
            return None
        line = int(getattr(call, "lineno", 1) or 1)
        return {
            "kind": "fastapi_background_task",
            "name": task_target,
            "task": task_target,
            "file": rel,
            "line": line,
            "evidence": make_evidence(rel, line),
        }

    def _extract_python_kafka_entries(call: ast.Call) -> list[dict[str, Any]]:
        entries: list[dict[str, Any]] = []
        constructor_name = _ast_get_call_name(call.func)
        constructor_full = _ast_get_full_name(call.func)
        is_kafka_constructor = False
        if constructor_name in {"KafkaConsumer", "AIOKafkaConsumer"}:
            is_kafka_constructor = bool(
                has_kafka_import or constructor_name in kafka_consumer_aliases or constructor_full.endswith(f".{constructor_name}")
            )
        if constructor_name in kafka_consumer_aliases:
            is_kafka_constructor = True
        if not is_kafka_constructor:
            return entries

        topics: list[str] = []
        for arg in call.args:
            resolved = _resolve_python_string_expression(arg, python_string_bindings)
            if resolved:
                topics.append(resolved)
        for kw in call.keywords or []:
            if kw.arg != "topics":
                continue
            for item in _ast_get_list_of_str_constants(kw.value):
                if item:
                    topics.append(item)

        line = int(getattr(call, "lineno", 1) or 1)
        seen_topics: set[str] = set()
        for topic_name in topics:
            normalized_topic = str(topic_name or "").strip()
            if not normalized_topic or normalized_topic in seen_topics:
                continue
            seen_topics.add(normalized_topic)
            entries.append(
                {
                    "kind": "kafka_consumer",
                    "name": normalized_topic,
                    "topic": normalized_topic,
                    "file": rel,
                    "line": line,
                    "evidence": make_evidence(rel, line),
                }
            )
        return entries

    def _is_python_kafka_producer_call(call: ast.Call) -> bool:
        constructor_name = _ast_get_call_name(call.func)
        constructor_full = _ast_get_full_name(call.func)
        is_kafka_constructor = False
        if constructor_name in {"KafkaProducer", "AIOKafkaProducer"}:
            is_kafka_constructor = bool(
                has_kafka_import or constructor_name in kafka_producer_aliases or constructor_full.endswith(f".{constructor_name}")
            )
        if constructor_name in kafka_producer_aliases:
            is_kafka_constructor = True
        return is_kafka_constructor

    kafka_producer_receivers: set[str] = set()
    for node in ast.walk(tree):
        call_value = None
        target_name = ""
        if isinstance(node, ast.Assign) and isinstance(node.value, ast.Call):
            call_value = node.value
            for target in node.targets:
                if isinstance(target, ast.Name):
                    target_name = str(target.id or "").strip()
                    if target_name:
                        break
        elif isinstance(node, ast.AnnAssign) and isinstance(node.value, ast.Call) and isinstance(node.target, ast.Name):
            call_value = node.value
            target_name = str(node.target.id or "").strip()
        if not target_name or not isinstance(call_value, ast.Call):
            continue
        if _is_python_kafka_producer_call(call_value):
            kafka_producer_receivers.add(target_name)

    def _extract_python_kafka_producer_entry(call: ast.Call) -> Optional[dict[str, Any]]:
        call_name = _ast_get_call_name(call.func)
        call_full = _ast_get_full_name(call.func)
        if call_name not in {"send", "send_and_wait"} and not (
            call_full.endswith(".send") or call_full.endswith(".send_and_wait")
        ):
            return None
        if not isinstance(call.func, ast.Attribute):
            return None
        receiver_name = _ast_get_full_name(call.func.value).rsplit(".", 1)[-1].strip()
        if receiver_name not in kafka_producer_receivers:
            return None

        topic_name = ""
        if call.args:
            topic_name = _resolve_python_string_expression(call.args[0], python_string_bindings)
        for kw in call.keywords or []:
            if kw.arg == "topic":
                topic_name = _resolve_python_string_expression(kw.value, python_string_bindings) or topic_name
        topic_name = str(topic_name or "").strip()
        if not topic_name:
            return None
        line = int(getattr(call, "lineno", 1) or 1)
        return {
            "kind": "kafka_producer",
            "name": topic_name,
            "topic": topic_name,
            "file": rel,
            "line": line,
            "evidence": make_evidence(rel, line),
        }

    def _extract_python_rabbitmq_entry(call: ast.Call) -> Optional[dict[str, Any]]:
        if not has_rabbitmq_import:
            return None
