def _stable_serialize_policy_item(value: Any) -> str:
    try:
        return json.dumps(value, sort_keys=True, separators=(",", ":"), ensure_ascii=True)
    except Exception:
        return repr(value)


def _merge_review_policy_values(base: Any, overlay: Any) -> Any:
    if isinstance(base, dict) and isinstance(overlay, dict):
        merged = {str(key): copy.deepcopy(value) for key, value in base.items()}
        for key, value in overlay.items():
            key_text = str(key)
            if key_text in merged:
                merged[key_text] = _merge_review_policy_values(merged[key_text], value)
            else:
                merged[key_text] = copy.deepcopy(value)
        return merged
    if isinstance(base, list) and isinstance(overlay, list):
        if not overlay:
            return []
        out: list[Any] = []
        seen: set[str] = set()
        for item in list(base) + list(overlay):
            token = _stable_serialize_policy_item(item)
            if token in seen:
                continue
            seen.add(token)
            out.append(copy.deepcopy(item))
        return out
    return copy.deepcopy(overlay)


def apply_policy_packs_to_review_policy(
    review_policy: Optional[dict[str, Any]],
    *,
    source: str = "",
) -> dict[str, Any]:
    raw_policy = dict(review_policy) if isinstance(review_policy, dict) else {}
    configured_names = _dedupe_string_list(raw_policy.get("policy_packs")) or _dedupe_string_list(raw_policy.get("policy_pack"))
    combined_names: list[str] = []
    seen_names: set[str] = set()
    for raw_name in configured_names:
        normalized = normalize_review_policy_pack_name(raw_name)
        if not normalized or normalized in seen_names:
            continue
        seen_names.add(normalized)
        combined_names.append(normalized)

    pack_defs = _builtin_review_policy_packs()
    merged: dict[str, Any] = {}
    for name in combined_names:
        pack = pack_defs.get(name)
        if not isinstance(pack, dict):
            label = source or "review policy packs"
            print(f"[WARN] Unknown review policy pack from {label}: {name}")
            continue
        review_overlay = pack.get("review_policy", pack)
        if isinstance(review_overlay, dict):
            merged = _merge_review_policy_values(merged, review_overlay)

    explicit_policy = {
        str(key): copy.deepcopy(value)
        for key, value in raw_policy.items()
        if str(key) not in {"policy_packs", "policy_pack"}
    }
    merged = _merge_review_policy_values(merged, explicit_policy)
    merged["policy_packs"] = combined_names
    return merged


def available_policy_pack_names() -> list[str]:
    return sorted(_builtin_policy_packs().keys())


