def _normalize_runtime_dependency_names(value: Any) -> list[str]:
    if value is None:
        return []
    items: list[str]
    if isinstance(value, str):
        items = [part.strip() for part in value.split(",")]
    elif isinstance(value, list):
        items = [str(part).strip() for part in value]
    else:
        return []
    out: list[str] = []
    seen: set[str] = set()
    for item in items:
        if not item:
            continue
        key = item.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(item)
    return out


RUNTIME_TEMPLATE_TOKEN_RE = re.compile(r"\{\{\s*(env:)?([A-Za-z_][A-Za-z0-9_]*)\s*\}\}")


def _normalize_runtime_template_variables(value: Any) -> dict[str, str]:
    return _normalize_env_map(value)


def _normalize_runtime_http_status_list(value: Any) -> list[int]:
    if value is None:
        return []
    items = value if isinstance(value, list) else [value]
    out: list[int] = []
    seen: set[int] = set()
    for item in items:
        try:
            code = int(item)
        except Exception:
            continue
        if code < 100 or code > 599 or code in seen:
            continue
        seen.add(code)
        out.append(code)
    return out


def _normalize_runtime_ready_tcp_targets(value: Any) -> list[str]:
    items = value if isinstance(value, list) else [value]
    out: list[str] = []
    seen: set[str] = set()
    for item in items:
        raw = str(item or "").strip()
        if not raw:
            continue
        host = "127.0.0.1"
        port_text = raw
        if ":" in raw:
            host_part, port_part = raw.rsplit(":", 1)
            if host_part.strip():
                host = _normalize_runtime_probe_host(host_part.strip()) or "127.0.0.1"
            port_text = port_part.strip()
        try:
            port = int(port_text)
        except Exception:
            continue
        if port <= 0:
            continue
        target = f"{host}:{port}"
        if target in seen:
            continue
        seen.add(target)
        out.append(target)
    return out


def _normalize_runtime_ready_http_targets(value: Any) -> list[str]:
    items = value if isinstance(value, list) else [value]
    out: list[str] = []
    seen: set[str] = set()
    for item in items:
        raw = str(item or "").strip()
        if not raw:
            continue
        normalized = _normalize_runtime_bootstrap_url(raw) if "://" in raw else raw
        if not normalized:
            continue
        if normalized in seen:
            continue
        seen.add(normalized)
        out.append(normalized)
    return out


def _normalize_runtime_ready_files(value: Any) -> list[str]:
    items = value if isinstance(value, list) else [value]
    out: list[str] = []
    seen: set[str] = set()
    for item in items:
        raw = str(item or "").strip()
        if not raw:
            continue
        if raw in seen:
            continue
        seen.add(raw)
        out.append(raw)
    return out


def _normalize_runtime_ready_protocol_name(value: Any) -> str:
    raw = str(value or "").strip().lower().replace("-", "_").replace(" ", "_")
    aliases = {
        "postgresql": "postgres",
        "pg": "postgres",
        "redis_server": "redis",
        "amqp": "rabbitmq",
        "rabbit": "rabbitmq",
        "rabbit_mq": "rabbitmq",
        "mariadb": "mysql",
        "mongodb": "mongo",
    }
    normalized = aliases.get(raw, raw)
    return normalized if normalized in {"redis", "postgres", "mysql", "mongo", "rabbitmq", "kafka"} else ""


def _normalize_runtime_ready_protocols(value: Any) -> list[dict[str, Any]]:
    items = value if isinstance(value, list) else [value]
    out: list[dict[str, Any]] = []
    seen: set[str] = set()
    for item in items:
        if isinstance(item, str):
            raw = str(item).strip()
            if ":" not in raw:
                continue
            protocol_part, target_part = raw.split(":", 1)
            protocol = _normalize_runtime_ready_protocol_name(protocol_part)
            target = str(target_part or "").strip()
            timeout_seconds = None
        elif isinstance(item, dict):
            protocol = _normalize_runtime_ready_protocol_name(
                item.get("type", item.get("protocol", item.get("kind")))
            )
            target = str(item.get("target", "")).strip()
            if not target:
                host = _normalize_runtime_probe_host(item.get("host", "")) or "127.0.0.1"
                port_raw = item.get("port")
                try:
                    port = int(port_raw)
                except Exception:
                    port = 0
                target = f"{host}:{port}" if port > 0 else ""
            timeout_raw = item.get("timeout_seconds")
            timeout_seconds = coerce_positive_float(timeout_raw, 0.0) if timeout_raw is not None else None
        else:
            continue
        if not protocol or not target:
            continue
        normalized_target = _normalize_runtime_ready_tcp_targets([target])
        if not normalized_target:
            continue
        normalized_target_text = normalized_target[0]
        dedupe_key = f"{protocol}:{normalized_target_text}"
        if dedupe_key in seen:
            continue
        seen.add(dedupe_key)
        entry = {"type": protocol, "target": normalized_target_text}
        if timeout_seconds is not None:
            entry["timeout_seconds"] = timeout_seconds
        out.append(entry)
    return out


def _merge_runtime_ready_protocols(*values: Any) -> list[dict[str, Any]]:
    merged: list[dict[str, Any]] = []
    for value in values:
        merged.extend(_normalize_runtime_ready_protocols(value))
    return _normalize_runtime_ready_protocols(merged)


def _render_runtime_template_string(value: Any, variables: dict[str, str], env: dict[str, str]) -> str:
    raw = str(value or "")

    def replace(match: re.Match[str]) -> str:
        source = str(match.group(1) or "").strip().lower()
        key = str(match.group(2) or "").strip()
        if not key:
            return match.group(0)
        if source == "env:":
            resolved = str(env.get(key, os.environ.get(key, "")) or "")
            return resolved if resolved else match.group(0)
        if key in variables:
            return str(variables.get(key, "") or "")
        resolved = str(env.get(key, os.environ.get(key, "")) or "")
        return resolved if resolved else match.group(0)

    return RUNTIME_TEMPLATE_TOKEN_RE.sub(replace, raw)


def _render_runtime_template_value(value: Any, variables: dict[str, str], env: dict[str, str]) -> Any:
    if isinstance(value, str):
        return _render_runtime_template_string(value, variables, env)
    if isinstance(value, list):
        return [_render_runtime_template_value(item, variables, env) for item in value]
    if isinstance(value, dict):
        return {
            str(key): _render_runtime_template_value(item, variables, env)
            for key, item in value.items()
        }
    return value


def _normalize_runtime_service_profiles(value: Any) -> dict[str, dict[str, Any]]:
    out: dict[str, dict[str, Any]] = {}
    if not isinstance(value, dict):
        return out
    for raw_name, raw_profile in value.items():
        name = str(raw_name).strip()
        if not name or not isinstance(raw_profile, dict):
            continue
        base_urls = _normalize_runtime_base_urls(raw_profile.get("base_urls"))
        if not base_urls and "base_url" in raw_profile:
            base_urls = _normalize_runtime_base_urls(raw_profile.get("base_url"))
        startup_seconds = raw_profile.get("startup_seconds")
        out[name] = {
            "name": name,
            "env": _normalize_env_map(raw_profile.get("env")),
            "base_urls": base_urls,
            "request_headers": _merge_runtime_request_headers(
                raw_profile.get("request_headers"),
                raw_profile.get("headers"),
            ),
            "request_cookies": _merge_runtime_request_cookies(
                raw_profile.get("request_cookies"),
                raw_profile.get("cookies"),
            ),
            "bootstrap_requests": _normalize_runtime_bootstrap_requests(
                raw_profile.get("bootstrap_requests") if "bootstrap_requests" in raw_profile else raw_profile.get("bootstrap"),
            ),
            "template_variables": _normalize_runtime_template_variables(
                raw_profile.get("template_variables")
                if "template_variables" in raw_profile
                else raw_profile.get("variables", raw_profile.get("auth_variables"))
            ),
            "ready_http": _normalize_runtime_ready_http_targets(raw_profile.get("ready_http")),
            "ready_tcp": _normalize_runtime_ready_tcp_targets(raw_profile.get("ready_tcp")),
            "ready_files": _normalize_runtime_ready_files(raw_profile.get("ready_files")),
            "ready_protocols": _normalize_runtime_ready_protocols(raw_profile.get("ready_protocols")),
            "ready_timeout_seconds": coerce_positive_float(raw_profile.get("ready_timeout_seconds"), 0.0)
            if raw_profile.get("ready_timeout_seconds") is not None
            else None,
            "refresh_on_status": _normalize_runtime_http_status_list(
                raw_profile.get("refresh_on_status")
                if "refresh_on_status" in raw_profile
                else raw_profile.get("credential_refresh_statuses")
            ),
            "max_bootstrap_refreshes": max(0, int(raw_profile.get("max_bootstrap_refreshes", 1) or 0)),
            "depends_on": _normalize_runtime_dependency_names(raw_profile.get("depends_on")),
            "startup_seconds": coerce_positive_float(startup_seconds, 0.0) if startup_seconds is not None else None,
        }
    return out


def _normalize_runtime_command_specs(repo_path: str, value: Any) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    if not isinstance(value, list):
        return out
    for idx, item in enumerate(value, start=1):
        if isinstance(item, str):
            cmd = item.strip()
            if not cmd:
                continue
            out.append(
                {
                    "name": f"runtime_{idx}",
                    "command": cmd,
                    "cwd": repo_path,
                    "env": {},
                    "mode": _infer_runtime_command_mode(f"runtime_{idx}", cmd),
                    "base_urls": [],
                    "request_headers": {},
                    "request_cookies": {},
                    "bootstrap_requests": [],
                    "template_variables": {},
                    "ready_http": [],
                    "ready_tcp": [],
                    "ready_files": [],
                    "ready_protocols": [],
                    "ready_timeout_seconds": None,
                    "refresh_on_status": [401, 403],
                    "max_bootstrap_refreshes": 1,
                    "depends_on": [],
                    "service_profile": "",
                }
            )
            continue
        if not isinstance(item, dict):
            continue
        cmd = str(item.get("command", "")).strip()
        if not cmd:
            continue
        name = str(item.get("name", "")).strip() or f"runtime_{idx}"
        cwd_raw = str(item.get("cwd", "")).strip()
        cwd = cwd_raw if os.path.isabs(cwd_raw) else os.path.join(repo_path, cwd_raw) if cwd_raw else repo_path
        mode = _normalize_runtime_command_mode(item.get("mode")) or _infer_runtime_command_mode(name, cmd)
        base_urls = _normalize_runtime_base_urls(item.get("base_urls"))
        if not base_urls and "base_url" in item:
            base_urls = _normalize_runtime_base_urls(item.get("base_url"))
        out.append(
            {
                "name": name,
                "command": cmd,
                "cwd": cwd,
                "env": _normalize_env_map(item.get("env")),
                "mode": mode,
                "base_urls": base_urls,
                "request_headers": _merge_runtime_request_headers(
                    item.get("request_headers"),
                    item.get("headers"),
                ),
                "request_cookies": _merge_runtime_request_cookies(
                    item.get("request_cookies"),
                    item.get("cookies"),
                ),
                "bootstrap_requests": _normalize_runtime_bootstrap_requests(
                    item.get("bootstrap_requests") if "bootstrap_requests" in item else item.get("bootstrap"),
                ),
                "template_variables": _normalize_runtime_template_variables(
                    item.get("template_variables")
                    if "template_variables" in item
                    else item.get("variables", item.get("auth_variables"))
                ),
                "ready_http": _normalize_runtime_ready_http_targets(item.get("ready_http")),
                "ready_tcp": _normalize_runtime_ready_tcp_targets(item.get("ready_tcp")),
                "ready_files": _normalize_runtime_ready_files(item.get("ready_files")),
                "ready_protocols": _normalize_runtime_ready_protocols(item.get("ready_protocols")),
                "ready_timeout_seconds": coerce_positive_float(item.get("ready_timeout_seconds"), 0.0)
                if item.get("ready_timeout_seconds") is not None
                else None,
                "refresh_on_status": _normalize_runtime_http_status_list(
                    item.get("refresh_on_status")
                    if "refresh_on_status" in item
                    else item.get("credential_refresh_statuses")
                ),
                "max_bootstrap_refreshes": max(0, int(item.get("max_bootstrap_refreshes", 1) or 0)),
                "depends_on": _normalize_runtime_dependency_names(item.get("depends_on")),
                "service_profile": str(item.get("service_profile", item.get("profile", ""))).strip(),
                "service_name": str(item.get("service_name", "")).strip(),
                "service_bucket": str(item.get("service_bucket", "")).strip(),
            }
        )
    return out

def default_scan_config() -> dict[str, Any]:
    return {
        "config_path": "",
        "include_exts": set(EXTS),
        "skip_dirs": set(SKIP_DIRS),
        "skip_dir_prefixes": [],
        "skip_file_patterns": list(SKIP_FILE_PATTERNS),
        "max_file_bytes": MAX_FILE_BYTES,
        "custom_redaction_rules": [],
        "redaction_policy_path": "",
        "security_policy": default_security_policy(),
        "security_policy_path": "",
        "runtime": default_runtime_probe_config(),
        "policy_packs": [],
        "recommended_grounding_profile": "",
    }


def _normalize_relative_dir_prefix(value: Any) -> str:
    raw = normalize_repo_path(str(value or "").strip())
    if not raw or raw == ".":
        return ""
    return raw.strip("/").strip()


def _dir_matches_prefix(rel_dir: str, prefixes: list[str]) -> bool:
    candidate = _normalize_relative_dir_prefix(rel_dir)
    if not candidate:
        return False
    for prefix in prefixes:
        normalized = _normalize_relative_dir_prefix(prefix)
        if not normalized:
            continue
        if candidate == normalized or candidate.startswith(f"{normalized}/"):
            return True
    return False


def _repo_relative_child_path(repo_path: str, target_path: str) -> str:
    repo_abs = os.path.abspath(os.path.expanduser(str(repo_path or "").strip()))
    target_abs = os.path.abspath(os.path.expanduser(str(target_path or "").strip()))
    if not repo_abs or not target_abs:
        return ""
    try:
        if os.path.commonpath([repo_abs, target_abs]) != repo_abs:
            return ""
    except Exception:
        return ""
    rel = os.path.relpath(target_abs, repo_abs).replace("\\", "/")
    return "" if rel in {"", "."} else rel


def display_safe_path(path: str, repo_path: str = "") -> str:
    raw = str(path or "").strip()
    if not raw:
        return ""
    if not os.path.isabs(os.path.expanduser(raw)):
        return normalize_repo_path(raw)
    rel = _repo_relative_child_path(repo_path, raw) if repo_path else ""
    if rel:
        return rel
    trimmed = raw.replace("\\", "/").rstrip("/")
    return os.path.basename(trimmed) or trimmed


def augment_scan_config_with_repo_artifact_exclusions(
    repo_path: str,
    scan_config: Optional[dict[str, Any]],
    artifact_paths: list[str],
) -> dict[str, Any]:
    cfg = dict(scan_config) if isinstance(scan_config, dict) else default_scan_config()
    cfg["skip_dirs"] = set(cfg.get("skip_dirs", set(SKIP_DIRS)))
    cfg["skip_file_patterns"] = list(cfg.get("skip_file_patterns", list(SKIP_FILE_PATTERNS)))
    raw_prefixes = cfg.get("skip_dir_prefixes", [])
    prefixes = [
        normalized
        for normalized in (_normalize_relative_dir_prefix(item) for item in (raw_prefixes if isinstance(raw_prefixes, list) else []))
        if normalized
    ]
    seen_prefixes = set(prefixes)

    for path in artifact_paths:
        rel = _repo_relative_child_path(repo_path, str(path or "").strip())
        normalized = _normalize_relative_dir_prefix(rel)
        if not normalized:
            continue
        if "/" not in normalized:
            cfg["skip_dirs"].add(normalized)
        if normalized not in seen_prefixes:
            prefixes.append(normalized)
            seen_prefixes.add(normalized)

    cfg["skip_dir_prefixes"] = prefixes
    return cfg

def default_security_policy() -> dict[str, Any]:
    return {
        "name": "default",
        "require_strict_local_only": False,
        "allow_remote_llm": False,
        "require_scan_config_file": False,
        "require_redaction_policy_file": False,
        "require_classification_rules": False,
        "min_custom_redaction_rules": 0,
        "allow_runtime_probe": True,
        "allowed_runtime_command_patterns": [],
        "blocked_runtime_command_patterns": [],
        "max_allowed_file_bytes": None,
        "fail_on_skipped_large_files": False,
        "default_data_classification": "unclassified",
        "classification_rules": [],
    }


CLASSIFICATION_RANKS = {
    "public": 0,
    "unclassified": 0,
    "internal": 1,
    "confidential": 2,
    "restricted": 3,
}

CLASSIFICATION_ALIASES = {
    "open": "public",
    "external": "public",
    "private": "confidential",
    "secret": "restricted",
    "highly_confidential": "restricted",
    "highly-confidential": "restricted",
    "unknown": "unclassified",
    "unset": "unclassified",
}


def normalize_data_classification(value: Any) -> str:
    raw = str(value or "").strip().lower().replace("-", "_").replace(" ", "_")
    if not raw:
        return "unclassified"
    return CLASSIFICATION_ALIASES.get(raw, raw)


def classification_rank(value: Any) -> int:
    normalized = normalize_data_classification(value)
    return CLASSIFICATION_RANKS.get(normalized, max(CLASSIFICATION_RANKS.values()) + 1)


def is_known_data_classification(value: Any) -> bool:
    return normalize_data_classification(value) in CLASSIFICATION_RANKS

def _normalize_security_pattern_list(raw_patterns: Any, source: str, field_name: str) -> list[str]:
    out: list[str] = []
    for pattern in _list_of_non_empty_strings(raw_patterns):
        try:
            re.compile(pattern)
        except Exception as e:
            print(f"[WARN] Invalid security policy regex {field_name} from {source}: {e}")
            continue
        out.append(pattern)
    return out

def _normalize_security_policy(raw_policy: Any, source: str) -> dict[str, Any]:
    policy = default_security_policy()
    if not isinstance(raw_policy, dict):
        return policy

    name = str(raw_policy.get("name", "")).strip()
    if name:
        policy["name"] = name

    bool_fields = [
        "require_strict_local_only",
        "allow_remote_llm",
        "require_scan_config_file",
        "require_redaction_policy_file",
        "require_classification_rules",
        "allow_runtime_probe",
        "fail_on_skipped_large_files",
    ]
    for field in bool_fields:
        if field in raw_policy:
            policy[field] = bool(raw_policy.get(field))

    if "min_custom_redaction_rules" in raw_policy:
        try:
            policy["min_custom_redaction_rules"] = max(0, int(raw_policy.get("min_custom_redaction_rules", 0)))
        except Exception:
            pass

    if "max_allowed_file_bytes" in raw_policy:
        policy["max_allowed_file_bytes"] = coerce_optional_positive_int(
            raw_policy.get("max_allowed_file_bytes"),
            policy["max_allowed_file_bytes"],
        )

    policy["allowed_runtime_command_patterns"] = _normalize_security_pattern_list(
        raw_policy.get("allowed_runtime_command_patterns"),
        source,
        "allowed_runtime_command_patterns",
    )
    policy["blocked_runtime_command_patterns"] = _normalize_security_pattern_list(
        raw_policy.get("blocked_runtime_command_patterns"),
        source,
        "blocked_runtime_command_patterns",
    )
    if "default_data_classification" in raw_policy:
        policy["default_data_classification"] = normalize_data_classification(
            raw_policy.get("default_data_classification")
        )
    raw_rules = raw_policy.get("classification_rules", [])
    if isinstance(raw_rules, list):
        normalized_rules: list[dict[str, Any]] = []
        for idx, item in enumerate(raw_rules, start=1):
            if not isinstance(item, dict):
                continue
            name = str(item.get("name", "")).strip() or f"classification_rule_{idx}"
            label = normalize_data_classification(item.get("classification", ""))
            patterns = _normalize_security_pattern_list(
                item.get("path_patterns"),
                source,
                f"classification_rules[{idx}].path_patterns",
            )
            single_pattern = str(item.get("path_pattern", "")).strip()
            if single_pattern:
                patterns.extend(
                    _normalize_security_pattern_list(
                        [single_pattern],
                        source,
                        f"classification_rules[{idx}].path_pattern",
                    )
                )
            deduped_patterns: list[str] = []
            seen_patterns: set[str] = set()
            for pattern in patterns:
                if pattern in seen_patterns:
                    continue
                seen_patterns.add(pattern)
                deduped_patterns.append(pattern)
            if not deduped_patterns:
                continue
            normalized_rules.append(
                {
                    "name": name,
                    "classification": label,
                    "path_patterns": deduped_patterns,
                }
            )
        policy["classification_rules"] = normalized_rules
    return policy

def _load_external_security_policy(repo_path: str, value: Any) -> tuple[dict[str, Any], str]:
    rel = str(value or "").strip()
    if not rel:
        return default_security_policy(), ""
    policy_path = rel if os.path.isabs(rel) else os.path.join(repo_path, rel)
    if not os.path.isfile(policy_path):
        print(f"[WARN] Security policy file not found: {policy_path}")
        return default_security_policy(), policy_path
    try:
        with open(policy_path, "r", encoding="utf-8") as f:
            raw = json.load(f)
    except Exception as e:
        print(f"[WARN] Failed to read security policy file {policy_path}: {e}")
        return default_security_policy(), policy_path
    return _normalize_security_policy(raw, policy_path), policy_path

def merge_security_policy(base: Optional[dict[str, Any]], overlay: Optional[dict[str, Any]]) -> dict[str, Any]:
    merged = default_security_policy()
    if isinstance(base, dict):
        merged.update(base)
    if isinstance(overlay, dict):
        merged.update(overlay)
    return merged


def _merge_runtime_probe_settings(base: Optional[dict[str, Any]], overlay: Optional[dict[str, Any]]) -> dict[str, Any]:
    merged = default_runtime_probe_config()
    if isinstance(base, dict):
        merged.update(base)
    if isinstance(overlay, dict):
        for key, value in overlay.items():
            if key in {"request_headers", "request_cookies", "template_variables", "service_profiles"}:
                current = merged.get(key, {})
                merged[key] = dict(current) if isinstance(current, dict) else {}
                if isinstance(value, dict):
                    merged[key].update(value)
                continue
            merged[key] = value
    return merged


def apply_policy_packs_to_scan_config(
    scan_config: Optional[dict[str, Any]],
    pack_names: Any,
    *,
    source: str = "",
) -> dict[str, Any]:
    cfg = default_scan_config()
    if isinstance(scan_config, dict):
        cfg.update(scan_config)
        cfg["include_exts"] = set(scan_config.get("include_exts", cfg["include_exts"]))
        cfg["skip_dirs"] = set(scan_config.get("skip_dirs", cfg["skip_dirs"]))
        cfg["skip_dir_prefixes"] = list(scan_config.get("skip_dir_prefixes", cfg["skip_dir_prefixes"]))
        cfg["skip_file_patterns"] = list(scan_config.get("skip_file_patterns", cfg["skip_file_patterns"]))
        cfg["custom_redaction_rules"] = list(scan_config.get("custom_redaction_rules", cfg["custom_redaction_rules"]))
        cfg["security_policy"] = merge_security_policy(default_security_policy(), scan_config.get("security_policy", {}))
        cfg["runtime"] = _merge_runtime_probe_settings(default_runtime_probe_config(), scan_config.get("runtime", {}))

    combined_names: list[str] = []
    seen_names: set[str] = set()
    requested = pack_names if isinstance(pack_names, list) else ([pack_names] if pack_names else [])
    for raw_name in list(cfg.get("policy_packs", [])) + list(requested):
        normalized = normalize_policy_pack_name(raw_name)
        if not normalized or normalized in seen_names:
            continue
        seen_names.add(normalized)
        combined_names.append(normalized)

    recommended_grounding_profile = normalize_grounding_profile(cfg.get("recommended_grounding_profile", ""))
    pack_defs = _builtin_policy_packs()
    for name in combined_names:
        pack = pack_defs.get(name)
        if not isinstance(pack, dict):
            label = source or "policy packs"
            print(f"[WARN] Unknown policy pack from {label}: {name}")
            continue
        scan_overlay = pack.get("scan_config", {}) if isinstance(pack.get("scan_config", {}), dict) else {}
        if "max_file_bytes" in scan_overlay:
            cfg["max_file_bytes"] = coerce_optional_positive_int(scan_overlay.get("max_file_bytes"), cfg.get("max_file_bytes"))
        for item in _dedupe_string_list(scan_overlay.get("skip_dirs")):
            cfg["skip_dirs"].add(item)
        for item in _dedupe_string_list(scan_overlay.get("skip_dir_prefixes")):
            if item not in cfg["skip_dir_prefixes"]:
                cfg["skip_dir_prefixes"].append(item)
        for item in _dedupe_string_list(scan_overlay.get("skip_file_patterns")):
            if item not in cfg["skip_file_patterns"]:
                cfg["skip_file_patterns"].append(item)
        cfg["security_policy"] = merge_security_policy(cfg.get("security_policy", {}), pack.get("security_policy", {}))
        cfg["runtime"] = _merge_runtime_probe_settings(cfg.get("runtime", {}), pack.get("runtime", {}))
        pack_grounding_profile = normalize_grounding_profile(pack.get("grounding_profile", ""))
        if pack_grounding_profile == "enterprise_strict":
            recommended_grounding_profile = pack_grounding_profile
        elif pack_grounding_profile and not recommended_grounding_profile:
            recommended_grounding_profile = pack_grounding_profile

    cfg["policy_packs"] = combined_names
    cfg["recommended_grounding_profile"] = recommended_grounding_profile
    return cfg


def summarize_security_policy(policy: Optional[dict[str, Any]]) -> str:
    current = merge_security_policy(default_security_policy(), policy if isinstance(policy, dict) else {})
    return (
        f"name={current.get('name', 'default')}, "
        f"require_strict_local_only={bool(current.get('require_strict_local_only', False))}, "
        f"allow_remote_llm={bool(current.get('allow_remote_llm', False))}, "
        f"require_redaction_policy_file={bool(current.get('require_redaction_policy_file', False))}, "
        f"require_classification_rules={bool(current.get('require_classification_rules', False))}, "
        f"min_custom_redaction_rules={int(current.get('min_custom_redaction_rules', 0) or 0)}, "
        f"allow_runtime_probe={bool(current.get('allow_runtime_probe', True))}, "
        f"allowed_runtime_patterns={len(current.get('allowed_runtime_command_patterns', []))}, "
        f"blocked_runtime_patterns={len(current.get('blocked_runtime_command_patterns', []))}, "
        f"default_data_classification={normalize_data_classification(current.get('default_data_classification', 'unclassified'))}, "
        f"classification_rules={len(current.get('classification_rules', []))}"
    )

def _normalize_redaction_rules(raw_rules: Any, source: str) -> list[tuple[str, Any, str]]:
    rules: list[tuple[str, Any, str]] = []
    if not isinstance(raw_rules, list):
        return rules
    for idx, item in enumerate(raw_rules, start=1):
        if not isinstance(item, dict):
            continue
        name = str(item.get("name", "")).strip() or f"custom_rule_{idx}"
        pattern_text = str(item.get("pattern", "")).strip()
        replacement = str(item.get("replacement", f"[REDACTED_{name.upper()}]")).strip() or f"[REDACTED_{name.upper()}]"
        if not pattern_text:
            continue
        try:
            compiled = re.compile(pattern_text)
        except Exception as e:
            print(f"[WARN] Invalid redaction regex {name} from {source}: {e}")
            continue
        rules.append((name, compiled, replacement))
    return rules

def _load_external_redaction_rules(repo_path: str, value: Any) -> tuple[list[tuple[str, Any, str]], str]:
    rel = str(value or "").strip()
    if not rel:
        return [], ""
    policy_path = rel if os.path.isabs(rel) else os.path.join(repo_path, rel)
    if not os.path.isfile(policy_path):
        print(f"[WARN] Redaction policy file not found: {policy_path}")
        return [], policy_path
    try:
        with open(policy_path, "r", encoding="utf-8") as f:
            raw = json.load(f)
    except Exception as e:
        print(f"[WARN] Failed to read redaction policy file {policy_path}: {e}")
        return [], policy_path
    if isinstance(raw, dict):
        raw = raw.get("redaction_rules", [])
    return _normalize_redaction_rules(raw, policy_path), policy_path

def configure_redaction_policy(scan_config: Optional[dict[str, Any]]) -> None:
    global _ACTIVE_SECRET_PATTERNS, _ACTIVE_SECRET_REPLACEMENTS
    active = list(SECRET_PATTERNS)
    replacements: dict[str, str] = {}
    if isinstance(scan_config, dict):
        for name, compiled, replacement in scan_config.get("custom_redaction_rules", []):
            active.append((name, compiled))
            replacements[name] = replacement
    _ACTIVE_SECRET_PATTERNS = active
    _ACTIVE_SECRET_REPLACEMENTS = replacements

def load_repo_scan_config(repo_path: str) -> dict[str, Any]:
    cfg = default_scan_config()
    config_path = ""
    for name in SCAN_CONFIG_FILENAMES:
        cand = os.path.join(repo_path, name)
        if os.path.isfile(cand):
            config_path = cand
            break
    if not config_path:
        return cfg

    cfg["config_path"] = config_path
    try:
        with open(config_path, "r", encoding="utf-8") as f:
            raw = json.load(f)
    except Exception as e:
        print(f"[WARN] Failed to read scan config {config_path}: {e}")
        return cfg

    if not isinstance(raw, dict):
        print(f"[WARN] Scan config must be a JSON object: {config_path}")
        return cfg

    configured_policy_packs = _dedupe_string_list(raw.get("policy_packs"))
    if not configured_policy_packs:
        configured_policy_packs = _dedupe_string_list(raw.get("policy_pack"))

    include_extensions = _list_of_non_empty_strings(raw.get("include_extensions"))
    if include_extensions:
        normalized = set()
        for item in include_extensions:
            ext = _normalize_extension_value(item)
            if ext:
                normalized.add(ext)
        if normalized:
            cfg["include_exts"] = normalized

    add_extensions = _list_of_non_empty_strings(raw.get("add_extensions"))
    if add_extensions:
        for item in add_extensions:
            ext = _normalize_extension_value(item)
            if ext:
                cfg["include_exts"].add(ext)

    remove_extensions = _list_of_non_empty_strings(raw.get("remove_extensions"))
    if remove_extensions:
        for item in remove_extensions:
            ext = _normalize_extension_value(item)
            if ext:
                cfg["include_exts"].discard(ext)

    skip_dirs = _list_of_non_empty_strings(raw.get("skip_dirs"))
    if skip_dirs:
        cfg["skip_dirs"] = set(skip_dirs)

    exclude_dirs = _list_of_non_empty_strings(raw.get("exclude_dirs"))
    for d in exclude_dirs:
        cfg["skip_dirs"].add(d)

    include_dirs = _list_of_non_empty_strings(raw.get("include_dirs"))
    for d in include_dirs:
        cfg["skip_dirs"].discard(d)

    skip_dir_prefixes = _list_of_non_empty_strings(raw.get("skip_dir_prefixes"))
    if not skip_dir_prefixes:
        skip_dir_prefixes = _list_of_non_empty_strings(raw.get("exclude_dir_prefixes"))
    if skip_dir_prefixes:
        cfg["skip_dir_prefixes"] = [
            normalized
            for normalized in (_normalize_relative_dir_prefix(item) for item in skip_dir_prefixes)
            if normalized
        ]

    skip_patterns = _list_of_non_empty_strings(raw.get("skip_file_patterns"))
    if skip_patterns:
        cfg["skip_file_patterns"] = skip_patterns

    extra_patterns = _list_of_non_empty_strings(raw.get("exclude_path_patterns"))
    if extra_patterns:
        cfg["skip_file_patterns"].extend(extra_patterns)

    if "max_file_bytes" in raw:
        cfg["max_file_bytes"] = coerce_optional_positive_int(raw.get("max_file_bytes"), cfg["max_file_bytes"])

    inline_redaction_rules = _normalize_redaction_rules(raw.get("redaction_rules"), config_path)
    if inline_redaction_rules:
        cfg["custom_redaction_rules"].extend(inline_redaction_rules)

    external_rules, external_policy_path = _load_external_redaction_rules(repo_path, raw.get("redaction_policy_file"))
    if external_rules:
        cfg["custom_redaction_rules"].extend(external_rules)
    if external_policy_path:
        cfg["redaction_policy_path"] = external_policy_path

    security_policy = default_security_policy()
    external_security_policy, external_security_policy_path = _load_external_security_policy(
        repo_path,
        raw.get("security_policy_file"),
    )
    security_policy = merge_security_policy(security_policy, external_security_policy)
    inline_security_policy = raw.get("security_policy")
    if isinstance(inline_security_policy, dict):
        security_policy = merge_security_policy(
            security_policy,
            _normalize_security_policy(inline_security_policy, config_path),
        )
        cfg["security_policy_path"] = config_path
    elif external_security_policy_path:
        cfg["security_policy_path"] = external_security_policy_path
    cfg["security_policy"] = security_policy

    runtime_cfg = default_runtime_probe_config()
    runtime_raw = raw.get("runtime")
    if isinstance(runtime_raw, dict):
        if "enabled" in runtime_raw:
            runtime_cfg["enabled"] = bool(runtime_raw.get("enabled"))
        if "commands" in runtime_raw:
            runtime_cfg["commands"] = _normalize_runtime_command_specs(repo_path, runtime_raw.get("commands"))
        if "timeout_seconds" in runtime_raw:
            runtime_cfg["timeout_seconds"] = coerce_positive_float(
                runtime_raw.get("timeout_seconds"),
                runtime_cfg["timeout_seconds"],
            )
        if "max_output_chars" in runtime_raw:
            runtime_cfg["max_output_chars"] = coerce_optional_positive_int(
                runtime_raw.get("max_output_chars"),
                runtime_cfg["max_output_chars"],
            )
        if "startup_seconds" in runtime_raw:
            runtime_cfg["startup_seconds"] = coerce_positive_float(
                runtime_raw.get("startup_seconds"),
                runtime_cfg["startup_seconds"],
            )
        if "request_timeout_seconds" in runtime_raw:
            runtime_cfg["request_timeout_seconds"] = coerce_positive_float(
                runtime_raw.get("request_timeout_seconds"),
                runtime_cfg["request_timeout_seconds"],
            )
        if "max_endpoint_probes" in runtime_raw:
            try:
                runtime_cfg["max_endpoint_probes"] = max(1, int(runtime_raw.get("max_endpoint_probes")))
            except Exception:
                pass
        if "verify_endpoints" in runtime_raw:
            runtime_cfg["verify_endpoints"] = bool(runtime_raw.get("verify_endpoints"))
        if "request_headers" in runtime_raw:
            runtime_cfg["request_headers"] = _normalize_runtime_request_headers(runtime_raw.get("request_headers"))
        elif "headers" in runtime_raw:
            runtime_cfg["request_headers"] = _normalize_runtime_request_headers(runtime_raw.get("headers"))
        if "request_cookies" in runtime_raw:
            runtime_cfg["request_cookies"] = _normalize_runtime_request_cookies(runtime_raw.get("request_cookies"))
        elif "cookies" in runtime_raw:
            runtime_cfg["request_cookies"] = _normalize_runtime_request_cookies(runtime_raw.get("cookies"))
        if "bootstrap_requests" in runtime_raw:
            runtime_cfg["bootstrap_requests"] = _normalize_runtime_bootstrap_requests(runtime_raw.get("bootstrap_requests"))
        elif "bootstrap" in runtime_raw:
            runtime_cfg["bootstrap_requests"] = _normalize_runtime_bootstrap_requests(runtime_raw.get("bootstrap"))
        if "template_variables" in runtime_raw:
            runtime_cfg["template_variables"] = _normalize_runtime_template_variables(runtime_raw.get("template_variables"))
        elif "variables" in runtime_raw:
            runtime_cfg["template_variables"] = _normalize_runtime_template_variables(runtime_raw.get("variables"))
        elif "auth_variables" in runtime_raw:
            runtime_cfg["template_variables"] = _normalize_runtime_template_variables(runtime_raw.get("auth_variables"))
        if "ready_http" in runtime_raw:
            runtime_cfg["ready_http"] = _normalize_runtime_ready_http_targets(runtime_raw.get("ready_http"))
        if "ready_tcp" in runtime_raw:
            runtime_cfg["ready_tcp"] = _normalize_runtime_ready_tcp_targets(runtime_raw.get("ready_tcp"))
        if "ready_files" in runtime_raw:
            runtime_cfg["ready_files"] = _normalize_runtime_ready_files(runtime_raw.get("ready_files"))
        if "ready_protocols" in runtime_raw:
            runtime_cfg["ready_protocols"] = _normalize_runtime_ready_protocols(runtime_raw.get("ready_protocols"))
        if "ready_timeout_seconds" in runtime_raw:
            raw_ready_timeout = runtime_raw.get("ready_timeout_seconds")
            runtime_cfg["ready_timeout_seconds"] = (
                coerce_positive_float(raw_ready_timeout, 0.0) if raw_ready_timeout is not None else None
            )
        if "refresh_on_status" in runtime_raw:
            runtime_cfg["refresh_on_status"] = _normalize_runtime_http_status_list(runtime_raw.get("refresh_on_status"))
        elif "credential_refresh_statuses" in runtime_raw:
            runtime_cfg["refresh_on_status"] = _normalize_runtime_http_status_list(runtime_raw.get("credential_refresh_statuses"))
        if "max_bootstrap_refreshes" in runtime_raw:
            try:
                runtime_cfg["max_bootstrap_refreshes"] = max(0, int(runtime_raw.get("max_bootstrap_refreshes", 1) or 0))
            except Exception:
                pass
        if "base_urls" in runtime_raw:
            runtime_cfg["base_urls"] = _normalize_runtime_base_urls(runtime_raw.get("base_urls"))
        elif "base_url" in runtime_raw:
            runtime_cfg["base_urls"] = _normalize_runtime_base_urls(runtime_raw.get("base_url"))
        if "max_commands" in runtime_raw:
            try:
                runtime_cfg["max_commands"] = max(1, int(runtime_raw.get("max_commands")))
            except Exception:
                pass
    if "runtime_probe" in raw:
        runtime_cfg["enabled"] = bool(raw.get("runtime_probe"))
    if "runtime_commands" in raw:
        runtime_cfg["commands"] = _normalize_runtime_command_specs(repo_path, raw.get("runtime_commands"))
    cfg["runtime"] = runtime_cfg
    cfg["policy_packs"] = configured_policy_packs

    if not cfg["include_exts"]:
        print(f"[WARN] Scan config removed all include extensions. Restoring defaults from {config_path}.")
        cfg["include_exts"] = set(EXTS)

    return apply_policy_packs_to_scan_config(cfg, configured_policy_packs, source=config_path)

def summarize_scan_config(scan_config: dict[str, Any]) -> str:
    source = scan_config.get("config_path", "") or "defaults"
    include_exts = scan_config.get("include_exts", set())
    skip_dirs = scan_config.get("skip_dirs", set())
    skip_dir_prefixes = scan_config.get("skip_dir_prefixes", [])
    skip_patterns = scan_config.get("skip_file_patterns", [])
    max_file_bytes = scan_config.get("max_file_bytes", MAX_FILE_BYTES)
    custom_redaction_rules = scan_config.get("custom_redaction_rules", [])
    runtime_cfg = scan_config.get("runtime", {})
    security_policy = merge_security_policy(default_security_policy(), scan_config.get("security_policy", {}))
    policy_packs = [str(item).strip() for item in scan_config.get("policy_packs", []) if str(item).strip()]
    max_file_bytes_text = "unlimited" if max_file_bytes is None else str(int(max_file_bytes))
    return (
        f"source={source}, include_exts={len(include_exts)}, "
        f"skip_dirs={len(skip_dirs) + len(skip_dir_prefixes)}, skip_patterns={len(skip_patterns)}, "
        f"max_file_bytes={max_file_bytes_text}, custom_redaction_rules={len(custom_redaction_rules)}, "
        f"runtime_probe={bool(runtime_cfg.get('enabled', False))}, runtime_commands={len(runtime_cfg.get('commands', []))}, "
        f"security_policy={str(security_policy.get('name', 'default')).strip() or 'default'}, "
        f"policy_packs={','.join(policy_packs) if policy_packs else 'none'}"
    )

def merge_runtime_probe_config(
    repo_path: str,
    scan_config: Optional[dict[str, Any]] = None,
    *,
    enabled: Optional[bool] = None,
    commands: Optional[list[str]] = None,
    timeout_seconds: Optional[float] = None,
    max_output_chars: Optional[int] = None,
) -> dict[str, Any]:
    base_cfg = default_runtime_probe_config()
    if isinstance(scan_config, dict):
        runtime_cfg = scan_config.get("runtime", {})
        if isinstance(runtime_cfg, dict):
            merged = dict(base_cfg)
            merged.update(runtime_cfg)
            base_cfg = merged

    if enabled is not None:
        base_cfg["enabled"] = bool(enabled)
    if commands:
        base_cfg["commands"] = _normalize_runtime_command_specs(repo_path, commands)
    if timeout_seconds is not None:
        base_cfg["timeout_seconds"] = coerce_positive_float(timeout_seconds, base_cfg["timeout_seconds"])
    if max_output_chars is not None:
        base_cfg["max_output_chars"] = coerce_optional_positive_int(max_output_chars, base_cfg["max_output_chars"])

    base_cfg["startup_seconds"] = coerce_positive_float(
        base_cfg.get("startup_seconds"),
        min(RUNTIME_SERVER_STARTUP_SECONDS, base_cfg["timeout_seconds"]),
    )
    base_cfg["request_timeout_seconds"] = coerce_positive_float(
        base_cfg.get("request_timeout_seconds"),
        RUNTIME_HTTP_PROBE_TIMEOUT_SECONDS,
    )
    base_cfg["verify_endpoints"] = bool(base_cfg.get("verify_endpoints", True))
    base_cfg["request_headers"] = _normalize_runtime_request_headers(base_cfg.get("request_headers", {}))
    base_cfg["request_cookies"] = _normalize_runtime_request_cookies(base_cfg.get("request_cookies", {}))
    base_cfg["bootstrap_requests"] = _normalize_runtime_bootstrap_requests(base_cfg.get("bootstrap_requests", []))
    base_cfg["template_variables"] = _normalize_runtime_template_variables(base_cfg.get("template_variables", {}))
    base_cfg["ready_http"] = _normalize_runtime_ready_http_targets(base_cfg.get("ready_http", []))
    base_cfg["ready_tcp"] = _normalize_runtime_ready_tcp_targets(base_cfg.get("ready_tcp", []))
    base_cfg["ready_files"] = _normalize_runtime_ready_files(base_cfg.get("ready_files", []))
    base_cfg["ready_protocols"] = _normalize_runtime_ready_protocols(base_cfg.get("ready_protocols", []))
    base_cfg["refresh_on_status"] = _normalize_runtime_http_status_list(base_cfg.get("refresh_on_status", [401, 403]))
    base_cfg["base_urls"] = _normalize_runtime_base_urls(base_cfg.get("base_urls", []))
    base_cfg["service_profiles"] = _normalize_runtime_service_profiles(base_cfg.get("service_profiles", {}))
    ready_timeout = base_cfg.get("ready_timeout_seconds")
    base_cfg["ready_timeout_seconds"] = coerce_positive_float(ready_timeout, 0.0) if ready_timeout is not None else None
    try:
        base_cfg["max_bootstrap_refreshes"] = max(0, int(base_cfg.get("max_bootstrap_refreshes", 1) or 0))
    except Exception:
        base_cfg["max_bootstrap_refreshes"] = 1

    try:
        base_cfg["max_commands"] = max(1, int(base_cfg.get("max_commands", 2)))
    except Exception:
        base_cfg["max_commands"] = 2
    try:
        base_cfg["max_endpoint_probes"] = max(1, int(base_cfg.get("max_endpoint_probes", RUNTIME_MAX_ENDPOINT_PROBES)))
    except Exception:
        base_cfg["max_endpoint_probes"] = RUNTIME_MAX_ENDPOINT_PROBES
    return base_cfg

def apply_runtime_config_to_scan_config(
    scan_config: Optional[dict[str, Any]],
    runtime_config: Optional[dict[str, Any]],
) -> dict[str, Any]:
    merged = dict(scan_config) if isinstance(scan_config, dict) else {}
    runtime_cfg = default_runtime_probe_config()
    raw_runtime = merged.get("runtime", {})
    if isinstance(raw_runtime, dict):
        runtime_cfg.update(raw_runtime)
    if isinstance(runtime_config, dict):
        runtime_cfg.update(runtime_config)
    merged["runtime"] = runtime_cfg
    return merged

def _command_matches_any_pattern(command: str, patterns: list[str]) -> bool:
    cmd = str(command or "").strip()
    if not cmd:
        return False
    for pattern in patterns:
        try:
            if re.search(pattern, cmd):
                return True
        except Exception:
            continue
    return False

def build_security_policy_audit(
    scan_config: Optional[dict[str, Any]],
    runtime_config: Optional[dict[str, Any]],
    *,
    requested_mode: str,
    effective_mode: str,
    redaction_stats: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    config = scan_config if isinstance(scan_config, dict) else default_scan_config()
    runtime_cfg = runtime_config if isinstance(runtime_config, dict) else default_runtime_probe_config()
    policy = merge_security_policy(default_security_policy(), config.get("security_policy", {}))
    checks: list[dict[str, Any]] = []
    violations: list[str] = []
    llm_mode_active = requested_mode == "agent" or effective_mode == "agent"

    def add_check(name: str, passed: bool, detail: str) -> None:
        checks.append({"name": name, "passed": bool(passed), "detail": detail})
        if not passed:
            violations.append(f"{name}: {detail}")

    strict_required = bool(policy.get("require_strict_local_only", False))
    add_check(
        "strict_local_only",
        (not strict_required) or STRICT_LOCAL_ONLY,
        "STRICT_LOCAL_ONLY must be enabled by environment/policy." if strict_required else "Policy does not require strict local mode.",
    )

    if llm_mode_active and not bool(policy.get("allow_remote_llm", False)):
        remote_error = privacy_lock_error(
            llm_backend=LLM_BACKEND,
            ollama_host=os.getenv("OLLAMA_HOST", ""),
        )
        add_check(
            "remote_llm_boundary",
            remote_error is None,
            remote_error or "LLM backend resolves to loopback/local endpoint.",
        )
    else:
        add_check(
            "remote_llm_boundary",
            True,
            "Remote LLM check skipped because agent mode is inactive or policy permits it.",
        )

    require_scan_config = bool(policy.get("require_scan_config_file", False))
    config_path = str(config.get("config_path", "")).strip()
    add_check(
        "scan_config_presence",
        (not require_scan_config) or bool(config_path),
        "Repository must provide a scan config file." if require_scan_config else "Policy does not require a scan config file.",
    )

    require_redaction_policy = bool(policy.get("require_redaction_policy_file", False))
    redaction_policy_path = str(config.get("redaction_policy_path", "")).strip()
    add_check(
        "redaction_policy_presence",
        (not require_redaction_policy) or bool(redaction_policy_path),
        "A redaction policy file is required for this repository." if require_redaction_policy else "Policy does not require a redaction policy file.",
    )

    min_rules = int(policy.get("min_custom_redaction_rules", 0) or 0)
    custom_rule_count = len(config.get("custom_redaction_rules", []))
    add_check(
        "custom_redaction_rule_count",
        custom_rule_count >= min_rules,
        f"Configured custom redaction rules={custom_rule_count}, required minimum={min_rules}.",
    )

    require_classification_rules = bool(policy.get("require_classification_rules", False))
    classification_rules = policy.get("classification_rules", [])
    classification_rule_count = len(classification_rules) if isinstance(classification_rules, list) else 0
    add_check(
        "classification_rules_presence",
        (not require_classification_rules) or classification_rule_count > 0,
        (
            f"Configured classification rules={classification_rule_count}."
            if require_classification_rules
            else "Policy does not require classification rules."
        ),
    )

    max_allowed_file_bytes = policy.get("max_allowed_file_bytes")
    configured_max_file_bytes = config.get("max_file_bytes", MAX_FILE_BYTES)
    max_file_bytes_ok = True
    if max_allowed_file_bytes is not None:
        if configured_max_file_bytes is None:
            max_file_bytes_ok = False
        else:
            try:
                max_file_bytes_ok = int(configured_max_file_bytes) <= int(max_allowed_file_bytes)
            except Exception:
                max_file_bytes_ok = False
    add_check(
        "max_file_bytes_limit",
        max_file_bytes_ok,
        (
            f"Configured max_file_bytes={configured_max_file_bytes}, policy limit={max_allowed_file_bytes}."
            if max_allowed_file_bytes is not None
            else "Policy does not cap max_file_bytes."
        ),
    )

    runtime_enabled = bool(runtime_cfg.get("enabled", False))
    allow_runtime_probe = bool(policy.get("allow_runtime_probe", True))
    add_check(
        "runtime_probe_allowed",
        (not runtime_enabled) or allow_runtime_probe,
        "Runtime probing is disabled by policy." if runtime_enabled and not allow_runtime_probe else "Runtime probe policy satisfied.",
    )

    commands = runtime_cfg.get("commands", [])
    if not isinstance(commands, list):
        commands = []
    command_texts = [str(item.get("command", "")).strip() for item in commands if isinstance(item, dict)]
    allowed_patterns = policy.get("allowed_runtime_command_patterns", [])
    blocked_patterns = policy.get("blocked_runtime_command_patterns", [])
    if runtime_enabled and command_texts and allowed_patterns:
        allowed_ok = all(_command_matches_any_pattern(cmd, allowed_patterns) for cmd in command_texts)
        add_check(
            "runtime_command_allowlist",
            allowed_ok,
            f"Runtime commands must match allowlist patterns. Commands={json.dumps(command_texts[:5], ensure_ascii=True)}",
        )
    else:
        add_check(
            "runtime_command_allowlist",
            True,
            "No runtime allowlist enforcement triggered.",
        )

    if runtime_enabled and command_texts and blocked_patterns:
        blocked_ok = not any(_command_matches_any_pattern(cmd, blocked_patterns) for cmd in command_texts)
        add_check(
            "runtime_command_blocklist",
            blocked_ok,
            f"Runtime commands matched blocked patterns. Commands={json.dumps(command_texts[:5], ensure_ascii=True)}",
        )
    else:
        add_check(
            "runtime_command_blocklist",
            True,
            "No runtime blocklist enforcement triggered.",
        )

    if isinstance(redaction_stats, dict):
        fail_on_skips = bool(policy.get("fail_on_skipped_large_files", False))
        skipped_large = int(redaction_stats.get("skipped_by_size_count", 0) or 0)
        add_check(
            "skipped_large_files",
            (not fail_on_skips) or skipped_large == 0,
            (
                f"Skipped large files by size guard={skipped_large}."
                if fail_on_skips
                else f"Skipped large files by size guard={skipped_large}; policy allows this."
            ),
        )

    return {
        "policy": policy,
        "policy_path": str(config.get("security_policy_path", "")).strip(),
        "policy_packs": list(config.get("policy_packs", [])) if isinstance(config.get("policy_packs", []), list) else [],
        "config_path": config_path,
        "requested_mode": requested_mode,
        "effective_mode": effective_mode,
        "llm_backend": LLM_BACKEND,
        "strict_local_only": STRICT_LOCAL_ONLY,
        "runtime_probe_enabled": runtime_enabled,
        "checks": checks,
        "pass": len(violations) == 0,
        "violations": violations,
    }

def enforce_security_policy(
    scan_config: Optional[dict[str, Any]],
    runtime_config: Optional[dict[str, Any]],
    *,
    requested_mode: str,
    effective_mode: str,
    redaction_stats: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    audit = build_security_policy_audit(
        scan_config,
        runtime_config,
        requested_mode=requested_mode,
        effective_mode=effective_mode,
        redaction_stats=redaction_stats,
    )
    if not audit.get("pass", False):
        raise RuntimeError("; ".join(audit.get("violations", [])[:3]))
    return audit

def should_skip_path(relpath: str, skip_file_patterns: Optional[list[str]] = None) -> bool:
    s = relpath.replace("\\", "/")
    patterns = SKIP_FILE_PATTERNS if skip_file_patterns is None else skip_file_patterns
    for pat in patterns:
        if re.search(pat, s, flags=re.IGNORECASE):
            return True
    return False

def should_take_file(filename: str, include_exts: Optional[set[str]] = None) -> bool:
    if filename in {"Dockerfile", "go.mod", "go.sum", "Gemfile", "Procfile", "pom.xml"}:
        return True
    _, ext = os.path.splitext(filename.lower())
    exts = EXTS if include_exts is None else include_exts
    return ext in exts

def merge_count_dict(dst: dict[str, int], src: dict[str, int]) -> None:
    for key, val in src.items():
        dst[key] = dst.get(key, 0) + val

def redact_secrets(text: str) -> tuple[str, dict[str, int]]:
    redacted = text
    counts: dict[str, int] = {}
    for name, pattern in _ACTIVE_SECRET_PATTERNS:
        placeholder = _ACTIVE_SECRET_REPLACEMENTS.get(name, f"[REDACTED_{name.upper()}]")
        redacted, n = pattern.subn(placeholder, redacted)
        if n:
            counts[name] = counts.get(name, 0) + n
    return redacted, counts

def summarize_redaction_stats(stats: dict) -> str:
    total = stats.get("total_redactions", 0)
    by_pattern = stats.get("by_pattern", {})
    files = stats.get("files_with_redactions", [])
    custom_count = int(stats.get("custom_redaction_rules_count", 0) or 0)
    policy_path = str(stats.get("redaction_policy_path", "")).strip()
    policy_text = policy_path or "none"
    return (
        f"total_redactions={total}, "
        f"patterns={json.dumps(by_pattern, ensure_ascii=True)}, "
        f"files_with_redactions={json.dumps(files[:MAX_FILES_WITH_REDACTIONS_IN_REPORT], ensure_ascii=True)}, "
        f"custom_redaction_rules={custom_count}, "
        f"redaction_policy_path={policy_text}"
    )

FACT_SANITIZE_PRESERVE_KEYS = {"path", "file", "evidence"}

FACT_CLASSIFICATION_LIST_KEYS = [
    "entrypoints",
    "event_dispatches",
    "imports",
    "module_resolution_hints",
    "python_import_aliases",
    "dependencies",
    "api_endpoints",
    "scripts",
    "run_hints",
    "infrastructure",
    "ai_signals",
    "framework_signals",
    "sql_entities",
    "sql_queries",
    "python_symbols",
    "python_calls",
    "python_module_state",
    "language_symbols",
    "language_calls",
    "cross_file_symbol_edges",
    "cross_file_event_edges",
    "runtime_observations",
    "api_contract_links",
]

API_CONTRACT_FRAMEWORKS = {"openapi_spec", "asyncapi_spec"}

def sanitize_fact_string(value: str) -> str:
    sanitized, _counts = redact_secrets(str(value))
    sanitized = sanitized.replace("\r", " ").replace("\n", " ").replace("\t", " ")
    sanitized = re.sub(r"\s+", " ", sanitized).strip()
    return sanitized

def sanitize_fact_structure(value: Any, preserve_keys: Optional[set[str]] = None) -> Any:
    keep_raw_keys = FACT_SANITIZE_PRESERVE_KEYS if preserve_keys is None else preserve_keys
    if isinstance(value, dict):
        out = {}
        for key, item in value.items():
            if key in keep_raw_keys:
                out[key] = item
            else:
                out[key] = sanitize_fact_structure(item, preserve_keys=keep_raw_keys)
        return out
    if isinstance(value, list):
        return [sanitize_fact_structure(item, preserve_keys=keep_raw_keys) for item in value]
    if isinstance(value, str):
        return sanitize_fact_string(value)
    return value


def _empty_classification_summary() -> dict[str, Any]:
    return {
        "default_classification": "unclassified",
        "highest_classification": "unclassified",
        "classification_counts": {},
        "classified_files": 0,
        "matched_files": 0,
        "rule_count": 0,
        "matched_rule_names": [],
    }


def _classification_annotation_for_path(path: str, policy: Optional[dict[str, Any]]) -> dict[str, Any]:
    current = merge_security_policy(default_security_policy(), policy if isinstance(policy, dict) else {})
    normalized_path = normalize_repo_path(str(path or "").strip())
    default_label = normalize_data_classification(current.get("default_data_classification", "unclassified"))
    effective_label = default_label
    effective_rank = classification_rank(default_label)
    matched_rule_names: list[str] = []
    for item in current.get("classification_rules", []):
        if not isinstance(item, dict):
            continue
        patterns = item.get("path_patterns", [])
        if not isinstance(patterns, list) or not patterns:
            continue
        matched = False
        for pattern in patterns:
            try:
                if re.search(str(pattern), normalized_path, flags=re.IGNORECASE):
                    matched = True
                    break
            except Exception:
                continue
        if not matched:
            continue
        matched_rule_names.append(str(item.get("name", "")).strip() or "classification_rule")
        label = normalize_data_classification(item.get("classification", default_label))
        label_rank = classification_rank(label)
        if label_rank >= effective_rank:
            effective_label = label
            effective_rank = label_rank
    return {
        "classification": effective_label,
        "classification_source": "default" if not matched_rule_names else f"rule:{matched_rule_names[0]}",
        "classification_rules": matched_rule_names,
    }


def apply_data_classification_annotations(
    fact_index: Optional[dict[str, Any]],
    scan_config: Optional[dict[str, Any]],
) -> dict[str, Any]:
    current = fact_index if isinstance(fact_index, dict) else _empty_fact_index()
    config = scan_config if isinstance(scan_config, dict) else default_scan_config()
    policy = merge_security_policy(default_security_policy(), config.get("security_policy", {}))
    default_label = normalize_data_classification(policy.get("default_data_classification", "unclassified"))
    highest_label = default_label
    highest_rank = classification_rank(default_label)
    counts: dict[str, int] = {}
    matched_files = 0
    matched_rule_names: set[str] = set()
    file_annotations: dict[str, dict[str, Any]] = {}

    files = current.get("files", [])
    if isinstance(files, list):
        for item in files:
            if not isinstance(item, dict):
                continue
            path = normalize_repo_path(str(item.get("path", "")).strip())
            annotation = _classification_annotation_for_path(path, policy)
            item["classification"] = annotation["classification"]
            item["classification_source"] = annotation["classification_source"]
            if annotation["classification_rules"]:
                item["classification_rules"] = list(annotation["classification_rules"])
            else:
                item.pop("classification_rules", None)
            file_annotations[path] = annotation
            label = annotation["classification"]
            counts[label] = counts.get(label, 0) + 1
            if annotation["classification_source"] != "default":
                matched_files += 1
            for rule_name in annotation["classification_rules"]:
                matched_rule_names.add(str(rule_name))
            label_rank = classification_rank(label)
            if label_rank >= highest_rank:
                highest_rank = label_rank
                highest_label = label

    for key in FACT_CLASSIFICATION_LIST_KEYS:
        items = current.get(key, [])
        if not isinstance(items, list):
            continue
        for item in items:
            if not isinstance(item, dict):
                continue
            path = normalize_repo_path(
                str(item.get("file", "") or item.get("path", "")).strip()
            )
            if not path:
                continue
            annotation = file_annotations.get(path)
            if annotation is None:
                annotation = _classification_annotation_for_path(path, policy)
                file_annotations[path] = annotation
            item["classification"] = annotation["classification"]
            item["classification_source"] = annotation["classification_source"]
            if annotation["classification_rules"]:
                item["classification_rules"] = list(annotation["classification_rules"])
            else:
                item.pop("classification_rules", None)

    summary = {
        "default_classification": default_label,
        "highest_classification": highest_label if counts else default_label,
        "classification_counts": dict(sorted(counts.items(), key=lambda item: (classification_rank(item[0]), item[0]))),
        "classified_files": sum(counts.values()),
        "matched_files": matched_files,
        "rule_count": len(policy.get("classification_rules", [])) if isinstance(policy.get("classification_rules", []), list) else 0,
        "matched_rule_names": sorted(list(matched_rule_names)),
    }
    current["classification_summary"] = summary
    if isinstance(current.get("summary", {}), dict):
        current["summary"]["classified_files"] = summary["classified_files"]
        current["summary"]["highest_classification"] = summary["highest_classification"]
    return current

def read_files(
    folder: str,
    max_chars: Optional[int] = MAX_CHARS,
    collect_text: bool = True,
    scan_config: Optional[dict[str, Any]] = None,
) -> tuple[str, dict]:
    if not os.path.isdir(folder):
        raise ValueError(f"Path is not a folder: {folder}")

    config = scan_config if isinstance(scan_config, dict) else load_repo_scan_config(folder)
    configure_redaction_policy(config)
    include_exts_raw = config.get("include_exts", set(EXTS))
    skip_dirs_raw = config.get("skip_dirs", set(SKIP_DIRS))
    skip_patterns_raw = config.get("skip_file_patterns", list(SKIP_FILE_PATTERNS))
    max_file_bytes = coerce_optional_positive_int(config.get("max_file_bytes"), MAX_FILE_BYTES)

    include_exts = set([_normalize_extension_value(ext) for ext in include_exts_raw if _normalize_extension_value(ext)])
    if not include_exts:
        include_exts = set(EXTS)
    skip_dirs = set([str(d).strip() for d in skip_dirs_raw if str(d).strip()])
    skip_dir_prefixes_raw = config.get("skip_dir_prefixes", [])
    skip_dir_prefixes = [
        normalized
        for normalized in (
            _normalize_relative_dir_prefix(item)
            for item in (skip_dir_prefixes_raw if isinstance(skip_dir_prefixes_raw, list) else [])
        )
        if normalized
    ]
    skip_patterns = [str(p).strip() for p in skip_patterns_raw if str(p).strip()]

    print(f"[INFO] scan_config: {summarize_scan_config(config)}")

    content_parts = []
    total_chars_collected = 0
    total_chars_scanned = 0
    files_read = 0
    skipped_by_ext_count = 0
    skipped_by_pattern_count = 0
    skipped_by_size_count = 0
    skipped_large_files: list[dict[str, Any]] = []
    redactions_by_pattern: dict[str, int] = {}
    files_with_redactions: list[str] = []
    files_with_redactions_set: set[str] = set()
    included_files: list[str] = []
    line_counts: dict[str, int] = {}

    def build_stats() -> dict[str, Any]:
        return {
            "total_redactions": sum(redactions_by_pattern.values()),
            "by_pattern": redactions_by_pattern,
            "files_with_redactions": files_with_redactions,
            "included_files": included_files,
            "line_counts": line_counts,
            "files_read": files_read,
            "chars_collected": total_chars_collected,
            "chars_scanned": total_chars_scanned,
            "skipped_by_ext_count": skipped_by_ext_count,
            "skipped_by_pattern_count": skipped_by_pattern_count,
            "skipped_by_size_count": skipped_by_size_count,
            "skipped_large_files": skipped_large_files,
            "repo_path": os.path.abspath(folder),
            "scan_config_path": config.get("config_path", ""),
            "redaction_policy_path": config.get("redaction_policy_path", ""),
            "security_policy_path": config.get("security_policy_path", ""),
            "security_policy_name": str(config.get("security_policy", {}).get("name", "default")).strip() or "default",
            "policy_packs": list(config.get("policy_packs", [])) if isinstance(config.get("policy_packs", []), list) else [],
            "recommended_grounding_profile": str(config.get("recommended_grounding_profile", "")).strip(),
            "custom_redaction_rules_count": len(config.get("custom_redaction_rules", [])),
            "max_file_bytes": max_file_bytes,
        }

    for root, dirs, files in os.walk(folder):
        pruned_dirs: list[str] = []
        for d in sorted(dirs):
            if d in skip_dirs:
                continue
            child_rel = os.path.relpath(os.path.join(root, d), folder).replace("\\", "/")
            if _dir_matches_prefix(child_rel, skip_dir_prefixes):
                continue
            pruned_dirs.append(d)
        dirs[:] = pruned_dirs

        for file in sorted(files):
            if not should_take_file(file, include_exts=include_exts):
                skipped_by_ext_count += 1
                continue

            path = os.path.join(root, file)
            rel = os.path.relpath(path, folder)

            if should_skip_path(rel, skip_file_patterns=skip_patterns):
                skipped_by_pattern_count += 1
                continue

            try:
                file_size = int(os.path.getsize(path))
            except Exception:
                continue

            if max_file_bytes is not None and file_size > max_file_bytes:
                skipped_by_size_count += 1
                if len(skipped_large_files) < 20:
                    skipped_large_files.append({"path": rel, "size_bytes": file_size})
                continue

            try:
                with open(path, "r", encoding="utf-8", errors="ignore") as f:
                    text = f.read()
                line_counts[rel] = text.count("\n") + 1

                redacted_text, local_counts = redact_secrets(text)
                if local_counts and rel not in files_with_redactions_set:
                    files_with_redactions_set.add(rel)
                    files_with_redactions.append(rel)
                merge_count_dict(redactions_by_pattern, local_counts)

                block = f"\n\nFILE: {rel}\n{redacted_text}"
                total_chars_scanned += len(block)

                if collect_text:
                    if max_chars is not None and total_chars_collected + len(block) > max_chars:
                        print(f"[INFO] Hit max_chars={max_chars}. Files read={files_read}, chars={total_chars_collected}")
                        return "\n".join(content_parts), build_stats()

                    content_parts.append(block)
                    total_chars_collected += len(block)
                files_read += 1
                included_files.append(rel)

            except Exception:
                pass

    if skipped_by_size_count > 0:
        max_file_bytes_text = "unlimited" if max_file_bytes is None else str(int(max_file_bytes))
        print(f"[INFO] skipped_large_files={skipped_by_size_count}, max_file_bytes={max_file_bytes_text}")

    if collect_text:
        print(f"[INFO] Done reading. Files read={files_read}, chars={total_chars_collected}")
    else:
        print(f"[INFO] Done reading metadata scan. Files read={files_read}, chars_scanned={total_chars_scanned}")
    return "\n".join(content_parts), build_stats()

