class Timeout(Exception):
    pass

def _handler(signum, frame):
    raise Timeout()

def has_cjk(text: str) -> bool:
    # Detect Chinese/Japanese/Korean characters
    return bool(re.search(r"[\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]", text))

# =========================
# MERMAID SANITIZER
# =========================
def _clean_mermaid_label(s: str) -> str:
    # Remove problematic characters for strict Mermaid parsers
    s = s.replace("(", " ").replace(")", " ")
    s = s.replace("/", " ")
    s = s.replace("\\", " ")
    s = s.replace(";", " ")
    s = s.replace(":", " -")
    s = s.replace("&", "and")

    # Clean extra spaces
    s = re.sub(r"\s+", " ", s).strip()
    return s

def sanitize_mermaid_block(diagram: str) -> str:
    """
    Sanitize a Mermaid diagram for picky renderers (VS Code extensions).
    - Removes ';' after graph direction
    - Cleans labels inside [] and ""
    """
    # graph TD;  -> graph TD
    diagram = re.sub(
        r'(^\s*graph\s+[A-Za-z]+\s*);\s*$',
        r'\1',
        diagram,
        flags=re.MULTILINE
    )

    # Clean labels in [ ... ]
    def bracket_repl(m: re.Match) -> str:
        inner = m.group(1)
        return f'[{_clean_mermaid_label(inner)}]'
    diagram = re.sub(r"\[([^\]]*)\]", bracket_repl, diagram)

    # Clean labels in " ... "
    def quote_repl(m: re.Match) -> str:
        inner = m.group(1)
        return f"\"{_clean_mermaid_label(inner)}\""
    diagram = re.sub(r"\"([^\"]*)\"", quote_repl, diagram)

    return diagram

def sanitize_all_mermaid(markdown: str) -> str:
    """
    Finds ```mermaid ... ``` blocks and sanitizes only the inside.
    """
    pattern = re.compile(r"```mermaid\s*\n(.*?)\n```", re.DOTALL | re.IGNORECASE)

    def repl(m: re.Match) -> str:
        body = m.group(1)
        fixed = sanitize_mermaid_block(body)
        return f"```mermaid\n{fixed}\n```"

    return pattern.sub(repl, markdown)

def split_code_by_file_blocks(code: str) -> list[str]:
    if not code.strip():
        return []
    blocks = re.split(r"\n{2}(?=FILE:\s)", code.strip())
    return [b.strip() for b in blocks if b.strip()]

def split_large_file_block(block: str, chunk_size: int) -> list[str]:
    if len(block) <= chunk_size:
        return [block]

    header, sep, body = block.partition("\n")
    if not sep:
        return [block[i:i + chunk_size] for i in range(0, len(block), chunk_size)]

    body_chunk_size = max(1_000, chunk_size - len(header) - 40)
    total_parts = (len(body) + body_chunk_size - 1) // body_chunk_size
    out = []
    for i in range(total_parts):
        start = i * body_chunk_size
        piece = body[start:start + body_chunk_size]
        out.append(f"{header} PART {i + 1} OF {total_parts}\n{piece}")
    return out

def chunk_text_by_file(text: str, chunk_size: int = CHUNK_SIZE) -> list[str]:
    chunks = []
    current_parts = []
    current_len = 0

    for block in split_code_by_file_blocks(text):
        for part in split_large_file_block(block, chunk_size):
            part_len = len(part)
            projected = part_len if not current_parts else current_len + 2 + part_len

            if current_parts and projected > chunk_size:
                chunks.append("\n\n".join(current_parts))
                current_parts = [part]
                current_len = part_len
            else:
                current_parts.append(part)
                current_len = projected if current_len else part_len

    if current_parts:
        chunks.append("\n\n".join(current_parts))
    return chunks

def infer_language(path: str) -> str:
    ext = os.path.splitext(path.lower())[1]
    if path == "Dockerfile":
        return "dockerfile"
    if os.path.basename(path) == "Rakefile":
        return "ruby"
    mapping = {
        ".py": "python",
        ".js": "javascript",
        ".ts": "typescript",
        ".tsx": "typescript",
        ".jsx": "javascript",
        ".html": "html",
        ".htm": "html",
        ".css": "css",
        ".scss": "scss",
        ".less": "less",
        ".md": "markdown",
        ".json": "json",
        ".yml": "yaml",
        ".yaml": "yaml",
        ".toml": "toml",
        ".sh": "shell",
        ".sql": "sql",
        ".go": "go",
        ".rs": "rust",
        ".java": "java",
        ".kt": "kotlin",
        ".cpp": "cpp",
        ".c": "c",
        ".cs": "csharp",
        ".php": "php",
        ".rb": "ruby",
        ".rake": "ruby",
        ".swift": "swift",
        ".graphql": "graphql",
        ".graphqls": "graphql",
        ".gql": "graphql",
        ".proto": "proto",
    }
    return mapping.get(ext, "other")

def normalize_package_name(name: str) -> str:
    s = name.strip().strip("'\"")
    if not s or s.startswith(".") or s.startswith("/"):
        return ""
    if s.startswith("@"):
        parts = s.split("/")
        if len(parts) >= 2:
            return f"{parts[0]}/{parts[1]}"
        return s
    return s.split("/")[0]


def normalize_go_package_name(name: str) -> str:
    s = str(name or "").strip().strip("'\"")
    if not s or s.startswith(".") or s.startswith("/"):
        return ""
    return s

def map_request_mapping_methods(methods_text: str) -> list[str]:
    if not methods_text.strip():
        return ["GET"]
    mappings = {
        "RequestMethod.GET": "GET",
        "RequestMethod.POST": "POST",
        "RequestMethod.PUT": "PUT",
        "RequestMethod.DELETE": "DELETE",
        "RequestMethod.PATCH": "PATCH",
        "RequestMethod.OPTIONS": "OPTIONS",
        "RequestMethod.HEAD": "HEAD",
        "GET": "GET",
        "POST": "POST",
        "PUT": "PUT",
        "DELETE": "DELETE",
        "PATCH": "PATCH",
        "OPTIONS": "OPTIONS",
        "HEAD": "HEAD",
    }
    out = []
    seen = set()
    for token in re.split(r"[,\s\[\]\{\}]+", methods_text):
        t = token.strip().strip("'\"")
        if not t:
            continue
        if t in mappings and mappings[t] not in seen:
            seen.add(mappings[t])
            out.append(mappings[t])
    return out or ["GET"]

