def make_evidence(path: str, line: int) -> str:
    return f"{path}#L{line}"

def find_line_containing(lines: list[str], needle: str, default: int = 1) -> int:
    for i, line in enumerate(lines, start=1):
        if needle in line:
            return i
    return default


def _line_number_from_offset(text: str, offset: int) -> int:
    return max(1, int(str(text or "").count("\n", 0, max(0, int(offset))) + 1))


def _normalize_route_prefix(value: str) -> str:
    normalized = _normalize_route_path(value)
    if normalized in {"", "/"}:
        return ""
    return normalized


def _compose_route_prefix(base_prefix: str, mount_prefix: str) -> str:
    base = _normalize_route_prefix(base_prefix)
    mount = _normalize_route_prefix(mount_prefix)
    if not base:
        return mount
    if not mount:
        return base
    return _normalize_route_prefix(f"{base.rstrip('/')}/{mount.lstrip('/')}")


def _compose_route_path(prefix: str, route: str) -> str:
    normalized_route = _normalize_route_path(route)
    normalized_prefix = _normalize_route_prefix(prefix)
    if not normalized_prefix:
        return normalized_route or "/"
    if not normalized_route or normalized_route == "/":
        return normalized_prefix or "/"
    return _normalize_route_path(f"{normalized_prefix.rstrip('/')}/{normalized_route.lstrip('/')}")


KUBERNETES_WORKLOAD_KINDS = {
    "deployment",
    "statefulset",
    "daemonset",
    "job",
    "cronjob",
}


def _split_yaml_documents(lines: list[str]) -> list[tuple[int, list[str]]]:
    docs: list[tuple[int, list[str]]] = []
    current: list[str] = []
    start_line = 1
    for idx, line in enumerate(lines, start=1):
        if re.match(r"^\s*---(?:\s+#.*)?\s*$", line):
            if any(str(item).strip() for item in current):
                docs.append((start_line, current))
            current = []
            start_line = idx + 1
            continue
        current.append(line)
    if any(str(item).strip() for item in current):
        docs.append((start_line, current))
    return docs


def _yaml_unquote_scalar(value: Any) -> str:
    raw = str(value or "").strip()
    if len(raw) >= 2 and raw[0] == raw[-1] and raw[0] in {"'", '"'}:
        raw = raw[1:-1]
    return raw.strip()


def _iter_simple_yaml_entries(doc_lines: list[str], start_line: int) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    stack: list[tuple[int, str]] = []
    for offset, line in enumerate(doc_lines):
        raw = str(line or "").rstrip("\n")
        stripped = raw.strip()
        if not stripped or stripped.startswith("#") or stripped == "...":
            continue
        indent = len(raw) - len(raw.lstrip(" "))
        is_list_item = False
        content = stripped
        if content.startswith("- "):
            is_list_item = True
            content = content[2:].strip()
        match = re.match(r"""(?:"([^"]+)"|'([^']+)'|([A-Za-z0-9_./{}-]+))\s*:\s*(.*)$""", content)
        if not match:
            continue
        key = str(match.group(1) or match.group(2) or match.group(3) or "").strip()
        value = str(match.group(4) or "").strip()
        level_indent = indent + (2 if is_list_item else 0)
        while stack and stack[-1][0] >= level_indent:
            stack.pop()
        path = tuple([item[1] for item in stack] + [key])
        line_no = start_line + offset
        entries.append(
            {
                "path": path,
                "key": key,
                "value": _yaml_unquote_scalar(value),
                "line": line_no,
                "indent": indent,
                "is_list_item": is_list_item,
            }
        )
        if not value:
            stack.append((level_indent, key))
    return entries


def _extract_kubernetes_manifest_items(rel: str, lines: list[str]) -> dict[str, list[dict[str, Any]]]:
    rel_lower = rel.replace("\\", "/").lower()
    out = {
        "infrastructure": [],
        "api_endpoints": [],
        "framework_signals": [],
        "run_hints": [],
    }
    is_helm_template = "/templates/" in f"/{rel_lower}"
    framework_keys: set[str] = set()
    for start_line, doc_lines in _split_yaml_documents(lines):
        entries = _iter_simple_yaml_entries(doc_lines, start_line)
        if not entries:
            continue
        kind_entry = next((item for item in entries if item.get("path") == ("kind",)), None)
        if not isinstance(kind_entry, dict):
            continue
        kind = str(kind_entry.get("value", "")).strip()
        if not kind:
            continue
        kind_lower = kind.lower()
        api_version = str(
            next((item.get("value", "") for item in entries if item.get("path") == ("apiVersion",)), "")
        ).strip()
        metadata_name_entry = next((item for item in entries if item.get("path") == ("metadata", "name")), None)
        namespace_entry = next((item for item in entries if item.get("path") == ("metadata", "namespace")), None)
        resource_name = str(metadata_name_entry.get("value", "") if isinstance(metadata_name_entry, dict) else "").strip()
        resource_namespace = str(namespace_entry.get("value", "") if isinstance(namespace_entry, dict) else "").strip()
        resource_line = int(
            metadata_name_entry.get("line", kind_entry.get("line", start_line))
            if isinstance(metadata_name_entry, dict)
            else kind_entry.get("line", start_line)
        )
        resource_evidence = make_evidence(rel, resource_line)

        if "kubernetes" not in framework_keys:
            framework_keys.add("kubernetes")
            out["framework_signals"].append(
                {
                    "name": "kubernetes",
                    "type": "infrastructure",
                    "evidence": make_evidence(rel, int(kind_entry.get("line", start_line) or start_line)),
                }
            )
        if is_helm_template and "helm" not in framework_keys:
            framework_keys.add("helm")
            out["framework_signals"].append(
                {
                    "name": "helm",
                    "type": "infrastructure",
                    "evidence": resource_evidence,
                }
            )

        if kind_lower == "service":
            ports: list[int] = []
            seen_ports: set[int] = set()
            for entry in entries:
                path = entry.get("path", ())
                if path[:1] != ("spec",) or path[-2:] != ("ports", "port"):
                    continue
                try:
                    port = int(str(entry.get("value", "")).strip())
                except Exception:
                    continue
                if port <= 0 or port in seen_ports:
                    continue
                seen_ports.add(port)
                ports.append(port)
            out["infrastructure"].append(
                {
                    "type": "kubernetes_service",
                    "kind": kind,
                    "name": resource_name,
                    "namespace": resource_namespace,
                    "ports": ports,
                    "api_version": api_version,
                    "file": rel,
                    "line": resource_line,
                    "evidence": resource_evidence,
                }
            )
            if resource_name and ports:
                service_port = int(ports[0])
                local_port = service_port if service_port >= 1024 else 18000 + service_port
                command_tokens = ["kubectl"]
                if resource_namespace:
                    command_tokens.extend(["--namespace", resource_namespace])
                command_tokens.extend(["port-forward", f"service/{resource_name}", f"{local_port}:{service_port}"])
                scheme = "https" if service_port == 443 else "http"
                out["run_hints"].append(
                    {
                        "command": _render_runtime_command(command_tokens),
                        "service_name": resource_name,
                        "service_bucket": _runtime_probe_manifest_cwd(rel) or "root",
                        "cwd": _runtime_probe_manifest_cwd(rel),
                        "mode": "service",
                        "base_urls": [f"{scheme}://127.0.0.1:{local_port}"],
                        "ready_tcp": [f"127.0.0.1:{local_port}"],
                        "file": rel,
                        "line": resource_line,
                        "evidence": resource_evidence,
                    }
                )
            continue

        if kind_lower == "cronjob":
            schedule = str(
                next((item.get("value", "") for item in entries if item.get("path") == ("spec", "schedule")), "")
            ).strip()
            images: list[str] = []
            seen_images: set[str] = set()
            for entry in entries:
                path = entry.get("path", ())
                if "containers" not in path or path[-1:] != ("image",):
                    continue
                image = str(entry.get("value", "")).strip()
                if image and image not in seen_images:
                    seen_images.add(image)
                    images.append(image)
            out["infrastructure"].append(
                {
                    "type": "kubernetes_cronjob",
                    "kind": kind,
                    "name": resource_name,
                    "namespace": resource_namespace,
                    "schedule": schedule,
                    "images": images,
                    "api_version": api_version,
                    "file": rel,
                    "line": resource_line,
                    "evidence": resource_evidence,
                }
            )
            if resource_name:
                command_tokens = ["kubectl"]
                if resource_namespace:
                    command_tokens.extend(["--namespace", resource_namespace])
                command_tokens.extend(
                    ["create", "job", f"--from=cronjob/{resource_name}", f"{resource_name}-manual"]
                )
                out["run_hints"].append(
                    {
                        "command": _render_runtime_command(command_tokens),
                        "service_name": resource_name,
                        "service_bucket": _runtime_probe_manifest_cwd(rel) or "root",
                        "cwd": _runtime_probe_manifest_cwd(rel),
                        "mode": "job",
                        "schedule": schedule,
                        "file": rel,
                        "line": resource_line,
                        "evidence": resource_evidence,
                    }
                )
            continue

        if kind_lower in KUBERNETES_WORKLOAD_KINDS:
            images: list[str] = []
            seen_images: set[str] = set()
            container_ports: list[int] = []
            seen_container_ports: set[int] = set()
            for entry in entries:
                path = entry.get("path", ())
                if "containers" in path and path[-1:] == ("image",):
                    image = str(entry.get("value", "")).strip()
                    if image and image not in seen_images:
                        seen_images.add(image)
                        images.append(image)
                if "containers" in path and path[-2:] == ("ports", "containerPort"):
                    try:
                        container_port = int(str(entry.get("value", "")).strip())
                    except Exception:
                        continue
                    if container_port > 0 and container_port not in seen_container_ports:
                        seen_container_ports.add(container_port)
                        container_ports.append(container_port)
            out["infrastructure"].append(
                {
                    "type": "kubernetes_workload",
                    "kind": kind,
                    "name": resource_name,
                    "images": images,
                    "container_ports": container_ports,
                    "api_version": api_version,
                    "file": rel,
                    "line": resource_line,
                    "evidence": resource_evidence,
                }
            )
            continue

        if kind_lower == "ingress":
            hosts: list[str] = []
            seen_hosts: set[str] = set()
            routes: list[str] = []
            seen_routes: set[str] = set()
            current_host = ""
            for entry in entries:
                path = entry.get("path", ())
                if path == ("spec", "rules", "host"):
                    current_host = str(entry.get("value", "")).strip()
                    if current_host and current_host not in seen_hosts:
                        seen_hosts.add(current_host)
                        hosts.append(current_host)
                    continue
                if path == ("spec", "rules", "http", "paths", "path"):
                    route = str(entry.get("value", "")).strip() or "/"
                    if not route.startswith("/"):
                        continue
                    if route not in seen_routes:
                        seen_routes.add(route)
                        routes.append(route)
                    endpoint = {
                        "method": "GET",
                        "route": route,
                        "framework": "kubernetes_ingress",
                        "file": rel,
                        "line": int(entry.get("line", resource_line) or resource_line),
                        "evidence": make_evidence(rel, int(entry.get("line", resource_line) or resource_line)),
                    }
                    if current_host:
                        endpoint["host"] = current_host
                    if resource_name:
                        endpoint["resource_name"] = resource_name
                    out["api_endpoints"].append(endpoint)
            out["infrastructure"].append(
                {
                    "type": "kubernetes_ingress",
                    "kind": kind,
                    "name": resource_name,
                    "hosts": hosts,
                    "routes": routes,
                    "api_version": api_version,
                    "file": rel,
                    "line": resource_line,
                    "evidence": resource_evidence,
                }
            )
            continue

        out["infrastructure"].append(
            {
                "type": "kubernetes_manifest",
                "kind": kind,
                "name": resource_name,
                "api_version": api_version,
                "file": rel,
                "line": resource_line,
                "evidence": resource_evidence,
            }
        )
    return out


def _extract_github_actions_workflow_items(rel: str, lines: list[str]) -> dict[str, list[dict[str, Any]]]:
    out = {
        "infrastructure": [],
        "framework_signals": [],
    }
    rel_lower = rel.replace("\\", "/").lower()
    if not rel_lower.startswith(".github/workflows/"):
        return out

    entries = _iter_simple_yaml_entries(lines, 1)
    if not entries:
        return out

    workflow_name = str(
        next((item.get("value", "") for item in entries if item.get("path") == ("name",)), "")
    ).strip() or os.path.basename(rel)
    cron_entries = [
        item
        for item in entries
        if tuple(item.get("path", ()))[:2] == ("on", "schedule") and tuple(item.get("path", ()))[-1:] == ("cron",)
    ]
    if not cron_entries:
        return out

    first_line = int(cron_entries[0].get("line", 1) or 1)
    out["framework_signals"].append(
        {
            "name": "github_actions",
            "type": "infrastructure",
            "evidence": make_evidence(rel, first_line),
        }
    )
    for entry in cron_entries:
        schedule = str(entry.get("value", "")).strip()
        line = int(entry.get("line", first_line) or first_line)
        out["infrastructure"].append(
            {
                "type": "ci_workflow_schedule",
                "name": workflow_name,
                "schedule": schedule,
                "file": rel,
                "line": line,
                "evidence": make_evidence(rel, line),
            }
        )
    return out


def _extract_helm_chart_metadata(rel: str, lines: list[str]) -> Optional[dict[str, Any]]:
    if os.path.basename(rel).lower() != "chart.yaml":
        return None
    entries = _iter_simple_yaml_entries(lines, 1)
    if not entries:
        return None
    chart_name_entry = next((item for item in entries if item.get("path") == ("name",)), None)
    if not isinstance(chart_name_entry, dict):
        return None
    chart_name = str(chart_name_entry.get("value", "")).strip()
    if not chart_name:
        return None
    api_version = str(next((item.get("value", "") for item in entries if item.get("path") == ("apiVersion",)), "")).strip()
    version = str(next((item.get("value", "") for item in entries if item.get("path") == ("version",)), "")).strip()
    app_version = str(next((item.get("value", "") for item in entries if item.get("path") == ("appVersion",)), "")).strip()
    chart_line = int(chart_name_entry.get("line", 1) or 1)
    return {
        "type": "helm_chart",
        "kind": "Chart",
        "name": chart_name,
        "version": version,
        "app_version": app_version,
        "api_version": api_version,
        "file": rel,
        "line": chart_line,
        "evidence": make_evidence(rel, chart_line),
    }


def _extract_api_contract_spec_items(rel: str, text: str, lines: list[str]) -> dict[str, list[dict[str, Any]]]:
    out = {
        "api_endpoints": [],
        "framework_signals": [],
    }
    seen_endpoints: set[str] = set()
    framework_keys: set[str] = set()

    def add_framework(name: str, line: int) -> None:
        normalized_name = str(name or "").strip().lower()
        if not normalized_name or normalized_name in framework_keys:
            return
        framework_keys.add(normalized_name)
        out["framework_signals"].append(
            {
                "name": normalized_name,
                "type": "backend",
                "evidence": make_evidence(rel, max(1, int(line or 1))),
            }
        )

    def add_openapi_endpoint(route: Any, method: Any, line: int, operation_id: Any = "") -> None:
        normalized_route = str(route or "").strip()
        if not normalized_route:
            return
        if not normalized_route.startswith("/"):
            normalized_route = f"/{normalized_route.lstrip('/')}"
        normalized_method = str(method or "").strip().upper()
        if normalized_method not in HTTP_METHODS:
            return
        source_line = max(1, int(line or 1))
        key = f"{rel}:{source_line}:openapi:{normalized_method}:{normalized_route}"
        if key in seen_endpoints:
            return
        seen_endpoints.add(key)
        out["api_endpoints"].append(
            {
                "method": normalized_method,
                "route": normalized_route,
                "framework": "openapi_spec",
                "protocol": "http",
                "operation_id": str(operation_id or "").strip(),
                "file": rel,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
        )

    def add_asyncapi_endpoint(channel: Any, operation_type: Any, line: int, operation_id: Any = "") -> None:
        normalized_channel = str(channel or "").strip()
        normalized_operation = str(operation_type or "").strip().lower()
        if not normalized_channel or normalized_operation not in {"publish", "subscribe"}:
            return
        source_line = max(1, int(line or 1))
        key = f"{rel}:{source_line}:asyncapi:{normalized_operation}:{normalized_channel}"
        if key in seen_endpoints:
            return
        seen_endpoints.add(key)
        out["api_endpoints"].append(
            {
                "method": normalized_operation.upper(),
                "route": normalized_channel,
                "framework": "asyncapi_spec",
                "protocol": "asyncapi",
                "operation_type": normalized_operation,
                "operation_id": str(operation_id or "").strip(),
                "file": rel,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
        )

    stripped_text = str(text or "").lstrip()
    if stripped_text.startswith("{"):
        try:
            payload = json.loads(text)
        except Exception:
            payload = None
        if isinstance(payload, dict):
            openapi_version = str(payload.get("openapi", "") or payload.get("swagger", "")).strip()
            asyncapi_version = str(payload.get("asyncapi", "")).strip()
            if openapi_version:
                line = find_line_containing(lines, '"openapi"') if payload.get("openapi") is not None else find_line_containing(lines, '"swagger"')
                add_framework("openapi", line)
                paths = payload.get("paths", {})
                if isinstance(paths, dict):
                    for route, operation_map in paths.items():
                        if not isinstance(operation_map, dict):
                            continue
                        route_line = find_line_containing(lines, f'"{route}"')
                        for method, operation in operation_map.items():
                            operation_id = ""
                            if isinstance(operation, dict):
                                operation_id = str(operation.get("operationId", "")).strip()
                            add_openapi_endpoint(route, method, route_line, operation_id)
            if asyncapi_version:
                add_framework("asyncapi", find_line_containing(lines, '"asyncapi"'))
                channels = payload.get("channels", {})
                if isinstance(channels, dict):
                    for channel_name, channel_item in channels.items():
                        if not isinstance(channel_item, dict):
                            continue
                        channel_line = find_line_containing(lines, f'"{channel_name}"')
                        for operation_type in ["publish", "subscribe"]:
                            operation = channel_item.get(operation_type)
                            operation_id = str(operation.get("operationId", "")).strip() if isinstance(operation, dict) else ""
                            add_asyncapi_endpoint(channel_name, operation_type, channel_line, operation_id)
            return out

    for start_line, doc_lines in _split_yaml_documents(lines):
        entries = _iter_simple_yaml_entries(doc_lines, start_line)
        if not entries:
            continue
        openapi_entry = next((item for item in entries if item.get("path") == ("openapi",) or item.get("path") == ("swagger",)), None)
        asyncapi_entry = next((item for item in entries if item.get("path") == ("asyncapi",)), None)
        if isinstance(openapi_entry, dict):
            add_framework("openapi", int(openapi_entry.get("line", start_line) or start_line))
            for entry in entries:
                path = tuple(entry.get("path", ()))
                if len(path) != 3 or path[0] != "paths":
                    continue
                route = str(path[1] or "").strip()
                method = str(path[2] or "").strip().lower()
                if method not in {m.lower() for m in HTTP_METHODS}:
                    continue
                operation_id_entry = next(
                    (item for item in entries if tuple(item.get("path", ())) == ("paths", route, method, "operationId")),
                    None,
                )
                add_openapi_endpoint(
                    route,
                    method,
                    int(entry.get("line", start_line) or start_line),
                    str(operation_id_entry.get("value", "")).strip() if isinstance(operation_id_entry, dict) else "",
                )
        if isinstance(asyncapi_entry, dict):
            add_framework("asyncapi", int(asyncapi_entry.get("line", start_line) or start_line))
            for entry in entries:
                path = tuple(entry.get("path", ()))
                if len(path) != 3 or path[0] != "channels":
                    continue
                channel_name = str(path[1] or "").strip()
                operation_type = str(path[2] or "").strip().lower()
                if operation_type not in {"publish", "subscribe"}:
                    continue
                operation_id_entry = next(
                    (item for item in entries if tuple(item.get("path", ())) == ("channels", channel_name, operation_type, "operationId")),
                    None,
                )
                add_asyncapi_endpoint(
                    channel_name,
                    operation_type,
                    int(entry.get("line", start_line) or start_line),
                    str(operation_id_entry.get("value", "")).strip() if isinstance(operation_id_entry, dict) else "",
                )
    return out


def _extract_balanced_js_call(text: str, open_paren_index: int) -> Optional[tuple[str, int]]:
    if open_paren_index < 0 or open_paren_index >= len(text) or text[open_paren_index] != "(":
        return None
    depth = 1
    quote = ""
    escape = False
    line_comment = False
    block_comment = False
    idx = open_paren_index + 1
    while idx < len(text):
        ch = text[idx]
        nxt = text[idx + 1] if idx + 1 < len(text) else ""
        if line_comment:
            if ch == "\n":
                line_comment = False
            idx += 1
            continue
        if block_comment:
            if ch == "*" and nxt == "/":
                block_comment = False
                idx += 2
                continue
            idx += 1
            continue
        if quote:
            if escape:
                escape = False
                idx += 1
                continue
            if ch == "\\":
                escape = True
                idx += 1
                continue
            if ch == quote:
                quote = ""
            idx += 1
            continue
        if ch == "/" and nxt == "/":
            line_comment = True
            idx += 2
            continue
        if ch == "/" and nxt == "*":
            block_comment = True
            idx += 2
            continue
        if ch in {"'", '"', "`"}:
            quote = ch
            idx += 1
            continue
        if ch == "(":
            depth += 1
        elif ch == ")":
            depth -= 1
            if depth == 0:
                return text[open_paren_index + 1 : idx], idx
        idx += 1
    return None


def _extract_balanced_js_braces(text: str, open_brace_index: int) -> Optional[tuple[str, int]]:
    if open_brace_index < 0 or open_brace_index >= len(text) or text[open_brace_index] != "{":
        return None
    depth = 1
    quote = ""
    escape = False
    line_comment = False
    block_comment = False
    idx = open_brace_index + 1
    while idx < len(text):
        ch = text[idx]
        nxt = text[idx + 1] if idx + 1 < len(text) else ""
        if line_comment:
            if ch == "\n":
                line_comment = False
            idx += 1
            continue
        if block_comment:
            if ch == "*" and nxt == "/":
                block_comment = False
                idx += 2
                continue
            idx += 1
            continue
        if quote:
            if escape:
                escape = False
                idx += 1
                continue
            if ch == "\\":
                escape = True
                idx += 1
                continue
            if ch == quote:
                quote = ""
            idx += 1
            continue
        if ch == "/" and nxt == "/":
            line_comment = True
            idx += 2
            continue
        if ch == "/" and nxt == "*":
            block_comment = True
            idx += 2
            continue
        if ch in {"'", '"', "`"}:
            quote = ch
            idx += 1
            continue
        if ch == "{":
            depth += 1
        elif ch == "}":
            depth -= 1
            if depth == 0:
                return text[open_brace_index + 1 : idx], idx
        idx += 1
    return None


def _split_js_top_level_args(text: str) -> list[str]:
    args: list[str] = []
    start = 0
    paren_depth = 0
    bracket_depth = 0
    brace_depth = 0
    quote = ""
    escape = False
    line_comment = False
    block_comment = False
    idx = 0
    while idx < len(text):
        ch = text[idx]
        nxt = text[idx + 1] if idx + 1 < len(text) else ""
        if line_comment:
            if ch == "\n":
                line_comment = False
            idx += 1
            continue
        if block_comment:
            if ch == "*" and nxt == "/":
                block_comment = False
                idx += 2
                continue
            idx += 1
            continue
        if quote:
            if escape:
                escape = False
                idx += 1
                continue
            if ch == "\\":
                escape = True
                idx += 1
                continue
            if ch == quote:
                quote = ""
            idx += 1
            continue
        if ch == "/" and nxt == "/":
            line_comment = True
            idx += 2
            continue
        if ch == "/" and nxt == "*":
            block_comment = True
            idx += 2
            continue
        if ch in {"'", '"', "`"}:
            quote = ch
            idx += 1
            continue
        if ch == "(":
            paren_depth += 1
        elif ch == ")":
            paren_depth = max(0, paren_depth - 1)
        elif ch == "[":
            bracket_depth += 1
        elif ch == "]":
            bracket_depth = max(0, bracket_depth - 1)
        elif ch == "{":
            brace_depth += 1
        elif ch == "}":
            brace_depth = max(0, brace_depth - 1)
        elif ch == "," and paren_depth == 0 and bracket_depth == 0 and brace_depth == 0:
            token = text[start:idx].strip()
            if token:
                args.append(token)
            start = idx + 1
        idx += 1
    tail = text[start:].strip()
    if tail:
        args.append(tail)
    return args


def _looks_like_js_string_literal(token: str) -> bool:
    stripped = str(token or "").strip()
    return len(stripped) >= 2 and stripped[0] in {"'", '"', "`"} and stripped[-1] == stripped[0]


def _parse_js_string_literal(token: str) -> str:
    stripped = str(token or "").strip()
    if not _looks_like_js_string_literal(stripped):
        return ""
    quote = stripped[0]
    body = stripped[1:-1]
    if quote == "`" and "${" in body:
        return ""
    out: list[str] = []
    escape = False
    for ch in body:
        if escape:
            out.append(ch)
            escape = False
            continue
        if ch == "\\":
            escape = True
            continue
        out.append(ch)
    if escape:
        out.append("\\")
    return "".join(out)


def _split_js_top_level_operator(text: str, delimiter: str) -> list[str]:
    parts: list[str] = []
    start = 0
    paren_depth = 0
    bracket_depth = 0
    brace_depth = 0
    quote = ""
    escape = False
    line_comment = False
    block_comment = False
    source = str(text or "")
    idx = 0
    while idx < len(source):
        ch = source[idx]
        nxt = source[idx + 1] if idx + 1 < len(source) else ""
        if line_comment:
            if ch == "\n":
                line_comment = False
            idx += 1
            continue
        if block_comment:
            if ch == "*" and nxt == "/":
                block_comment = False
                idx += 2
                continue
            idx += 1
            continue
        if quote:
            if escape:
                escape = False
                idx += 1
                continue
            if ch == "\\":
                escape = True
                idx += 1
                continue
            if ch == quote:
                quote = ""
            idx += 1
            continue
        if ch == "/" and nxt == "/":
            line_comment = True
            idx += 2
            continue
        if ch == "/" and nxt == "*":
            block_comment = True
            idx += 2
            continue
        if ch in {"'", '"', "`"}:
            quote = ch
            idx += 1
            continue
        if ch == "(":
            paren_depth += 1
        elif ch == ")":
            paren_depth = max(0, paren_depth - 1)
        elif ch == "[":
            bracket_depth += 1
        elif ch == "]":
            bracket_depth = max(0, bracket_depth - 1)
        elif ch == "{":
            brace_depth += 1
        elif ch == "}":
            brace_depth = max(0, brace_depth - 1)
        elif ch == delimiter and paren_depth == 0 and bracket_depth == 0 and brace_depth == 0:
            token = source[start:idx].strip()
            if token:
                parts.append(token)
            start = idx + 1
        idx += 1
    tail = source[start:].strip()
    if tail:
        parts.append(tail)
    return parts


def _strip_wrapping_js_parentheses(token: str) -> str:
    value = str(token or "").strip()
    while value.startswith("(") and value.endswith(")"):
        inner = value[1:-1].strip()
        if not inner:
            break
        balanced = _extract_balanced_js_call(value, 0)
        if not balanced or int(balanced[1]) != len(value) - 1:
            break
        value = inner
    return value


def _resolve_js_template_literal(token: str, string_bindings: dict[str, str]) -> str:
    stripped = str(token or "").strip()
    if len(stripped) < 2 or stripped[0] != "`" or stripped[-1] != "`":
        return ""
    body = stripped[1:-1]
    out: list[str] = []
    idx = 0
    while idx < len(body):
        ch = body[idx]
        if ch == "\\" and idx + 1 < len(body):
            out.append(body[idx + 1])
            idx += 2
            continue
        if ch == "$" and idx + 1 < len(body) and body[idx + 1] == "{":
            end = body.find("}", idx + 2)
            if end < 0:
                return ""
            expr = body[idx + 2 : end].strip()
            resolved = _resolve_js_string_expression(expr, string_bindings)
            if not resolved:
                return ""
            out.append(resolved)
            idx = end + 1
            continue
        out.append(ch)
        idx += 1
    return "".join(out)


def _resolve_js_string_expression(token: str, string_bindings: dict[str, str]) -> str:
    stripped = _strip_wrapping_js_parentheses(token)
    if not stripped:
        return ""
    if stripped.endswith(" as const"):
        stripped = stripped[: -len(" as const")].rstrip()
    if _looks_like_js_string_literal(stripped):
        if stripped.startswith("`") and "${" in stripped:
            return _resolve_js_template_literal(stripped, string_bindings)
        return _parse_js_string_literal(stripped)
    if re.fullmatch(r"[A-Za-z_$][A-Za-z0-9_$]*", stripped):
        return str(string_bindings.get(stripped, "")).strip()
    pieces = _split_js_top_level_operator(stripped, "+")
    if len(pieces) > 1:
        resolved_parts: list[str] = []
        for piece in pieces:
            resolved_piece = _resolve_js_string_expression(piece, string_bindings)
            if not resolved_piece:
                return ""
            resolved_parts.append(resolved_piece)
        return "".join(resolved_parts)
    return ""


def _extract_js_string_bindings(lines: list[str]) -> dict[str, str]:
    candidates: dict[str, str] = {}
    for line in lines:
        match = JS_STRING_CONST_ASSIGN_RE.match(str(line or ""))
        if not match:
            continue
        name = str(match.group("name") or "").strip()
        expr = str(match.group("expr") or "").strip()
        if name and expr:
            candidates[name] = expr
    bindings: dict[str, str] = {}
    for _ in range(max(1, len(candidates) + 1)):
        changed = False
        for name, expr in candidates.items():
            resolved = _resolve_js_string_expression(expr, bindings)
            if resolved and bindings.get(name) != resolved:
                bindings[name] = resolved
                changed = True
        if not changed:
            break
    return bindings


def _find_js_top_level_delimiter(text: str, delimiter: str) -> int:
    paren_depth = 0
    bracket_depth = 0
    brace_depth = 0
    quote = ""
    escape = False
    line_comment = False
    block_comment = False
    for idx, ch in enumerate(str(text or "")):
        nxt = text[idx + 1] if idx + 1 < len(text) else ""
        if line_comment:
            if ch == "\n":
                line_comment = False
            continue
        if block_comment:
            if ch == "*" and nxt == "/":
                block_comment = False
            continue
        if quote:
            if escape:
                escape = False
                continue
            if ch == "\\":
                escape = True
                continue
            if ch == quote:
                quote = ""
            continue
        if ch == "/" and nxt == "/":
            line_comment = True
            continue
        if ch == "/" and nxt == "*":
            block_comment = True
            continue
        if ch in {"'", '"', "`"}:
            quote = ch
            continue
        if ch == "(":
            paren_depth += 1
            continue
        if ch == ")":
            paren_depth = max(0, paren_depth - 1)
            continue
        if ch == "[":
            bracket_depth += 1
            continue
        if ch == "]":
            bracket_depth = max(0, bracket_depth - 1)
            continue
        if ch == "{":
            brace_depth += 1
            continue
        if ch == "}":
            brace_depth = max(0, brace_depth - 1)
            continue
        if ch == delimiter and paren_depth == 0 and bracket_depth == 0 and brace_depth == 0:
            return idx
    return -1


def _normalize_js_object_property_key(token: str) -> str:
    stripped = str(token or "").strip()
    if not stripped:
        return ""
    if re.fullmatch(r"[A-Za-z_$][A-Za-z0-9_$]*", stripped):
        return stripped
    if _looks_like_js_string_literal(stripped):
        return _parse_js_string_literal(stripped)
    return ""


def _extract_js_router_export_paths_from_object_literal(
    body: str,
    route_receivers: set[str],
    *,
    prefix: str = "",
) -> list[tuple[str, str]]:
    out: list[tuple[str, str]] = []
    for raw_prop in _split_js_top_level_args(body):
        prop = str(raw_prop or "").strip().rstrip(";")
        if not prop or prop.startswith("..."):
            continue
        split_at = _find_js_top_level_delimiter(prop, ":")
        if split_at < 0:
            key = _normalize_js_object_property_key(prop)
            value = prop.strip()
        else:
            key = _normalize_js_object_property_key(prop[:split_at])
            value = prop[split_at + 1 :].strip()
        if not key:
            continue
        export_name = f"{prefix}.{key}" if prefix else key
        if value.startswith("{") and value.endswith("}"):
            out.extend(
                _extract_js_router_export_paths_from_object_literal(
                    value[1:-1],
                    route_receivers,
                    prefix=export_name,
                )
            )
            continue
        if value in route_receivers:
            out.append((export_name, value))
    return out


def _parse_js_mount_child_reference(candidate: str) -> Optional[dict[str, str]]:
    expr = str(candidate or "").strip().rstrip(";")
    if not expr:
        return None
    direct_dynamic = JS_DIRECT_DYNAMIC_IMPORT_EXPR_RE.match(expr)
    if direct_dynamic:
        pkg = str(direct_dynamic.group("pkg") or direct_dynamic.group("pkg_paren") or "").strip()
        member = str(direct_dynamic.group("member") or "").strip().lstrip(".")
        if not pkg:
            return None
        return {
            "child": "",
            "child_module": pkg,
            "child_member_path": member,
        }
    identifier_chain = re.fullmatch(
        r"([A-Za-z_$][A-Za-z0-9_$]*)(?:\.([A-Za-z_$][A-Za-z0-9_$]*(?:\.[A-Za-z_$][A-Za-z0-9_$]*)*))?",
        expr,
    )
    if not identifier_chain:
        return None
    return {
        "child": str(identifier_chain.group(1)).strip(),
        "child_module": "",
        "child_member_path": str(identifier_chain.group(2) or "").strip(),
    }


def _parse_js_named_specifiers(spec: str, *, alias_separator: str) -> list[tuple[str, str]]:
    out: list[tuple[str, str]] = []
    for token in _split_js_top_level_args(spec):
        raw = str(token or "").strip()
        if not raw:
            continue
        left = raw
        right = raw
        if alias_separator in raw:
            left, right = raw.split(alias_separator, 1)
        left = left.strip()
        right = right.strip()
        if re.fullmatch(r"[A-Za-z_$][A-Za-z0-9_$]*", left) and re.fullmatch(r"[A-Za-z_$][A-Za-z0-9_$]*", right):
            out.append((left, right))
    return out


def _extract_js_import_bindings(rel: str, lines: list[str]) -> list[dict[str, Any]]:
    bindings: list[dict[str, Any]] = []
    seen: set[str] = set()

    def add(alias: str, target_module: str, target_symbol: str, line: int) -> None:
        normalized_alias = str(alias or "").strip()
        normalized_module = str(target_module or "").strip()
        normalized_symbol = str(target_symbol or "").strip() or "default"
        if not normalized_alias or not normalized_module:
            return
        if not re.fullmatch(r"[A-Za-z_$][A-Za-z0-9_$]*", normalized_alias):
            return
        key = f"{line}:{normalized_alias}:{normalized_module}:{normalized_symbol}"
        if key in seen:
            return
        seen.add(key)
        bindings.append(
            {
                "alias": normalized_alias,
                "target_module": normalized_module,
                "target_symbol": normalized_symbol,
                "file": rel,
                "line": int(line or 1),
                "evidence": make_evidence(rel, int(line or 1)),
            }
        )

    for line_no, line in enumerate(lines, start=1):
        import_match = JS_IMPORT_BINDING_LINE_RE.match(line)
        if import_match:
            spec = str(import_match.group("spec") or "").strip()
            pkg = str(import_match.group("pkg") or "").strip()
            for segment in _split_js_top_level_args(spec):
                token = str(segment or "").strip()
                if not token:
                    continue
                if token.startswith("type "):
                    token = token[len("type ") :].strip()
                if not token:
                    continue
                if token.startswith("{") and token.endswith("}"):
                    for target_symbol, alias in _parse_js_named_specifiers(token[1:-1], alias_separator=" as "):
                        add(alias, pkg, target_symbol, line_no)
                    continue
                if token.startswith("* as "):
                    alias = token[len("* as ") :].strip()
                    add(alias, pkg, "*", line_no)
                    continue
                if re.fullmatch(r"[A-Za-z_$][A-Za-z0-9_$]*", token):
                    add(token, pkg, "default", line_no)

        require_match = JS_REQUIRE_ASSIGN_RE.search(line)
        if require_match:
            lhs = str(require_match.group("lhs") or "").strip()
            pkg = str(require_match.group("pkg") or "").strip()
            member = str(require_match.group("member") or "").strip().lstrip(".")
            if lhs.startswith("{") and lhs.endswith("}"):
                for target_symbol, alias in _parse_js_named_specifiers(lhs[1:-1], alias_separator=":"):
                    add(alias, pkg, target_symbol, line_no)
            else:
                add(lhs, pkg, member or "default", line_no)

        dynamic_match = JS_DYNAMIC_IMPORT_ASSIGN_RE.search(line)
        if dynamic_match:
            lhs = str(dynamic_match.group("lhs") or "").strip()
            pkg = str(dynamic_match.group("pkg") or dynamic_match.group("pkg_paren") or "").strip()
            member = str(dynamic_match.group("member") or "").strip().lstrip(".")
            if lhs.startswith("{") and lhs.endswith("}"):
                for target_symbol, alias in _parse_js_named_specifiers(lhs[1:-1], alias_separator=":"):
                    add(alias, pkg, target_symbol, line_no)
            else:
                add(lhs, pkg, member or "*", line_no)

    return bindings


def _extract_js_router_exports(rel: str, text: str, lines: list[str], route_receivers: set[str]) -> list[dict[str, Any]]:
    exports: list[dict[str, Any]] = []
    seen: set[str] = set()

    def add(export_name: str, local_receiver: str, line: int) -> None:
        normalized_export = str(export_name or "").strip() or "default"
        normalized_local = str(local_receiver or "").strip()
        if normalized_local not in route_receivers:
            return
        key = f"{line}:{normalized_export}:{normalized_local}"
        if key in seen:
            return
        seen.add(key)
        exports.append(
            {
                "export_name": normalized_export,
                "local_receiver": normalized_local,
                "file": rel,
                "line": int(line or 1),
                "evidence": make_evidence(rel, int(line or 1)),
            }
        )

    for line_no, line in enumerate(lines, start=1):
        exported_receiver = JS_EXPORTED_ROUTE_RECEIVER_RE.match(line)
        if exported_receiver:
            add(str(exported_receiver.group(1)).strip(), str(exported_receiver.group(1)).strip(), line_no)

        export_default = JS_EXPORT_DEFAULT_RE.match(line)
        if export_default:
            add("default", str(export_default.group(1)).strip(), line_no)

        module_default = JS_MODULE_EXPORT_DEFAULT_RE.search(line)
        if module_default:
            add("default", str(module_default.group(1)).strip(), line_no)

        named_exports = JS_NAMED_EXPORTS_RE.match(line)
        if named_exports:
            for local_receiver, export_name in _parse_js_named_specifiers(str(named_exports.group(1)), alias_separator=" as "):
                add(export_name, local_receiver, line_no)

        for match in JS_COMMONJS_NAMED_EXPORT_RE.finditer(line):
            add(str(match.group(1)).strip(), str(match.group(2)).strip(), line_no)

        module_object = JS_MODULE_EXPORT_OBJECT_RE.search(line)
        if module_object:
            for export_name, local_receiver in _parse_js_named_specifiers(str(module_object.group("body")), alias_separator=":"):
                add(export_name, local_receiver, line_no)

    for match in JS_EXPORT_DEFAULT_OBJECT_START_RE.finditer(text):
        open_brace_index = text.find("{", match.start())
        if open_brace_index < 0:
            continue
        block = _extract_balanced_js_braces(text, open_brace_index)
        if not block:
            continue
        body, _end = block
        line_no = _line_number_from_offset(text, match.start())
        for export_name, local_receiver in _extract_js_router_export_paths_from_object_literal(
            body,
            route_receivers,
            prefix="default",
        ):
            add(export_name, local_receiver, line_no)

    for match in JS_EXPORTED_OBJECT_START_RE.finditer(text):
        export_root = str(match.group(1)).strip()
        if not export_root:
            continue
        open_brace_index = text.find("{", match.end() - 1)
        if open_brace_index < 0:
            continue
        block = _extract_balanced_js_braces(text, open_brace_index)
        if not block:
            continue
        body, _end = block
        line_no = _line_number_from_offset(text, match.start())
        for export_name, local_receiver in _extract_js_router_export_paths_from_object_literal(
            body,
            route_receivers,
            prefix=export_root,
        ):
            add(export_name, local_receiver, line_no)

    for match in JS_MODULE_EXPORT_OBJECT_START_RE.finditer(text):
        open_brace_index = text.find("{", match.start())
        if open_brace_index < 0:
            continue
        block = _extract_balanced_js_braces(text, open_brace_index)
        if not block:
            continue
        body, _end = block
        line_no = _line_number_from_offset(text, match.start())
        for export_name, local_receiver in _extract_js_router_export_paths_from_object_literal(
            body,
            route_receivers,
        ):
            add(export_name, local_receiver, line_no)

    return exports


def _extract_js_object_route_prefix(body: str, string_bindings: Optional[dict[str, str]] = None) -> str:
    for raw_prop in _split_js_top_level_args(body):
        prop = str(raw_prop or "").strip().rstrip(";")
        if not prop:
            continue
        split_at = _find_js_top_level_delimiter(prop, ":")
        if split_at < 0:
            continue
        key = _normalize_js_object_property_key(prop[:split_at]).strip().lower()
        value = prop[split_at + 1 :].strip()
        if key not in {"prefix", "basepath"}:
            continue
        resolved = _resolve_js_string_expression(value, string_bindings or {})
        if resolved:
            return resolved
    return ""


def _extract_js_object_property_value(body: str, keys: set[str]) -> str:
    normalized_keys = {str(item).strip().lower() for item in keys if str(item).strip()}
    for raw_prop in _split_js_top_level_args(body):
        prop = str(raw_prop or "").strip().rstrip(";")
        if not prop:
            continue
        split_at = _find_js_top_level_delimiter(prop, ":")
        if split_at < 0:
            continue
        key = _normalize_js_object_property_key(prop[:split_at]).strip().lower()
        if key not in normalized_keys:
            continue
        return prop[split_at + 1 :].strip()
    return ""


def _collect_js_route_receiver_frameworks(text: str) -> dict[str, str]:
    frameworks: dict[str, str] = {}
    patterns = [
        (
            re.compile(
                r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*express\s*\(""",
                re.IGNORECASE,
            ),
            "express",
        ),
        (
            re.compile(
                r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:express\.)?Router\s*\(""",
                re.IGNORECASE,
            ),
            "express",
        ),
        (
            re.compile(
                r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:fastify|Fastify)\s*\(""",
                re.IGNORECASE,
            ),
            "fastify",
        ),
        (
            re.compile(
                r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*new\s+Hono\s*\(""",
                re.IGNORECASE,
            ),
            "hono",
        ),
        (
            re.compile(
                r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:new\s+)?Router\s*\(""",
                re.IGNORECASE,
            ),
            "koa",
        ),
    ]
    source = str(text or "")
    for pattern, framework in patterns:
        for match in pattern.finditer(source):
            frameworks[str(match.group(1)).strip()] = framework

    changed = True
    rounds = 0
    while changed and rounds < 8:
        changed = False
        rounds += 1
        for match in JS_BASEPATH_ASSIGN_RE.finditer(source):
            child = str(match.group("child") or "").strip()
            parent = str(match.group("parent") or "").strip()
            parent_framework = frameworks.get(parent, "")
            if not child or not parent_framework:
                continue
            if frameworks.get(child) != parent_framework:
                frameworks[child] = parent_framework
                changed = True

    return frameworks


def _collect_js_route_receivers(text: str) -> set[str]:
    receivers = {"app", "router"}
    for receiver in _collect_js_route_receiver_frameworks(text).keys():
        receivers.add(str(receiver).strip())
    return {item for item in receivers if item}


def _collect_js_root_route_receivers(text: str) -> set[str]:
    receivers = {"app"}
    patterns = [
        re.compile(r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*express\s*\(""", re.IGNORECASE),
        re.compile(r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*(?:fastify|Fastify)\s*\(""", re.IGNORECASE),
        re.compile(r"""\b(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\s*=\s*new\s+Hono\s*\(""", re.IGNORECASE),
    ]
    for pattern in patterns:
        for match in pattern.finditer(str(text or "")):
            receivers.add(str(match.group(1)).strip())
    return {item for item in receivers if item}


def _extract_js_declared_route_prefixes(
    text: str,
    route_receivers: set[str],
    string_bindings: Optional[dict[str, str]] = None,
) -> dict[str, str]:
    prefixes: dict[str, str] = {}
    source = str(text or "")
    bindings = string_bindings or {}
    for match in JS_ROUTER_CONSTRUCTOR_ASSIGN_RE.finditer(source):
        receiver = str(match.group("name") or "").strip()
        if receiver not in route_receivers:
            continue
        call = _extract_balanced_js_call(source, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        first_arg = str(args[0] or "").strip()
        if not (first_arg.startswith("{") and first_arg.endswith("}")):
            continue
        prefix = _extract_js_object_route_prefix(first_arg[1:-1], bindings)
        if prefix:
            prefixes[receiver] = _compose_route_prefix(prefixes.get(receiver, ""), prefix)

    for match in JS_RECEIVER_PREFIX_CALL_RE.finditer(source):
        receiver = str(match.group("receiver") or "").strip()
        method = str(match.group("method") or "").strip().lower()
        if receiver not in route_receivers:
            continue
        if method != "prefix":
            continue
        call = _extract_balanced_js_call(source, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        prefix = _resolve_js_string_expression(args[0], bindings)
        if prefix:
            prefixes[receiver] = _compose_route_prefix(prefixes.get(receiver, ""), prefix)
    return prefixes


def _extract_js_basepath_mounts(
    text: str,
    route_receivers: set[str],
    string_bindings: Optional[dict[str, str]] = None,
) -> list[dict[str, Any]]:
    mounts: list[dict[str, Any]] = []
    source = str(text or "")
    bindings = string_bindings or {}
    for match in JS_BASEPATH_ASSIGN_RE.finditer(source):
        child = str(match.group("child") or "").strip()
        parent = str(match.group("parent") or "").strip()
        if not child or not parent or parent not in route_receivers:
            continue
        call = _extract_balanced_js_call(source, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        prefix = _resolve_js_string_expression(args[0], bindings)
        if not prefix:
            continue
        mounts.append(
            {
                "parent": parent,
                "child": child,
                "child_module": "",
                "child_member_path": "",
                "prefix": prefix,
                "line": _line_number_from_offset(source, match.start()),
            }
        )
    return mounts


def _extract_js_router_mounts(
    text: str,
    route_receivers: set[str],
    string_bindings: Optional[dict[str, str]] = None,
) -> list[dict[str, Any]]:
    mounts: list[dict[str, Any]] = []
    bindings = string_bindings or {}
    for match in JS_ROUTER_MOUNT_CALL_START_RE.finditer(str(text or "")):
        parent = str(match.group(1)).strip()
        method_name = str(match.group(2)).strip().lower()
        if parent not in route_receivers:
            continue
        call = _extract_balanced_js_call(text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        mount_prefix = ""
        child_args = args
        resolved_prefix = _resolve_js_string_expression(args[0], bindings)
        if resolved_prefix:
            mount_prefix = resolved_prefix
            child_args = args[1:]
        elif method_name == "route":
            continue
        child_ref: Optional[dict[str, str]] = None
        for token in reversed(child_args):
            child_ref = _parse_js_mount_child_reference(str(token).strip())
            if child_ref:
                break
        if not child_ref:
            continue
        mounts.append(
            {
                "parent": parent,
                "child": str(child_ref.get("child", "")).strip(),
                "child_module": str(child_ref.get("child_module", "")).strip(),
                "child_member_path": str(child_ref.get("child_member_path", "")).strip(),
                "prefix": mount_prefix,
                "line": _line_number_from_offset(text, match.start()),
            }
        )
    return mounts


def _resolve_js_route_prefixes(
    route_receivers: set[str],
    root_receivers: set[str],
    mounts: list[dict[str, Any]],
    declared_prefixes: Optional[dict[str, str]] = None,
) -> dict[str, list[str]]:
    prefixes: dict[str, set[str]] = {receiver: set() for receiver in route_receivers}
    declared = declared_prefixes if isinstance(declared_prefixes, dict) else {}
    for receiver in root_receivers:
        base_prefix = str(declared.get(receiver, "")).strip()
        prefixes.setdefault(receiver, set()).add(base_prefix or "")
    for receiver, prefix in declared.items():
        normalized_receiver = str(receiver or "").strip()
        normalized_prefix = str(prefix or "").strip()
        if normalized_receiver and normalized_prefix:
            prefixes.setdefault(normalized_receiver, set()).add(normalized_prefix)
    max_rounds = max(1, len(route_receivers) + len(mounts) + 1)
    for _ in range(max_rounds):
        changed = False
        for mount in mounts:
            parent = str(mount.get("parent", "")).strip()
            child = str(mount.get("child", "")).strip()
            if not parent or not child:
                continue
            parent_prefixes = prefixes.get(parent, set())
            if not parent_prefixes and parent in root_receivers:
                parent_prefixes = {""}
            if not parent_prefixes:
                continue
            mount_prefix = str(mount.get("prefix", ""))
            for base_prefix in parent_prefixes:
                composed = _compose_route_prefix(base_prefix, mount_prefix)
                if composed not in prefixes.setdefault(child, set()):
                    prefixes[child].add(composed)
                    changed = True
        if not changed:
            break
    return {receiver: sorted(values) for receiver, values in prefixes.items() if values}


def _effective_js_routes_for_receiver(receiver: str, route: str, receiver_prefixes: dict[str, list[str]]) -> list[str]:
    prefixes = receiver_prefixes.get(str(receiver or "").strip(), [])
    if not prefixes:
        normalized = _normalize_route_path(route)
        return [normalized] if normalized else []
    out: list[str] = []
    seen: set[str] = set()
    for prefix in prefixes:
        composed = _compose_route_path(prefix, route)
        if composed and composed not in seen:
            seen.add(composed)
            out.append(composed)
    return out


def _push_js_endpoint(
    out: list[dict[str, Any]],
    seen: set[str],
    *,
    rel: str,
    line: int,
    method: str,
    route: str,
    framework: str,
    receiver: str = "",
) -> None:
    normalized_method = str(method or "").upper().strip()
    normalized_route = str(route or "").strip()
    normalized_receiver = str(receiver or "").strip()
    if normalized_method not in HTTP_METHODS or not normalized_route:
        return
    _push_unique(
        out,
        seen,
        f"{rel}:{line}:{normalized_method}:{normalized_route}:{framework}:{normalized_receiver}",
        {
            "method": normalized_method,
            "route": normalized_route,
            "framework": framework,
            "file": rel,
            "line": max(1, int(line or 1)),
            "evidence": make_evidence(rel, max(1, int(line or 1))),
            **({"receiver": normalized_receiver} if normalized_receiver else {}),
        },
    )


def _extract_jsts_endpoints(rel: str, text: str) -> list[dict[str, Any]]:
    rel_lower = str(rel or "").lower()
    masked_text = _mask_js_comments(text)
    string_bindings = _extract_js_string_bindings(masked_text.splitlines())
    receiver_frameworks = _collect_js_route_receiver_frameworks(masked_text)
    route_receivers = _collect_js_route_receivers(masked_text)
    root_route_receivers = _collect_js_root_route_receivers(masked_text)
    declared_prefixes = _extract_js_declared_route_prefixes(masked_text, route_receivers, string_bindings)
    mounts = _extract_js_router_mounts(masked_text, route_receivers, string_bindings) + _extract_js_basepath_mounts(masked_text, route_receivers, string_bindings)
    receiver_prefixes = _resolve_js_route_prefixes(
        route_receivers,
        root_route_receivers,
        mounts,
        declared_prefixes=declared_prefixes,
    )
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()

    nuxt_route, nuxt_methods, nuxt_framework = _nuxt_nitro_route_spec_from_path(rel)
    if nuxt_route and nuxt_methods and nuxt_framework:
        for method in nuxt_methods:
            _push_js_endpoint(
                endpoints,
                seen,
                rel=rel,
                line=1,
                method=method,
                route=nuxt_route,
                framework=nuxt_framework,
            )

    file_routes = [
        (_nextjs_route_from_path(rel), "nextjs_route_handler"),
        (_nextjs_pages_api_route_from_path(rel), "nextjs_pages_api_route"),
        (_sveltekit_route_from_path(rel), "sveltekit_route_handler"),
        (_astro_route_from_path(rel), "astro_api_route"),
        (_remix_route_from_path(rel), "remix_route_handler"),
    ]
    for route, framework in file_routes:
        if not route:
            continue
        if framework == "nextjs_pages_api_route":
            for method, line in _extract_nextjs_pages_api_methods(masked_text):
                _push_js_endpoint(
                    endpoints,
                    seen,
                    rel=rel,
                    line=line,
                    method=method,
                    route=route,
                    framework=framework,
                )
            continue
        if framework == "remix_route_handler":
            for pattern in [REMIX_ROUTE_HANDLER_RE, REMIX_ROUTE_HANDLER_CONST_RE]:
                for match in pattern.finditer(masked_text):
                    handler_name = str(match.group(1) or "").strip().lower()
                    method = "GET" if handler_name == "loader" else "POST" if handler_name == "action" else ""
                    if not method:
                        continue
                    _push_js_endpoint(
                        endpoints,
                        seen,
                        rel=rel,
                        line=_line_number_from_offset(masked_text, match.start()),
                        method=method,
                        route=route,
                        framework=framework,
                    )
            continue
        for pattern in [NEXTJS_ROUTE_HANDLER_RE, NEXTJS_ROUTE_HANDLER_CONST_RE]:
            for match in pattern.finditer(masked_text):
                _push_js_endpoint(
                    endpoints,
                    seen,
                    rel=rel,
                    line=_line_number_from_offset(masked_text, match.start()),
                    method=str(match.group(1)).upper(),
                    route=route,
                    framework=framework,
                )

    for match in JS_ROUTE_CALL_START_RE.finditer(masked_text):
        receiver = str(match.group(1)).strip()
        if receiver not in route_receivers:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        route_arg = _resolve_js_string_expression(args[0], string_bindings)
        if not route_arg:
            continue
        framework_name = str(receiver_frameworks.get(receiver, "")).strip().lower()
        framework = "node_route"
        if framework_name == "hono":
            framework = "hono_route"
        elif framework_name == "koa":
            framework = "koa_route"
        for resolved_route in _effective_js_routes_for_receiver(receiver, route_arg, receiver_prefixes):
            _push_js_endpoint(
                endpoints,
                seen,
                rel=rel,
                line=_line_number_from_offset(masked_text, match.start()),
                method=str(match.group(2)).upper(),
                route=resolved_route,
                framework=framework,
                receiver=receiver,
            )

    for match in JS_ROUTE_CHAIN_CALL_START_RE.finditer(masked_text):
        receiver = str(match.group(1)).strip()
        if receiver not in route_receivers:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        route = _resolve_js_string_expression(args[0], string_bindings)
        if not route:
            continue
        framework_name = str(receiver_frameworks.get(receiver, "")).strip().lower()
        framework = "node_route_chain"
        if framework_name == "hono":
            framework = "hono_route_chain"
        elif framework_name == "koa":
            framework = "koa_route_chain"
        line = _line_number_from_offset(masked_text, match.start())
        tail = masked_text[match.end() : match.end() + 600]
        if ";" in tail:
            tail = tail.split(";", 1)[0]
        for method_match in JS_ROUTE_CHAIN_METHOD_RE.finditer(tail):
            for resolved_route in _effective_js_routes_for_receiver(receiver, route, receiver_prefixes):
                _push_js_endpoint(
                    endpoints,
                    seen,
                    rel=rel,
                    line=line,
                    method=str(method_match.group(1)).upper(),
                    route=resolved_route,
                    framework=framework,
                    receiver=receiver,
                )

    for match in FASTIFY_ROUTE_BLOCK_RE.finditer(masked_text):
        receiver = str(match.group(1)).strip()
        if receiver not in route_receivers:
            continue
        body = str(match.group("body") or "")
        route = _resolve_js_string_expression(_extract_js_object_property_value(body, {"url", "path"}), string_bindings)
        method_match = FASTIFY_ROUTE_METHOD_FIELD_RE.search(body)
        if not route or not method_match:
            continue
        method_value = str(method_match.group("value") or "")
        methods = [
            str(item.group(1)).upper()
            for item in HTTP_METHOD_RE.finditer(method_value)
            if str(item.group(1)).upper() in HTTP_METHODS
        ]
        if not methods:
            continue
        line = _line_number_from_offset(masked_text, match.start())
        for method in methods:
            for resolved_route in _effective_js_routes_for_receiver(receiver, route, receiver_prefixes):
                _push_js_endpoint(
                    endpoints,
                    seen,
                    rel=rel,
                    line=line,
                    method=method,
                    route=resolved_route,
                    framework="fastify_route",
                    receiver=receiver,
                )

    return endpoints

def clean_sql_identifier(value: str) -> str:
    s = str(value or "").strip()
    if not s:
        return ""
    s = s.rstrip(",;")
    if s.startswith("[") and s.endswith("]"):
        s = s[1:-1]
    s = s.strip("`\"")
    return s

def _module_name_from_path(rel: str) -> str:
    normalized = str(rel or "").replace("\\", "/").strip("/")
    if not normalized:
        return "module"
    base, _ext = os.path.splitext(normalized)
    base = base.replace("-", "_")
    return base.replace("/", ".") or "module"

def _extract_java_package_name(lines: list[str]) -> str:
    for line in lines[:80]:
        match = JAVA_PACKAGE_RE.match(line.strip())
        if match:
            return str(match.group(1)).strip()
    return ""

def _module_name_from_language_source(rel: str, lines: list[str], language: str) -> str:
    if language in {"java", "kotlin"}:
        package_name = _extract_java_package_name(lines)
        if package_name:
            return package_name
    return _module_name_from_path(rel)

def _normalize_route_path(route: str) -> str:
    value = str(route or "").strip()
    if not value:
        return ""
    if not value.startswith("/"):
        value = f"/{value}"
    value = re.sub(r"/+", "/", value)
    if len(value) > 1:
        value = value.rstrip("/")
    return value or "/"

def _join_route_paths(base: str, child: str) -> str:
    left = _normalize_route_path(base)
    right = _normalize_route_path(child)
    if not left:
        return right or "/"
    if not right:
        return left or "/"
    if left == "/":
        return right or "/"
    if right == "/":
        return left or "/"
    return re.sub(r"/+", "/", f"{left.rstrip('/')}/{right.lstrip('/')}") or "/"

def _extract_first_quoted_string(value: Any) -> str:
    match = re.search(r"""['"]([^'"]*)['"]""", str(value or ""))
    return str(match.group(1)).strip() if match else ""

def _combine_multiline_annotation_lines(lines: list[str]) -> list[tuple[int, str]]:
    combined: list[tuple[int, str]] = []
    index = 0
    while index < len(lines):
        line = str(lines[index] or "")
        stripped = line.strip()
        if not stripped.startswith("@"):
            combined.append((index + 1, line))
            index += 1
            continue
        merged = line
        paren_depth = line.count("(") - line.count(")")
        cursor = index
        while paren_depth > 0 and cursor + 1 < len(lines):
            cursor += 1
            next_line = str(lines[cursor] or "")
            merged += " " + next_line.strip()
            paren_depth += next_line.count("(") - next_line.count(")")
        combined.append((index + 1, merged))
        index = cursor + 1
    return combined


def _combine_multiline_bracket_attribute_lines(lines: list[str]) -> list[tuple[int, str]]:
    combined: list[tuple[int, str]] = []
    index = 0
    while index < len(lines):
        line = str(lines[index] or "")
        stripped = line.strip()
        if not stripped.startswith("["):
            combined.append((index + 1, line))
            index += 1
            continue
        merged = line
        attr_depth = line.count("[") - line.count("]")
        paren_depth = line.count("(") - line.count(")")
        cursor = index
        while (attr_depth > 0 or paren_depth > 0) and cursor + 1 < len(lines):
            cursor += 1
            next_line = str(lines[cursor] or "")
            merged += " " + next_line.strip()
            attr_depth += next_line.count("[") - next_line.count("]")
            paren_depth += next_line.count("(") - next_line.count(")")
        combined.append((index + 1, merged))
        index = cursor + 1
    return combined

def _resolve_java_string_expression(token: str, string_bindings: dict[str, str]) -> str:
    stripped = str(token or "").strip()
    if not stripped:
        return ""
    if stripped.startswith("{") and stripped.endswith("}"):
        for piece in str(stripped[1:-1]).split(","):
            resolved_piece = _resolve_java_string_expression(piece, string_bindings)
            if resolved_piece:
                return resolved_piece
        return ""
    if len(stripped) >= 2 and stripped[0] == '"' and stripped[-1] == '"':
        return stripped[1:-1]
    if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", stripped):
        return str(string_bindings.get(stripped, "")).strip()
    parts = _split_js_top_level_operator(stripped, "+")
    if len(parts) > 1:
        resolved_parts: list[str] = []
        for piece in parts:
            resolved_piece = _resolve_java_string_expression(piece, string_bindings)
            if not resolved_piece:
                return ""
            resolved_parts.append(resolved_piece)
        return "".join(resolved_parts)
    return ""

def _extract_java_string_bindings(lines: list[str]) -> dict[str, str]:
    candidates: dict[str, str] = {}
    for line in lines:
        match = JAVA_STRING_CONST_ASSIGN_RE.match(str(line or ""))
        if not match:
            continue
        name = str(match.group(1) or "").strip()
        expr = str(match.group(2) or "").strip()
        if name and expr:
            candidates[name] = expr
    bindings: dict[str, str] = {}
    for _ in range(max(1, len(candidates) + 1)):
        changed = False
        for name, expr in candidates.items():
            resolved = _resolve_java_string_expression(expr, bindings)
            if resolved and bindings.get(name) != resolved:
                bindings[name] = resolved
                changed = True
        if not changed:
            break
    return bindings


def _extract_kotlin_string_bindings(lines: list[str]) -> dict[str, str]:
    candidates: dict[str, str] = {}
    for line in lines:
        match = KOTLIN_STRING_CONST_ASSIGN_RE.match(str(line or ""))
        if not match:
            continue
        name = str(match.group(1) or "").strip()
        expr = str(match.group(2) or "").strip()
        if name and expr:
            candidates[name] = expr
    bindings: dict[str, str] = {}
    for _ in range(max(1, len(candidates) + 1)):
        changed = False
        for name, expr in candidates.items():
            resolved = _resolve_java_string_expression(expr, bindings)
            if resolved and bindings.get(name) != resolved:
                bindings[name] = resolved
                changed = True
        if not changed:
            break
    return bindings


def _kotlin_triple_quote_line_numbers(lines: list[str]) -> set[int]:
    flagged: set[int] = set()
    inside = False
    for index, line in enumerate(lines, start=1):
        current = str(line or "")
        quote_count = current.count('"""')
        if inside or quote_count:
            flagged.add(index)
        if quote_count % 2 == 1:
            inside = not inside
    return flagged


def _resolve_java_string_expression_list(token: str, string_bindings: dict[str, str]) -> list[str]:
    stripped = str(token or "").strip()
    if not stripped:
        return []
    if stripped.startswith("{") and stripped.endswith("}"):
        out: list[str] = []
        seen: set[str] = set()
        for piece in _split_js_top_level_args(stripped[1:-1]):
            resolved_piece = _resolve_java_string_expression(piece, string_bindings)
            if not resolved_piece or resolved_piece in seen:
                continue
            seen.add(resolved_piece)
            out.append(resolved_piece)
        return out
    resolved = _resolve_java_string_expression(stripped, string_bindings)
    return [resolved] if resolved else []


def _parse_java_annotation_arguments(args_text: str) -> tuple[dict[str, str], list[str]]:
    named: dict[str, str] = {}
    positional: list[str] = []
    for raw_part in _split_js_top_level_args(str(args_text or "").strip()):
        part = str(raw_part or "").strip()
        if not part:
            continue
        split_at = _find_js_top_level_delimiter(part, "=")
        if split_at < 0:
            positional.append(part)
            continue
        key = str(part[:split_at]).strip()
        value = str(part[split_at + 1 :]).strip()
        if key and value:
            named[key] = value
    return named, positional


def _find_java_next_method_declaration(source: str, start_offset: int, default_line: int) -> tuple[str, int]:
    window_start = max(0, int(start_offset))
    window = source[window_start : min(len(source), window_start + 600)]
    consumed = 0
    for line in window.splitlines(keepends=True):
        stripped = str(line or "").strip()
        if not stripped:
            consumed += len(line)
            continue
        method_match = JAVA_METHOD_DECL_RE.match(stripped)
        if method_match:
            method_name = str(method_match.group(1) or "").strip()
            method_line = source.count("\n", 0, window_start + consumed) + 1
            if method_name:
                return method_name, method_line
        consumed += len(line)
    return "", max(1, int(default_line or 1))


def _resolve_rust_string_expression(token: str, string_bindings: dict[str, str]) -> str:
    stripped = str(token or "").strip().rstrip(",").strip()
    if not stripped:
        return ""
    if len(stripped) >= 2 and stripped[0] == '"' and stripped[-1] == '"':
        return stripped[1:-1]
    if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", stripped):
        return str(string_bindings.get(stripped, "")).strip()
    parts = _split_js_top_level_operator(stripped, "+")
    if len(parts) > 1:
        resolved_parts: list[str] = []
        for piece in parts:
            resolved_piece = _resolve_rust_string_expression(piece, string_bindings)
            if not resolved_piece:
                return ""
            resolved_parts.append(resolved_piece)
        return "".join(resolved_parts)
    return _extract_first_quoted_string(stripped)


def _extract_rust_string_bindings(lines: list[str]) -> dict[str, str]:
    candidates: dict[str, str] = {}
    for line in lines:
        match = RUST_STRING_ASSIGN_RE.match(str(line or ""))
        if not match:
            continue
        name = str(match.group(1) or "").strip()
        expr = str(match.group(2) or "").strip()
        if name and expr:
            candidates[name] = expr
    bindings: dict[str, str] = {}
    for _ in range(max(1, len(candidates) + 1)):
        changed = False
        for name, expr in candidates.items():
            resolved = _resolve_rust_string_expression(expr, bindings)
            if resolved and bindings.get(name) != resolved:
                bindings[name] = resolved
                changed = True
        if not changed:
            break
    return bindings


