def _normalize_csharp_controller_name(name: Any) -> str:
    raw = str(name or "").strip()
    if raw.lower().endswith("controller") and len(raw) > len("controller"):
        raw = raw[: -len("controller")]
    return raw.lower()


def _normalize_csharp_type_name(name: Any) -> str:
    raw = str(name or "").strip()
    if not raw:
        return ""
    raw = raw.split("<", 1)[0].strip()
    if "." in raw:
        raw = raw.rsplit(".", 1)[-1].strip()
    return raw


def _substitute_csharp_route_tokens(route: Any, *, controller_name: str = "", action_name: str = "") -> str:
    value = str(route or "").strip()
    if not value:
        return ""

    def replace(match: re.Match[str]) -> str:
        token = str(match.group(1) or "").strip().lower()
        if token == "controller":
            return controller_name
        if token == "action":
            return action_name
        return ""

    return re.sub(r"\[([A-Za-z_][A-Za-z0-9_]*)\]", replace, value, flags=re.IGNORECASE)


def _parse_csharp_attribute_route(args_text: Any, string_bindings: Optional[dict[str, str]] = None) -> str:
    raw = str(args_text or "").strip()
    if not raw:
        return ""
    expr = raw.split(",", 1)[0].strip()
    resolved = _resolve_csharp_string_expression(expr, string_bindings or {})
    if resolved:
        return resolved
    return _extract_first_quoted_string(raw)

def _parse_nest_decorator_route(args_text: Any, string_bindings: Optional[dict[str, str]] = None) -> str:
    raw = str(args_text or "").strip()
    if not raw:
        return ""
    expr = raw
    if raw.startswith("{") and raw.endswith("}"):
        path_value = _extract_js_object_property_value(raw[1:-1], {"path"})
        if path_value:
            expr = path_value
    expr = str(expr).strip().rstrip(",").strip()
    resolved = _resolve_js_string_expression(expr, string_bindings or {})
    if resolved:
        return resolved
    return _extract_first_quoted_string(raw)

def _normalize_django_url_route(route: str) -> str:
    value = str(route or "").strip()
    if not value:
        return "/"
    value = value.replace("\\/", "/").lstrip("^").rstrip("$")
    value = re.sub(
        r"\(\?P<([A-Za-z_][A-Za-z0-9_]*)>[^)]+\)",
        lambda match: f"{{{match.group(1)}}}",
        value,
    )
    value = re.sub(
        r"<(?:[A-Za-z_][A-Za-z0-9_]*:)?([A-Za-z_][A-Za-z0-9_]*)>",
        lambda match: f"{{{match.group(1)}}}",
        value,
    )
    unnamed_group_index = 0

    def replace_unnamed_group(match: re.Match[str]) -> str:
        nonlocal unnamed_group_index
        unnamed_group_index += 1
        return f"{{param{unnamed_group_index}}}"

    value = re.sub(r"\((?!\?P<)[^)]+\)", replace_unnamed_group, value)
    return _normalize_route_path(value or "/")


def _is_api_contract_endpoint(endpoint: dict[str, Any]) -> bool:
    framework = str(endpoint.get("framework", "")).strip().lower()
    return framework in API_CONTRACT_FRAMEWORKS


def _canonicalize_contract_route(route: Any, protocol: str) -> str:
    normalized_protocol = str(protocol or "").strip().lower() or "http"
    raw_route = str(route or "").strip()
    if normalized_protocol == "asyncapi":
        return raw_route

    normalized_route = _normalize_route_path(raw_route)
    if not normalized_route:
        return ""
    if normalized_route == "/":
        return normalized_route

    normalized_parts: list[str] = []
    for raw_part in normalized_route.strip("/").split("/"):
        part = str(raw_part or "").strip()
        if not part:
            continue
        is_dynamic = (
            bool(re.fullmatch(r"\{[^{}]+\}", part))
            or bool(re.fullmatch(r"<[^<>]+>", part))
            or part.startswith(":")
            or part == "*"
            or part.startswith("*")
            or bool(re.fullmatch(r"\[[^][]+\]", part))
            or bool(re.fullmatch(r"\[\.\.\.[^][]+\]", part))
            or bool(re.fullmatch(r"\[\[\.\.\.[^][]+\]\]", part))
            or bool(re.search(r"\(\?P<[^>]+>[^)]+\)", part))
            or bool(re.search(r"\([^)]*\)", part))
        )
        normalized_parts.append("{param}" if is_dynamic else part)
    return "/" + "/".join(normalized_parts) if normalized_parts else "/"


def _api_contract_match_key(endpoint: dict[str, Any]) -> str:
    protocol = str(endpoint.get("protocol", "")).strip().lower() or "http"
    method = str(endpoint.get("method", "")).upper().strip()
    route = _canonicalize_contract_route(endpoint.get("route", ""), protocol)
    if not method or not route:
        return ""
    return json.dumps(
        {"protocol": protocol, "method": method, "route": route},
        sort_keys=True,
        ensure_ascii=True,
    )


def annotate_api_contract_links(endpoints: Any) -> dict[str, Any]:
    summary: dict[str, Any] = {
        "contract_spec_endpoints": 0,
        "linked_contract_spec_endpoints": 0,
        "unlinked_contract_spec_endpoints": 0,
        "contract_backed_endpoints": 0,
        "implementation_endpoints": 0,
        "contract_link_rate": 0.0,
        "contract_backed_implementation_rate": 0.0,
        "links": [],
    }
    if not isinstance(endpoints, list):
        return summary

    implementation_by_key: dict[str, list[dict[str, Any]]] = {}
    contract_endpoints: list[tuple[dict[str, Any], str]] = []
    implementation_endpoints: list[dict[str, Any]] = []

    for endpoint in endpoints:
        if not isinstance(endpoint, dict):
            continue
        for key in [
            "contract_spec",
            "contract_link_status",
            "contract_implementation_count",
            "linked_implementation_files",
            "linked_implementation_evidence",
            "contract_backed",
            "contract_sources",
            "contract_operation_ids",
            "contract_match_count",
            "contract_match_kinds",
            "contract_evidence",
        ]:
            endpoint.pop(key, None)

        match_key = _api_contract_match_key(endpoint)
        if _is_api_contract_endpoint(endpoint):
            endpoint["contract_spec"] = True
            summary["contract_spec_endpoints"] += 1
            if match_key:
                contract_endpoints.append((endpoint, match_key))
            else:
                endpoint["contract_link_status"] = "unlinked"
        else:
            implementation_endpoints.append(endpoint)
            if match_key:
                implementation_by_key.setdefault(match_key, []).append(endpoint)

    summary["implementation_endpoints"] = len(implementation_endpoints)
    seen_links: set[str] = set()

    for contract_endpoint, match_key in contract_endpoints:
        contract_route = _canonicalize_contract_route(
            contract_endpoint.get("route", ""),
            str(contract_endpoint.get("protocol", "")).strip().lower() or "http",
        )
        contract_operation_id = str(contract_endpoint.get("operation_id", "")).strip()
        matches = implementation_by_key.get(match_key, [])
        if not matches:
            contract_endpoint["contract_link_status"] = "unlinked"
            contract_endpoint["contract_implementation_count"] = 0
            continue

        summary["linked_contract_spec_endpoints"] += 1
        contract_endpoint["contract_link_status"] = "linked"
        contract_endpoint["contract_implementation_count"] = len(matches)
        contract_endpoint["linked_implementation_files"] = sorted(
            set(
                [
                    str(item.get("file", "")).replace("\\", "/").strip()
                    for item in matches
                    if str(item.get("file", "")).strip()
                ]
            )
        )
        contract_endpoint["linked_implementation_evidence"] = _merge_evidence_tokens(
            [str(item.get("evidence", "")).strip() for item in matches],
            max_items=3,
        )

        for implementation in matches:
            implementation["contract_backed"] = True
            sources = implementation.setdefault("contract_sources", [])
            if not isinstance(sources, list):
                sources = []
                implementation["contract_sources"] = sources
            contract_file = str(contract_endpoint.get("file", "")).replace("\\", "/").strip()
            if contract_file and contract_file not in sources:
                sources.append(contract_file)

            op_ids = implementation.setdefault("contract_operation_ids", [])
            if not isinstance(op_ids, list):
                op_ids = []
                implementation["contract_operation_ids"] = op_ids
            if contract_operation_id and contract_operation_id not in op_ids:
                op_ids.append(contract_operation_id)

            match_kinds = implementation.setdefault("contract_match_kinds", [])
            if not isinstance(match_kinds, list):
                match_kinds = []
                implementation["contract_match_kinds"] = match_kinds
            implementation_route = _canonicalize_contract_route(
                implementation.get("route", ""),
                str(implementation.get("protocol", "")).strip().lower() or "http",
            )
            implementation_raw_route = _normalize_route_path(str(implementation.get("route", "")).strip())
            contract_raw_route = _normalize_route_path(str(contract_endpoint.get("route", "")).strip())
            match_kind = "exact" if implementation_raw_route == contract_raw_route else "templated"
            if match_kind not in match_kinds:
                match_kinds.append(match_kind)

            link_key = json.dumps(
                {
                    "contract_evidence": str(contract_endpoint.get("evidence", "")).strip(),
                    "implementation_evidence": str(implementation.get("evidence", "")).strip(),
                    "method": str(contract_endpoint.get("method", "")).upper().strip(),
                    "route": contract_route,
                    "protocol": str(contract_endpoint.get("protocol", "")).strip().lower() or "http",
                },
                sort_keys=True,
                ensure_ascii=True,
            )
            if link_key not in seen_links:
                seen_links.add(link_key)
                summary["links"].append(
                    {
                        "protocol": str(contract_endpoint.get("protocol", "")).strip().lower() or "http",
                        "method": str(contract_endpoint.get("method", "")).upper().strip(),
                        "route": str(contract_endpoint.get("route", "")).strip(),
                        "contract_framework": str(contract_endpoint.get("framework", "")).strip(),
                        "contract_file": contract_file,
                        "contract_line": int(contract_endpoint.get("line", 1) or 1),
                        "contract_evidence": str(contract_endpoint.get("evidence", "")).strip(),
                        "operation_id": contract_operation_id,
                        "implementation_framework": str(implementation.get("framework", "")).strip(),
                        "implementation_file": str(implementation.get("file", "")).replace("\\", "/").strip(),
                        "implementation_line": int(implementation.get("line", 1) or 1),
                        "implementation_evidence": str(implementation.get("evidence", "")).strip(),
                        "match_kind": match_kind,
                    }
                )

    for implementation in implementation_endpoints:
        if not isinstance(implementation, dict):
            continue
        if bool(implementation.get("contract_backed")):
            summary["contract_backed_endpoints"] += 1
            implementation["contract_match_count"] = len(
                [item for item in implementation.get("contract_sources", []) if str(item).strip()]
            )
            implementation["contract_evidence"] = _merge_evidence_tokens(
                [str(item.get("contract_evidence", "")).strip() for item in summary["links"] if str(item.get("implementation_evidence", "")).strip() == str(implementation.get("evidence", "")).strip()]
                + [str(implementation.get("evidence", "")).strip()],
                max_items=3,
            )

    contract_spec_total = int(summary.get("contract_spec_endpoints", 0) or 0)
    linked_contracts = int(summary.get("linked_contract_spec_endpoints", 0) or 0)
    implementation_total = int(summary.get("implementation_endpoints", 0) or 0)
    contract_backed = int(summary.get("contract_backed_endpoints", 0) or 0)
    summary["unlinked_contract_spec_endpoints"] = max(0, contract_spec_total - linked_contracts)
    summary["contract_link_rate"] = (float(linked_contracts) / float(contract_spec_total)) if contract_spec_total else 0.0
    summary["contract_backed_implementation_rate"] = (
        float(contract_backed) / float(implementation_total)
    ) if implementation_total else 0.0
    return summary

def _extract_django_urlpatterns(rel: str, lines: list[str]) -> list[dict[str, Any]]:
    if not any("urlpatterns" in str(line) for line in lines) and os.path.basename(str(rel or "")).lower() != "urls.py":
        return []
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    in_triple_quote: str = ""
    for i, line in enumerate(lines, start=1):
        raw_line = str(line or "")
        if in_triple_quote:
            if in_triple_quote in raw_line:
                in_triple_quote = ""
            continue
        if raw_line.lstrip().startswith("#"):
            continue
        if '"""' in raw_line or "'''" in raw_line:
            if raw_line.count('"""') % 2 == 1:
                in_triple_quote = '"""'
            elif raw_line.count("'''") % 2 == 1:
                in_triple_quote = "'''"
            continue
        if "include(" in raw_line:
            continue
        match = DJANGO_URL_PATTERN_RE.match(raw_line)
        if not match:
            continue
        route = _normalize_django_url_route(match.group(1))
        key = f"{rel}:{i}:GET:{route}"
        if key in seen:
            continue
        seen.add(key)
        endpoints.append(
            {
                "method": "GET",
                "route": route,
                "framework": "django_urls",
                "file": rel,
                "line": i,
                "evidence": make_evidence(rel, i),
            }
        )
    return endpoints

def _parse_nest_controller_route(args_text: Any, string_bindings: Optional[dict[str, str]] = None) -> str:
    return _parse_nest_decorator_route(args_text, string_bindings=string_bindings)


def _parse_nest_gateway_namespace(args_text: Any, string_bindings: Optional[dict[str, str]] = None) -> str:
    raw = str(args_text or "").strip()
    if not raw:
        return "/"
    bindings = string_bindings or {}
    for part in _split_js_top_level_args(raw):
        candidate = str(part or "").strip()
        if not candidate:
            continue
        if candidate.startswith("{") and candidate.endswith("}"):
            namespace_value = _extract_js_object_property_value(candidate[1:-1], {"namespace"})
            if namespace_value:
                resolved_namespace = _resolve_js_string_expression(namespace_value, bindings)
                if resolved_namespace:
                    return _normalize_route_path(resolved_namespace)
            path_value = _extract_js_object_property_value(candidate[1:-1], {"path"})
            if path_value:
                resolved_path = _resolve_js_string_expression(path_value, bindings)
                if resolved_path:
                    return _normalize_route_path(resolved_path)
            continue
        resolved = _resolve_js_string_expression(candidate, bindings)
        if resolved:
            return _normalize_route_path(resolved)
    resolved = _resolve_js_string_expression(raw, bindings)
    if resolved:
        return _normalize_route_path(resolved)
    return "/"


def _parse_nest_gateway_event_name(args_text: Any, string_bindings: Optional[dict[str, str]] = None) -> str:
    raw = str(args_text or "").strip()
    if not raw:
        return ""
    args = _split_js_top_level_args(raw)
    expr = str(args[0] if args else raw).strip()
    resolved = _resolve_js_string_expression(expr, string_bindings or {})
    return str(resolved or "").strip()


def _extract_nestjs_controller_endpoints(rel: str, text: str) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    controller_stack: list[dict[str, Any]] = []
    pending_controller: Optional[dict[str, Any]] = None
    pending_routes: list[dict[str, Any]] = []
    brace_depth = 0
    masked_text = _mask_js_comments(text)
    lines = masked_text.splitlines()
    string_bindings = _extract_js_string_bindings(lines)

    for i, line in _combine_multiline_annotation_lines(lines):
        stripped = line.strip()
        controller_match = NEST_CONTROLLER_RE.search(line)
        if controller_match:
            pending_controller = {
                "route": _parse_nest_controller_route(controller_match.group(1) or "", string_bindings=string_bindings),
                "line": i,
            }
        decorator_matches = list(NEST_HTTP_DECORATOR_RE.finditer(line))
        if decorator_matches:
            for match in decorator_matches:
                pending_routes.append(
                    {
                        "method": str(match.group(1)).upper(),
                        "route": _parse_nest_decorator_route(match.group(2) or "", string_bindings=string_bindings),
                        "line": i,
                    }
                )

        class_match = NEST_CLASS_DECL_RE.search(stripped)
        method_match = NEST_METHOD_DECL_RE.match(stripped)
        if class_match and pending_controller is not None:
            controller_stack.append(
                {
                    "depth": brace_depth,
                    "base_route": _normalize_route_path(str(pending_controller.get("route", "")).strip() or "/"),
                }
            )
            pending_controller = None
            pending_routes = []
        elif method_match and pending_routes and controller_stack:
            method_name = str(method_match.group(1) or "").strip()
            if method_name and method_name != "constructor":
                base_route = str(controller_stack[-1].get("base_route", "")).strip()
                for pending_route in pending_routes:
                    method = str(pending_route.get("method", "GET")).upper().strip() or "GET"
                    route = _join_route_paths(base_route, str(pending_route.get("route", "")).strip())
                    source_line = int(pending_route.get("line", i) or i)
                    key = f"{rel}:{source_line}:{method}:{route}"
                    if key in seen:
                        continue
                    seen.add(key)
                    endpoints.append(
                        {
                            "method": method,
                            "route": route,
                            "framework": "nestjs_controller",
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )
            pending_routes = []
        elif stripped and not stripped.startswith("@") and pending_routes and "(" not in stripped:
            pending_routes = []

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while controller_stack and brace_depth <= int(controller_stack[-1].get("depth", 0)):
            controller_stack.pop()

    return endpoints


def _extract_nestjs_gateway_artifacts(rel: str, text: str) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    endpoints: list[dict[str, Any]] = []
    entrypoints: list[dict[str, Any]] = []
    seen_endpoints: set[str] = set()
    seen_entrypoints: set[str] = set()
    gateway_stack: list[dict[str, Any]] = []
    pending_gateway: Optional[dict[str, Any]] = None
    pending_events: list[dict[str, Any]] = []
    brace_depth = 0
    source_text = str(text or "")
    if not source_text.strip():
        return endpoints, entrypoints

    masked_text = _mask_js_comments(source_text)
    lines = masked_text.splitlines()
    string_bindings = _extract_js_string_bindings(lines)
    source_lines = source_text.splitlines(keepends=True)
    line_offsets: list[int] = []
    running_offset = 0
    for line in source_lines:
        line_offsets.append(running_offset)
        running_offset += len(line)
    while len(line_offsets) < len(lines):
        line_offsets.append(running_offset)

    for i, line in _combine_multiline_annotation_lines(lines):
        stripped = line.strip()
        line_offset = line_offsets[i - 1] if 0 <= i - 1 < len(line_offsets) else 0

        gateway_match = NEST_GATEWAY_RE.search(line)
        if gateway_match and _js_offset_is_code(source_text, line_offset + gateway_match.start()):
            pending_gateway = {
                "namespace": _parse_nest_gateway_namespace(gateway_match.group(1) or "", string_bindings=string_bindings),
                "line": i,
            }

        for match in NEST_SUBSCRIBE_MESSAGE_RE.finditer(line):
            if not _js_offset_is_code(source_text, line_offset + match.start()):
                continue
            event_name = _parse_nest_gateway_event_name(match.group(1) or "", string_bindings=string_bindings)
            if not event_name:
                continue
            pending_events.append({"name": event_name, "line": i})

        class_match = NEST_CLASS_DECL_RE.search(line)
        method_match = NEST_METHOD_DECL_RE.match(line)
        if class_match and pending_gateway is not None and _js_offset_is_code(source_text, line_offset + class_match.start()):
            namespace = _normalize_route_path(str(pending_gateway.get("namespace", "")).strip() or "/")
            gateway_stack.append({"depth": brace_depth, "namespace": namespace})
            source_line = int(pending_gateway.get("line", i) or i)
            endpoint_key = f"{rel}:{source_line}:{namespace}:nestjs_gateway"
            if endpoint_key not in seen_endpoints:
                seen_endpoints.add(endpoint_key)
                endpoints.append(
                    {
                        "method": "GET",
                        "route": namespace,
                        "framework": "nestjs_gateway",
                        "protocol": "websocket",
                        "file": rel,
                        "line": source_line,
                        "evidence": make_evidence(rel, source_line),
                    }
                )
            pending_gateway = None
            pending_events = []
        elif method_match and pending_events and gateway_stack and _js_offset_is_code(source_text, line_offset + method_match.start()):
            method_name = str(method_match.group(1) or "").strip()
            if method_name and method_name != "constructor":
                namespace = str(gateway_stack[-1].get("namespace", "")).strip() or "/"
                for pending_event in pending_events:
                    entry_name = str(pending_event.get("name", "")).strip()
                    if not entry_name:
                        continue
                    source_line = int(pending_event.get("line", i) or i)
                    entry_key = f"{rel}:{source_line}:{namespace}:{entry_name}:nestjs_gateway_event"
                    if entry_key in seen_entrypoints:
                        continue
                    seen_entrypoints.add(entry_key)
                    entrypoints.append(
                        {
                            "kind": "nestjs_gateway_event",
                            "name": entry_name,
                            "namespace": namespace,
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )
            pending_events = []
        elif stripped and not stripped.startswith("@") and pending_events and "(" not in stripped:
            pending_events = []

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while gateway_stack and brace_depth <= int(gateway_stack[-1].get("depth", 0)):
            gateway_stack.pop()

    return endpoints, entrypoints

def _parse_graphql_resolver_operation_name(
    args_text: str,
    default_name: str,
    *,
    string_bindings: Optional[dict[str, str]] = None,
) -> str:
    bindings = string_bindings or {}
    args = _split_js_top_level_args(str(args_text or ""))
    for raw_arg in reversed(args):
        candidate = str(raw_arg or "").strip()
        if not (candidate.startswith("{") and candidate.endswith("}")):
            continue
        name_expr = _extract_js_object_property_value(candidate[1:-1], {"name"})
        resolved = _resolve_js_string_expression(name_expr, bindings)
        if resolved:
            return resolved
    for raw_arg in args:
        resolved = _resolve_js_string_expression(str(raw_arg or "").strip(), bindings)
        if resolved:
            return resolved
    return str(default_name or "").strip()


def _extract_js_graphql_resolver_artifacts(rel: str, text: str) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    endpoints: list[dict[str, Any]] = []
    entrypoints: list[dict[str, Any]] = []
    seen_endpoints: set[str] = set()
    seen_entrypoints: set[str] = set()
    resolver_stack: list[dict[str, Any]] = []
    pending_resolver = False
    pending_operations: list[dict[str, Any]] = []
    brace_depth = 0
    source_text = str(text or "")
    if not source_text.strip():
        return endpoints, entrypoints

    masked_text = _mask_js_comments(source_text)
    lines = masked_text.splitlines()
    string_bindings = _extract_js_string_bindings(lines)
    source_lines = source_text.splitlines(keepends=True)
    line_offsets: list[int] = []
    running_offset = 0
    for line in source_lines:
        line_offsets.append(running_offset)
        running_offset += len(line)
    while len(line_offsets) < len(lines):
        line_offsets.append(running_offset)

    for i, line in _combine_multiline_annotation_lines(lines):
        stripped = line.strip()
        line_offset = line_offsets[i - 1] if 0 <= i - 1 < len(line_offsets) else 0

        resolver_match = GRAPHQL_RESOLVER_RE.search(line)
        if resolver_match and _js_offset_is_code(source_text, line_offset + resolver_match.start()):
            pending_resolver = True

        for match in GRAPHQL_OPERATION_DECORATOR_RE.finditer(line):
            if not _js_offset_is_code(source_text, line_offset + match.start()):
                continue
            pending_operations.append(
                {
                    "operation_type": str(match.group(1) or "").strip().lower(),
                    "args_text": str(match.group(2) or "").strip(),
                    "line": i,
                }
            )

        class_match = NEST_CLASS_DECL_RE.search(line)
        method_match = NEST_METHOD_DECL_RE.match(line)
        if class_match and pending_resolver and _js_offset_is_code(source_text, line_offset + class_match.start()):
            resolver_stack.append({"depth": brace_depth})
            pending_resolver = False
            pending_operations = []
        elif method_match and pending_operations and resolver_stack and _js_offset_is_code(source_text, line_offset + method_match.start()):
            method_name = str(method_match.group(1) or "").strip()
            if method_name and method_name != "constructor":
                for pending_operation in pending_operations:
                    operation_type = str(pending_operation.get("operation_type", "")).strip().lower()
                    if operation_type == "resolvefield":
                        operation_type = "field"
                    if operation_type not in {"query", "mutation", "subscription", "field"}:
                        continue
                    source_line = int(pending_operation.get("line", i) or i)
                    operation_name = _parse_graphql_resolver_operation_name(
                        str(pending_operation.get("args_text", "")).strip(),
                        method_name,
                        string_bindings=string_bindings,
                    )
                    if not operation_name:
                        continue
                    endpoint_key = f"{rel}:{source_line}:{operation_type}:{operation_name}:graphql_resolver"
                    if endpoint_key not in seen_endpoints:
                        seen_endpoints.add(endpoint_key)
                        endpoints.append(
                            {
                                "method": "POST",
                                "route": "/graphql",
                                "framework": "graphql_resolver",
                                "protocol": "graphql",
                                "operation_type": operation_type,
                                "operation_name": operation_name,
                                "file": rel,
                                "line": source_line,
                                "evidence": make_evidence(rel, source_line),
                            }
                        )
                    entry_key = f"{rel}:{source_line}:{operation_name}:graphql_resolver"
                    if entry_key not in seen_entrypoints:
                        seen_entrypoints.add(entry_key)
                        entrypoints.append(
                            {
                                "kind": "graphql_resolver",
                                "name": operation_name,
                                "operation_type": operation_type,
                                "file": rel,
                                "line": source_line,
                                "evidence": make_evidence(rel, source_line),
                            }
                        )
            pending_operations = []
        elif stripped and not stripped.startswith("@") and pending_operations and "(" not in stripped:
            pending_operations = []

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while resolver_stack and brace_depth <= int(resolver_stack[-1].get("depth", 0)):
            resolver_stack.pop()

    return endpoints, entrypoints


def _parse_js_graphql_resolver_map_name(prop_source: str, string_bindings: dict[str, str]) -> str:
    stripped = str(prop_source or "").strip()
    if not stripped or stripped.startswith("..."):
        return ""
    computed_match = re.match(r"""^\[\s*([^\]]+?)\s*\]\s*:""", stripped)
    if computed_match:
        return str(_resolve_js_string_expression(computed_match.group(1), string_bindings) or "").strip()
    quoted_match = re.match(r"""^(['"`])([^'"`]+)\1\s*:""", stripped)
    if quoted_match:
        return str(quoted_match.group(2) or "").strip()
    method_match = re.match(r"""^([A-Za-z_$][A-Za-z0-9_$]*)\s*\(""", stripped)
    if method_match:
        return str(method_match.group(1) or "").strip()
    prop_match = re.match(r"""^([A-Za-z_$][A-Za-z0-9_$]*)\s*:""", stripped)
    if prop_match:
        return str(prop_match.group(1) or "").strip()
    return ""


def _collect_js_graphql_object_bindings(masked_text: str, source_text: str) -> dict[str, dict[str, Any]]:
    bindings: dict[str, dict[str, Any]] = {}
    object_binding_re = re.compile(
        r"""\b(?:export\s+)?(?:const|let|var)\s+(?P<name>[A-Za-z_$][A-Za-z0-9_$]*)\s*(?::\s*[^=\n]+?)?\s*=\s*\{""",
        re.IGNORECASE,
    )
    for match in object_binding_re.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        binding_name = str(match.group("name") or "").strip()
        if not binding_name:
            continue
        open_brace_index = masked_text.find("{", match.end() - 1)
        if open_brace_index < 0:
            continue
        balanced = _extract_balanced_js_braces(masked_text, open_brace_index)
        if not balanced:
            continue
        body, _ = balanced
        bindings[binding_name] = {
            "body": body,
            "open_brace_index": open_brace_index,
        }
    return bindings


def _normalize_js_graphql_resolver_map_value(expr: str) -> str:
    value = _strip_wrapping_js_parentheses(str(expr or "").strip())
    if not value:
        return ""
    if value.startswith("{"):
        balanced = _extract_balanced_js_braces(value, 0)
        if balanced:
            body, end_index = balanced
            trailing = value[end_index + 1 :].strip()
            if not trailing or re.fullmatch(r"""(?:as|satisfies)\s+.+""", trailing, flags=re.IGNORECASE | re.DOTALL):
                return "{" + body + "}"
    bare_ref_match = re.match(
        r"""^([A-Za-z_$][A-Za-z0-9_$]*)\b(?:\s+(?:as|satisfies)\s+.+)?$""",
        value,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if bare_ref_match:
        return str(bare_ref_match.group(1) or "").strip()
    return value


def _extract_js_graphql_binding_operations(
    rel: str,
    source_text: str,
    binding_name: str,
    binding: dict[str, Any],
    object_bindings: dict[str, dict[str, Any]],
    string_bindings: dict[str, str],
) -> list[dict[str, Any]]:
    if not isinstance(binding, dict):
        return []
    body = str(binding.get("body", "") or "")
    open_brace_index = int(binding.get("open_brace_index", -1) or -1)
    if not body or open_brace_index < 0:
        return []

    operations: list[dict[str, Any]] = []
    seen: set[str] = set()
    for prop_text, prop_index, prop_open_offset in _iter_js_graphql_resolver_map_properties(
        body,
        open_brace_index,
        object_bindings,
    ):
        operation_name = _parse_js_graphql_resolver_map_name(prop_text, string_bindings)
        if not operation_name:
            continue
        source_line = _line_number_from_offset(source_text, prop_open_offset + 1 + prop_index)
        key = f"{binding_name}:{source_line}:{operation_name}"
        if key in seen:
            continue
        seen.add(key)
        operations.append(
            {
                "name": operation_name,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
        )
    return operations


def _extract_js_graphql_object_exports(
    rel: str,
    source_text: str,
    masked_text: str,
    object_bindings: dict[str, dict[str, Any]],
    string_bindings: dict[str, str],
) -> list[dict[str, Any]]:
    exports: list[dict[str, Any]] = []
    seen: set[str] = set()
    bindings = dict(object_bindings)

    default_export_object_re = re.compile(r"""\bexport\s+default\s*(\{)""", re.IGNORECASE)
    for match in default_export_object_re.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        open_brace_index = int(match.start(1))
        balanced = _extract_balanced_js_braces(masked_text, open_brace_index)
        if not balanced:
            continue
        body, _ = balanced
        synthetic_name = f"__graphql_default_export__:{open_brace_index}"
        bindings[synthetic_name] = {
            "body": body,
            "open_brace_index": open_brace_index,
        }
        key = f"default:{synthetic_name}"
        if key not in seen:
            seen.add(key)
            exports.append(
                {
                    "export_name": "default",
                    "binding_name": synthetic_name,
                    "operations": _extract_js_graphql_binding_operations(
                        rel,
                        source_text,
                        synthetic_name,
                        bindings[synthetic_name],
                        bindings,
                        string_bindings,
                    ),
                }
            )

    lines = masked_text.splitlines()
    for line_no, line in enumerate(lines, start=1):
        export_decl = re.match(
            r"""^\s*export\s+(?:const|let|var)\s+([A-Za-z_$][A-Za-z0-9_$]*)\b""",
            str(line or ""),
            re.IGNORECASE,
        )
        if export_decl:
            binding_name = str(export_decl.group(1) or "").strip()
            if binding_name in bindings:
                key = f"{binding_name}:{binding_name}"
                if key not in seen:
                    seen.add(key)
                    exports.append(
                        {
                            "export_name": binding_name,
                            "binding_name": binding_name,
                            "operations": _extract_js_graphql_binding_operations(
                                rel,
                                source_text,
                                binding_name,
                                bindings[binding_name],
                                bindings,
                                string_bindings,
                            ),
                        }
                    )

        named_export = re.match(r"""^\s*export\s*\{([^}]+)\}""", str(line or ""), re.IGNORECASE)
        if named_export:
            for binding_name, export_name in _parse_js_named_specifiers(str(named_export.group(1) or ""), alias_separator=" as "):
                binding_name = str(binding_name or "").strip()
                export_name = str(export_name or "").strip()
                if not binding_name or not export_name or binding_name not in bindings:
                    continue
                key = f"{export_name}:{binding_name}"
                if key in seen:
                    continue
                seen.add(key)
                exports.append(
                    {
                        "export_name": export_name,
                        "binding_name": binding_name,
                        "operations": _extract_js_graphql_binding_operations(
                            rel,
                            source_text,
                            binding_name,
                            bindings[binding_name],
                            bindings,
                            string_bindings,
                        ),
                    }
                )

        default_export = re.match(r"""^\s*export\s+default\s+(.+?)\s*;?\s*$""", str(line or ""), re.IGNORECASE)
        if default_export:
            normalized = _normalize_js_graphql_resolver_map_value(str(default_export.group(1) or "").strip())
            if normalized in bindings:
                key = f"default:{normalized}"
                if key not in seen:
                    seen.add(key)
                    exports.append(
                        {
                            "export_name": "default",
                            "binding_name": normalized,
                            "operations": _extract_js_graphql_binding_operations(
                                rel,
                                source_text,
                                normalized,
                                bindings[normalized],
                                bindings,
                                string_bindings,
                            ),
                        }
                    )

    return exports


def _iter_js_graphql_resolver_map_properties(
    body: str,
    block_open_offset: int,
    object_bindings: dict[str, dict[str, Any]],
    *,
    depth: int = 0,
    max_depth: int = 4,
) -> Iterable[tuple[str, int, int]]:
    cursor = 0
    for raw_prop in _split_js_top_level_args(body):
        prop_text = str(raw_prop or "")
        if not prop_text:
            continue
        prop_index = body.find(prop_text, cursor)
        if prop_index < 0:
            prop_index = body.find(prop_text.strip(), cursor)
        if prop_index < 0:
            prop_index = cursor
        cursor = prop_index + len(prop_text)
        stripped = prop_text.strip()
        if stripped.startswith("...") and depth < max_depth:
            spread_expr = _normalize_js_graphql_resolver_map_value(stripped[3:].strip())
            spread_ref_match = re.match(
                r"""^([A-Za-z_$][A-Za-z0-9_$]*)\s*$""",
                spread_expr,
                flags=re.IGNORECASE,
            )
            if spread_ref_match:
                binding = object_bindings.get(str(spread_ref_match.group(1) or "").strip())
                if isinstance(binding, dict):
                    nested_body = str(binding.get("body", "") or "")
                    nested_open_offset = int(binding.get("open_brace_index", -1) or -1)
                    if nested_body and nested_open_offset >= 0:
                        yield from _iter_js_graphql_resolver_map_properties(
                            nested_body,
                            nested_open_offset,
                            object_bindings,
                            depth=depth + 1,
                            max_depth=max_depth,
                        )
            continue
        yield prop_text, prop_index, block_open_offset


def _extract_js_graphql_resolver_map_analysis(rel: str, text: str) -> dict[str, Any]:
    endpoints: list[dict[str, Any]] = []
    entrypoints: list[dict[str, Any]] = []
    exported_bindings: list[dict[str, Any]] = []
    imported_root_blocks: list[dict[str, Any]] = []
    seen_endpoints: set[str] = set()
    seen_entrypoints: set[str] = set()
    seen_exported_bindings: set[str] = set()
    seen_imported_roots: set[str] = set()
    source_text = str(text or "")
    if not source_text.strip():
        return {
            "endpoints": endpoints,
            "entrypoints": entrypoints,
            "exported_bindings": exported_bindings,
            "imported_root_blocks": imported_root_blocks,
        }

    masked_text = _mask_js_comments(source_text)
    lines = masked_text.splitlines()
    string_bindings = _extract_js_string_bindings(lines)
    object_bindings = _collect_js_graphql_object_bindings(masked_text, source_text)
    for item in _extract_js_graphql_object_exports(rel, source_text, masked_text, object_bindings, string_bindings):
        export_name = str(item.get("export_name", "")).strip()
        binding_name = str(item.get("binding_name", "")).strip()
        key = f"{export_name}:{binding_name}"
        if not export_name or not binding_name or key in seen_exported_bindings:
            continue
        seen_exported_bindings.add(key)
        exported_bindings.append(item)
    resolver_map_re = re.compile(
        r"""(?:\bmodule\.exports\s*=|\bexport\s+default\b|\b(?:export\s+)?(?:const|let|var)\s+[A-Za-z_$][A-Za-z0-9_$]*\s*(?::\s*[^=\n]+?)?\s*=)\s*\{""",
        re.IGNORECASE,
    )

    for match in resolver_map_re.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        open_brace_index = masked_text.find("{", match.end() - 1)
        if open_brace_index < 0:
            continue
        balanced = _extract_balanced_js_braces(masked_text, open_brace_index)
        if not balanced:
            continue
        body, _end = balanced
        cursor = 0
        for raw_root_prop in _split_js_top_level_args(body):
            root_prop_text = str(raw_root_prop or "")
            if not root_prop_text:
                continue
            root_prop_index = body.find(root_prop_text, cursor)
            if root_prop_index < 0:
                root_prop_index = body.find(root_prop_text.strip(), cursor)
            if root_prop_index < 0:
                root_prop_index = cursor
            cursor = root_prop_index + len(root_prop_text)
            root_prop_source = root_prop_text.rstrip().rstrip(";")
            root_shorthand_match = re.match(
                r"""^\s*(Query|Mutation|Subscription)\s*$""",
                root_prop_source,
                flags=re.IGNORECASE,
            )
            root_match = re.match(
                r"""^\s*(?:['"`])?(Query|Mutation|Subscription)(?:['"`])?\s*:\s*(.+)$""",
                root_prop_source,
                flags=re.IGNORECASE | re.DOTALL,
            )
            operation_type = ""
            block_body = ""
            block_open_offset = -1
            if root_shorthand_match:
                operation_type = str(root_shorthand_match.group(1) or "").strip().lower()
                ref_name = str(root_shorthand_match.group(1) or "").strip()
                binding = object_bindings.get(ref_name)
                if isinstance(binding, dict):
                    block_body = str(binding.get("body", "") or "")
                    block_open_offset = int(binding.get("open_brace_index", -1) or -1)
                else:
                    root_line = _line_number_from_offset(source_text, open_brace_index + 1 + root_prop_index)
                    root_key = f"{rel}:{root_line}:{operation_type}:{ref_name}"
                    if root_key not in seen_imported_roots:
                        seen_imported_roots.add(root_key)
                        imported_root_blocks.append(
                            {
                                "operation_type": operation_type,
                                "ref_name": ref_name,
                                "file": rel,
                                "line": root_line,
                                "evidence": make_evidence(rel, root_line),
                            }
                        )
            elif root_match:
                operation_type = str(root_match.group(1) or "").strip().lower()
                block_expr = _normalize_js_graphql_resolver_map_value(str(root_match.group(2) or "").strip())
                if block_expr.startswith("{") and block_expr.endswith("}"):
                    block_body = block_expr[1:-1]
                    value_offset = root_prop_source.find(block_expr)
                    if value_offset < 0:
                        value_offset = root_prop_source.find("{")
                    if value_offset >= 0:
                        block_open_offset = open_brace_index + 1 + root_prop_index + value_offset
                else:
                    ref_match = re.match(
                        r"""^([A-Za-z_$][A-Za-z0-9_$]*)\s*$""",
                        block_expr,
                        flags=re.IGNORECASE,
                    )
                    qualified_ref_match = re.match(
                        r"""^([A-Za-z_$][A-Za-z0-9_$]*(?:\.[A-Za-z_$][A-Za-z0-9_$]*)+)\s*$""",
                        block_expr,
                        flags=re.IGNORECASE,
                    )
                    if ref_match or qualified_ref_match:
                        ref_name = str((ref_match or qualified_ref_match).group(1) or "").strip()
                        binding = object_bindings.get(ref_name)
                        if isinstance(binding, dict):
                            block_body = str(binding.get("body", "") or "")
                            block_open_offset = int(binding.get("open_brace_index", -1) or -1)
                        else:
                            root_line = _line_number_from_offset(source_text, open_brace_index + 1 + root_prop_index)
                            root_key = f"{rel}:{root_line}:{operation_type}:{ref_name}"
                            if root_key not in seen_imported_roots:
                                seen_imported_roots.add(root_key)
                                imported_root_blocks.append(
                                    {
                                        "operation_type": operation_type,
                                        "ref_name": ref_name,
                                        "file": rel,
                                        "line": root_line,
                                        "evidence": make_evidence(rel, root_line),
                                    }
                                )
            if not operation_type or not block_body or block_open_offset < 0:
                continue
            for prop_text, prop_index, prop_open_offset in _iter_js_graphql_resolver_map_properties(
                block_body,
                block_open_offset,
                object_bindings,
            ):
                operation_name = _parse_js_graphql_resolver_map_name(prop_text, string_bindings)
                if not operation_name:
                    continue
                source_line = _line_number_from_offset(source_text, prop_open_offset + 1 + prop_index)
                endpoint_key = f"{rel}:{source_line}:{operation_type}:{operation_name}:graphql_resolver_map"
                if endpoint_key not in seen_endpoints:
                    seen_endpoints.add(endpoint_key)
                    endpoints.append(
                        {
                            "method": "POST",
                            "route": "/graphql",
                            "framework": "graphql_resolver",
                            "protocol": "graphql",
                            "operation_type": operation_type,
                            "operation_name": operation_name,
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )
                entry_key = f"{rel}:{source_line}:{operation_type}:{operation_name}:graphql_resolver_map"
                if entry_key not in seen_entrypoints:
                    seen_entrypoints.add(entry_key)
                    entrypoints.append(
                        {
                            "kind": "graphql_resolver",
                            "name": operation_name,
                            "operation_type": operation_type,
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )

    return {
        "endpoints": endpoints,
        "entrypoints": entrypoints,
        "exported_bindings": exported_bindings,
        "imported_root_blocks": imported_root_blocks,
    }


def _extract_js_graphql_resolver_map_artifacts(rel: str, text: str) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    analysis = _extract_js_graphql_resolver_map_analysis(rel, text)
    return list(analysis.get("endpoints", [])), list(analysis.get("entrypoints", []))

def _resolve_csharp_minimal_api_prefix(receiver: Any, group_routes: dict[str, str]) -> str:
    candidate = str(receiver or "").strip()
    if not candidate:
        return ""
    if candidate in group_routes:
        return str(group_routes.get(candidate, "")).strip()
    if "." in candidate:
        tail = candidate.rsplit(".", 1)[-1].strip()
        if tail in group_routes:
            return str(group_routes.get(tail, "")).strip()
    return ""

def _extract_csharp_minimal_api_endpoints(rel: str, lines: list[str]) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    group_routes: dict[str, str] = {"app": ""}

    for i, line in enumerate(lines, start=1):
        group_match = CS_MAP_GROUP_RE.search(line)
        if group_match:
            lhs = str(group_match.group(1)).strip()
            parent = str(group_match.group(2)).strip()
            route = str(group_match.group(3)).strip()
            group_routes[lhs] = _join_route_paths(_resolve_csharp_minimal_api_prefix(parent, group_routes), route)

        route_match = CS_MINIMAL_API_RE.search(line)
        if not route_match:
            continue
        receiver = str(route_match.group(1)).strip()
        method = str(route_match.group(2)).replace("Map", "").upper().strip()
        route = str(route_match.group(3)).strip()
        full_route = _join_route_paths(_resolve_csharp_minimal_api_prefix(receiver, group_routes), route)
        key = f"{rel}:{i}:{method}:{full_route}"
        if key in seen:
            continue
        seen.add(key)
        endpoints.append(
            {
                "method": method,
                "route": full_route,
                "framework": "csharp_minimal_api",
                "file": rel,
                "line": i,
                "evidence": make_evidence(rel, i),
            }
        )

    return endpoints


def _extract_csharp_hosted_service_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    for match in CS_HOSTED_SERVICE_CLASS_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        class_name = str(match.group(1) or "").strip()
        base_list = str(match.group(2) or "").strip()
        if not class_name or not base_list:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        base_tokens = {
            str(token or "").strip().split("<", 1)[0]
            for token in base_list.split(",")
            if str(token or "").strip()
        }
        service_type = ""
        if "BackgroundService" in base_tokens:
            service_type = "BackgroundService"
        elif "IHostedService" in base_tokens:
            service_type = "IHostedService"
        if not service_type:
            continue
        key = f"{rel}:{line_no}:{class_name}:{service_type}"
        if key in seen:
            continue
        seen.add(key)
        payload = {
            "kind": "csharp_hosted_service",
            "name": class_name,
            "file": rel,
            "line": line_no,
            "evidence": make_evidence(rel, line_no),
        }
        payload["service_type"] = service_type
        entrypoints.append(payload)
    return entrypoints


def _extract_csharp_hangfire_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    for match in HANGFIRE_RECURRING_JOB_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        job_name = str(match.group(1) or match.group(2) or "").strip()
        if not job_name:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        schedule = ""
        window = source[match.end() : min(len(source), match.end() + 240)]
        schedule_match = HANGFIRE_CRON_RE.search(window)
        if schedule_match:
            schedule = f"Cron.{str(schedule_match.group(1) or '').strip()}{str(schedule_match.group(2) or '').strip()}"
        key = f"{rel}:{line_no}:{job_name}"
        if key in seen:
            continue
        seen.add(key)
        payload = {
            "kind": "hangfire_recurring_job",
            "name": job_name,
            "file": rel,
            "line": line_no,
            "evidence": make_evidence(rel, line_no),
        }
        if schedule:
            payload["schedule"] = schedule
        entrypoints.append(payload)
    return entrypoints


def _extract_csharp_quartz_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    for match in QUARTZ_SCHEDULE_JOB_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        job_name = _normalize_csharp_type_name(match.group(1))
        if not job_name:
            continue
        window = source[match.end() : min(len(source), match.end() + 480)]
        schedule_match = QUARTZ_CRON_RE.search(window)
        if not schedule_match:
            continue
        schedule = str(schedule_match.group(1) or schedule_match.group(2) or "").strip()
        if not schedule:
            continue
        identity_match = QUARTZ_IDENTITY_RE.search(window)
        entry_name = str(identity_match.group(1) or identity_match.group(2) or "").strip() if identity_match else ""
        entry_name = entry_name or job_name
        line_no = source.count("\n", 0, match.start()) + 1
        key = f"{rel}:{line_no}:{entry_name}:{schedule}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "quartz_scheduled_job",
                "name": entry_name,
                "job": job_name,
                "schedule": schedule,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
            }
        )
    return entrypoints


def _extract_csharp_masstransit_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    source = str(text or "")
    entrypoints: list[dict[str, Any]] = []
    payloads_by_consumer_name: dict[str, list[dict[str, Any]]] = {}
    seen: set[str] = set()
    for match in CS_HOSTED_SERVICE_CLASS_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        class_name = str(match.group(1) or "").strip()
        base_list = str(match.group(2) or "").strip()
        if not class_name or not base_list:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        for interface_match in CS_MASSTRANSIT_CONSUMER_INTERFACE_RE.finditer(base_list):
            message_name = _normalize_csharp_type_name(interface_match.group(1))
            if not message_name:
                continue
            key = f"{rel}:{line_no}:{class_name}:{message_name}"
            if key in seen:
                continue
            seen.add(key)
            payload = {
                "kind": "masstransit_consumer",
                "name": class_name,
                "message": message_name,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
            }
            payloads_by_consumer_name.setdefault(class_name, []).append(payload)
            entrypoints.append(payload)
    if not entrypoints:
        return entrypoints
    for match in CS_MASSTRANSIT_RECEIVE_ENDPOINT_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        queue_name = str(match.group(1) or match.group(2) or "").strip()
        if not queue_name:
            continue
        window = source[match.end() : min(len(source), match.end() + 480)]
        for consumer_match in CS_MASSTRANSIT_CONFIGURE_CONSUMER_RE.finditer(window):
            consumer_name = _normalize_csharp_type_name(consumer_match.group(1))
            if not consumer_name:
                continue
            for payload in payloads_by_consumer_name.get(consumer_name, []):
                if not str(payload.get("queue", "")).strip():
                    payload["queue"] = queue_name
    return entrypoints


def _extract_csharp_masstransit_producer_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    source = str(text or "")
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    for match in CS_MASSTRANSIT_PUBLISH_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        message_name = _normalize_csharp_type_name(match.group(1))
        if not message_name:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        key = f"{rel}:{line_no}:{message_name}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "masstransit_producer",
                "name": message_name,
                "message": message_name,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
            }
        )
    return entrypoints


def _parse_csharp_grpc_service_name(base_list: Any) -> str:
    raw = str(base_list or "").strip()
    if not raw:
        return ""
    for match in CS_GRPC_BASE_CLASS_RE.finditer(raw):
        service_name = _normalize_csharp_type_name(match.group(2))
        if service_name:
            return service_name
    return ""


def _extract_csharp_grpc_service_bindings(rel: str, text: str) -> list[dict[str, Any]]:
    source = str(text or "")
    if "Base" not in source or "override" not in source:
        return []

    bindings: list[dict[str, Any]] = []
    masked_text = _mask_js_comments(source)
    lines = masked_text.splitlines()
    source_lines = source.splitlines(keepends=True)
    line_offsets: list[int] = []
    running_offset = 0
    for line in source_lines:
        line_offsets.append(running_offset)
        running_offset += len(line)
    while len(line_offsets) < len(lines):
        line_offsets.append(running_offset)

    service_stack: list[dict[str, Any]] = []
    brace_depth = 0
    for i, line in enumerate(lines, start=1):
        stripped = str(line or "").strip()
        line_offset = line_offsets[i - 1] if 0 <= i - 1 < len(line_offsets) else 0
        pushed_service = False
        class_match = CS_HOSTED_SERVICE_CLASS_RE.search(stripped)
        if class_match and _js_offset_is_code(source, line_offset + class_match.start()):
            impl_class = _normalize_csharp_type_name(class_match.group(1))
            base_list = str(class_match.group(2) or "").strip()
            service_name = _parse_csharp_grpc_service_name(base_list)
            if impl_class and service_name:
                service_stack.append(
                    {
                        "depth": brace_depth,
                        "impl_class": impl_class,
                        "service": service_name,
                        "file": rel,
                        "line": i,
                        "evidence": make_evidence(rel, i),
                        "rpcs": [],
                    }
                )
                pushed_service = True
        elif service_stack:
            method_match = CS_METHOD_DECL_RE.match(stripped)
            if method_match and _js_offset_is_code(source, line_offset + method_match.start()) and "override" in stripped.lower():
                rpc_name = str(method_match.group(1) or "").strip()
                if rpc_name and rpc_name != "constructor":
                    current = service_stack[-1]
                    rpc_key = f"{str(current.get('impl_class', '')).strip()}:{rpc_name}:{i}"
                    seen_rpc_keys = current.setdefault("seen_rpc_keys", set())
                    if rpc_key not in seen_rpc_keys:
                        seen_rpc_keys.add(rpc_key)
                        current.setdefault("rpcs", []).append(
                            {
                                "name": rpc_name,
                                "line": i,
                                "evidence": make_evidence(rel, i),
                            }
                        )

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while service_stack and brace_depth <= int(service_stack[-1].get("depth", 0)) and not pushed_service:
            current = service_stack.pop()
            current.pop("seen_rpc_keys", None)
            current.pop("depth", None)
            if current.get("rpcs"):
                bindings.append(current)

    while service_stack:
        current = service_stack.pop()
        current.pop("seen_rpc_keys", None)
        current.pop("depth", None)
        if current.get("rpcs"):
            bindings.append(current)
    return bindings


def _extract_csharp_grpc_service_mappings(rel: str, text: str) -> list[dict[str, Any]]:
    source = str(text or "")
    mappings: list[dict[str, Any]] = []
    seen: set[str] = set()
    for match in CS_GRPC_MAP_SERVICE_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        impl_class = _normalize_csharp_type_name(match.group(1))
        if not impl_class:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        key = f"{rel}:{line_no}:{impl_class}"
        if key in seen:
            continue
        seen.add(key)
        mappings.append(
            {
                "impl_class": impl_class,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
            }
        )
    return mappings


def _compose_csharp_controller_route(base_route: str, method_route: str, attribute_route: str) -> str:
    base = str(base_route or "").strip()
    middle = str(method_route or "").strip()
    leaf = str(attribute_route or "").strip()
    local_is_absolute = middle.startswith("/") or middle.startswith("~/")

    def normalize_local(value: str) -> str:
        trimmed = str(value or "").strip()
        if trimmed.startswith("~/"):
            trimmed = "/" + trimmed[2:].lstrip("/")
        return _normalize_route_path(trimmed) if trimmed else ""

    if leaf.startswith("/") or leaf.startswith("~/"):
        return normalize_local(leaf)

    local = normalize_local(middle)
    if leaf:
        local_is_absolute = local_is_absolute or leaf.startswith("/") or leaf.startswith("~/")
        local = _join_route_paths(local, leaf) if local else normalize_local(leaf)
    if local:
        return _join_route_paths(base, local) if base and not local_is_absolute else normalize_local(local)
    return normalize_local(base)


def _extract_csharp_controller_endpoints(rel: str, text: str) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    controller_stack: list[dict[str, Any]] = []
    pending_route_attrs: list[dict[str, Any]] = []
    pending_http_attrs: list[dict[str, Any]] = []
    brace_depth = 0
    masked_text = _mask_js_comments(text)
    lines = masked_text.splitlines()
    string_bindings = _extract_csharp_string_bindings(lines)

    for i, line in _combine_multiline_bracket_attribute_lines(lines):
        stripped = line.strip()
        pushed_controller = False
        if stripped.startswith("["):
            route_matches = list(CS_CONTROLLER_ROUTE_ATTR_RE.finditer(line))
            if route_matches:
                pending_route_attrs = [
                    {
                        "route": _parse_csharp_attribute_route(match.group(1) or "", string_bindings=string_bindings),
                        "line": i,
                    }
                    for match in route_matches
                ]
            http_matches = list(CS_HTTP_ATTR_RE.finditer(line))
            if http_matches:
                pending_http_attrs = [
                    {
                        "method": str(match.group(1) or "").upper().strip() or "GET",
                        "route": _parse_csharp_attribute_route(match.group(2) or "", string_bindings=string_bindings),
                        "line": i,
                    }
                    for match in http_matches
                ]

        class_match = CS_TYPE_DECL_RE.search(stripped)
        method_match = CS_METHOD_DECL_RE.match(stripped)
        if class_match:
            class_name = str(class_match.group(2) or "").strip()
            controller_name = _normalize_csharp_controller_name(class_name)
            class_route = ""
            if pending_route_attrs:
                class_route = _substitute_csharp_route_tokens(
                    str(pending_route_attrs[-1].get("route", "")).strip(),
                    controller_name=controller_name,
                    action_name="",
                )
            controller_stack.append(
                {
                    "depth": brace_depth,
                    "base_route": _normalize_route_path(class_route) if class_route else "",
                    "controller_name": controller_name,
                }
            )
            pushed_controller = True
            pending_route_attrs = []
            pending_http_attrs = []
        elif method_match and pending_http_attrs and controller_stack:
            method_name = str(method_match.group(1) or "").strip()
            if method_name and method_name != "constructor":
                controller_context = controller_stack[-1]
                controller_name = str(controller_context.get("controller_name", "")).strip()
                action_name = method_name.lower()
                base_route = str(controller_context.get("base_route", "")).strip()
                method_route = ""
                if pending_route_attrs:
                    method_route = _substitute_csharp_route_tokens(
                        str(pending_route_attrs[-1].get("route", "")).strip(),
                        controller_name=controller_name,
                        action_name=action_name,
                    )
                for pending_http_attr in pending_http_attrs:
                    attribute_route = _substitute_csharp_route_tokens(
                        str(pending_http_attr.get("route", "")).strip(),
                        controller_name=controller_name,
                        action_name=action_name,
                    )
                    full_route = _compose_csharp_controller_route(base_route, method_route, attribute_route)
                    if not full_route:
                        continue
                    method = str(pending_http_attr.get("method", "GET")).upper().strip() or "GET"
                    framework = (
                        "csharp_controller"
                        if base_route or method_route
                        else "csharp_attribute_route"
                    )
                    source_line = int(pending_http_attr.get("line", i) or i)
                    key = f"{rel}:{source_line}:{method}:{full_route}"
                    if key in seen:
                        continue
                    seen.add(key)
                    endpoints.append(
                        {
                            "method": method,
                            "route": full_route,
                            "framework": framework,
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )
            pending_route_attrs = []
            pending_http_attrs = []
        elif stripped and not stripped.startswith("[") and pending_http_attrs and "(" not in stripped:
            pending_route_attrs = []
            pending_http_attrs = []

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while controller_stack and not pushed_controller and brace_depth <= int(controller_stack[-1].get("depth", 0)):
            controller_stack.pop()

    return endpoints


def _iter_rust_semicolon_statements(text: str) -> list[tuple[int, int, str]]:
    statements: list[tuple[int, int, str]] = []
    source = str(text or "")
    start = 0
    quote = ""
    raw_string_hashes: Optional[int] = None
    escape = False
    line_comment = False
    block_comment = False
    idx = 0
    while idx < len(source):
        ch = source[idx]
        nxt = source[idx + 1] if idx + 1 < len(source) else ""
        if line_comment:
            if ch == "\n":
                line_comment = False
            idx += 1
            continue
        if block_comment:
            if ch == "*" and nxt == "/":
                block_comment = False
                idx += 2
                continue
            idx += 1
            continue
        if raw_string_hashes is not None:
            if ch == '"' and source.startswith("#" * raw_string_hashes, idx + 1):
                idx += 1 + raw_string_hashes
                raw_string_hashes = None
                continue
            idx += 1
            continue
        if quote:
            if escape:
                escape = False
                idx += 1
                continue
            if ch == "\\" and quote == '"':
                escape = True
                idx += 1
                continue
            if ch == quote:
                quote = ""
            idx += 1
            continue
        if ch == "/" and nxt == "/":
            line_comment = True
            idx += 2
            continue
        if ch == "/" and nxt == "*":
            block_comment = True
            idx += 2
            continue
        raw_prefix_index = idx
        if source.startswith("br", idx) or source.startswith("rb", idx):
            raw_prefix_index = idx + 2
        elif ch == "r":
            raw_prefix_index = idx + 1
        if raw_prefix_index > idx:
            hash_index = raw_prefix_index
            while hash_index < len(source) and source[hash_index] == "#":
                hash_index += 1
            if hash_index < len(source) and source[hash_index] == '"':
                raw_string_hashes = hash_index - raw_prefix_index
                idx = hash_index + 1
                continue
        if ch == "b" and nxt == '"':
            quote = '"'
            idx += 2
            continue
        if ch in {'"', "`"}:
            quote = ch
            idx += 1
            continue
        if ch == ";":
            statement = source[start : idx + 1]
            if statement.strip():
                statements.append((start, _line_number_from_offset(source, start), statement))
            start = idx + 1
        idx += 1
    tail = source[start:]
    if tail.strip():
        statements.append((start, _line_number_from_offset(source, start), tail))
    return statements


def _split_rust_semicolon_statements(text: str) -> list[tuple[int, str]]:
    return [(line_no, statement) for _offset, line_no, statement in _iter_rust_semicolon_statements(text)]


def _extract_rust_member_calls(statement: str, members: Optional[list[str]] = None) -> list[tuple[str, int, str, int]]:
    calls: list[tuple[str, int, str, int]] = []
    source = str(statement or "")
    member_names = [str(item or "").strip() for item in (members or ["route", "nest"]) if str(item or "").strip()]
    quote = ""
    raw_string_hashes: Optional[int] = None
    escape = False
    idx = 0
    while idx < len(source):
        ch = source[idx]
        nxt = source[idx + 1] if idx + 1 < len(source) else ""
        if raw_string_hashes is not None:
            if ch == '"' and source.startswith("#" * raw_string_hashes, idx + 1):
                idx += 1 + raw_string_hashes
                raw_string_hashes = None
                continue
            idx += 1
            continue
        if quote:
            if escape:
                escape = False
                idx += 1
                continue
            if ch == "\\" and quote == '"':
                escape = True
                idx += 1
                continue
            if ch == quote:
                quote = ""
            idx += 1
            continue
        raw_prefix_index = idx
        if source.startswith("br", idx) or source.startswith("rb", idx):
            raw_prefix_index = idx + 2
        elif ch == "r":
            raw_prefix_index = idx + 1
        if raw_prefix_index > idx:
            hash_index = raw_prefix_index
            while hash_index < len(source) and source[hash_index] == "#":
                hash_index += 1
            if hash_index < len(source) and source[hash_index] == '"':
                raw_string_hashes = hash_index - raw_prefix_index
                idx = hash_index + 1
                continue
        if ch == "b" and nxt == '"':
            quote = '"'
            idx += 2
            continue
        if ch in {'"', "`"}:
            quote = ch
            idx += 1
            continue
        if ch != ".":
            idx += 1
            continue
        matched = False
        for member in member_names:
            if not source.startswith(member, idx + 1):
                continue
            cursor = idx + 1 + len(member)
            while cursor < len(source) and source[cursor].isspace():
                cursor += 1
            if cursor >= len(source) or source[cursor] != "(":
                continue
            call = _extract_balanced_js_call(source, cursor)
            if not call:
                continue
            calls.append((member, idx, str(call[0]), int(call[1])))
            idx = int(call[1]) + 1
            matched = True
            break
        if not matched:
            idx += 1
    return calls


def _extract_rust_call_receiver(statement: str, dot_index: int) -> str:
    cursor = max(0, int(dot_index) - 1)
    source = str(statement or "")
    while cursor >= 0 and source[cursor].isspace():
        cursor -= 1
    end = cursor
    while cursor >= 0 and (source[cursor].isalnum() or source[cursor] == "_"):
        cursor -= 1
    candidate = source[cursor + 1 : end + 1].strip()
    if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", candidate):
        return candidate
    return ""


def _resolve_rust_router_reference(token: Any) -> str:
    value = _strip_wrapping_js_parentheses(str(token or "")).strip().lstrip("&").strip()
    clone_match = re.fullmatch(r"([A-Za-z_][A-Za-z0-9_]*)\s*\.\s*clone\s*\(\s*\)", value)
    if clone_match:
        return str(clone_match.group(1) or "").strip()
    if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", value):
        return value
    return ""


def _extract_rust_actix_member_calls(statement: str) -> list[tuple[str, int, str, int]]:
    return _extract_rust_member_calls(statement, ["route", "service"])


def _extract_rust_rocket_mount_calls(statement: str) -> list[tuple[str, int, str, int]]:
    return _extract_rust_member_calls(statement, ["mount"])


def _normalize_rocket_route_path(route: str) -> str:
    normalized = _normalize_route_path(route)
    return re.sub(r"""<([A-Za-z_][A-Za-z0-9_]*)>""", r"{\1}", normalized)


def _extract_rust_rocket_endpoints(rel: str, text: str) -> tuple[list[dict[str, Any]], set[int]]:
    endpoints: list[dict[str, Any]] = []
    mounted_route_lines: set[int] = set()
    seen: set[str] = set()
    source = str(text or "")
    if not source:
        return endpoints, mounted_route_lines

    masked_text = _mask_js_comments(source)
    lines = masked_text.splitlines()
    string_bindings = _extract_rust_string_bindings(lines)
    route_defs: dict[str, dict[str, Any]] = {}
    pending_route: Optional[dict[str, Any]] = None
    line_offsets: list[int] = []
    cursor = 0
    for line in lines:
        line_offsets.append(cursor)
        cursor += len(line) + 1

    for line_no, line in enumerate(lines, start=1):
        stripped = str(line or "").strip()
        start_offset = line_offsets[line_no - 1] if 1 <= line_no <= len(line_offsets) else 0
        route_match = RUST_ROUTE_ATTR_RE.match(stripped)
        if route_match and _rust_offset_is_code(masked_text, start_offset):
            pending_route = {
                "method": str(route_match.group(1) or "").upper().strip(),
                "route": _normalize_rocket_route_path(str(route_match.group(2) or "").strip()),
                "line": line_no,
            }
            continue
        if pending_route:
            fn_match = RUST_FN_DECL_RE.match(stripped)
            if fn_match and _rust_offset_is_code(masked_text, start_offset):
                fn_name = str(fn_match.group(1) or "").strip()
                if fn_name:
                    route_defs[fn_name] = dict(pending_route)
            if stripped:
                pending_route = None

    for start_line, statement in _split_rust_semicolon_statements(masked_text):
        for _member, dot_index, args_text, _end_index in _extract_rust_rocket_mount_calls(statement):
            parts = _split_js_top_level_args(args_text)
            if len(parts) < 2:
                continue
            prefix = _resolve_rust_string_expression(parts[0], string_bindings)
            if not prefix:
                continue
            routes_match = RUST_ROCKET_ROUTES_MACRO_RE.search(parts[1])
            if not routes_match:
                continue
            source_line = max(1, int(start_line) + _line_number_from_offset(statement, dot_index) - 1)
            route_names = [
                str(token or "").strip()
                for token in re.split(r"[,\s]+", str(routes_match.group(1) or ""))
                if str(token or "").strip()
            ]
            for route_name in route_names:
                route_def = route_defs.get(route_name)
                if not route_def:
                    continue
                mounted_route_lines.add(int(route_def.get("line", 0) or 0))
                method = str(route_def.get("method", "GET")).upper().strip() or "GET"
                route = _join_route_paths(prefix, str(route_def.get("route", "")).strip())
                key = f"{rel}:{source_line}:{method}:{route}"
                if key in seen:
                    continue
                seen.add(key)
                endpoints.append(
                    {
                        "method": method,
                        "route": route,
                        "framework": "rust_rocket",
                        "file": rel,
                        "line": source_line,
                        "evidence": make_evidence(rel, source_line),
                    }
                )

    return endpoints, mounted_route_lines


def _extract_rust_warp_endpoints(rel: str, text: str) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    if not source:
        return endpoints

    masked_source = _mask_js_comments(source)
    string_bindings = _extract_rust_string_bindings(masked_source.splitlines())
    for start_offset, start_line, statement in _iter_rust_semicolon_statements(masked_source):
        method_match = RUST_WARP_METHOD_RE.search(statement)
        if not method_match or not _rust_offset_is_code(source, start_offset + method_match.start()):
            continue
        segments: list[str] = []
        saw_path = False
        for path_match in RUST_WARP_PATH_TOKEN_RE.finditer(statement):
            if not _rust_offset_is_code(source, start_offset + path_match.start()):
                continue
            resolved_expr = str(path_match.group(1) or "").strip()
            if resolved_expr:
                resolved_path = _resolve_rust_string_expression(resolved_expr, string_bindings)
                normalized = _normalize_route_path(resolved_path).strip("/")
                if normalized:
                    segments.extend([part for part in normalized.split("/") if part])
                    saw_path = True
                continue
            token = str(path_match.group(0) or "")
            if "::param" in token:
                segments.append("{param}")
                saw_path = True
        if not saw_path:
            continue
        method = str(method_match.group(1) or "").upper().strip() or "GET"
        route = "/" + "/".join(segments) if segments else "/"
        source_line = max(1, int(start_line) + _line_number_from_offset(statement, method_match.start()) - 1)
        key = f"{rel}:{source_line}:{method}:{route}"
        if key in seen:
            continue
        seen.add(key)
        endpoints.append(
            {
                "method": method,
                "route": route,
                "framework": "rust_warp",
                "file": rel,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
        )
    return endpoints


def _snake_to_pascal_case(value: Any) -> str:
    return "".join(part[:1].upper() + part[1:] for part in re.split(r"[_\s]+", str(value or "").strip()) if part)


def _rust_identifier_to_kebab_case(value: Any) -> str:
    normalized = str(value or "").strip()
    if not normalized:
        return ""
    normalized = re.sub(r"([a-z0-9])([A-Z])", r"\1-\2", normalized)
    normalized = re.sub(r"([A-Z]+)([A-Z][a-z])", r"\1-\2", normalized)
    normalized = normalized.replace("_", "-")
    normalized = re.sub(r"-+", "-", normalized)
    return normalized.strip("-").lower()


def _extract_rust_clap_declared_name(attr_args: str, identifier: str, string_bindings: dict[str, str]) -> str:
    raw_args = str(attr_args or "").strip()
    if raw_args:
        match = re.search(r"""\bname\s*=\s*([^,\)]+)""", raw_args)
        if match:
            resolved_name = _resolve_rust_string_expression(str(match.group(1) or "").strip(), string_bindings).strip()
            if resolved_name:
                return resolved_name
    return _rust_identifier_to_kebab_case(identifier)


def _parse_rust_tonic_trait_context(
    trait_expr: str,
    *,
    default_package: str,
    package_by_module: dict[str, str],
    pending_tonic_async_trait: bool,
) -> tuple[str, str]:
    normalized = _strip_wrapping_js_parentheses(str(trait_expr or "")).strip()
    if not normalized:
        return "", ""
    parts = [part for part in normalized.split("::") if part and part not in {"crate", "self", "super"}]
    if len(parts) >= 2 and parts[-2].endswith("_server"):
        module_prefix = "::".join(parts[:-2]).strip()
        package_name = (
            package_by_module.get(module_prefix)
            or package_by_module.get(str(parts[0] or "").strip(), "")
            or default_package
        )
        return str(parts[-1] or "").strip(), package_name
    if pending_tonic_async_trait and parts:
        module_prefix = "::".join(parts[:-1]).strip()
        package_name = (
            package_by_module.get(module_prefix)
            or package_by_module.get(str(parts[0] or "").strip(), "")
            or default_package
        )
        return str(parts[-1] or "").strip(), package_name
    return "", ""


def _extract_rust_tonic_endpoints(rel: str, text: str) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    if "tonic" not in source.lower() and "include_proto!" not in source:
        return endpoints

    masked_source = _mask_js_comments(source)
    lines = masked_source.splitlines()
    string_bindings = _extract_rust_string_bindings(lines)
    line_offsets: list[int] = []
    cursor = 0
    for line in lines:
        line_offsets.append(cursor)
        cursor += len(line) + 1

    package_by_module: dict[str, str] = {}
    default_package = ""
    module_stack: list[dict[str, Any]] = []
    brace_depth = 0
    for i, line in enumerate(lines, start=1):
        stripped = str(line or "").strip()
        line_offset = line_offsets[i - 1] if i - 1 < len(line_offsets) else 0
        pushed_module = False
        module_match = RUST_MODULE_DECL_RE.match(stripped)
        if module_match and "{" in stripped and _rust_offset_is_code(source, line_offset):
            module_name = str(module_match.group(1) or "").strip()
            if module_name:
                parent_prefix = str(module_stack[-1].get("prefix", "")).strip() if module_stack else ""
                prefix = "::".join([part for part in [parent_prefix, module_name] if part])
                module_stack.append(
                    {
                        "depth": brace_depth,
                        "name": module_name,
                        "prefix": prefix or module_name,
                    }
                )
                pushed_module = True
        for match in RUST_TONIC_INCLUDE_PROTO_RE.finditer(line):
            if not _rust_offset_is_code(source, line_offset + match.start()):
                continue
            package_name = _resolve_rust_string_expression(str(match.group(1) or "").strip(), string_bindings)
            if not package_name:
                continue
            if not default_package:
                default_package = package_name
            if module_stack:
                module_prefix = str(module_stack[-1].get("prefix", "")).strip()
                module_name = str(module_stack[-1].get("name", "")).strip()
                if module_prefix:
                    package_by_module[module_prefix] = package_name
                if module_name:
                    package_by_module[module_name] = package_name
        brace_depth = max(0, brace_depth + _brace_delta(line))
        while module_stack and brace_depth <= int(module_stack[-1].get("depth", 0)) and not pushed_module:
            module_stack.pop()

    pending_tonic_async_trait = False
    impl_stack: list[dict[str, Any]] = []
    brace_depth = 0
    for i, line in enumerate(lines, start=1):
        stripped = str(line or "").strip()
        line_offset = line_offsets[i - 1] if i - 1 < len(line_offsets) else 0
        pushed_impl = False
        if re.match(r"""^\s*#\s*\[\s*tonic::async_trait\b""", stripped, re.IGNORECASE):
            if _rust_offset_is_code(source, line_offset):
                pending_tonic_async_trait = True
        else:
            impl_match = RUST_TONIC_IMPL_RE.match(stripped)
            if impl_match and _rust_offset_is_code(source, line_offset):
                service_name, package_name = _parse_rust_tonic_trait_context(
                    str(impl_match.group(1) or "").strip(),
                    default_package=default_package,
                    package_by_module=package_by_module,
                    pending_tonic_async_trait=pending_tonic_async_trait,
                )
                if service_name:
                    impl_stack.append(
                        {
                            "depth": brace_depth,
                            "service": service_name,
                            "package": package_name,
                        }
                    )
                    pushed_impl = True
                pending_tonic_async_trait = False
            elif impl_stack:
                fn_match = RUST_FN_DECL_RE.match(stripped)
                if fn_match and _rust_offset_is_code(source, line_offset):
                    fn_name = str(fn_match.group(1) or "").strip()
                    rpc_name = _snake_to_pascal_case(fn_name)
                    service_name = str(impl_stack[-1].get("service", "")).strip()
                    package_name = str(impl_stack[-1].get("package", "")).strip()
                    qualified_service = f"{package_name}.{service_name}" if package_name else service_name
                    route = f"/{qualified_service}/{rpc_name}" if qualified_service and rpc_name else ""
                    if route:
                        key = f"{rel}:{i}:{route}"
                        if key not in seen:
                            seen.add(key)
                            endpoints.append(
                                {
                                    "method": "POST",
                                    "route": route,
                                    "framework": "rust_tonic",
                                    "protocol": "grpc",
                                    "service": service_name,
                                    "rpc_name": rpc_name,
                                    "package": package_name,
                                    "file": rel,
                                    "line": i,
                                    "evidence": make_evidence(rel, i),
                                }
                            )
            elif stripped and not stripped.startswith("#") and pending_tonic_async_trait:
                pending_tonic_async_trait = False
        brace_depth = max(0, brace_depth + _brace_delta(line))
        while impl_stack and brace_depth <= int(impl_stack[-1].get("depth", 0)) and not pushed_impl:
            impl_stack.pop()

    return endpoints


def _find_rust_actix_constructor(source: str) -> Optional[dict[str, Any]]:
    text = str(source or "")
    candidates: list[tuple[int, str, re.Match[str]]] = []
    for kind, regex in [
        ("app", RUST_ACTIX_APP_START_RE),
        ("scope", RUST_ACTIX_SCOPE_START_RE),
        ("resource", RUST_ACTIX_RESOURCE_START_RE),
    ]:
        match = regex.search(text)
        if match and _js_offset_is_code(text, match.start()):
            candidates.append((match.start(), kind, match))
    if not candidates:
        return None
    candidates.sort(key=lambda item: item[0])
    _offset, kind, match = candidates[0]
    call = _extract_balanced_js_call(text, match.end() - 1)
    if not call:
        return None
    args_text, end_index = call
    path = ""
    if kind in {"scope", "resource"}:
        args = _split_js_top_level_args(args_text)
        if not args:
            return None
        path = args[0]
    return {
        "kind": kind,
        "start": int(match.start()),
        "args_text": args_text,
        "end": int(end_index),
        "path_expr": path,
    }


def _parse_rust_actix_builder(
    expr: str,
    statement_start_line: int,
    string_bindings: dict[str, str],
    named_builders: dict[str, dict[str, Any]],
) -> Optional[dict[str, Any]]:
    source = _strip_wrapping_js_parentheses(str(expr or "")).strip()
    constructor = _find_rust_actix_constructor(source)
    if not constructor:
        return None
    kind = str(constructor.get("kind", "")).strip()
    path_expr = str(constructor.get("path_expr", "")).strip()
    path = _resolve_rust_string_expression(path_expr, string_bindings) if path_expr else ""
    if kind in {"scope", "resource"} and not path:
        return None
    start_offset = int(constructor.get("start", 0) or 0)
    chain_source = source[start_offset:]
    node = {
        "kind": kind,
        "path": _normalize_route_path(path) if path else "",
        "line": max(1, int(statement_start_line) + _line_number_from_offset(source, start_offset) - 1),
        "routes": [],
        "children": [],
    }
    for member, dot_index, args_text, _end_index in _extract_rust_actix_member_calls(chain_source):
        source_line = max(1, int(statement_start_line) + _line_number_from_offset(chain_source, dot_index) - 1)
        args = _split_js_top_level_args(args_text)
        if member == "route":
            route_expr = ""
            methods_expr = args_text
            if kind == "resource":
                if args:
                    methods_expr = ",".join(args)
            else:
                if len(args) < 2:
                    continue
                route_expr = args[0]
                methods_expr = ",".join(args[1:])
            methods = [
                str(match.group(1) or "").upper().strip()
                for match in RUST_ACTIX_METHOD_RE.finditer(methods_expr)
                if str(match.group(1) or "").upper().strip() in HTTP_METHODS
            ]
            if not methods:
                continue
            route_expr_stripped = _strip_wrapping_js_parentheses(route_expr).strip()
            route_path = _resolve_rust_string_expression(route_expr, string_bindings) if route_expr else ""
            if kind != "resource" and not route_path and route_expr_stripped not in {'""', "''"}:
                continue
            normalized_route = _normalize_route_path(route_path) if route_path else ""
            for method in methods:
                node["routes"].append(
                    {
                        "method": method,
                        "route": normalized_route,
                        "line": source_line,
                    }
                )
        elif member == "service" and args:
            child_expr = args[0]
            child_ref = _resolve_rust_router_reference(child_expr)
            if child_ref and child_ref in named_builders:
                node["children"].append({"kind": "ref", "name": child_ref, "line": source_line})
                continue
            child_node = _parse_rust_actix_builder(child_expr, source_line, string_bindings, named_builders)
            if child_node:
                node["children"].append({"kind": "node", "node": child_node, "line": source_line})
    return node


def _extract_rust_actix_endpoints(rel: str, text: str) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    if not source:
        return endpoints
    masked_text = _mask_js_comments(source)
    lines = masked_text.splitlines()
    string_bindings = _extract_rust_string_bindings(lines)
    named_builders: dict[str, dict[str, Any]] = {}
    root_nodes: list[dict[str, Any]] = []
    statements = _split_rust_semicolon_statements(masked_text)

    for start_line, statement in statements:
        assign_match = RUST_ACTIX_ASSIGN_RE.search(statement)
        if not assign_match or not _js_offset_is_code(statement, assign_match.start(1)):
            continue
        builder_name = str(assign_match.group(1) or "").strip()
        expr = str(assign_match.group(2) or "").strip()
        if not builder_name or "scope" not in expr and "resource" not in expr and "App::new" not in expr:
            continue
        node = _parse_rust_actix_builder(expr, start_line, string_bindings, named_builders)
        if node:
            named_builders[builder_name] = node

    for start_line, statement in statements:
        for match in RUST_ACTIX_APP_START_RE.finditer(statement):
            if not _js_offset_is_code(statement, match.start()):
                continue
            node = _parse_rust_actix_builder(statement[match.start() :], start_line, string_bindings, named_builders)
            if node:
                root_nodes.append(node)

    def emit_node(node: dict[str, Any], prefix: str = "", refs: tuple[str, ...] = ()) -> None:
        kind = str(node.get("kind", "")).strip()
        node_prefix = prefix
        if kind in {"scope", "resource"}:
            node_prefix = _join_route_paths(prefix, str(node.get("path", "")).strip())
        for route_item in node.get("routes", []):
            method = str(route_item.get("method", "GET")).upper().strip() or "GET"
            local_route = str(route_item.get("route", "")).strip()
            full_route = _join_route_paths(node_prefix, local_route) if local_route else (node_prefix or "/")
            line_no = int(route_item.get("line", node.get("line", 1)) or 1)
            key = f"{rel}:{line_no}:{method}:{full_route}"
            if key in seen:
                continue
            seen.add(key)
            endpoints.append(
                {
                    "method": method,
                    "route": full_route,
                    "framework": "rust_actix",
                    "file": rel,
                    "line": line_no,
                    "evidence": make_evidence(rel, line_no),
                }
            )
        for child in node.get("children", []):
            child_kind = str(child.get("kind", "")).strip()
            if child_kind == "ref":
                child_name = str(child.get("name", "")).strip()
                if not child_name or child_name in refs:
                    continue
                child_node = named_builders.get(child_name)
                if child_node:
                    emit_node(child_node, node_prefix, refs + (child_name,))
            elif child_kind == "node":
                child_node = child.get("node")
                if isinstance(child_node, dict):
                    emit_node(child_node, node_prefix, refs)

    for root in root_nodes:
        emit_node(root)

    return endpoints


def _extract_rust_axum_endpoints(rel: str, text: str) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    masked_text = _mask_js_comments(text)
    string_bindings = _extract_rust_string_bindings(masked_text.splitlines())
    router_routes: dict[str, list[dict[str, Any]]] = {}
    router_nests: dict[str, list[dict[str, Any]]] = {}
    nested_receivers: set[str] = set()

    def ensure_router(name: str) -> None:
        router_routes.setdefault(name, [])
        router_nests.setdefault(name, [])

    for start_line, statement in _split_rust_semicolon_statements(masked_text):
        assigned_router = ""
        assign_match = RUST_AXUM_ROUTER_ASSIGN_RE.search(statement)
        if assign_match:
            assigned_router = str(assign_match.group(1) or "").strip()
            if assigned_router:
                ensure_router(assigned_router)

        for member, dot_index, args_text, _end_index in _extract_rust_member_calls(statement):
            receiver = _extract_rust_call_receiver(statement, dot_index) or assigned_router
            if not receiver:
                continue
            ensure_router(receiver)
            source_line = max(1, int(start_line) + _line_number_from_offset(statement, dot_index) - 1)
            parts = _split_js_top_level_operator(args_text, ",")
            if member == "route":
                route_expr = parts[0] if parts else ""
                methods_expr = ",".join(parts[1:]) if len(parts) > 1 else ""
                route = _resolve_rust_string_expression(route_expr, string_bindings)
                if not route:
                    continue
                methods = [
                    str(match.group(1) or "").upper().strip()
                    for match in RUST_AXUM_METHOD_RE.finditer(methods_expr)
                    if str(match.group(1) or "").upper().strip() in HTTP_METHODS
                ]
                if not methods:
                    continue
                for method in methods:
                    router_routes[receiver].append(
                        {
                            "method": method,
                            "route": _normalize_route_path(route),
                            "line": source_line,
                        }
                    )
            elif member == "nest" and len(parts) >= 2:
                prefix = _resolve_rust_string_expression(parts[0], string_bindings)
                child = _resolve_rust_router_reference(parts[1])
                if not prefix or not child:
                    continue
                ensure_router(child)
                nested_receivers.add(child)
                router_nests[receiver].append(
                    {
                        "prefix": _normalize_route_path(prefix),
                        "child": child,
                        "line": source_line,
                    }
                )

    router_names = set(router_routes.keys()) | set(router_nests.keys())
    root_receivers = sorted(router_names - nested_receivers) or sorted(router_names)

    def emit_routes(receiver: str, prefix: str = "", trail: tuple[str, ...] = ()) -> None:
        if receiver in trail:
            return
        for item in router_routes.get(receiver, []):
            method = str(item.get("method", "GET")).upper().strip() or "GET"
            route = _join_route_paths(prefix, str(item.get("route", "")).strip())
            line = int(item.get("line", 1) or 1)
            key = f"{rel}:{line}:{method}:{route}"
            if key in seen:
                continue
            seen.add(key)
            endpoints.append(
                {
                    "method": method,
                    "route": route,
                    "framework": "rust_axum",
                    "file": rel,
                    "line": line,
                    "evidence": make_evidence(rel, line),
                }
            )
        for item in router_nests.get(receiver, []):
            child = str(item.get("child", "")).strip()
            if not child:
                continue
            child_prefix = _join_route_paths(prefix, str(item.get("prefix", "")).strip())
            emit_routes(child, child_prefix, trail + (receiver,))

    for receiver in root_receivers:
        emit_routes(receiver)

    return endpoints


def _extract_rust_clap_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    if "clap" not in source.lower() and "Command::new" not in source and "derive(Parser" not in source and "derive(Subcommand" not in source:
        return entrypoints
    masked_source = _mask_js_comments(source)
    masked_lines = masked_source.splitlines()
    string_bindings = _extract_rust_string_bindings(masked_lines)
    for match in RUST_CLAP_COMMAND_NEW_START_RE.finditer(masked_source):
        if not _js_offset_is_code(source, match.start()):
            continue
        call = _extract_balanced_js_call(masked_source, match.end() - 1)
        if not call:
            continue
        args = _split_js_top_level_args(call[0])
        if not args:
            continue
        command_name = _resolve_rust_string_expression(args[0], string_bindings).strip()
        if not command_name:
            continue
        source_line = _line_number_from_offset(source, match.start())
        key = f"{rel}:{source_line}:{command_name}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "rust_clap_command",
                "name": command_name,
                "file": rel,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
        )
    pending_kind = ""
    pending_command_args = ""
    subcommand_depth: Optional[int] = None
    subcommand_command_args = ""
    brace_depth = 0
    line_offset = 0
    raw_lines = source.splitlines()
    for i, line in enumerate(masked_lines, start=1):
        raw_line = raw_lines[i - 1] if i - 1 < len(raw_lines) else ""
        stripped = str(line or "").strip()
        derive_match = RUST_CLAP_DERIVE_RE.match(stripped)
        if derive_match and _rust_offset_is_code(source, line_offset):
            derive_args = str(derive_match.group("args") or "").strip()
            if re.search(r"""\b(?:clap::)?Parser\b""", derive_args):
                pending_kind = "parser"
            elif re.search(r"""\b(?:clap::)?Subcommand\b""", derive_args):
                pending_kind = "subcommand"
            pending_command_args = ""
        else:
            attr_match = RUST_CLAP_ATTR_RE.match(stripped)
            if attr_match and _rust_offset_is_code(source, line_offset):
                if subcommand_depth is not None:
                    subcommand_command_args = str(attr_match.group("args") or "").strip()
                elif pending_kind:
                    pending_command_args = str(attr_match.group("args") or "").strip()
            elif pending_kind == "parser":
                struct_match = RUST_STRUCT_DECL_RE.match(stripped)
                if struct_match and _rust_offset_is_code(source, line_offset):
                    struct_name = str(struct_match.group(1) or "").strip()
                    command_name = _extract_rust_clap_declared_name(pending_command_args, struct_name, string_bindings)
                    if command_name:
                        key = f"{rel}:{i}:{command_name}:derive_parser"
                        if key not in seen:
                            seen.add(key)
                            entrypoints.append(
                                {
                                    "kind": "rust_clap_command",
                                    "name": command_name,
                                    "file": rel,
                                    "line": i,
                                    "evidence": make_evidence(rel, i),
                                }
                            )
                    pending_kind = ""
                    pending_command_args = ""
                elif stripped and not stripped.startswith("#"):
                    pending_kind = ""
                    pending_command_args = ""
            elif pending_kind == "subcommand":
                enum_match = RUST_ENUM_DECL_RE.match(stripped)
                if enum_match and _rust_offset_is_code(source, line_offset):
                    subcommand_depth = brace_depth
                    subcommand_command_args = ""
                    pending_kind = ""
                    pending_command_args = ""
                elif stripped and not stripped.startswith("#"):
                    pending_kind = ""
                    pending_command_args = ""
            elif subcommand_depth is not None:
                variant_match = RUST_ENUM_VARIANT_RE.match(stripped)
                if variant_match and _rust_offset_is_code(source, line_offset):
                    variant_name = str(variant_match.group(1) or "").strip()
                    command_name = _extract_rust_clap_declared_name(subcommand_command_args, variant_name, string_bindings)
                    if command_name:
                        key = f"{rel}:{i}:{command_name}:derive_subcommand"
                        if key not in seen:
                            seen.add(key)
                            entrypoints.append(
                                {
                                    "kind": "rust_clap_command",
                                    "name": command_name,
                                    "file": rel,
                                    "line": i,
                                    "evidence": make_evidence(rel, i),
                                }
                            )
                    subcommand_command_args = ""
                elif stripped and not stripped.startswith("#"):
                    subcommand_command_args = ""
        brace_depth = max(0, brace_depth + _brace_delta(line))
        line_offset += len(raw_line) + 1
        if subcommand_depth is not None and brace_depth <= int(subcommand_depth):
            subcommand_depth = None
            subcommand_command_args = ""
    return entrypoints


def _extract_bullmq_worker_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source_text = str(text or "")
    masked_text = _mask_js_comments(source_text)
    lines = masked_text.splitlines()
    string_bindings = _extract_js_string_bindings(lines)
    import_bindings = _extract_js_import_bindings(rel, lines)
    worker_aliases: set[str] = set()
    namespace_aliases: set[str] = set()

    for item in import_bindings:
        if not isinstance(item, dict):
            continue
        target_module = str(item.get("target_module", "")).strip()
        if target_module != "bullmq":
            continue
        alias = str(item.get("alias", "")).strip()
        target_symbol = str(item.get("target_symbol", "")).strip()
        if not alias:
            continue
        if target_symbol == "Worker":
            worker_aliases.add(alias)
        elif target_symbol in {"*", "default"}:
            namespace_aliases.add(alias)

    if not worker_aliases and not namespace_aliases:
        return entrypoints

    for match in JS_BULLMQ_WORKER_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        constructor = str(match.group(1) or "").strip()
        if not constructor:
            continue
        is_bullmq_worker = constructor in worker_aliases
        if not is_bullmq_worker and "." in constructor:
            namespace_alias, member_name = constructor.split(".", 1)
            is_bullmq_worker = namespace_alias in namespace_aliases and member_name == "Worker"
        if not is_bullmq_worker:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        queue_name = _resolve_js_string_expression(args[0], string_bindings)
        if not queue_name:
            continue
        source_line = _line_number_from_offset(masked_text, match.start())
        key = f"{rel}:{source_line}:{queue_name}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "bullmq_worker",
                "name": queue_name,
                "file": rel,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
        )

    return entrypoints


def _extract_bullmq_repeat_schedule(options_expr: str, string_bindings: dict[str, str]) -> str:
    expr = str(options_expr or "").strip()
    if not expr.startswith("{") or not expr.endswith("}"):
        return ""
    repeat_expr = _extract_js_object_property_value(expr[1:-1], {"repeat"})
    repeat_expr = str(repeat_expr or "").strip()
    if not repeat_expr:
        return ""
    if repeat_expr.startswith("{") and repeat_expr.endswith("}"):
        repeat_body = repeat_expr[1:-1]
        cron_value = _extract_js_object_property_value(repeat_body, {"cron", "pattern"})
        cron_value = _resolve_js_string_expression(cron_value, string_bindings)
        if cron_value:
            return cron_value
        every_value = _extract_js_object_property_value(repeat_body, {"every"})
        every_value = str(every_value or "").strip()
        if every_value:
            resolved_every = _resolve_js_string_expression(every_value, string_bindings) or every_value
            return f"every:{resolved_every}"
    resolved_repeat = _resolve_js_string_expression(repeat_expr, string_bindings)
    return str(resolved_repeat or "").strip()


def _extract_bullmq_scheduler_schedule(schedule_expr: str, string_bindings: dict[str, str]) -> str:
    expr = str(schedule_expr or "").strip()
    if not expr:
        return ""
    if expr.startswith("{") and expr.endswith("}"):
        body = expr[1:-1]
        cron_value = _extract_js_object_property_value(body, {"cron", "pattern"})
        cron_value = _resolve_js_string_expression(cron_value, string_bindings)
        if cron_value:
            return cron_value
        every_value = _extract_js_object_property_value(body, {"every"})
        every_value = str(every_value or "").strip()
        if every_value:
            resolved_every = _resolve_js_string_expression(every_value, string_bindings) or every_value
            return f"every:{resolved_every}"
    resolved_expr = _resolve_js_string_expression(expr, string_bindings)
    return str(resolved_expr or "").strip()


def _extract_bullmq_scheduler_template_name(template_expr: str, string_bindings: dict[str, str]) -> str:
    expr = str(template_expr or "").strip()
    if not expr.startswith("{") or not expr.endswith("}"):
        return ""
    name_expr = _extract_js_object_property_value(expr[1:-1], {"name"})
    resolved_name = _resolve_js_string_expression(name_expr, string_bindings)
    return str(resolved_name or "").strip()


def _extract_bullmq_flow_job_specs(flow_expr: str, string_bindings: dict[str, str]) -> list[dict[str, str]]:
    specs: list[dict[str, str]] = []
    seen: set[str] = set()

    def visit(node_expr: str) -> None:
        expr = str(node_expr or "").strip()
        if expr.startswith("[") and expr.endswith("]"):
            for child_expr in _split_js_top_level_args(expr[1:-1]):
                visit(child_expr)
            return
        if not expr.startswith("{") or not expr.endswith("}"):
            return
        body = expr[1:-1]
        queue_expr = _extract_js_object_property_value(body, {"queueName", "queue"})
        queue_name = _resolve_js_string_expression(queue_expr, string_bindings)
        queue_name = str(queue_name or "").strip()
        job_expr = _extract_js_object_property_value(body, {"name"})
        job_name = _resolve_js_string_expression(job_expr, string_bindings)
        job_name = str(job_name or "").strip()
        if queue_name:
            key = json.dumps([queue_name, job_name], ensure_ascii=True)
            if key not in seen:
                seen.add(key)
                payload = {"queue": queue_name}
                if job_name:
                    payload["job"] = job_name
                specs.append(payload)
        children_expr = str(_extract_js_object_property_value(body, {"children"}) or "").strip()
        if children_expr.startswith("[") and children_expr.endswith("]"):
            for child_expr in _split_js_top_level_args(children_expr[1:-1]):
                visit(child_expr)

    visit(flow_expr)
    return specs


def _extract_bullmq_producer_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source_text = str(text or "")
    masked_text = _mask_js_comments(source_text)
    lines = masked_text.splitlines()
    string_bindings = _extract_js_string_bindings(lines)
    import_bindings = _extract_js_import_bindings(rel, lines)
    queue_aliases: set[str] = set()
    flow_producer_aliases: set[str] = set()
    namespace_aliases: set[str] = set()

    for item in import_bindings:
        if not isinstance(item, dict):
            continue
        target_module = str(item.get("target_module", "")).strip()
        if target_module != "bullmq":
            continue
        alias = str(item.get("alias", "")).strip()
        target_symbol = str(item.get("target_symbol", "")).strip()
        if not alias:
            continue
        if target_symbol == "Queue":
            queue_aliases.add(alias)
        elif target_symbol == "FlowProducer":
            flow_producer_aliases.add(alias)
        elif target_symbol in {"*", "default"}:
            namespace_aliases.add(alias)

    if not queue_aliases and not flow_producer_aliases and not namespace_aliases:
        return entrypoints

    queue_receivers: dict[str, str] = {}
    flow_receivers: set[str] = set()
    for match in JS_BULLMQ_QUEUE_ASSIGN_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("name") or "").strip()
        constructor = str(match.group("constructor") or "").strip()
        if not receiver_name or not constructor:
            continue
        is_bullmq_queue = constructor in queue_aliases
        is_bullmq_flow_producer = constructor in flow_producer_aliases
        if not is_bullmq_queue and "." in constructor:
            namespace_alias, member_name = constructor.split(".", 1)
            is_bullmq_queue = namespace_alias in namespace_aliases and member_name == "Queue"
            is_bullmq_flow_producer = namespace_alias in namespace_aliases and member_name == "FlowProducer"
        if is_bullmq_queue:
            call = _extract_balanced_js_call(masked_text, match.end() - 1)
            if not call:
                continue
            args_text, _end = call
            args = _split_js_top_level_args(args_text)
            if not args:
                continue
            queue_name = _resolve_js_string_expression(args[0], string_bindings)
            if queue_name:
                queue_receivers[receiver_name] = queue_name
        elif is_bullmq_flow_producer:
            flow_receivers.add(receiver_name)

    if not queue_receivers and not flow_receivers:
        return entrypoints

    for match in JS_BULLMQ_QUEUE_ADD_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("receiver") or "").strip()
        queue_name = queue_receivers.get(receiver_name, "")
        if not queue_name:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        job_name = _resolve_js_string_expression(args[0], string_bindings)
        source_line = _line_number_from_offset(source_text, match.start())
        options_expr = args[2] if len(args) > 2 else ""
        schedule = _extract_bullmq_repeat_schedule(options_expr, string_bindings)
        if not schedule:
            producer_key = f"{rel}:{source_line}:bullmq_producer:{queue_name}:{job_name}"
            if producer_key not in seen:
                seen.add(producer_key)
                payload = {
                    "kind": "bullmq_producer",
                    "name": queue_name,
                    "queue": queue_name,
                    "file": rel,
                    "line": source_line,
                    "evidence": make_evidence(rel, source_line),
                }
                if job_name:
                    payload["job"] = job_name
                entrypoints.append(payload)
        if not schedule:
            continue
        repeat_key = f"{rel}:{source_line}:bullmq_repeatable_job:{queue_name}:{job_name}:{schedule}"
        if repeat_key in seen:
            continue
        seen.add(repeat_key)
        payload = {
            "kind": "bullmq_repeatable_job",
            "name": job_name or queue_name,
            "queue": queue_name,
            "file": rel,
            "line": source_line,
            "evidence": make_evidence(rel, source_line),
            "schedule": schedule,
        }
        if job_name:
            payload["job"] = job_name
        entrypoints.append(payload)

    for match in JS_BULLMQ_QUEUE_SCHEDULER_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("receiver") or "").strip()
        queue_name = queue_receivers.get(receiver_name, "")
        if not queue_name:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if len(args) < 2:
            continue
        scheduler_id = _resolve_js_string_expression(args[0], string_bindings)
        schedule = _extract_bullmq_scheduler_schedule(args[1], string_bindings)
        if not schedule:
            continue
        template_expr = args[2] if len(args) > 2 else ""
        job_name = _extract_bullmq_scheduler_template_name(template_expr, string_bindings)
        source_line = _line_number_from_offset(source_text, match.start())
        repeat_key = f"{rel}:{source_line}:bullmq_repeatable_job:{queue_name}:{job_name or scheduler_id}:{schedule}"
        if repeat_key in seen:
            continue
        seen.add(repeat_key)
        payload = {
            "kind": "bullmq_repeatable_job",
            "name": job_name or scheduler_id or queue_name,
            "queue": queue_name,
            "file": rel,
            "line": source_line,
            "evidence": make_evidence(rel, source_line),
            "schedule": schedule,
        }
        if job_name:
            payload["job"] = job_name
        if scheduler_id:
            payload["scheduler_id"] = scheduler_id
        entrypoints.append(payload)

    for match in JS_BULLMQ_QUEUE_ADD_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("receiver") or "").strip()
        if receiver_name not in flow_receivers:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        source_line = _line_number_from_offset(source_text, match.start())
        for spec in _extract_bullmq_flow_job_specs(args[0], string_bindings):
            queue_name = str(spec.get("queue", "")).strip()
            job_name = str(spec.get("job", "")).strip()
            if not queue_name:
                continue
            producer_key = f"{rel}:{source_line}:bullmq_flow_producer:{queue_name}:{job_name}"
            if producer_key in seen:
                continue
            seen.add(producer_key)
            payload = {
                "kind": "bullmq_producer",
                "name": queue_name,
                "queue": queue_name,
                "file": rel,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
            if job_name:
                payload["job"] = job_name
            entrypoints.append(payload)

    for match in JS_BULLMQ_FLOW_BULK_ADD_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("receiver") or "").strip()
        if receiver_name not in flow_receivers:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        if not args:
            continue
        source_line = _line_number_from_offset(source_text, match.start())
        for spec in _extract_bullmq_flow_job_specs(args[0], string_bindings):
            queue_name = str(spec.get("queue", "")).strip()
            job_name = str(spec.get("job", "")).strip()
            if not queue_name:
                continue
            producer_key = f"{rel}:{source_line}:bullmq_flow_producer_bulk:{queue_name}:{job_name}"
            if producer_key in seen:
                continue
            seen.add(producer_key)
            payload = {
                "kind": "bullmq_producer",
                "name": queue_name,
                "queue": queue_name,
                "file": rel,
                "line": source_line,
                "evidence": make_evidence(rel, source_line),
            }
            if job_name:
                payload["job"] = job_name
            entrypoints.append(payload)

    return entrypoints


def _extract_js_kafka_subscribe_topics(args: list[str], string_bindings: dict[str, str]) -> list[str]:
    topics: list[str] = []
    seen: set[str] = set()
    if not args:
        return topics

    def add_topic(expr: Any) -> None:
        topic_name = _resolve_js_string_expression(expr, string_bindings)
        normalized = str(topic_name or "").strip()
        if not normalized or normalized in seen:
            return
        seen.add(normalized)
        topics.append(normalized)

    first = str(args[0] or "").strip()
    if not first:
        return topics
    if first.startswith("{") and first.endswith("}"):
        for prop in _split_js_top_level_args(first[1:-1]):
            prop_text = str(prop or "").strip()
            if not prop_text:
                continue
            split_at = _find_js_top_level_delimiter(prop_text, ":")
            if split_at < 0:
                continue
            key = _normalize_js_object_property_key(prop_text[:split_at])
            value = prop_text[split_at + 1 :].strip()
            if key == "topic":
                add_topic(value)
            elif key == "topics" and value.startswith("[") and value.endswith("]"):
                for item in _split_js_top_level_args(value[1:-1]):
                    add_topic(item)
        return topics
    add_topic(first)
    return topics


def _extract_js_kafka_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source_text = str(text or "")
    if not source_text.strip():
        return entrypoints

    masked_text = _mask_js_comments(source_text)
    lines = masked_text.splitlines()
    string_bindings = _extract_js_string_bindings(lines)
    import_bindings = _extract_js_import_bindings(rel, lines)
    has_kafka_import = any(
        str(item.get("target_module", "")).strip() == "kafkajs"
        for item in import_bindings
        if isinstance(item, dict)
    )
    if not has_kafka_import:
        return entrypoints

    consumer_receivers: set[str] = set()
    for match in JS_KAFKA_CONSUMER_ASSIGN_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("name") or "").strip()
        if receiver_name:
            consumer_receivers.add(receiver_name)
    if not consumer_receivers:
        return entrypoints

    subscribed_topics: dict[str, list[tuple[str, int]]] = {}
    for match in JS_KAFKA_SUBSCRIBE_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("receiver") or "").strip()
        if receiver_name not in consumer_receivers:
            continue
        call = _extract_balanced_js_call(masked_text, match.end() - 1)
        if not call:
            continue
        args_text, _end = call
        args = _split_js_top_level_args(args_text)
        topics = _extract_js_kafka_subscribe_topics(args, string_bindings)
        if not topics:
            continue
        source_line = _line_number_from_offset(source_text, match.start())
        bucket = subscribed_topics.setdefault(receiver_name, [])
        for topic_name in topics:
            if (topic_name, source_line) not in bucket:
                bucket.append((topic_name, source_line))

    runnable_receivers: set[str] = set()
    for match in JS_KAFKA_RUN_RE.finditer(masked_text):
        if not _js_offset_is_code(source_text, match.start()):
            continue
        receiver_name = str(match.group("receiver") or "").strip()
        if receiver_name in consumer_receivers:
            runnable_receivers.add(receiver_name)

    for receiver_name in sorted(runnable_receivers):
        for topic_name, source_line in subscribed_topics.get(receiver_name, []):
            key = f"{rel}:{source_line}:{topic_name}"
            if key in seen:
                continue
            seen.add(key)
            entrypoints.append(
                {
                    "kind": "kafka_consumer",
                    "name": topic_name,
                    "topic": topic_name,
                    "file": rel,
                    "line": source_line,
                    "evidence": make_evidence(rel, source_line),
                }
            )

    return entrypoints


