def _extract_ruby_resque_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    normalized_rel = "/" + str(rel or "").replace("\\", "/").strip("/").lower()
    if not normalized_rel.endswith(".rb"):
        return []

    masked_lines = _mask_ruby_comments_and_strings(text).splitlines()
    stack: list[dict[str, str]] = []
    entrypoints_by_name: dict[str, dict[str, Any]] = {}
    entrypoint_order: list[str] = []

    def current_class() -> Optional[dict[str, str]]:
        for item in reversed(stack):
            if item.get("kind") == "class":
                return item
        return None

    for line_no, masked_line in enumerate(masked_lines, start=1):
        stripped = masked_line.strip()
        if not stripped:
            continue
        if re.match(r"^end\b", stripped, re.IGNORECASE):
            if stack:
                stack.pop()
            continue
        module_match = RUBY_MODULE_DECL_RE.match(stripped)
        if module_match:
            stack.append({"kind": "module", "name": str(module_match.group(1) or "").strip()})
            continue
        class_match = RUBY_CLASS_DECL_RE.match(stripped)
        if class_match:
            class_name = str(class_match.group(1) or "").strip()
            prefix = [str(item.get("name", "")).strip() for item in stack if item.get("kind") in {"module", "class"}]
            full_name = "::".join([item for item in prefix + [class_name] if item])
            stack.append({"kind": "class", "name": class_name, "full_name": full_name or class_name})
            continue
        current = current_class()
        if current:
            queue_match = RUBY_RESQUE_QUEUE_ASSIGN_RE.match(stripped)
            if queue_match:
                worker_name = str(current.get("full_name", "") or current.get("name", "")).strip()
                if worker_name and worker_name not in entrypoints_by_name:
                    payload = {
                        "kind": "resque_worker",
                        "name": worker_name,
                        "file": rel,
                        "line": line_no,
                        "evidence": make_evidence(rel, line_no),
                    }
                    queue_name = str(queue_match.group(1) or queue_match.group(2) or "").strip()
                    if queue_name:
                        payload["queue"] = queue_name
                    entrypoints_by_name[worker_name] = payload
                    entrypoint_order.append(worker_name)
        if RUBY_BLOCK_START_RE.match(stripped) or re.search(r"\bdo\b\s*(?:\|[^|]*\|)?\s*$", stripped):
            stack.append({"kind": "block", "name": ""})

    return [entrypoints_by_name[name] for name in entrypoint_order if name in entrypoints_by_name]


