def _extract_ruby_rake_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    normalized_rel = "/" + str(rel or "").replace("\\", "/").strip("/").lower()
    if not normalized_rel.endswith(".rake"):
        return []

    raw_lines = str(text or "").splitlines()
    stack: list[dict[str, str]] = []
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()

    def current_namespace() -> str:
        parts = [str(item.get("name", "")).strip() for item in stack if item.get("kind") == "namespace"]
        return ":".join([part for part in parts if part])

    for line_no, raw_line in enumerate(raw_lines, start=1):
        stripped = raw_line.strip()
        if not stripped:
            continue
        if stripped.startswith("#"):
            continue
        if re.match(r"^end\b", stripped, re.IGNORECASE):
            if stack:
                stack.pop()
            continue

        namespace_match = RUBY_RAKE_NAMESPACE_RE.match(stripped)
        if namespace_match:
            namespace_name = str(namespace_match.group(1) or namespace_match.group(2) or "").strip()
            if namespace_name:
                stack.append({"kind": "namespace", "name": namespace_name})
            continue

        task_match = RUBY_RAKE_TASK_RE.match(stripped)
        if task_match:
            task_name = str(task_match.group(1) or task_match.group(2) or "").strip()
            if task_name:
                full_name = task_name if ":" in task_name or not current_namespace() else f"{current_namespace()}:{task_name}"
                key = f"{rel}:{line_no}:{full_name}"
                if key not in seen:
                    seen.add(key)
                    entrypoints.append(
                        {
                            "kind": "rake_task",
                            "name": full_name,
                            "file": rel,
                            "line": line_no,
                            "evidence": make_evidence(rel, line_no),
                        }
                    )
            if re.search(r"\bdo\b\s*(?:\|[^|]*\|)?\s*$", stripped):
                stack.append({"kind": "task", "name": ""})
            continue

        if RUBY_BLOCK_START_RE.match(stripped) or re.search(r"\bdo\b\s*(?:\|[^|]*\|)?\s*$", stripped):
            stack.append({"kind": "block", "name": ""})

    return entrypoints


def _extract_spring_scheduled_entrypoints(rel: str, text: str, lines: list[str]) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    string_bindings = _extract_java_string_bindings(lines)
    for match in JAVA_SCHEDULED_ANNOTATION_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        args_text = str(match.group(1) or "").strip()
        if not args_text:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        schedule = ""
        cron_match = re.search(r"""\bcron\s*=\s*([^,\)]+)""", args_text, re.IGNORECASE)
        if cron_match:
            schedule = _resolve_java_string_expression(str(cron_match.group(1) or "").strip(), string_bindings)
        if not schedule:
            fixed_rate_match = re.search(r"""\bfixedRate(?:String)?\s*=\s*([^,\)]+)""", args_text, re.IGNORECASE)
            if fixed_rate_match:
                resolved = _resolve_java_string_expression(str(fixed_rate_match.group(1) or "").strip(), string_bindings)
                schedule = f"fixedRate={resolved}" if resolved else ""
        if not schedule:
            fixed_delay_match = re.search(r"""\bfixedDelay(?:String)?\s*=\s*([^,\)]+)""", args_text, re.IGNORECASE)
            if fixed_delay_match:
                resolved = _resolve_java_string_expression(str(fixed_delay_match.group(1) or "").strip(), string_bindings)
                schedule = f"fixedDelay={resolved}" if resolved else ""
        method_name = ""
        method_line = line_no
        window_start = match.end()
        window = source[window_start : min(len(source), window_start + 400)]
        consumed = 0
        for line in window.splitlines(keepends=True):
            stripped = str(line or "").strip()
            if not stripped:
                consumed += len(line)
                continue
            method_match = JAVA_METHOD_DECL_RE.match(stripped)
            if method_match:
                method_name = str(method_match.group(1) or "").strip()
                method_line = source.count("\n", 0, window_start + consumed) + 1
                break
            consumed += len(line)
        if not method_name:
            continue
        key = f"{rel}:{method_line}:{method_name}"
        if key in seen:
            continue
        seen.add(key)
        payload = {
            "kind": "spring_scheduled_job",
            "name": method_name,
            "file": rel,
            "line": method_line,
            "evidence": make_evidence(rel, method_line),
        }
        if schedule:
            payload["schedule"] = schedule
        entrypoints.append(payload)
    return entrypoints


def _extract_spring_batch_entrypoints(rel: str, text: str, lines: list[str]) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    string_bindings = _extract_java_string_bindings(lines)
    for match in JAVA_BEAN_ANNOTATION_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        annotation_line = source.count("\n", 0, match.start()) + 1
        window_start = match.end()
        window = source[window_start : min(len(source), window_start + 800)]
        consumed = 0
        method_name = ""
        method_line = annotation_line
        method_offset = window_start
        for line in window.splitlines(keepends=True):
            stripped = str(line or "").strip()
            if not stripped:
                consumed += len(line)
                continue
            method_match = JAVA_SPRING_BATCH_JOB_METHOD_RE.match(stripped)
            if method_match:
                method_name = str(method_match.group(1) or "").strip()
                method_line = source.count("\n", 0, window_start + consumed) + 1
                method_offset = window_start + consumed
                break
            consumed += len(line)
        if not method_name:
            continue

        entry_name = ""
        method_window = source[method_offset : min(len(source), method_offset + 1600)]
        for builder_match in JAVA_SPRING_BATCH_JOB_BUILDER_RE.finditer(method_window):
            absolute_offset = method_offset + builder_match.start()
            if not _js_offset_is_code(source, absolute_offset):
                continue
            entry_name = _resolve_java_string_expression(str(builder_match.group(1) or "").strip(), string_bindings)
            if entry_name:
                break
        if not entry_name:
            entry_name = method_name

        key = f"{rel}:{method_line}:{entry_name}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "spring_batch_job",
                "name": entry_name,
                "handler": method_name,
                "file": rel,
                "line": method_line,
                "evidence": make_evidence(rel, method_line),
            }
        )
    return entrypoints


def _extract_spring_kafka_entrypoints(rel: str, text: str, lines: list[str]) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    string_bindings = _extract_java_string_bindings(lines)
    for match in JAVA_KAFKA_LISTENER_ANNOTATION_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        args_text = str(match.group(1) or "").strip()
        named_args, positional_args = _parse_java_annotation_arguments(args_text)
        topic_names: list[str] = []
        for key in ["topics", "topicPattern", "value"]:
            if key in named_args:
                topic_names.extend(_resolve_java_string_expression_list(named_args[key], string_bindings))
        if not topic_names and positional_args:
            topic_names.extend(_resolve_java_string_expression_list(positional_args[0], string_bindings))
        if not topic_names:
            continue
        method_name, method_line = _find_java_next_method_declaration(source, match.end(), line_no)
        for topic_name in topic_names:
            key = f"{rel}:{method_line}:{topic_name}"
            if key in seen:
                continue
            seen.add(key)
            entrypoints.append(
                {
                    "kind": "kafka_consumer",
                    "name": topic_name,
                    "topic": topic_name,
                    "handler": method_name,
                    "file": rel,
                    "line": method_line,
                    "evidence": make_evidence(rel, method_line),
                }
            )
    return entrypoints


def _extract_spring_rabbitmq_entrypoints(rel: str, text: str, lines: list[str]) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    string_bindings = _extract_java_string_bindings(lines)
    for match in JAVA_RABBIT_LISTENER_ANNOTATION_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        args_text = str(match.group(1) or "").strip()
        named_args, positional_args = _parse_java_annotation_arguments(args_text)
        queue_names: list[str] = []
        for key in ["queues", "value"]:
            if key in named_args:
                queue_names.extend(_resolve_java_string_expression_list(named_args[key], string_bindings))
        if not queue_names and positional_args:
            queue_names.extend(_resolve_java_string_expression_list(positional_args[0], string_bindings))
        if not queue_names:
            continue
        method_name, method_line = _find_java_next_method_declaration(source, match.end(), line_no)
        for queue_name in queue_names:
            key = f"{rel}:{method_line}:{queue_name}"
            if key in seen:
                continue
            seen.add(key)
            entrypoints.append(
                {
                    "kind": "rabbitmq_consumer",
                    "name": queue_name,
                    "queue": queue_name,
                    "handler": method_name,
                    "file": rel,
                    "line": method_line,
                    "evidence": make_evidence(rel, method_line),
                }
            )
    return entrypoints


