def _extract_go_cobra_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    for match in GO_COBRA_COMMAND_START_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        brace_depth = 1
        idx = match.end()
        while idx < len(source) and brace_depth > 0:
            ch = source[idx]
            if ch == "{":
                brace_depth += 1
            elif ch == "}":
                brace_depth -= 1
            idx += 1
        block = source[match.end() : max(match.end(), idx - 1)]
        use_match = GO_COBRA_USE_RE.search(block)
        if not use_match:
            continue
        command_name = str(use_match.group(1) or use_match.group(2) or "").strip()
        if not command_name:
            continue
        key = f"{rel}:{line_no}:{command_name}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "cobra_command",
                "name": command_name,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
            }
        )
    return entrypoints


def _extract_go_cron_entrypoints(rel: str, text: str) -> list[dict[str, Any]]:
    entrypoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    source = str(text or "")
    if "robfig/cron" not in source and "gocron" not in source:
        return entrypoints

    for match in GO_CRON_ADD_CALL_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        schedule = str(match.group(3) or "").strip()
        handler_name = str(match.group(4) or "").strip()
        if not schedule or not handler_name:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        key = f"{rel}:{line_no}:{handler_name}:{schedule}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "go_cron_job",
                "name": handler_name,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
                "schedule": schedule,
            }
        )
    for match in GO_GOCRON_EVERY_DO_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        every_arg = re.sub(r"\s+", " ", str(match.group(2) or "").strip())
        handler_name = str(match.group(4) or "").strip()
        if not every_arg or not handler_name:
            continue
        chain = str(match.group("chain") or "").strip()
        schedule_parts = [f"Every({every_arg})"]
        for method_match in re.finditer(r"""\.\s*([A-Za-z_][A-Za-z0-9_]*)\s*\(([^)]*)\)""", chain):
            method_name = str(method_match.group(1) or "").strip()
            method_args = re.sub(r"\s+", " ", str(method_match.group(2) or "").strip())
            if method_name:
                if method_args:
                    schedule_parts.append(f"{method_name}({method_args})")
                else:
                    schedule_parts.append(f"{method_name}()")
        schedule = ".".join(schedule_parts)
        line_no = source.count("\n", 0, match.start()) + 1
        key = f"{rel}:{line_no}:{handler_name}:{schedule}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "go_cron_job",
                "name": handler_name,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
                "schedule": schedule,
            }
        )
    for match in GO_GOCRON_CRON_DO_RE.finditer(source):
        if not _js_offset_is_code(source, match.start()):
            continue
        schedule = str(match.group(2) or "").strip()
        handler_name = str(match.group(3) or "").strip()
        if not schedule or not handler_name:
            continue
        line_no = source.count("\n", 0, match.start()) + 1
        key = f"{rel}:{line_no}:{handler_name}:{schedule}"
        if key in seen:
            continue
        seen.add(key)
        entrypoints.append(
            {
                "kind": "go_cron_job",
                "name": handler_name,
                "file": rel,
                "line": line_no,
                "evidence": make_evidence(rel, line_no),
                "schedule": schedule,
            }
        )
    return entrypoints


def _parse_spring_mapping(annotation: str, args_text: str, string_bindings: Optional[dict[str, str]] = None) -> dict[str, Any]:
    normalized = str(annotation or "").strip().lower()
    method_map = {
        "getmapping": ["GET"],
        "postmapping": ["POST"],
        "putmapping": ["PUT"],
        "deletemapping": ["DELETE"],
        "patchmapping": ["PATCH"],
        "requestmapping": map_request_mapping_methods(args_text),
    }
    methods = method_map.get(normalized, ["GET"])
    route = ""
    expr_match = JAVA_MAPPING_PATH_EXPR_RE.search(args_text)
    if expr_match:
        route = _resolve_java_string_expression(expr_match.group(1), string_bindings or {})
    if not route:
        path_match = JAVA_MAPPING_PATH_RE.search(args_text)
        if path_match:
            route = str(path_match.group(1)).strip()
    if not route:
        first_expr = JAVA_MAPPING_FIRST_EXPR_RE.search(args_text)
        if first_expr:
            route = _resolve_java_string_expression(first_expr.group(1), string_bindings or {})
    if not route:
        first = JAVA_MAPPING_FIRST_STR_RE.search(args_text)
        route = str(first.group(1)).strip() if first else ""
    return {"annotation": normalized, "methods": methods, "route": route}


def _resolve_java_annotation_route(args_text: str, string_bindings: Optional[dict[str, str]] = None) -> str:
    bindings = string_bindings or {}
    named, positional = _parse_java_annotation_arguments(args_text)
    candidates: list[str] = []
    for key in ["path", "value", "uri"]:
        if key in named:
            candidates.extend(_resolve_java_string_expression_list(named[key], bindings))
    if not candidates:
        for value in positional:
            candidates.extend(_resolve_java_string_expression_list(value, bindings))
    for value in candidates:
        resolved = str(value or "").strip()
        if resolved:
            return resolved
    return ""


def _extract_quarkus_jaxrs_endpoints(rel: str, lines: list[str]) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    class_stack: list[dict[str, Any]] = []
    pending_annotations: list[dict[str, Any]] = []
    brace_depth = 0
    string_bindings = _extract_java_string_bindings(lines)

    for i, line in _combine_multiline_annotation_lines(lines):
        stripped = line.strip()
        if not stripped or stripped.startswith("//"):
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        path_match = JAVA_JAXRS_PATH_ANNOTATION_RE.match(stripped)
        if path_match:
            pending_annotations.append(
                {
                    "kind": "path",
                    "route": _resolve_java_annotation_route(path_match.group(1) or "", string_bindings),
                    "line": i,
                }
            )
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        http_match = JAVA_JAXRS_HTTP_ANNOTATION_RE.match(stripped)
        if http_match:
            pending_annotations.append(
                {
                    "kind": "method",
                    "methods": [str(http_match.group(1) or "").strip().upper()],
                    "line": i,
                }
            )
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        java_type = JAVA_TYPE_DECL_RE.search(stripped)
        java_method = JAVA_METHOD_DECL_RE.match(stripped)
        if java_type:
            base_route = ""
            for annotation in pending_annotations:
                if str(annotation.get("kind", "")).strip() == "path":
                    base_route = _join_route_paths(base_route, str(annotation.get("route", "")).strip())
            class_stack.append({"depth": brace_depth, "base_route": base_route})
            pending_annotations = []
        elif java_method:
            base_route = str(class_stack[-1].get("base_route", "")).strip() if class_stack else ""
            child_route = ""
            methods: list[str] = []
            source_line = i
            for annotation in pending_annotations:
                kind = str(annotation.get("kind", "")).strip()
                source_line = min(source_line, int(annotation.get("line", i) or i))
                if kind == "path":
                    child_route = _join_route_paths(child_route, str(annotation.get("route", "")).strip())
                elif kind == "method":
                    methods.extend([str(item).upper() for item in annotation.get("methods", []) if str(item).strip()])
            if methods:
                route = _join_route_paths(base_route, child_route)
                for method in methods:
                    key = f"{rel}:{source_line}:{method}:{route}"
                    if key in seen:
                        continue
                    seen.add(key)
                    endpoints.append(
                        {
                            "method": method,
                            "route": route or "/",
                            "framework": "quarkus_jaxrs",
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )
            pending_annotations = []
        elif pending_annotations and not stripped.startswith("@"):
            pending_annotations = []

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
            class_stack.pop()

    return endpoints


def _extract_micronaut_endpoints(rel: str, lines: list[str]) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    class_stack: list[dict[str, Any]] = []
    pending_annotations: list[dict[str, Any]] = []
    brace_depth = 0
    string_bindings = _extract_java_string_bindings(lines)
    method_map = {
        "get": "GET",
        "post": "POST",
        "put": "PUT",
        "delete": "DELETE",
        "patch": "PATCH",
        "head": "HEAD",
        "options": "OPTIONS",
    }

    for i, line in _combine_multiline_annotation_lines(lines):
        stripped = line.strip()
        if not stripped or stripped.startswith("//"):
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        controller_match = JAVA_MICRONAUT_CONTROLLER_ANNOTATION_RE.match(stripped)
        if controller_match:
            pending_annotations.append(
                {
                    "kind": "controller",
                    "route": _resolve_java_annotation_route(controller_match.group(1) or "", string_bindings),
                    "line": i,
                }
            )
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        mapping_match = JAVA_MICRONAUT_MAPPING_RE.match(stripped)
        if mapping_match:
            annotation = str(mapping_match.group(1) or "").strip().lower()
            pending_annotations.append(
                {
                    "kind": "method",
                    "methods": [method_map.get(annotation, "GET")],
                    "route": _resolve_java_annotation_route(mapping_match.group(2) or "", string_bindings),
                    "line": i,
                }
            )
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        java_type = JAVA_TYPE_DECL_RE.search(stripped)
        java_method = JAVA_METHOD_DECL_RE.match(stripped)
        if java_type:
            base_route = ""
            for annotation in pending_annotations:
                if str(annotation.get("kind", "")).strip() == "controller":
                    base_route = _join_route_paths(base_route, str(annotation.get("route", "")).strip())
            class_stack.append({"depth": brace_depth, "base_route": base_route})
            pending_annotations = []
        elif java_method:
            base_route = str(class_stack[-1].get("base_route", "")).strip() if class_stack else ""
            for annotation in pending_annotations:
                if str(annotation.get("kind", "")).strip() != "method":
                    continue
                source_line = int(annotation.get("line", i) or i)
                route = _join_route_paths(base_route, str(annotation.get("route", "")).strip())
                for method in annotation.get("methods", ["GET"]):
                    method_name = str(method).upper()
                    key = f"{rel}:{source_line}:{method_name}:{route}"
                    if key in seen:
                        continue
                    seen.add(key)
                    endpoints.append(
                        {
                            "method": method_name,
                            "route": route or "/",
                            "framework": "micronaut_controller",
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )
            pending_annotations = []
        elif pending_annotations and not stripped.startswith("@"):
            pending_annotations = []

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
            class_stack.pop()

    return endpoints

def _extract_spring_endpoints(rel: str, lines: list[str]) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    class_stack: list[dict[str, Any]] = []
    pending_mappings: list[dict[str, Any]] = []
    brace_depth = 0
    string_bindings = _extract_java_string_bindings(lines)

    for i, line in _combine_multiline_annotation_lines(lines):
        stripped = line.strip()
        if not stripped or stripped.startswith("//"):
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        matches = list(JAVA_MAPPING_RE.finditer(line))
        if matches:
            for match in matches:
                parsed = _parse_spring_mapping(match.group(1), match.group(2) or "", string_bindings=string_bindings)
                parsed["line"] = i
                pending_mappings.append(parsed)
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
                class_stack.pop()
            continue

        java_type = JAVA_TYPE_DECL_RE.search(stripped)
        java_method = JAVA_METHOD_DECL_RE.match(stripped)
        if java_type:
            base_route = ""
            for mapping in pending_mappings:
                if str(mapping.get("annotation", "")).strip() == "requestmapping":
                    base_route = _join_route_paths(base_route, str(mapping.get("route", "")).strip())
            class_stack.append({"depth": brace_depth, "base_route": base_route})
            pending_mappings = []
        elif java_method:
            base_route = str(class_stack[-1].get("base_route", "")).strip() if class_stack else ""
            for mapping in pending_mappings:
                route = _join_route_paths(base_route, str(mapping.get("route", "")).strip())
                source_line = int(mapping.get("line", i) or i)
                for method in mapping.get("methods", ["GET"]):
                    key = f"{rel}:{source_line}:{method}:{route}"
                    if key in seen:
                        continue
                    seen.add(key)
                    endpoints.append(
                        {
                            "method": str(method).upper(),
                            "route": route or "/",
                            "framework": "spring_mapping",
                            "file": rel,
                            "line": source_line,
                            "evidence": make_evidence(rel, source_line),
                        }
                    )
            pending_mappings = []
        elif pending_mappings and not stripped.startswith("@"):
            pending_mappings = []

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while class_stack and brace_depth <= int(class_stack[-1].get("depth", 0)):
            class_stack.pop()

    return endpoints


def _extract_ktor_endpoints(rel: str, text: str, lines: list[str]) -> list[dict[str, Any]]:
    endpoints: list[dict[str, Any]] = []
    seen: set[str] = set()
    brace_depth = 0
    routing_stack: list[dict[str, Any]] = []
    route_stack: list[dict[str, Any]] = []
    string_bindings = _extract_kotlin_string_bindings(lines)
    masked_lines = _mask_js_comments(text).splitlines()
    triple_quote_lines = _kotlin_triple_quote_line_numbers(lines)

    for index, masked_line in enumerate(masked_lines, start=1):
        raw_line = str(lines[index - 1] or "")
        stripped = str(masked_line or "").strip()
        if index in triple_quote_lines or not stripped:
            brace_depth = max(0, brace_depth + _brace_delta(raw_line))
            while route_stack and brace_depth <= int(route_stack[-1].get("depth", 0)):
                route_stack.pop()
            while routing_stack and brace_depth <= int(routing_stack[-1].get("depth", 0)):
                routing_stack.pop()
            continue

        if KTOR_ROUTING_BLOCK_RE.match(stripped):
            routing_stack.append({"depth": brace_depth})
        else:
            route_match = KTOR_ROUTE_BLOCK_RE.match(stripped)
            if route_match and routing_stack:
                route_stack.append(
                    {
                        "depth": brace_depth,
                        "prefix": _resolve_java_string_expression(route_match.group(1) or "", string_bindings),
                    }
                )
            else:
                method_match = KTOR_METHOD_BLOCK_RE.match(stripped)
                if method_match and routing_stack:
                    base_route = ""
                    for item in route_stack:
                        base_route = _join_route_paths(base_route, str(item.get("prefix", "")).strip())
                    child_route = _resolve_java_string_expression(method_match.group(2) or "", string_bindings)
                    route = _join_route_paths(base_route, child_route)
                    method = str(method_match.group(1) or "").upper()
                    key = f"{rel}:{index}:{method}:{route}"
                    if key not in seen:
                        seen.add(key)
                        endpoints.append(
                            {
                                "method": method,
                                "route": route or "/",
                                "framework": "ktor_route",
                                "file": rel,
                                "line": index,
                                "evidence": make_evidence(rel, index),
                            }
                        )

        brace_depth = max(0, brace_depth + _brace_delta(raw_line))
        while route_stack and brace_depth <= int(route_stack[-1].get("depth", 0)):
            route_stack.pop()
        while routing_stack and brace_depth <= int(routing_stack[-1].get("depth", 0)):
            routing_stack.pop()

    return endpoints

def _extract_module_resolution_hints(rel: str, text: str, lines: list[str]) -> list[dict[str, Any]]:
    basename = os.path.basename(str(rel or "")).lower()
    if basename not in {"tsconfig.json", "jsconfig.json"}:
        return []
    try:
        data = json.loads(text)
    except Exception:
        return []
    if not isinstance(data, dict):
        return []

    compiler_options = data.get("compilerOptions", {})
    if not isinstance(compiler_options, dict):
        compiler_options = {}

    hints: list[dict[str, Any]] = []
    seen: set[str] = set()
    base_url = str(compiler_options.get("baseUrl", ".")).strip() or "."
    base_url_line = find_line_containing(lines, "\"baseUrl\"", default=1)
    base_url_hint = {
        "kind": "js_base_url",
        "base_url": base_url,
        "file": rel,
        "line": base_url_line,
        "evidence": make_evidence(rel, base_url_line),
    }
    key = json.dumps(base_url_hint, sort_keys=True, ensure_ascii=True)
    seen.add(key)
    hints.append(base_url_hint)

    raw_paths = compiler_options.get("paths", {})
    if not isinstance(raw_paths, dict):
        raw_paths = {}
    for alias, targets in raw_paths.items():
        alias_name = str(alias or "").strip()
        if not alias_name:
            continue
        alias_line = find_line_containing(lines, f"\"{alias_name}\"", default=base_url_line)
        target_values = targets if isinstance(targets, list) else [targets]
        for target in target_values:
            target_name = str(target or "").strip()
            if not target_name:
                continue
            hint = {
                "kind": "js_path_alias",
                "alias": alias_name,
                "target": target_name,
                "base_url": base_url,
                "file": rel,
                "line": alias_line,
                "evidence": make_evidence(rel, alias_line),
            }
            hint_key = json.dumps(hint, sort_keys=True, ensure_ascii=True)
            if hint_key in seen:
                continue
            seen.add(hint_key)
            hints.append(hint)
    return hints

def _brace_delta(line: str) -> int:
    return line.count("{") - line.count("}")

def _push_language_symbol(
    items: list[dict[str, Any]],
    seen: set[str],
    *,
    language: str,
    kind: str,
    name: str,
    module: str,
    file: str,
    line: int,
    container: str = "",
) -> None:
    symbol_name = str(name or "").strip()
    if not symbol_name:
        return
    container_name = str(container or "").strip()
    qualname = f"{container_name}.{symbol_name}" if container_name else symbol_name
    key = f"{language}:{file}:{line}:{kind}:{qualname}"
    if key in seen:
        return
    seen.add(key)
    items.append(
        {
            "language": language,
            "kind": kind,
            "name": symbol_name,
            "qualname": qualname,
            "container": container_name,
            "module": module,
            "file": file,
            "line": line,
            "evidence": make_evidence(file, line),
        }
    )

def _push_language_call(
    items: list[dict[str, Any]],
    seen: set[str],
    *,
    language: str,
    caller: str,
    callee: str,
    module: str,
    file: str,
    line: int,
) -> None:
    caller_name = str(caller or "").strip() or module
    callee_name = str(callee or "").strip().strip(":.")
    if not callee_name:
        return
    short = callee_name.rsplit(".", 1)[-1].rsplit("::", 1)[-1]
    if short.lower() in CALL_NAME_STOPWORDS:
        return
    key = f"{language}:{file}:{line}:{caller_name}:{callee_name}"
    if key in seen:
        return
    seen.add(key)
    items.append(
        {
            "language": language,
            "caller": caller_name,
            "callee": callee_name,
            "module": module,
            "file": file,
            "line": line,
            "evidence": make_evidence(file, line),
        }
    )

def _extract_regex_language_structure(rel: str, text: str, language: str) -> dict[str, list[dict[str, Any]]]:
    supported = {"javascript", "typescript", "go", "java", "kotlin", "csharp", "php", "ruby", "swift"}
    if language not in supported:
        return {"symbols": [], "calls": []}

    lines = text.splitlines()
    module = _module_name_from_language_source(rel, lines, language)
    symbols: list[dict[str, Any]] = []
    calls: list[dict[str, Any]] = []
    seen_symbols: set[str] = set()
    seen_calls: set[str] = set()

    if language == "ruby":
        stack: list[dict[str, Any]] = []
        for i, line in enumerate(lines, start=1):
            stripped = line.strip()
            if not stripped or stripped.startswith("#"):
                continue
            if stripped == "end":
                if stack:
                    stack.pop()
                continue

            container = ".".join([str(item.get("name", "")).strip() for item in stack if str(item.get("name", "")).strip()])
            ruby_class = RUBY_CLASS_DECL_RE.match(stripped)
            ruby_module = RUBY_MODULE_DECL_RE.match(stripped)
            ruby_def = RUBY_DEF_DECL_RE.match(stripped)
            if ruby_class:
                name = ruby_class.group(1).split("::")[-1]
                _push_language_symbol(
                    symbols,
                    seen_symbols,
                    language=language,
                    kind="class",
                    name=name,
                    module=module,
                    file=rel,
                    line=i,
                    container=container,
                )
                stack.append({"name": name, "kind": "class"})
            elif ruby_module:
                name = ruby_module.group(1).split("::")[-1]
                _push_language_symbol(
                    symbols,
                    seen_symbols,
                    language=language,
                    kind="module",
                    name=name,
                    module=module,
                    file=rel,
                    line=i,
                    container=container,
                )
                stack.append({"name": name, "kind": "module"})
            elif ruby_def:
                name = ruby_def.group(1)
                _push_language_symbol(
                    symbols,
                    seen_symbols,
                    language=language,
                    kind="method",
                    name=name,
                    module=module,
                    file=rel,
                    line=i,
                    container=container,
                )
                stack.append({"name": name, "kind": "method"})

            caller = ".".join([str(item.get("name", "")).strip() for item in stack if str(item.get("name", "")).strip()]) or module
            for match in GENERIC_CALL_RE.finditer(line):
                callee = match.group(1)
                if callee in {"def", "class", "module"}:
                    continue
                _push_language_call(
                    calls,
                    seen_calls,
                    language=language,
                    caller=caller,
                    callee=callee,
                    module=module,
                    file=rel,
                    line=i,
                )
        return {"symbols": symbols, "calls": calls}

    stack: list[dict[str, Any]] = []
    brace_depth = 0
    for i, line in enumerate(lines, start=1):
        stripped = line.strip()
        if not stripped or stripped.startswith(("//", "#")):
            brace_depth = max(0, brace_depth + _brace_delta(line))
            while stack and brace_depth <= int(stack[-1].get("depth", 0)):
                stack.pop()
            continue

        container = ".".join([str(item.get("name", "")).strip() for item in stack if str(item.get("name", "")).strip()])
        declared_names: set[str] = set()

        if language in {"javascript", "typescript"}:
            js_class = JS_CLASS_RE.match(stripped)
            js_func = JS_FUNCTION_DECL_RE.match(stripped)
            js_arrow = JS_ARROW_FUNC_RE.match(stripped)
            js_method = JS_METHOD_DECL_RE.match(stripped)
            if js_class:
                name = js_class.group(1)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind="class", name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": "class"})
            elif js_func:
                name = js_func.group(1)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind="function", name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": "function"})
            elif js_arrow:
                name = js_arrow.group(1)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind="function", name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": "function"})
            elif js_method and stack and str(stack[-1].get("kind", "")).strip() == "class":
                name = js_method.group(1)
                if name not in {"if", "for", "while", "switch", "catch", "constructor"}:
                    declared_names.add(name)
                    _push_language_symbol(symbols, seen_symbols, language=language, kind="method", name=name, module=module, file=rel, line=i, container=container)
                    stack.append({"name": name, "depth": brace_depth, "kind": "method"})
        elif language == "go":
            go_func = GO_FUNC_DECL_RE.match(stripped)
            if go_func:
                name = go_func.group(1)
                declared_names.add(name)
                kind = "function" if name != "main" else "entrypoint"
                _push_language_symbol(symbols, seen_symbols, language=language, kind=kind, name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": kind})
        elif language in {"java", "kotlin"}:
            java_type = JAVA_TYPE_DECL_RE.search(stripped)
            java_method = JAVA_METHOD_DECL_RE.match(stripped)
            if java_type:
                kind = java_type.group(1).lower()
                name = java_type.group(2)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind=kind, name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": kind})
            elif java_method:
                name = java_method.group(1)
                if name not in {"if", "for", "while", "switch", "catch"}:
                    declared_names.add(name)
                    _push_language_symbol(symbols, seen_symbols, language=language, kind="method", name=name, module=module, file=rel, line=i, container=container)
                    stack.append({"name": name, "depth": brace_depth, "kind": "method"})
        elif language == "csharp":
            cs_type = CS_TYPE_DECL_RE.search(stripped)
            cs_method = CS_METHOD_DECL_RE.match(stripped)
            if cs_type:
                kind = cs_type.group(1).lower()
                name = cs_type.group(2)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind=kind, name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": kind})
            elif cs_method:
                name = cs_method.group(1)
                if name not in {"if", "for", "while", "switch", "catch"}:
                    declared_names.add(name)
                    _push_language_symbol(symbols, seen_symbols, language=language, kind="method", name=name, module=module, file=rel, line=i, container=container)
                    stack.append({"name": name, "depth": brace_depth, "kind": "method"})
        elif language == "php":
            php_class = PHP_CLASS_DECL_RE.match(stripped)
            php_func = PHP_FUNCTION_DECL_RE.match(stripped)
            if php_class:
                name = php_class.group(1)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind="class", name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": "class"})
            elif php_func:
                name = php_func.group(1)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind="method", name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": "method"})
        elif language == "swift":
            swift_type = SWIFT_TYPE_DECL_RE.match(stripped)
            swift_func = SWIFT_FUNC_DECL_RE.match(stripped)
            if swift_type:
                kind = swift_type.group(1).lower()
                name = swift_type.group(2)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind=kind, name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": kind})
            elif swift_func:
                name = swift_func.group(1)
                declared_names.add(name)
                _push_language_symbol(symbols, seen_symbols, language=language, kind="method", name=name, module=module, file=rel, line=i, container=container)
                stack.append({"name": name, "depth": brace_depth, "kind": "method"})

        caller = ".".join([str(item.get("name", "")).strip() for item in stack if str(item.get("name", "")).strip()]) or module
        if not declared_names and not stripped.startswith("@") and not stripped.startswith("["):
            for match in GENERIC_CALL_RE.finditer(line):
                callee = match.group(1)
                short = callee.rsplit(".", 1)[-1].rsplit("::", 1)[-1]
                if short in declared_names:
                    continue
                _push_language_call(
                    calls,
                    seen_calls,
                    language=language,
                    caller=caller,
                    callee=callee,
                    module=module,
                    file=rel,
                    line=i,
                )

        brace_depth = max(0, brace_depth + _brace_delta(line))
        while stack and brace_depth <= int(stack[-1].get("depth", 0)):
            stack.pop()

    return {"symbols": symbols, "calls": calls}

def derive_subsystem_name(path: str) -> str:
    p = str(path or "").replace("\\", "/").strip("/")
    if not p:
        return "root"
    parts = [part for part in p.split("/") if part]
    if len(parts) <= 1:
        return "root"
    head = parts[0].lower()
    if head in {"tests", "test"}:
        return "tests"
    if head in GENERIC_SUBSYSTEM_ROOTS and len(parts) >= 2:
        if len(parts) == 2 and "." in parts[1]:
            return parts[0]
        return "/".join(parts[:2])
    return parts[0]

def _push_unique(store: list[dict], seen: set[str], key: str, item: dict) -> None:
    if key in seen:
        return
    seen.add(key)
    store.append(item)

