def _merge_presence_flags(dst: dict[str, bool], src: dict[str, bool]) -> None:
    for key, value in src.items():
        if value:
            dst[key] = True

def _append_unique_items(dst: list[dict], src: list[dict], seen: set[str]) -> None:
    for item in src:
        key = json.dumps(item, sort_keys=True, ensure_ascii=True)
        if key in seen:
            continue
        seen.add(key)
        dst.append(item)


def _build_local_path_alias_to_file(known_paths: set[str]) -> dict[str, str]:
    alias_to_file: dict[str, str] = {}
    for raw_path in known_paths:
        path = str(raw_path or "").replace("\\", "/").strip("/")
        if not path:
            continue
        stem = os.path.splitext(path)[0]
        aliases = [stem]
        if stem.endswith("/index"):
            aliases.append(stem[: -len("/index")])
        if stem.endswith("/route"):
            aliases.append(stem[: -len("/route")])
        base = os.path.basename(stem)
        if base:
            aliases.append(base)
        for alias in aliases:
            normalized_alias = str(alias or "").replace("\\", "/").strip("/")
            if not normalized_alias or normalized_alias in alias_to_file:
                continue
            alias_to_file[normalized_alias] = path
    return alias_to_file


def _js_router_export_local_receivers(part: dict[str, Any], target_symbol: str) -> Optional[set[str]]:
    target = str(target_symbol or "").strip() or "default"
    if target == "*":
        return set()
    exports = part.get("js_router_exports", [])
    if not isinstance(exports, list) or not exports:
        return None
    matches: set[str] = set()
    for item in exports:
        if not isinstance(item, dict):
            continue
        if str(item.get("export_name", "")).strip() == target:
            local_receiver = str(item.get("local_receiver", "")).strip()
            if local_receiver:
                matches.add(local_receiver)
    return matches


def _effective_js_mount_target_symbol(base_target_symbol: str, child_member_path: str) -> str:
    target_symbol = str(base_target_symbol or "").strip() or "default"
    member_path = str(child_member_path or "").strip()
    if not member_path:
        return target_symbol
    if target_symbol == "*":
        return member_path
    return f"{target_symbol}.{member_path}"


def _apply_cross_file_js_router_mounts(file_parts: list[dict]) -> None:
    path_to_part: dict[str, dict[str, Any]] = {}
    known_paths: set[str] = set()
    module_resolution_hints: list[dict[str, Any]] = []
    for part in file_parts:
        if not isinstance(part, dict):
            continue
        file_info = part.get("file", {})
        if not isinstance(file_info, dict):
            continue
        path = str(file_info.get("path", "")).replace("\\", "/").strip("/")
        if not path:
            continue
        path_to_part[path] = part
        known_paths.add(path)
        for item in part.get("module_resolution_hints", []):
            if isinstance(item, dict):
                module_resolution_hints.append(item)
    if not path_to_part:
        return

    alias_to_file = _build_local_path_alias_to_file(known_paths)
    resolved_imports_by_file: dict[str, dict[str, dict[str, Any]]] = {}
    for path, part in path_to_part.items():
        bindings_by_alias: dict[str, dict[str, Any]] = {}
        for item in part.get("js_import_bindings", []):
            if not isinstance(item, dict):
                continue
            alias = str(item.get("alias", "")).strip()
            target_module = str(item.get("target_module", "")).strip()
            if not alias or not target_module:
                continue
            resolved_file = _resolve_local_architecture_target(
                target_module,
                alias_to_file,
                current_path=path,
                known_paths=known_paths,
                module_resolution_hints=module_resolution_hints,
            )
            if not resolved_file:
                continue
            enriched = dict(item)
            enriched["resolved_file"] = resolved_file
            bindings_by_alias[alias] = enriched
        resolved_imports_by_file[path] = bindings_by_alias

    max_rounds = max(1, len(path_to_part) + 1)
    for _ in range(max_rounds):
        changed = False
        for path, part in path_to_part.items():
            mounts = part.get("js_router_mounts", [])
            imports_by_alias = resolved_imports_by_file.get(path, {})
            if not isinstance(mounts, list) or not mounts:
                continue
            endpoints = part.setdefault("api_endpoints", [])
            seen_endpoint_keys = {
                (
                    str(item.get("method", "")).upper().strip(),
                    str(item.get("route", "")).strip(),
                    str(item.get("framework", "")).strip(),
                    str(item.get("file", "")).replace("\\", "/").strip(),
                    int(item.get("line", 0) or 0),
                    str(item.get("source_file", item.get("file", ""))).replace("\\", "/").strip(),
                    int(item.get("source_line", item.get("line", 0)) or 0),
                )
                for item in endpoints
                if isinstance(item, dict)
            }
            for mount in mounts:
                if not isinstance(mount, dict):
                    continue
                child_module = str(mount.get("child_module", "")).strip()
                child_alias = str(mount.get("child", "")).strip()
                base_target_symbol = "*"
                child_file = ""
                if child_module:
                    child_file = _resolve_local_architecture_target(
                        child_module,
                        alias_to_file,
                        current_path=path,
                        known_paths=known_paths,
                        module_resolution_hints=module_resolution_hints,
                    )
                else:
                    binding = imports_by_alias.get(child_alias)
                    if not binding:
                        continue
                    child_file = str(binding.get("resolved_file", "")).replace("\\", "/").strip("/")
                    base_target_symbol = str(binding.get("target_symbol", "")).strip() or "default"
                child_part = path_to_part.get(child_file)
                if child_part is None or child_part is part:
                    continue
                target_symbol = _effective_js_mount_target_symbol(
                    base_target_symbol,
                    str(mount.get("child_member_path", "")).strip(),
                )
                matching_receivers = _js_router_export_local_receivers(child_part, target_symbol)
                if matching_receivers == set():
                    continue
                mount_prefix = str(mount.get("prefix", "")).strip()
                mount_line = int(mount.get("line", 1) or 1)
                mount_evidence = str(mount.get("evidence", "")).strip() or make_evidence(path, mount_line)
                for endpoint in child_part.get("api_endpoints", []):
                    if not isinstance(endpoint, dict):
                        continue
                    endpoint_receiver = str(endpoint.get("receiver", "")).strip()
                    if matching_receivers is not None and endpoint_receiver not in matching_receivers:
                        continue
                    method = str(endpoint.get("method", "")).upper().strip()
                    if method not in HTTP_METHODS:
                        continue
                    composed_route = _compose_route_path(mount_prefix, str(endpoint.get("route", "")).strip())
                    if not composed_route:
                        continue
                    depth = int(endpoint.get("mount_chain_depth", 0) or 0)
                    if depth >= 8:
                        continue
                    source_file = str(endpoint.get("source_file", endpoint.get("file", child_file))).replace("\\", "/").strip()
                    source_line = int(endpoint.get("source_line", endpoint.get("line", 1)) or 1)
                    source_evidence = str(endpoint.get("source_evidence", endpoint.get("evidence", ""))).strip()
                    framework = str(endpoint.get("framework", "node_route")).strip() or "node_route"
                    dedupe_key = (
                        method,
                        composed_route,
                        framework,
                        path,
                        mount_line,
                        source_file,
                        source_line,
                    )
                    if dedupe_key in seen_endpoint_keys:
                        continue
                    seen_endpoint_keys.add(dedupe_key)
                    endpoints.append(
                        {
                            "method": method,
                            "route": composed_route,
                            "framework": framework,
                            "file": path,
                            "line": mount_line,
                            "evidence": mount_evidence,
                            "source_file": source_file,
                            "source_line": source_line,
                            "source_evidence": source_evidence,
                            "imported_from": child_file,
                            "route_resolution": "cross_file_import_mount",
                            "mount_file": path,
                            "mount_line": mount_line,
                            "mount_evidence": mount_evidence,
                            "mount_chain_depth": depth + 1,
                            **({"receiver": endpoint_receiver} if endpoint_receiver else {}),
                        }
                    )
                    changed = True
        if not changed:
            break


def _apply_cross_file_python_drf_router_mounts(file_parts: list[dict]) -> None:
    path_to_part: dict[str, dict[str, Any]] = {}
    known_paths: set[str] = set()
    module_resolution_hints: list[dict[str, Any]] = []
    for part in file_parts:
        if not isinstance(part, dict):
            continue
        file_info = part.get("file", {})
        if not isinstance(file_info, dict):
            continue
        path = str(file_info.get("path", "")).replace("\\", "/").strip("/")
        if not path:
            continue
        path_to_part[path] = part
        known_paths.add(path)
        for item in part.get("module_resolution_hints", []):
            if isinstance(item, dict):
                module_resolution_hints.append(item)
    if not path_to_part:
        return

    alias_to_file: dict[str, str] = {}
    for path in known_paths:
        for alias in _file_aliases_for_architecture(path):
            alias_to_file.setdefault(alias, path)

    bindings_by_file: dict[str, list[dict[str, Any]]] = {}
    for path, part in path_to_part.items():
        for item in part.get("python_import_aliases", []):
            if not isinstance(item, dict):
                continue
            alias = str(item.get("alias", "")).strip()
            target_module = str(item.get("target_module", "")).strip()
            if not alias or not target_module:
                continue
            target_path = _resolve_local_architecture_target(
                target_module,
                alias_to_file,
                current_path=path,
                known_paths=known_paths,
                module_resolution_hints=module_resolution_hints,
            )
            if not target_path:
                continue
            bindings_by_file.setdefault(path, []).append(
                {
                    "alias": alias,
                    "target_module": target_module,
                    "target_symbol": str(item.get("target_symbol", "")).strip(),
                    "target_path": target_path,
                    "evidence": str(item.get("evidence", "")).strip(),
                }
            )

    viewset_symbols_by_file: dict[str, list[dict[str, Any]]] = {}
    for path, part in path_to_part.items():
        records = [
            item
            for item in part.get("python_symbols", [])
            if isinstance(item, dict) and bool(item.get("drf_viewset", False))
        ]
        if records:
            viewset_symbols_by_file[path] = records

    def _symbol_terms(item: dict[str, Any]) -> set[str]:
        out: set[str] = set()
        for value in [
            str(item.get("name", "")).strip(),
            str(item.get("qualname", "")).strip(),
        ]:
            if not value:
                continue
            out.add(value)
            short = _symbol_graph_short_name(value)
            if short:
                out.add(short)
        return out

    def _pick_viewset_symbol(path: str, terms: list[str]) -> Optional[dict[str, Any]]:
        normalized_terms = [str(term or "").strip().strip(":.") for term in terms if str(term or "").strip()]
        if not normalized_terms:
            return None
        candidates = viewset_symbols_by_file.get(path, [])
        for symbol in candidates:
            candidate_terms = _symbol_terms(symbol)
            if any(
                term in candidate_terms
                or any(candidate.endswith(f".{term}") for candidate in candidate_terms)
                or any(term.endswith(f".{candidate}") for candidate in candidate_terms)
                for term in normalized_terms
            ):
                return symbol
        return None

    def _resolve_viewset_symbol(source_path: str, viewset_ref: str) -> Optional[dict[str, Any]]:
        normalized_ref = str(viewset_ref or "").strip()
        if not normalized_ref:
            return None
        local = _pick_viewset_symbol(source_path, [normalized_ref, _symbol_graph_short_name(normalized_ref)])
        if local is not None:
            return local

        for binding in sorted(
            bindings_by_file.get(source_path, []),
            key=lambda item: (-len(str(item.get("alias", ""))), str(item.get("alias", ""))),
        ):
            alias = str(binding.get("alias", "")).strip()
            if normalized_ref != alias and not normalized_ref.startswith(f"{alias}."):
                continue
            target_path = str(binding.get("target_path", "")).replace("\\", "/").strip("/")
            if not target_path:
                continue
            remainder = normalized_ref[len(alias):].lstrip(".")
            target_symbol = str(binding.get("target_symbol", "")).strip()
            candidate_terms: list[str] = []
            if target_symbol:
                candidate_terms.append(target_symbol)
            if remainder:
                candidate_terms.append(remainder)
                if target_symbol:
                    candidate_terms.append(f"{target_symbol}.{remainder}")
            else:
                candidate_terms.append(alias)
            match = _pick_viewset_symbol(target_path, candidate_terms)
            if match is not None:
                return match

        short = _symbol_graph_short_name(normalized_ref)
        if short:
            matches = [
                symbol
                for path, symbols in viewset_symbols_by_file.items()
                if path != source_path
                for symbol in symbols
                if short in _symbol_terms(symbol)
            ]
            if len(matches) == 1:
                return matches[0]
        return None

    for path, part in path_to_part.items():
        module_state = part.get("python_module_state", [])
        if not isinstance(module_state, list) or not module_state:
            continue
        registrations = [
            item
            for item in module_state
            if isinstance(item, dict) and str(item.get("kind", "")).strip() == "drf_router_registration"
        ]
        if not registrations:
            continue
        mounts_by_router: dict[str, list[dict[str, Any]]] = {}
        for item in module_state:
            if not isinstance(item, dict) or str(item.get("kind", "")).strip() != "drf_router_mount":
                continue
            router_name = str(item.get("router", item.get("name", ""))).strip()
            if not router_name:
                continue
            mounts_by_router.setdefault(router_name, []).append(item)

        endpoints = part.setdefault("api_endpoints", [])
        seen_endpoint_keys = {
            (
                str(item.get("method", "")).upper().strip(),
                str(item.get("route", "")).strip(),
                str(item.get("framework", "")).strip(),
                str(item.get("file", "")).replace("\\", "/").strip(),
                int(item.get("line", 0) or 0),
                str(item.get("source_file", item.get("file", ""))).replace("\\", "/").strip(),
                int(item.get("source_line", item.get("line", 0)) or 0),
            )
            for item in endpoints
            if isinstance(item, dict)
        }

        for registration in registrations:
            router_name = str(registration.get("router", registration.get("name", ""))).strip()
            base_route = str(registration.get("route", "")).strip() or "/"
            viewset_symbol = _resolve_viewset_symbol(path, str(registration.get("viewset", "")).strip())
            if viewset_symbol is None:
                continue
            source_file = str(viewset_symbol.get("file", path)).replace("\\", "/").strip("/") or path
            source_line = int(viewset_symbol.get("line", 1) or 1)
            source_evidence = str(viewset_symbol.get("evidence", "")).strip() or make_evidence(source_file, source_line)
            standard_actions = [
                str(item).strip()
                for item in viewset_symbol.get("drf_actions", [])
                if str(item).strip() in DRF_STANDARD_ACTION_ROUTE_MAP
            ]
            custom_actions = [
                item
                for item in viewset_symbol.get("drf_custom_actions", [])
                if isinstance(item, dict)
            ]
            mount_items = mounts_by_router.get(router_name) or [registration]
            registration_line = int(registration.get("line", 1) or 1)
            registration_evidence = str(registration.get("evidence", "")).strip() or make_evidence(path, registration_line)

            for mount in mount_items:
                mount_prefix = str(mount.get("route", "")).strip() or "/"
                collection_route = _compose_route_path(mount_prefix, base_route)
                detail_route = _compose_route_path(collection_route, "{pk}")
                mount_line = int(mount.get("line", registration_line) or registration_line)
                mount_evidence = str(mount.get("evidence", "")).strip() or registration_evidence

                for action_name in standard_actions:
                    for method, scope in DRF_STANDARD_ACTION_ROUTE_MAP.get(action_name, []):
                        resolved_route = collection_route if scope == "collection" else detail_route
                        dedupe_key = (
                            method,
                            resolved_route,
                            "django_rest_framework_router",
                            path,
                            mount_line,
                            source_file,
                            source_line,
                        )
                        if dedupe_key in seen_endpoint_keys:
                            continue
                        seen_endpoint_keys.add(dedupe_key)
                        endpoints.append(
                            {
                                "method": method,
                                "route": resolved_route,
                                "framework": "django_rest_framework_router",
                                "file": path,
                                "line": mount_line,
                                "evidence": mount_evidence,
                                "source_file": source_file,
                                "source_line": source_line,
                                "source_evidence": source_evidence,
                                "route_resolution": "drf_router_registration",
                                "router": router_name,
                                "viewset": str(viewset_symbol.get("qualname", viewset_symbol.get("name", ""))).strip(),
                            }
                        )

                for custom in custom_actions:
                    custom_route = _compose_route_path(
                        detail_route if bool(custom.get("detail", False)) else collection_route,
                        str(custom.get("url_path", "")).strip(),
                    )
                    custom_line = int(custom.get("line", source_line) or source_line)
                    for method in [
                        str(item).upper().strip()
                        for item in custom.get("methods", [])
                        if str(item).upper().strip() in HTTP_METHODS
                    ] or ["GET"]:
                        dedupe_key = (
                            method,
                            custom_route,
                            "django_rest_framework_router",
                            path,
                            mount_line,
                            source_file,
                            custom_line,
                        )
                        if dedupe_key in seen_endpoint_keys:
                            continue
                        seen_endpoint_keys.add(dedupe_key)
                        endpoints.append(
                            {
                                "method": method,
                                "route": custom_route,
                                "framework": "django_rest_framework_router",
                                "file": path,
                                "line": mount_line,
                                "evidence": mount_evidence,
                                "source_file": source_file,
                                "source_line": custom_line,
                                "source_evidence": make_evidence(source_file, custom_line),
                                "route_resolution": "drf_router_custom_action",
                                "router": router_name,
                                "viewset": str(viewset_symbol.get("qualname", viewset_symbol.get("name", ""))).strip(),
                            }
                        )


def _apply_cross_file_python_django_url_includes(file_parts: list[dict]) -> None:
    path_to_part: dict[str, dict[str, Any]] = {}
    known_paths: set[str] = set()
    module_resolution_hints: list[dict[str, Any]] = []
    for part in file_parts:
        if not isinstance(part, dict):
            continue
        file_info = part.get("file", {})
        if not isinstance(file_info, dict):
            continue
        path = str(file_info.get("path", "")).replace("\\", "/").strip("/")
        if not path:
            continue
        path_to_part[path] = part
        known_paths.add(path)
        for item in part.get("module_resolution_hints", []):
            if isinstance(item, dict):
                module_resolution_hints.append(item)
    if not path_to_part:
        return

    alias_to_file: dict[str, str] = {}
    for path in known_paths:
        for alias in _file_aliases_for_architecture(path):
            alias_to_file.setdefault(alias, path)

    included_child_files: set[str] = set()
    max_rounds = max(1, len(path_to_part) + 1)
    for _ in range(max_rounds):
        changed = False
        for path, part in path_to_part.items():
            module_state = part.get("python_module_state", [])
            if not isinstance(module_state, list) or not module_state:
                continue
            include_mounts = [
                item
                for item in module_state
                if isinstance(item, dict) and str(item.get("kind", "")).strip() == "django_url_include_mount"
            ]
            if not include_mounts:
                continue
            endpoints = part.setdefault("api_endpoints", [])
            seen_endpoint_keys = {
                (
                    str(item.get("method", "")).upper().strip(),
                    str(item.get("route", "")).strip(),
                    str(item.get("framework", "")).strip(),
                    str(item.get("file", "")).replace("\\", "/").strip(),
                    int(item.get("line", 0) or 0),
                    str(item.get("source_file", item.get("file", ""))).replace("\\", "/").strip(),
                    int(item.get("source_line", item.get("line", 0)) or 0),
                )
                for item in endpoints
                if isinstance(item, dict)
            }
            for mount in include_mounts:
                target_module = str(mount.get("target_module", mount.get("name", ""))).strip()
                if not target_module:
                    continue
                child_file = _resolve_local_architecture_target(
                    target_module,
                    alias_to_file,
                    current_path=path,
                    known_paths=known_paths,
                    module_resolution_hints=module_resolution_hints,
                )
                child_part = path_to_part.get(child_file)
                if child_part is None or child_part is part:
                    continue
                included_child_files.add(child_file)
                mount_prefix = str(mount.get("route", "")).strip() or "/"
                mount_line = int(mount.get("line", 1) or 1)
                mount_evidence = str(mount.get("evidence", "")).strip() or make_evidence(path, mount_line)
                for endpoint in child_part.get("api_endpoints", []):
                    if not isinstance(endpoint, dict):
                        continue
                    method = str(endpoint.get("method", "")).upper().strip()
                    if method not in HTTP_METHODS:
                        continue
                    child_route = str(endpoint.get("route", "")).strip()
                    if not child_route:
                        continue
                    composed_route = _compose_route_path(mount_prefix, child_route)
                    if not composed_route:
                        continue
                    depth = int(endpoint.get("mount_chain_depth", 0) or 0)
                    if depth >= 8:
                        continue
                    framework = str(endpoint.get("framework", "django_urls")).strip() or "django_urls"
                    source_file = ""
                    source_line = 0
                    source_evidence = ""
                    child_source_file = str(endpoint.get("source_file", "")).replace("\\", "/").strip("/")
                    child_file_ref = str(endpoint.get("file", child_file)).replace("\\", "/").strip("/") or child_file
                    if child_source_file and child_source_file != child_file_ref:
                        source_file = child_source_file
                        source_line = int(endpoint.get("source_line", endpoint.get("line", 1)) or 1)
                        source_evidence = str(endpoint.get("source_evidence", endpoint.get("evidence", ""))).strip()
                    dedupe_key = (
                        method,
                        composed_route,
                        framework,
                        path,
                        mount_line,
                        source_file or child_file_ref,
                        source_line or int(endpoint.get("line", 1) or 1),
                    )
                    if dedupe_key in seen_endpoint_keys:
                        continue
                    seen_endpoint_keys.add(dedupe_key)
                    payload = {
                        "method": method,
                        "route": composed_route,
                        "framework": framework,
                        "file": path,
                        "line": mount_line,
                        "evidence": mount_evidence,
                        "imported_from": child_file,
                        "route_resolution": "cross_file_import_mount",
                        "mount_file": path,
                        "mount_line": mount_line,
                        "mount_evidence": mount_evidence,
                        "mount_chain_depth": depth + 1,
                    }
                    if source_file:
                        payload["source_file"] = source_file
                        payload["source_line"] = source_line
                        payload["source_evidence"] = source_evidence or make_evidence(source_file, source_line)
                    for field in ["handler_name", "target_module", "handler_ref", "handler_qualname", "handler_resolution"]:
                        value = endpoint.get(field)
                        if str(value or "").strip():
                            payload[field] = value
                    endpoints.append(payload)
                    changed = True
        if not changed:
            break

    for child_file in included_child_files:
        child_part = path_to_part.get(child_file)
        if child_part is None:
            continue
        child_endpoints = child_part.get("api_endpoints", [])
        if not isinstance(child_endpoints, list) or not child_endpoints:
            continue
        child_part["api_endpoints"] = [
            endpoint
            for endpoint in child_endpoints
            if not isinstance(endpoint, dict)
            or str(endpoint.get("file", "")).replace("\\", "/").strip("/") != child_file
        ]


def _apply_cross_file_python_fastapi_router_mounts(file_parts: list[dict]) -> None:
    path_to_part: dict[str, dict[str, Any]] = {}
    known_paths: set[str] = set()
    module_resolution_hints: list[dict[str, Any]] = []
    for part in file_parts:
        if not isinstance(part, dict):
            continue
        file_info = part.get("file", {})
        if not isinstance(file_info, dict):
            continue
        path = str(file_info.get("path", "")).replace("\\", "/").strip("/")
        if not path:
            continue
        path_to_part[path] = part
        known_paths.add(path)
        for item in part.get("module_resolution_hints", []):
            if isinstance(item, dict):
                module_resolution_hints.append(item)
    if not path_to_part:
        return

    alias_to_file: dict[str, str] = {}
    for path in known_paths:
        for alias in _file_aliases_for_architecture(path):
            alias_to_file.setdefault(alias, path)

    mounted_router_symbols_by_file: dict[str, set[str]] = {}
    max_rounds = max(1, len(path_to_part) + 1)
    for _ in range(max_rounds):
        changed = False
        for path, part in path_to_part.items():
            module_state = part.get("python_module_state", [])
            if not isinstance(module_state, list) or not module_state:
                continue
            router_mounts = [
                item
                for item in module_state
                if isinstance(item, dict) and str(item.get("kind", "")).strip() == "fastapi_router_mount"
            ]
            if not router_mounts:
                continue
            endpoints = part.setdefault("api_endpoints", [])
            seen_endpoint_keys = {
                (
                    str(item.get("protocol", "")).strip().lower(),
                    str(item.get("method", "")).upper().strip(),
                    str(item.get("route", "")).strip(),
                    str(item.get("framework", "")).strip(),
                    str(item.get("file", "")).replace("\\", "/").strip(),
                    int(item.get("line", 0) or 0),
                    str(item.get("source_file", item.get("file", ""))).replace("\\", "/").strip(),
                    int(item.get("source_line", item.get("line", 0)) or 0),
                )
                for item in endpoints
                if isinstance(item, dict)
            }
            for mount in router_mounts:
                target_module = str(mount.get("target_module", "")).strip()
                if not target_module:
                    continue
                child_file = _resolve_local_architecture_target(
                    target_module,
                    alias_to_file,
                    current_path=path,
                    known_paths=known_paths,
                    module_resolution_hints=module_resolution_hints,
                )
                child_part = path_to_part.get(child_file)
                if child_part is None or child_part is part:
                    continue
                router_symbol = str(mount.get("router_symbol", mount.get("router", ""))).strip()
                owner_router_symbol = str(mount.get("owner_router_symbol", "")).strip()
                if router_symbol:
                    mounted_router_symbols_by_file.setdefault(child_file, set()).add(router_symbol)
                mount_prefix = str(mount.get("route", "")).strip() or "/"
                mount_line = int(mount.get("line", 1) or 1)
                mount_evidence = str(mount.get("evidence", "")).strip() or make_evidence(path, mount_line)
                for endpoint in child_part.get("api_endpoints", []):
                    if not isinstance(endpoint, dict):
                        continue
                    framework = str(endpoint.get("framework", "")).strip()
                    if framework not in {"fastapi_router", "fastapi_router_websocket"}:
                        continue
                    endpoint_router = str(endpoint.get("router", "")).strip()
                    if router_symbol and endpoint_router != router_symbol:
                        continue
                    method = str(endpoint.get("method", "")).upper().strip()
                    if method not in HTTP_METHODS:
                        continue
                    child_route = str(endpoint.get("route", "")).strip()
                    if not child_route:
                        continue
                    composed_route = _compose_route_path(mount_prefix, child_route)
                    if not composed_route:
                        continue
                    depth = int(endpoint.get("mount_chain_depth", 0) or 0)
                    if depth >= 8:
                        continue
                    protocol = str(endpoint.get("protocol", "")).strip().lower()
                    child_file_ref = str(endpoint.get("file", child_file)).replace("\\", "/").strip("/") or child_file
                    source_file = str(endpoint.get("source_file", "")).replace("\\", "/").strip("/") or child_file_ref
                    source_line = int(endpoint.get("source_line", endpoint.get("line", 1)) or 1)
                    source_evidence = str(endpoint.get("source_evidence", endpoint.get("evidence", ""))).strip() or make_evidence(source_file, source_line)
                    dedupe_key = (
                        protocol,
                        method,
                        composed_route,
                        framework,
                        path,
                        mount_line,
                        source_file,
                        source_line,
                    )
                    if dedupe_key in seen_endpoint_keys:
                        continue
                    seen_endpoint_keys.add(dedupe_key)
                    payload = {
                        "method": method,
                        "route": composed_route,
                        "framework": framework,
                        "file": path,
                        "line": mount_line,
                        "evidence": mount_evidence,
                        "source_file": source_file,
                        "source_line": source_line,
                        "source_evidence": source_evidence,
                        "imported_from": child_file,
                        "route_resolution": "cross_file_import_mount",
                        "mount_file": path,
                        "mount_line": mount_line,
                        "mount_evidence": mount_evidence,
                        "mount_chain_depth": depth + 1,
                    }
                    if protocol:
                        payload["protocol"] = protocol
                    propagated_router = owner_router_symbol or endpoint_router
                    if propagated_router:
                        payload["router"] = propagated_router
                    for field in ["handler_name", "target_module", "handler_ref", "handler_qualname", "handler_resolution"]:
                        value = endpoint.get(field)
                        if str(value or "").strip():
                            payload[field] = value
                    endpoints.append(payload)
                    changed = True
        if not changed:
            break

    for child_file, router_symbols in mounted_router_symbols_by_file.items():
        child_part = path_to_part.get(child_file)
        if child_part is None:
            continue
        child_endpoints = child_part.get("api_endpoints", [])
        if not isinstance(child_endpoints, list) or not child_endpoints:
            continue
        child_part["api_endpoints"] = [
            endpoint
            for endpoint in child_endpoints
            if not isinstance(endpoint, dict)
            or str(endpoint.get("file", "")).replace("\\", "/").strip("/") != child_file
            or str(endpoint.get("framework", "")).strip() not in {"fastapi_router", "fastapi_router_websocket"}
            or str(endpoint.get("router", "")).strip() not in router_symbols
        ]


