def _parse_dispatch_response_json(item: dict[str, Any]) -> dict[str, Any]:
    preview = str(item.get("response_body_preview", "")).strip()
    if not preview:
        return {}
    try:
        parsed = json.loads(preview)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


def _replace_dispatch_completion_note(item: dict[str, Any], existing: str, replacement: str) -> None:
    notes = [str(value).strip() for value in item.get("notes", []) if str(value).strip()]
    updated_notes = [replacement if value == existing else value for value in notes]
    if replacement not in updated_notes:
        updated_notes.append(replacement)
    item["notes"] = updated_notes


