def _resolve_identity_certificate_material(
    config: dict[str, Any],
    *,
    config_path: str = "",
    env: Optional[dict[str, str]] = None,
) -> tuple[str, str]:
    runtime_env = env if isinstance(env, dict) else os.environ
    selected = config if isinstance(config, dict) else {}
    certificate_pem, certificate_from_env = _resolve_dispatch_secret_from_config(
        selected,
        direct_keys=["certificate_pem", "certificate"],
        env_keys=["certificate_env"],
        env=runtime_env,
    )
    if certificate_pem:
        source = "certificate_env" if certificate_from_env else "certificate_inline"
        return certificate_pem, source
    certificate_path = str(selected.get("certificate_path", "")).strip()
    if not certificate_path:
        return "", ""
    resolved_path = os.path.abspath(os.path.expanduser(certificate_path))
    if not os.path.isabs(certificate_path) and str(config_path).strip():
        resolved_path = os.path.abspath(os.path.join(os.path.dirname(config_path), certificate_path))
    if not os.path.isfile(resolved_path):
        return "", ""
    try:
        with open(resolved_path, "r", encoding="utf-8") as handle:
            return handle.read(), resolved_path
    except Exception:
        return "", ""


def _execute_local_xml_signature_verify_dispatch(
    item: dict[str, Any],
    *,
    env: Optional[dict[str, str]] = None,
) -> dict[str, Any]:
    runtime_env = env if isinstance(env, dict) else os.environ
    normalized_item = dict(item)
    config = _load_dispatch_execution_config(normalized_item)
    certificate_pem, certificate_source = _resolve_identity_certificate_material(
        config,
        config_path=str(normalized_item.get("config_path", "")).strip(),
        env=runtime_env,
    )
    if not certificate_pem.strip():
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = "missing_identity_certificate_material"
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("dispatch execution failed: missing_identity_certificate_material")
        return normalized_item
    try:
        der_bytes = ssl.PEM_cert_to_DER_cert(certificate_pem)
        normalized_item["status"] = "executed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = True
        normalized_item["execution_backend"] = "local_xml_signature_verify"
        normalized_item["execution_provider"] = "saml"
        normalized_item["executed_at"] = utc_now_iso()
        normalized_item["certificate_source"] = certificate_source
        normalized_item["certificate_bytes"] = len(der_bytes)
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("local xml signature verification completed")
        return normalized_item
    except Exception as e:
        failure_kind = str(e).strip() or "invalid_identity_certificate_material"
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = failure_kind
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append(f"dispatch execution failed: {failure_kind}")
        return normalized_item


def _execute_remote_jwt_verify_dispatch(
    item: dict[str, Any],
    *,
    env: Optional[dict[str, str]] = None,
) -> dict[str, Any]:
    runtime_env = env if isinstance(env, dict) else os.environ
    normalized_item = dict(item)
    config = _load_dispatch_execution_config(normalized_item)
    issuer = str(config.get("issuer", normalized_item.get("target", ""))).strip()
    discovery_url = str(config.get("discovery_url", config.get("metadata_url", ""))).strip()
    if not discovery_url and issuer:
        discovery_url = issuer.rstrip("/") + "/.well-known/openid-configuration"
    if not issuer:
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "remote_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = "missing_identity_issuer"
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("dispatch execution failed: missing_identity_issuer")
        return normalized_item
    if not discovery_url or not _is_valid_external_integration_url(discovery_url):
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "remote_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = "invalid_oidc_discovery_url"
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("dispatch execution failed: invalid_oidc_discovery_url")
        return normalized_item
    headers, header_failures = _build_dispatch_http_headers(config, env=runtime_env)
    if header_failures:
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "remote_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = header_failures[0]
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append(f"dispatch execution failed: {header_failures[0]}")
        return normalized_item
    headers.setdefault("Accept", "application/json")

    def _fetch_json(target_url: str) -> tuple[dict[str, Any], int]:
        request = urllib.request.Request(target_url, headers=headers, method="GET")
        with urllib.request.urlopen(request, timeout=5.0) as response:
            status_code = int(getattr(response, "status", 0) or response.getcode() or 0)
            response_body = response.read()
        if status_code < 200 or status_code >= 300:
            raise RuntimeError(f"http_status:{status_code}")
        parsed = json.loads(response_body.decode("utf-8"))
        if not isinstance(parsed, dict):
            raise RuntimeError("invalid_json_response")
        return parsed, status_code

    try:
        discovery_doc, discovery_status = _fetch_json(discovery_url)
        jwks_url = str(config.get("jwks_url", config.get("jwks_uri", discovery_doc.get("jwks_uri", "")))).strip()
        if not jwks_url or not _is_valid_external_integration_url(jwks_url):
            raise RuntimeError("invalid_oidc_jwks_url")
        jwks_doc, jwks_status = _fetch_json(jwks_url)
        jwks_keys = jwks_doc.get("keys", [])
        if not isinstance(jwks_keys, list):
            raise RuntimeError("invalid_oidc_jwks_keys")
        normalized_item["status"] = "executed"
        normalized_item["mode"] = "remote_execution"
        normalized_item["pass"] = True
        normalized_item["execution_backend"] = "remote_jwt_verify"
        normalized_item["execution_provider"] = "oidc"
        normalized_item["executed_at"] = utc_now_iso()
        normalized_item["oidc_issuer"] = str(discovery_doc.get("issuer", issuer)).strip() or issuer
        normalized_item["oidc_discovery_url"] = discovery_url
        normalized_item["oidc_jwks_url"] = jwks_url
        normalized_item["oidc_discovery_status"] = discovery_status
        normalized_item["oidc_jwks_status"] = jwks_status
        normalized_item["jwks_key_count"] = len(jwks_keys)
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("remote jwt verification completed")
        return normalized_item
    except urllib.error.HTTPError as e:
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "remote_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = f"http_status:{int(getattr(e, 'code', 0) or 0)}"
        normalized_item["http_status"] = int(getattr(e, "code", 0) or 0)
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append(f"dispatch execution failed: http_status:{int(getattr(e, 'code', 0) or 0)}")
        return normalized_item
    except Exception as e:
        failure_kind = str(e).strip() or "execution_failed"
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "remote_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = failure_kind
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append(f"dispatch execution failed: {failure_kind}")
        return normalized_item


def _execute_loopback_http_upload_dispatch(
    item: dict[str, Any],
    *,
    publish_source_path: str,
    publish_label: str,
    payload_bytes: bytes,
) -> dict[str, Any]:
    normalized_item = dict(item)
    target = str(normalized_item.get("target", "")).strip()
    if not target or not is_loopback_url(target):
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = "non_loopback_http_target"
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("dispatch execution failed: non_loopback_http_target")
        return normalized_item
    if not payload_bytes:
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = "missing_dispatch_payload"
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("dispatch execution failed: missing_dispatch_payload")
        return normalized_item
    try:
        request = urllib.request.Request(
            target,
            data=payload_bytes,
            headers={
                "Content-Type": "application/json",
                "Content-Length": str(len(payload_bytes)),
                "User-Agent": "code-analyzer-local-dispatch/1",
                "X-Code-Analyzer-Dispatch-Operation": str(normalized_item.get("operation", "")).strip(),
                "X-Code-Analyzer-Publish-Label": str(publish_label or "").strip(),
            },
            method="PUT",
        )
        with urllib.request.urlopen(request, timeout=5.0) as response:
            status_code = int(getattr(response, "status", 0) or response.getcode() or 0)
            response_body = response.read()
        if status_code < 200 or status_code >= 300:
            raise RuntimeError(f"http_status:{status_code}")
        normalized_item["status"] = "executed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = True
        normalized_item["execution_backend"] = "loopback_http_upload"
        normalized_item["executed_at"] = utc_now_iso()
        normalized_item["http_status"] = status_code
        normalized_item["response_body_preview"] = response_body.decode("utf-8", errors="ignore")[:400]
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append("loopback http upload completed")
        return normalized_item
    except urllib.error.HTTPError as e:
        body = b""
        try:
            body = e.read()
        except Exception:
            body = b""
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = f"http_status:{int(getattr(e, 'code', 0) or 0)}"
        normalized_item["http_status"] = int(getattr(e, "code", 0) or 0)
        normalized_item["response_body_preview"] = body.decode("utf-8", errors="ignore")[:400]
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append(f"dispatch execution failed: http_status:{int(getattr(e, 'code', 0) or 0)}")
        return normalized_item
    except Exception as e:
        failure_kind = str(e).strip() or "execution_failed"
        normalized_item["status"] = "execution_failed"
        normalized_item["mode"] = "local_execution"
        normalized_item["pass"] = False
        normalized_item["execution_failure_kind"] = failure_kind
        normalized_item["notes"] = [str(value) for value in normalized_item.get("notes", []) if str(value).strip()]
        normalized_item["notes"].append(f"dispatch execution failed: {failure_kind}")
        return normalized_item


