def load_run_synthesis_checkpoint(run_path: str) -> Optional[dict[str, Any]]:
    return read_json_file(os.path.join(run_path, RUN_SYNTHESIS_CHECKPOINT_FILENAME))


def load_gather_resume_context(run_path: str) -> Optional[dict[str, Any]]:
    checkpoint = load_run_gather_checkpoint(run_path)
    if not isinstance(checkpoint, dict):
        return None
    artifacts = checkpoint.get("artifacts", {})
    if not isinstance(artifacts, dict):
        return None
    required_json_keys = [
        "run_fact_index",
        "run_model_safe_fact_index",
        "run_prompt_fact_context",
        "run_claim_support_index",
    ]
    loaded: dict[str, Any] = {}
    for key in required_json_keys:
        path = str(artifacts.get(key, "")).strip()
        if not path or not os.path.isfile(path):
            return None
        payload = read_json_file(path)
        if not isinstance(payload, dict):
            return None
        loaded[key] = payload
    included_files = set([str(p).replace("\\", "/") for p in checkpoint.get("included_files", []) if str(p).strip()])
    line_counts_raw = checkpoint.get("line_counts", {})
    line_counts: dict[str, int] = {}
    if isinstance(line_counts_raw, dict):
        for path, count in line_counts_raw.items():
            try:
                line_counts[str(path).replace("\\", "/")] = int(count)
            except Exception:
                continue
    redaction_stats = checkpoint.get("redaction_stats", {})
    fact_index_cache_stats = checkpoint.get("fact_index_cache_stats", {})
    runtime_config = checkpoint.get("runtime_config", {})
    repo_fingerprint = str(checkpoint.get("repo_fingerprint", "")).strip()
    if not included_files or not line_counts or not isinstance(redaction_stats, dict) or not isinstance(fact_index_cache_stats, dict):
        return None
    return {
        "repo_fingerprint": repo_fingerprint,
        "included_files": included_files,
        "line_counts": line_counts,
        "redaction_stats": redaction_stats,
        "fact_index_cache_stats": fact_index_cache_stats,
        "runtime_config": runtime_config if isinstance(runtime_config, dict) else {},
        "fact_index": loaded["run_fact_index"],
        "model_safe_fact_index": loaded["run_model_safe_fact_index"],
        "prompt_fact_context": loaded["run_prompt_fact_context"],
        "claim_support_index": loaded["run_claim_support_index"],
    }


def load_synthesis_resume_context(run_path: str) -> Optional[dict[str, Any]]:
    checkpoint = load_run_synthesis_checkpoint(run_path)
    if not isinstance(checkpoint, dict):
        return None
    required = ["final_text", "final_validation", "final_gate", "source"]
    for key in required:
        if key not in checkpoint:
            return None
    if not isinstance(checkpoint.get("final_validation"), dict):
        return None
    if not isinstance(checkpoint.get("final_gate"), dict):
        return None
    return checkpoint


def find_previous_run_for_repo(
    runs_dir: str,
    current_run_dir: str,
    repo_path: str,
    current_state: Optional[dict[str, Any]] = None,
) -> Optional[dict[str, Any]]:
    root = resolve_runs_dir(runs_dir)
    if not os.path.isdir(root):
        return None
    current_abs = os.path.abspath(current_run_dir)
    repo_norm = normalize_repo_path_value(repo_path)
    current_git = {}
    if isinstance(current_state, dict):
        current_git = current_state.get("repo_metadata", {}).get("git", {}) or {}
    current_commit = str(current_git.get("commit", "")).strip()
    current_branch = str(current_git.get("branch", "")).strip()
    candidates = []
    for name in os.listdir(root):
        run_dir = os.path.join(root, name)
        if not os.path.isdir(run_dir) or os.path.abspath(run_dir) == current_abs:
            continue
        state_path = os.path.join(run_dir, RUN_STATE_FILENAME)
        state = read_json_file(state_path)
        if not isinstance(state, dict):
            continue
        state_repo = normalize_repo_path_value(str(state.get("repo_path", "")))
        if state_repo != repo_norm:
            continue
        if str(state.get("status", "")).strip() not in {"completed", "failed_gate"}:
            continue
        git_info = state.get("repo_metadata", {}).get("git", {}) or {}
        branch = str(git_info.get("branch", "")).strip()
        commit = str(git_info.get("commit", "")).strip()
        same_branch = bool(current_branch and branch and branch == current_branch)
        different_commit = bool(current_commit and commit and commit != current_commit)
        same_commit = bool(current_commit and commit and commit == current_commit)
        try:
            mtime = os.path.getmtime(state_path)
        except Exception:
            mtime = 0.0
        candidates.append((1 if different_commit else 0, 1 if same_branch else 0, 0 if same_commit else 1, mtime, run_dir, branch, commit))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (item[0], item[1], item[2], item[3]), reverse=True)
    _different_commit, _same_branch, _different_from_same_commit, _mtime, run_dir, branch, commit = candidates[0]
    return {
        "run_dir": run_dir,
        "run_id": os.path.basename(run_dir),
        "branch": branch,
        "commit": commit,
    }


class ShutdownRequested(Exception):
    pass


_SHUTDOWN_CONTEXT: dict[str, Any] = {"requested": False, "signal": "", "count": 0}


def reset_shutdown_context() -> None:
    _SHUTDOWN_CONTEXT["requested"] = False
    _SHUTDOWN_CONTEXT["signal"] = ""
    _SHUTDOWN_CONTEXT["count"] = 0


def _signal_name(signum: int) -> str:
    try:
        return signal.Signals(signum).name
    except Exception:
        return f"SIG{signum}"


def _shutdown_handler(signum, frame):
    _SHUTDOWN_CONTEXT["count"] = int(_SHUTDOWN_CONTEXT.get("count", 0) or 0) + 1
    _SHUTDOWN_CONTEXT["requested"] = True
    _SHUTDOWN_CONTEXT["signal"] = _signal_name(signum)
    if _SHUTDOWN_CONTEXT["count"] > 1:
        raise SystemExit(130)
    raise ShutdownRequested(f"Received {_SHUTDOWN_CONTEXT['signal']}")


def install_runtime_signal_handlers() -> dict[int, Any]:
    previous: dict[int, Any] = {}
    for sig in (signal.SIGINT, signal.SIGTERM):
        try:
            previous[sig] = signal.getsignal(sig)
            signal.signal(sig, _shutdown_handler)
        except Exception:
            continue
    try:
        previous[signal.SIGALRM] = signal.getsignal(signal.SIGALRM)
        signal.signal(signal.SIGALRM, _handler)
        signal.alarm(TIMEOUT_SECONDS)
    except Exception:
        pass
    return previous


def restore_runtime_signal_handlers(previous: dict[int, Any]) -> None:
    try:
        signal.alarm(0)
    except Exception:
        pass
    for sig, handler in previous.items():
        try:
            signal.signal(sig, handler)
        except Exception:
            continue


def default_desktop_reports_root() -> str:
    return os.path.abspath(os.path.expanduser(DEFAULT_DESKTOP_REPORTS_ROOT))


def default_repo_report_label(repo_path: str) -> str:
    repo_name = os.path.basename(os.path.abspath(os.path.expanduser(str(repo_path or "").strip())).rstrip("/\\")) or "repo"
    return sanitize_queue_scope_name(repo_name, default="repo")


def default_repo_report_home(repo_path: str) -> str:
    return os.path.join(default_desktop_reports_root(), default_repo_report_label(repo_path))


def default_repo_runs_dir(repo_path: str) -> str:
    return os.path.join(default_repo_report_home(repo_path), DEFAULT_REPO_REPORTS_DIRNAME)


def resolve_runs_dir(value: str, repo_path: str = "") -> str:
    explicit = (value or "").strip()
    if explicit:
        return os.path.abspath(os.path.expanduser(explicit))
    if str(repo_path or "").strip():
        return default_repo_runs_dir(repo_path)
    return os.path.abspath(os.path.expanduser(DEFAULT_RUNS_DIR))


def resolve_published_dir(value: str) -> str:
    return os.path.abspath(os.path.expanduser((value or "").strip() or DEFAULT_PUBLISHED_DIR))


def resolve_queue_dir(value: str) -> str:
    return os.path.abspath(os.path.expanduser((value or "").strip() or DEFAULT_QUEUE_DIR))


def resolve_run_reference(runs_dir: str, run_ref: str) -> str:
    return resolve_resume_run_path(runs_dir, run_ref)


def canonical_json_dumps(data: Any) -> str:
    return json.dumps(data, ensure_ascii=True, sort_keys=True, separators=(",", ":"))


def _sha256_text(text: str) -> str:
    return hashlib.sha256(str(text or "").encode("utf-8")).hexdigest()


def audit_hmac_key() -> str:
    return str(os.getenv("AUDIT_HMAC_KEY", "")).strip()


def sign_audit_payload(payload: dict[str, Any]) -> dict[str, Any]:
    key = audit_hmac_key()
    if not key:
        return {}
    digest = hmac.new(key.encode("utf-8"), canonical_json_dumps(payload).encode("utf-8"), hashlib.sha256).hexdigest()
    return {
        "algorithm": "hmac-sha256",
        "signed_fields": sorted(list(payload.keys())),
        "digest": digest,
    }


def _publish_audit_ledger_path(publish_root: str) -> str:
    return os.path.join(os.path.abspath(os.path.expanduser(str(publish_root or "").strip() or DEFAULT_PUBLISHED_DIR)), PUBLISH_AUDIT_LEDGER_FILENAME)


def _load_publish_audit_ledger(ledger_path: str) -> dict[str, Any]:
    resolved_path = os.path.abspath(os.path.expanduser(str(ledger_path or "").strip()))
    if not resolved_path or not os.path.isfile(resolved_path):
        return {
            "path": resolved_path,
            "entries": [],
            "exists": False,
            "chain_valid": True,
            "last_hash": "",
            "failure": "",
            "line_count": 0,
        }
    try:
        with open(resolved_path, "r", encoding="utf-8") as fh:
            raw_lines = fh.read().splitlines()
    except Exception as e:
        return {
            "path": resolved_path,
            "entries": [],
            "exists": True,
            "chain_valid": False,
            "last_hash": "",
            "failure": f"read_error:{e}",
            "line_count": 0,
        }
    entries: list[dict[str, Any]] = []
    previous_hash = ""
    for index, raw_line in enumerate(raw_lines, start=1):
        line = str(raw_line or "").strip()
        if not line:
            continue
        try:
            payload = json.loads(line)
        except Exception:
            return {
                "path": resolved_path,
                "entries": entries,
                "exists": True,
                "chain_valid": False,
                "last_hash": previous_hash,
                "failure": f"invalid_json_line:{index}",
                "line_count": len(raw_lines),
            }
        if not isinstance(payload, dict):
            return {
                "path": resolved_path,
                "entries": entries,
                "exists": True,
                "chain_valid": False,
                "last_hash": previous_hash,
                "failure": f"invalid_record_line:{index}",
                "line_count": len(raw_lines),
            }
        entry_hash = str(payload.get("entry_hash", "")).strip()
        expected_previous = previous_hash
        observed_previous = str(payload.get("previous_hash", "")).strip()
        hashed_payload = {k: v for k, v in payload.items() if k != "entry_hash"}
        computed_hash = _sha256_text(canonical_json_dumps(hashed_payload))
        if not entry_hash or entry_hash != computed_hash:
            return {
                "path": resolved_path,
                "entries": entries,
                "exists": True,
                "chain_valid": False,
                "last_hash": previous_hash,
                "failure": f"hash_mismatch_line:{index}",
                "line_count": len(raw_lines),
            }
        if observed_previous != expected_previous:
            return {
                "path": resolved_path,
                "entries": entries,
                "exists": True,
                "chain_valid": False,
                "last_hash": previous_hash,
                "failure": f"previous_hash_mismatch_line:{index}",
                "line_count": len(raw_lines),
            }
        entries.append(payload)
        previous_hash = entry_hash
    return {
        "path": resolved_path,
        "entries": entries,
        "exists": True,
        "chain_valid": True,
        "last_hash": previous_hash,
        "failure": "",
        "line_count": len(raw_lines),
    }


def append_publish_audit_ledger(ledger_path: str, payload: dict[str, Any]) -> dict[str, Any]:
    ledger_state = _load_publish_audit_ledger(ledger_path)
    if not bool(ledger_state.get("chain_valid", False)):
        raise RuntimeError(
            "Publish audit ledger is corrupted: "
            + str(ledger_state.get("failure", "")).strip()
        )
    existing_entries = ledger_state.get("entries", []) if isinstance(ledger_state.get("entries", []), list) else []
    previous_hash = str(ledger_state.get("last_hash", "")).strip()
    entry: dict[str, Any] = {
        "sequence": len(existing_entries) + 1,
        "recorded_at": utc_now_iso(),
        "previous_hash": previous_hash,
    }
    for key, value in payload.items():
        entry[str(key)] = value
    entry["entry_hash"] = _sha256_text(canonical_json_dumps({k: v for k, v in entry.items() if k != "entry_hash"}))
    next_lines = [canonical_json_dumps(item) for item in existing_entries] + [canonical_json_dumps(entry)]
    write_text_atomic(ledger_path, "\n".join(next_lines) + "\n")
    return {
        "path": os.path.abspath(os.path.expanduser(ledger_path)),
        "entry": entry,
        "prior_entry_count": len(existing_entries),
        "chain_valid": True,
    }


def build_review_audit_bundle(
    *,
    phase: str,
    run_path: str,
    state: dict[str, Any],
    review_policy_path: str,
    classification_summary: dict[str, Any],
    endpoint_quality_summary: dict[str, Any],
    grounding_summary: Optional[dict[str, Any]] = None,
    contradiction_summary: Optional[dict[str, Any]] = None,
    unsupported_claim_summary: Optional[dict[str, Any]] = None,
    self_review_summary: Optional[dict[str, Any]] = None,
    external_integrations_summary: Optional[dict[str, Any]] = None,
    external_integration_plan_summary: Optional[dict[str, Any]] = None,
    external_integration_dispatch_specs_summary: Optional[dict[str, Any]] = None,
    external_integration_dispatch_results_summary: Optional[dict[str, Any]] = None,
    artifact_hashes: Optional[list[dict[str, Any]]] = None,
    approval: Optional[dict[str, Any]] = None,
    manifest: Optional[dict[str, Any]] = None,
    published_artifacts: Optional[list[dict[str, Any]]] = None,
) -> dict[str, Any]:
    normalized_phase = str(phase or "").strip() or "review"
    approval_required = normalized_phase in {"approval", "publish"}
    payload: dict[str, Any] = {
        "phase": normalized_phase,
        "generated_at": utc_now_iso(),
        "run_id": str(state.get("run_id", os.path.basename(run_path))).strip(),
        "run_path": run_path,
        "repo_path": str(state.get("repo_path", "")).strip(),
        "run_status": str(state.get("status", "")).strip(),
        "requested_mode": str(state.get("requested_mode", "")).strip(),
        "effective_mode": str(state.get("mode", "")).strip(),
        "review_policy_path": review_policy_path,
        "approval_required": approval_required,
        "classification_summary": classification_summary if isinstance(classification_summary, dict) else {},
        "endpoint_quality_summary": endpoint_quality_summary if isinstance(endpoint_quality_summary, dict) else {},
    }
    if isinstance(grounding_summary, dict) and grounding_summary:
        payload["grounding_summary"] = grounding_summary
    if isinstance(contradiction_summary, dict) and contradiction_summary:
        payload["contradiction_summary"] = contradiction_summary
    if isinstance(unsupported_claim_summary, dict) and unsupported_claim_summary:
        payload["unsupported_claim_summary"] = unsupported_claim_summary
    if isinstance(self_review_summary, dict) and self_review_summary:
        payload["self_review_summary"] = self_review_summary
    if isinstance(external_integrations_summary, dict) and external_integrations_summary:
        payload["external_integrations_summary"] = external_integrations_summary
    computed_external_integration_plan_summary = (
        external_integration_plan_summary
        if isinstance(external_integration_plan_summary, dict) and external_integration_plan_summary
        else (
            build_external_integration_execution_plan(external_integrations_summary)
            if isinstance(external_integrations_summary, dict) and external_integrations_summary
            else {}
        )
    )
    if isinstance(computed_external_integration_plan_summary, dict) and computed_external_integration_plan_summary:
        payload["external_integration_plan_summary"] = computed_external_integration_plan_summary
    computed_external_integration_dispatch_specs_summary = (
        external_integration_dispatch_specs_summary
        if isinstance(external_integration_dispatch_specs_summary, dict) and external_integration_dispatch_specs_summary
        else (
            build_external_integration_dispatch_specs(external_integrations_summary)
            if isinstance(external_integrations_summary, dict) and external_integrations_summary
            else {}
        )
    )
    if isinstance(computed_external_integration_dispatch_specs_summary, dict) and computed_external_integration_dispatch_specs_summary:
        payload["external_integration_dispatch_specs_summary"] = computed_external_integration_dispatch_specs_summary
    computed_external_integration_dispatch_results_summary = (
        external_integration_dispatch_results_summary
        if isinstance(external_integration_dispatch_results_summary, dict) and external_integration_dispatch_results_summary
        else (
            build_external_integration_dispatch_results(computed_external_integration_dispatch_specs_summary)
            if isinstance(computed_external_integration_dispatch_specs_summary, dict) and computed_external_integration_dispatch_specs_summary
            else {}
        )
    )
    if isinstance(computed_external_integration_dispatch_results_summary, dict) and computed_external_integration_dispatch_results_summary:
        payload["external_integration_dispatch_results_summary"] = computed_external_integration_dispatch_results_summary
    if isinstance(artifact_hashes, list) and artifact_hashes:
        payload["artifact_hashes"] = artifact_hashes
    if isinstance(approval, dict):
        payload["approval"] = approval
        payload["approval_present"] = bool(max(0, int(approval.get("approval_count", 1) or 1)))
        payload["approval_count"] = max(0, int(approval.get("approval_count", 1) or 1))
        payload["approval_requirements_met"] = bool(approval.get("approval_requirements_met", payload["approval_present"]))
        missing_roles = [str(item).strip() for item in approval.get("missing_approval_roles", []) if str(item).strip()]
        if missing_roles:
            payload["missing_approval_roles"] = missing_roles
    else:
        payload["approval_present"] = False
        payload["approval_count"] = 0
        payload["approval_requirements_met"] = not approval_required
    if isinstance(manifest, dict):
        payload["publish_manifest"] = manifest
    if isinstance(published_artifacts, list):
        payload["published_artifacts"] = published_artifacts
        payload["published_artifacts_count"] = len(published_artifacts)
    payload["signature"] = sign_audit_payload(payload)
    return payload


def build_review_audit_sarif(bundle: dict[str, Any]) -> dict[str, Any]:
    payload = bundle if isinstance(bundle, dict) else {}
    endpoint_quality = payload.get("endpoint_quality_summary", {})
    if not isinstance(endpoint_quality, dict):
        endpoint_quality = {}
    classification = payload.get("classification_summary", {})
    if not isinstance(classification, dict):
        classification = {}
    grounding = payload.get("grounding_summary", {})
    if not isinstance(grounding, dict):
        grounding = {}
    contradictions = payload.get("contradiction_summary", {})
    if not isinstance(contradictions, dict):
        contradictions = {}
    unsupported_claims = payload.get("unsupported_claim_summary", {})
    if not isinstance(unsupported_claims, dict):
        unsupported_claims = {}
    self_review = payload.get("self_review_summary", {})
    if not isinstance(self_review, dict):
        self_review = {}
    external_integrations = payload.get("external_integrations_summary", {})
    if not isinstance(external_integrations, dict):
        external_integrations = {}
    external_integration_plan = payload.get("external_integration_plan_summary", {})
    if not isinstance(external_integration_plan, dict) or not external_integration_plan:
        external_integration_plan = build_external_integration_execution_plan(external_integrations)
    external_integration_dispatch_specs = payload.get("external_integration_dispatch_specs_summary", {})
    if not isinstance(external_integration_dispatch_specs, dict) or not external_integration_dispatch_specs:
        external_integration_dispatch_specs = build_external_integration_dispatch_specs(external_integrations)
    external_integration_dispatch_results = payload.get("external_integration_dispatch_results_summary", {})
    if not isinstance(external_integration_dispatch_results, dict) or not external_integration_dispatch_results:
        external_integration_dispatch_results = build_external_integration_dispatch_results(external_integration_dispatch_specs)
    external_integration_items = external_integrations.get("integrations", [])
    if not isinstance(external_integration_items, list):
        external_integration_items = []
    publish_manifest = payload.get("publish_manifest", {})
    if not isinstance(publish_manifest, dict):
        publish_manifest = {}
    publish_environment_policy = publish_manifest.get("publish_environment_policy", {})
    if not isinstance(publish_environment_policy, dict):
        publish_environment_policy = {}
    publish_audit_ledger = publish_manifest.get("publish_audit_ledger", {})
    if not isinstance(publish_audit_ledger, dict):
        publish_audit_ledger = {}

    total_endpoints = max(0, int(endpoint_quality.get("total_endpoints", 0) or 0))
    verified_endpoints = max(0, int(endpoint_quality.get("runtime_verified_endpoints", 0) or 0))
    high_confidence_endpoints = max(0, int(endpoint_quality.get("high_confidence_endpoints", 0) or 0))
    cross_file_endpoints = max(0, int(endpoint_quality.get("cross_file_endpoints", 0) or 0))
    max_classification = str(classification.get("max_classification", "")).strip() or "unknown"
    approval_required = bool(payload.get("approval_required", False))
    contradiction_issue_count = max(0, int(contradictions.get("issue_count", 0) or 0))
    duplicate_endpoint_count = max(0, int(contradictions.get("duplicate_endpoint_signature_count", 0) or 0))
    verification_conflict_count = max(0, int(contradictions.get("endpoint_verification_conflict_count", 0) or 0))
    grounding_gate_pass = bool(grounding.get("gate_pass", False))
    grounding_evidence_coverage = float(grounding.get("evidence_coverage", 0.0) or 0.0)
    grounding_semantic_coverage = float(grounding.get("semantic_coverage", 0.0) or 0.0)
    grounding_missing_files = max(0, int(grounding.get("files_missing_evidence_count", 0) or 0))
    grounding_unsupported_claims = max(0, int(grounding.get("claims_semantically_unsupported", 0) or 0))
    unsupported_claim_issue_count = max(0, int(unsupported_claims.get("issue_count", 0) or 0))
    self_review_issue_count = max(0, int(self_review.get("issue_count", 0) or 0))
    external_blocking_count = max(0, int(external_integrations.get("blocking_failure_count", 0) or 0))
    external_plan_count = max(0, int(external_integration_plan.get("plan_count", 0) or 0))
    external_failing_plan_count = max(0, int(external_integration_plan.get("failing_plan_count", 0) or 0))
    external_blocking_plan_count = max(0, int(external_integration_plan.get("blocking_plan_failure_count", 0) or 0))
    external_dispatch_spec_count = max(0, int(external_integration_dispatch_specs.get("spec_count", 0) or 0))
    external_ready_dispatch_spec_count = max(0, int(external_integration_dispatch_specs.get("ready_spec_count", 0) or 0))
    external_blocking_dispatch_spec_count = max(0, int(external_integration_dispatch_specs.get("blocking_spec_failure_count", 0) or 0))
    external_transport_count = max(0, int(external_integration_dispatch_specs.get("transport_count", 0) or 0))
    external_dispatch_result_count = max(0, int(external_integration_dispatch_results.get("result_count", 0) or 0))
    external_passing_dispatch_result_count = max(0, int(external_integration_dispatch_results.get("passing_result_count", 0) or 0))
    external_blocking_dispatch_result_count = max(0, int(external_integration_dispatch_results.get("blocking_result_failure_count", 0) or 0))
    external_dry_run_dispatch_result_count = max(0, int(external_integration_dispatch_results.get("dry_run_result_count", 0) or 0))
    external_local_validation_result_count = max(0, int(external_integration_dispatch_results.get("local_validation_result_count", 0) or 0))
    external_local_execution_result_count = max(0, int(external_integration_dispatch_results.get("local_execution_result_count", 0) or 0))
    external_remote_execution_result_count = max(0, int(external_integration_dispatch_results.get("remote_execution_result_count", 0) or 0))
    external_executed_result_count = max(0, int(external_integration_dispatch_results.get("executed_result_count", 0) or 0))

    rules = [
        {
            "id": "review.run-status",
            "name": "review.run-status",
            "shortDescription": {"text": "Run status recorded for review workflow."},
        },
        {
            "id": "review.approval",
            "name": "review.approval",
            "shortDescription": {"text": "Approval presence recorded for review workflow."},
        },
        {
            "id": "review.classification",
            "name": "review.classification",
            "shortDescription": {"text": "Maximum output classification recorded for review workflow."},
        },
        {
            "id": "review.endpoint-quality",
            "name": "review.endpoint-quality",
            "shortDescription": {"text": "Endpoint verification and confidence metrics exported for governance."},
        },
        {
            "id": "review.grounding",
            "name": "review.grounding",
            "shortDescription": {"text": "Grounding and evidence coverage metrics exported for review."},
        },
        {
            "id": "review.contradictions",
            "name": "review.contradictions",
            "shortDescription": {"text": "Contradiction and duplicate-endpoint checks exported for review."},
        },
        {
            "id": "review.unsupported-claims",
            "name": "review.unsupported-claims",
            "shortDescription": {"text": "Unsupported semantic claim details exported for review."},
        },
        {
            "id": "review.self-review",
            "name": "review.self-review",
            "shortDescription": {"text": "Self-review findings exported for release governance."},
        },
        {
            "id": "review.external-integrations",
            "name": "review.external-integrations",
            "shortDescription": {"text": "External identity, approval, and signing integration readiness exported for governance."},
        },
        {
            "id": "review.publish-artifacts",
            "name": "review.publish-artifacts",
            "shortDescription": {"text": "Published artifact counts exported for governance."},
        },
        {
            "id": "review.publish-environment",
            "name": "review.publish-environment",
            "shortDescription": {"text": "Publish environment promotion status exported for governance."},
        },
        {
            "id": "review.publish-ledger",
            "name": "review.publish-ledger",
            "shortDescription": {"text": "Publish audit ledger append and chain status exported for governance."},
        },
    ]

    def result(rule_id: str, level: str, message: str, properties: Optional[dict[str, Any]] = None) -> dict[str, Any]:
        item: dict[str, Any] = {
            "ruleId": rule_id,
            "level": level,
            "message": {"text": message},
        }
        if isinstance(properties, dict) and properties:
            item["properties"] = properties
        return item

    results = [
        result(
            "review.run-status",
            "note",
            f"Run status {str(payload.get('run_status', '')).strip() or 'unknown'} in {str(payload.get('phase', '')).strip() or 'review'} phase.",
            {"runId": str(payload.get("run_id", "")).strip()},
        ),
        result(
            "review.approval",
            (
                "note"
                if (not approval_required)
                or (bool(payload.get("approval_present", False)) and bool(payload.get("approval_requirements_met", False)))
                else "warning"
            ),
            (
                "Approval not required in analysis phase."
                if not approval_required
                else (
                    f"Approval requirements satisfied with {max(0, int(payload.get('approval_count', 0) or 0))} approval(s)."
                    if bool(payload.get("approval_present", False)) and bool(payload.get("approval_requirements_met", False))
                    else (
                        "Approval artifact missing."
                        if not bool(payload.get("approval_present", False))
                        else "Approval artifact present, but role/count requirements are not satisfied."
                    )
                )
            ),
            {
                "approvalCount": max(0, int(payload.get("approval_count", 0) or 0)),
                "approvalRequired": approval_required,
                "approvalRequirementsMet": bool(payload.get("approval_requirements_met", False)),
                "missingApprovalRoles": [str(item).strip() for item in payload.get("missing_approval_roles", []) if str(item).strip()],
            },
        ),
        result(
            "review.grounding",
            (
                "note"
                if grounding_gate_pass and grounding_missing_files == 0 and grounding_unsupported_claims == 0
                else "warning"
            ),
            (
                f"Grounding gate pass={grounding_gate_pass}, evidence_coverage={grounding_evidence_coverage:.3f}, "
                f"semantic_coverage={grounding_semantic_coverage:.3f}, missing_files={grounding_missing_files}, "
                f"unsupported_claims={grounding_unsupported_claims}."
            ),
            {
                "gatePass": grounding_gate_pass,
                "evidenceCoverage": grounding_evidence_coverage,
                "semanticCoverage": grounding_semantic_coverage,
                "filesMissingEvidenceCount": grounding_missing_files,
                "claimsSemanticallyUnsupported": grounding_unsupported_claims,
            },
        ),
        result(
            "review.contradictions",
            "note" if contradiction_issue_count == 0 else "warning",
            (
                f"Contradiction audit issues={contradiction_issue_count}, duplicate_endpoints={duplicate_endpoint_count}, "
                f"verification_conflicts={verification_conflict_count}."
            ),
            {
                "issueCount": contradiction_issue_count,
                "duplicateEndpointSignatureCount": duplicate_endpoint_count,
                "endpointVerificationConflictCount": verification_conflict_count,
            },
        ),
        result(
            "review.unsupported-claims",
            "note" if unsupported_claim_issue_count == 0 else "warning",
            (
                f"Unsupported claim audit issues={unsupported_claim_issue_count}, "
                f"claims_semantically_unsupported={grounding_unsupported_claims}."
            ),
            {
                "issueCount": unsupported_claim_issue_count,
                "claimsSemanticallyUnsupported": grounding_unsupported_claims,
            },
        ),
        result(
            "review.self-review",
            "note" if self_review_issue_count == 0 else "warning",
            (
                f"Self review pass={bool(self_review.get('pass', False))}, issue_count={self_review_issue_count}, "
                f"blocking_issue_count={int(self_review.get('blocking_issue_count', 0) or 0)}."
            ),
            {
                "pass": bool(self_review.get("pass", False)),
                "issueCount": self_review_issue_count,
                "blockingIssueCount": int(self_review.get("blocking_issue_count", 0) or 0),
            },
        ),
        result(
            "review.external-integrations",
            "note" if external_blocking_count == 0 else "warning",
            (
                f"External integrations pass={bool(external_integrations.get('pass', False))}, "
                f"configured={int(external_integrations.get('configured_count', 0) or 0)}, "
                f"required={int(external_integrations.get('required_count', 0) or 0)}, "
                f"blocking_failures={external_blocking_count}, "
                f"ready_operations={int(external_integrations.get('ready_operation_count', 0) or 0)}, "
                f"planned={external_plan_count}, failing_plans={external_failing_plan_count}, "
                f"blocking_plan_failures={external_blocking_plan_count}, "
                f"dispatch_specs={external_dispatch_spec_count}, ready_dispatch_specs={external_ready_dispatch_spec_count}, "
                f"blocking_dispatch_specs={external_blocking_dispatch_spec_count}, transports={external_transport_count}, "
                f"dispatch_results={external_dispatch_result_count}, passing_dispatch_results={external_passing_dispatch_result_count}, "
                f"blocking_dispatch_results={external_blocking_dispatch_result_count}, dry_run_dispatch_results={external_dry_run_dispatch_result_count}, "
                f"local_validation_dispatch_results={external_local_validation_result_count}, "
                f"local_execution_dispatch_results={external_local_execution_result_count}, "
                f"remote_execution_dispatch_results={external_remote_execution_result_count}, "
                f"executed_dispatch_results={external_executed_result_count}."
            ),
            {
                "pass": bool(external_integrations.get("pass", False)),
                "configuredCount": int(external_integrations.get("configured_count", 0) or 0),
                "requiredCount": int(external_integrations.get("required_count", 0) or 0),
                "blockingFailureCount": external_blocking_count,
                "readyOperationCount": int(external_integrations.get("ready_operation_count", 0) or 0),
                "plannedCount": external_plan_count,
                "failingPlanCount": external_failing_plan_count,
                "blockingPlanFailureCount": external_blocking_plan_count,
                "dispatchSpecCount": external_dispatch_spec_count,
                "readyDispatchSpecCount": external_ready_dispatch_spec_count,
                "blockingDispatchSpecCount": external_blocking_dispatch_spec_count,
                "transportCount": external_transport_count,
                "dispatchResultCount": external_dispatch_result_count,
                "passingDispatchResultCount": external_passing_dispatch_result_count,
                "blockingDispatchResultCount": external_blocking_dispatch_result_count,
                "dryRunDispatchResultCount": external_dry_run_dispatch_result_count,
                "localValidationDispatchResultCount": external_local_validation_result_count,
                "localExecutionDispatchResultCount": external_local_execution_result_count,
                "remoteExecutionDispatchResultCount": external_remote_execution_result_count,
                "executedDispatchResultCount": external_executed_result_count,
            },
        ),
        result(
            "review.classification",
            "note",
            f"Maximum output classification: {max_classification}.",
            {"maxClassification": max_classification},
        ),
        result(
            "review.endpoint-quality",
            "note",
            (
                f"Endpoint quality totals: total={total_endpoints}, verified={verified_endpoints}, "
                f"high_confidence={high_confidence_endpoints}, cross_file={cross_file_endpoints}."
            ),
            {
                "totalEndpoints": total_endpoints,
                "runtimeVerifiedEndpoints": verified_endpoints,
                "highConfidenceEndpoints": high_confidence_endpoints,
                "crossFileEndpoints": cross_file_endpoints,
            },
        ),
    ]
    if "published_artifacts_count" in payload:
        results.append(
            result(
                "review.publish-artifacts",
                "note",
                f"Published artifact count: {max(0, int(payload.get('published_artifacts_count', 0) or 0))}.",
                {"publishedArtifactsCount": max(0, int(payload.get("published_artifacts_count", 0) or 0))},
            )
        )
    if publish_manifest:
        publish_environment = str(publish_manifest.get("publish_environment", "")).strip() or "default"
        missing_predecessors = [
            str(item).strip()
            for item in publish_environment_policy.get("missing_predecessors", [])
            if str(item).strip()
        ]
        results.append(
            result(
                "review.publish-environment",
                "note" if bool(publish_environment_policy.get("pass", True)) else "warning",
                (
                    f"Publish environment {publish_environment} promotion pass={bool(publish_environment_policy.get('pass', True))}, "
                    f"required_predecessors={len(publish_environment_policy.get('required_predecessors', []))}, "
                    f"missing_predecessors={len(missing_predecessors)}."
                ),
                {
                    "publishEnvironment": publish_environment,
                    "promotionPass": bool(publish_environment_policy.get("pass", True)),
                    "requiredPredecessors": [
                        str(item).strip()
                        for item in publish_environment_policy.get("required_predecessors", [])
                        if str(item).strip()
                    ],
                    "missingPredecessors": missing_predecessors,
                },
            )
        )
        results.append(
            result(
                "review.publish-ledger",
                "note" if bool(publish_audit_ledger.get("chain_valid", False)) else "warning",
                (
                    f"Publish audit ledger chain_valid={bool(publish_audit_ledger.get('chain_valid', False))}, "
                    f"sequence={int(publish_audit_ledger.get('sequence', 0) or 0)}, "
                    f"prior_entries={int(publish_audit_ledger.get('prior_entry_count', 0) or 0)}."
                ),
                {
                    "chainValid": bool(publish_audit_ledger.get("chain_valid", False)),
                    "sequence": int(publish_audit_ledger.get("sequence", 0) or 0),
                    "priorEntryCount": int(publish_audit_ledger.get("prior_entry_count", 0) or 0),
                    "ledgerPath": str(publish_audit_ledger.get("path", "")).strip(),
                },
            )
        )

    existing_rule_ids = {str(item.get("id", "")).strip() for item in rules if isinstance(item, dict)}
    for item in external_integration_items:
        if not isinstance(item, dict) or not bool(item.get("required_for_phase", False)) or bool(item.get("ready", False)):
            continue
        category = str(item.get("category", "")).strip() or "external"
        name = str(item.get("name", "")).strip() or "integration"
        rule_suffix = re.sub(r"[^a-z0-9._-]+", "-", f"{category}.{name}".lower()).strip("-") or "external-integration"
        rule_id = f"review.external-integrations.{rule_suffix}"
        if rule_id not in existing_rule_ids:
            rules.append(
                {
                    "id": rule_id,
                    "name": rule_id,
                    "shortDescription": {"text": "Required external integration readiness exported for governance."},
                }
            )
            existing_rule_ids.add(rule_id)
        detail_parts: list[str] = []
        for key in ["missing_env", "missing_files", "missing_commands", "missing_metadata", "missing_config_keys", "adapter_plan_failures"]:
            values = [str(value).strip() for value in item.get(key, []) if str(value).strip()]
            if values:
                detail_parts.append(f"{key}=" + ",".join(values))
        if str(item.get("config_path", "")).strip() and not bool(item.get("config_resolved", False)):
            detail_parts.append("config_unresolved=true")
        if str(item.get("config_selector", "")).strip():
            detail_parts.append("config_selector=" + str(item.get("config_selector", "")).strip())
        if str(item.get("config_kind", "")).strip():
            detail_parts.append("config_kind=" + str(item.get("config_kind", "")).strip())
        if str(item.get("adapter_plan_summary", "")).strip():
            detail_parts.append("adapter_plan=" + str(item.get("adapter_plan_summary", "")).strip())
        preview_ops = [
            f"{str(preview.get('operation', '')).strip()}@{str(preview.get('transport', '')).strip()}"
            for preview in item.get("adapter_plan_operation_previews", [])
            if isinstance(preview, dict)
            and str(preview.get("operation", "")).strip()
            and str(preview.get("transport", "")).strip()
        ]
        if preview_ops:
            detail_parts.append("adapter_preview_ops=" + ",".join(preview_ops))
        results.append(
            result(
                rule_id,
                "warning",
                (
                    f"Required external integration {category} {name} is not ready: "
                    + (", ".join(detail_parts) if detail_parts else "unspecified readiness failure")
                    + "."
                ),
                {
                    "category": category,
                    "name": name,
                    "kind": str(item.get("kind", "")).strip(),
                    "failures": [str(value).strip() for value in item.get("failures", []) if str(value).strip()],
                },
            )
        )

    return {
        "version": "2.1.0",
        "$schema": "https://json.schemastore.org/sarif-2.1.0.json",
        "runs": [
            {
                "tool": {
                    "driver": {
                        "name": "code-analyzer-review-audit",
                        "informationUri": "https://example.invalid/code-analyzer-review-audit",
                        "rules": rules,
                    }
                },
                "results": results,
                "properties": {
                    "phase": str(payload.get("phase", "")).strip() or "review",
                    "runId": str(payload.get("run_id", "")).strip(),
                },
            }
        ],
    }


def load_review_policy(path: str) -> dict[str, Any]:
    policy_path = str(path or "").strip()
    if not policy_path:
        return {}
    loaded = read_json_file(os.path.abspath(os.path.expanduser(policy_path)))
    if not isinstance(loaded, dict):
        raise RuntimeError(f"Failed to load review policy: {path}")
    return apply_policy_packs_to_review_policy(loaded, source=policy_path)


def _normalize_reviewer_role(value: Any) -> str:
    normalized = re.sub(r"[^a-z0-9_.-]+", "_", str(value or "").strip().lower()).strip("._-")
    return normalized


def _normalize_identity_string_list(value: Any) -> list[str]:
    raw_values = value if isinstance(value, list) else [value]
    out: list[str] = []
    seen: set[str] = set()
    for item in raw_values:
        normalized = str(item or "").strip()
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        out.append(normalized)
    return out


def _coerce_reviewer_roles(value: Any) -> list[str]:
    raw_values = value if isinstance(value, list) else [value]
    out: list[str] = []
    seen: set[str] = set()
    for item in raw_values:
        normalized = _normalize_reviewer_role(item)
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        out.append(normalized)
    return out


def _normalize_identity_kind(value: Any) -> str:
    normalized = _normalize_reviewer_role(value)
    return normalized or "unknown"


def _normalize_identity_phases(value: Any) -> list[str]:
    raw_values = value if isinstance(value, list) else [value]
    out: list[str] = []
    seen: set[str] = set()
    for item in raw_values:
        normalized = _normalize_reviewer_role(item)
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        out.append(normalized)
    return out


def _normalize_authn_strength(value: Any) -> str:
    normalized = _normalize_reviewer_role(value)
    aliases = {
        "single_factor": "password",
        "password": "password",
        "sso": "sso",
        "2fa": "mfa",
        "otp": "mfa",
        "totp": "mfa",
        "mfa": "mfa",
        "passkey": "hardware_key",
        "webauthn": "hardware_key",
        "hardware_key": "hardware_key",
    }
    return aliases.get(normalized, normalized)


def _authn_strength_rank(value: Any) -> int:
    normalized = _normalize_authn_strength(value)
    return {
        "": 0,
        "password": 1,
        "sso": 2,
        "mfa": 3,
        "hardware_key": 4,
    }.get(normalized, 0)


def _configured_reviewer_roles_map(review_policy: dict[str, Any]) -> dict[str, list[str]]:
    configured = review_policy.get("reviewer_roles", {})
    if not isinstance(configured, dict):
        return {}
    mapping: dict[str, list[str]] = {}
    for reviewer, roles in configured.items():
        reviewer_name = str(reviewer or "").strip()
        if not reviewer_name:
            continue
        mapping[reviewer_name] = _coerce_reviewer_roles(roles)
    return mapping


def _normalize_identity_directory(value: Any, *, fallback_roles_map: Optional[dict[str, list[str]]] = None) -> dict[str, dict[str, Any]]:
    configured = value if isinstance(value, dict) else {}
    fallback = fallback_roles_map if isinstance(fallback_roles_map, dict) else {}
    mapping: dict[str, dict[str, Any]] = {}
    names = sorted(set(list(configured.keys()) + list(fallback.keys())))
    for name in names:
        actor_name = str(name or "").strip()
        if not actor_name:
            continue
        item = configured.get(name)
        payload = item if isinstance(item, dict) else {}
        roles = _coerce_reviewer_roles(
            payload.get("roles")
            or payload.get("reviewer_roles")
            or payload.get("required_roles")
            or (item if isinstance(item, list) else [])
            or fallback.get(actor_name, [])
        )
        mapping[actor_name] = {
            "name": actor_name,
            "subject": str(payload.get("subject", payload.get("id", actor_name))).strip() or actor_name,
            "roles": roles,
            "team": str(payload.get("team", "")).strip(),
            "kind": _normalize_identity_kind(payload.get("kind", payload.get("type", ""))),
            "authn_strength": _normalize_authn_strength(payload.get("authn_strength", payload.get("authn", ""))),
            "allowed_phases": _normalize_identity_phases(payload.get("allowed_phases") or payload.get("phases")),
            "email": str(payload.get("email", "")).strip(),
        }
    return mapping


def _reviewer_identities(review_policy: dict[str, Any]) -> dict[str, dict[str, Any]]:
    return _normalize_identity_directory(
        review_policy.get("reviewer_identities", {}),
        fallback_roles_map=_configured_reviewer_roles_map(review_policy),
    )


def _deployer_identities(review_policy: dict[str, Any]) -> dict[str, dict[str, Any]]:
    return _normalize_identity_directory(
        review_policy.get("deployer_identities", review_policy.get("publisher_identities", {})),
    )


def _identity_policy_requirements(value: Any) -> dict[str, Any]:
    payload = value if isinstance(value, dict) else {}
    return {
        "required_roles": _coerce_reviewer_roles(payload.get("required_roles", [])),
        "allowed_kinds": [_normalize_identity_kind(item) for item in _normalize_identity_string_list(payload.get("allowed_kinds", []))],
        "required_teams": _normalize_identity_string_list(payload.get("required_teams", [])),
        "required_authn_strength": _normalize_authn_strength(payload.get("required_authn_strength", "")),
        "require_distinct_from_reviewers": bool(payload.get("require_distinct_from_reviewers", False)),
    }


def _reviewer_identity_requirements(review_policy: dict[str, Any]) -> dict[str, Any]:
    return _identity_policy_requirements(review_policy.get("reviewer_identity_requirements", {}))


def _deployer_identity_requirements(review_policy: dict[str, Any]) -> dict[str, Any]:
    return _identity_policy_requirements(review_policy.get("deployer_identity_requirements", {}))


def _identity_requirements_configured(requirements: dict[str, Any]) -> bool:
    payload = requirements if isinstance(requirements, dict) else {}
    return bool(
        payload.get("required_roles")
        or payload.get("allowed_kinds")
        or payload.get("required_teams")
        or payload.get("required_authn_strength")
        or payload.get("require_distinct_from_reviewers")
    )


def _reviewer_roles_map(review_policy: dict[str, Any]) -> dict[str, list[str]]:
    return {
        actor: list(item.get("roles", []))
        for actor, item in _reviewer_identities(review_policy).items()
        if isinstance(item, dict)
    }


def _reviewer_roles(reviewer: str, review_policy: dict[str, Any]) -> list[str]:
    reviewer_name = str(reviewer or "").strip()
    if not reviewer_name:
        return []
    return list(_reviewer_roles_map(review_policy).get(reviewer_name, []))


def _authorized_reviewer(reviewer: str, review_policy: dict[str, Any]) -> bool:
    reviewer_name = str(reviewer or "").strip()
    if not reviewer_name:
        return False
    allowed = set([str(item).strip() for item in review_policy.get("authorized_reviewers", []) if str(item).strip()])
    allowed.update(_reviewer_identities(review_policy).keys())
    if not allowed:
        return True
    return reviewer_name in allowed


def _authorized_deployer(deployer: str, review_policy: dict[str, Any]) -> bool:
    deployer_name = str(deployer or "").strip()
    if not deployer_name:
        return False
    allowed = set(
        [
            str(item).strip()
            for item in (
                review_policy.get("authorized_deployers", review_policy.get("authorized_publishers", []))
                if isinstance(review_policy.get("authorized_deployers", review_policy.get("authorized_publishers", [])), list)
                else []
            )
            if str(item).strip()
        ]
    )
    allowed.update(_deployer_identities(review_policy).keys())
    if not allowed:
        return True
    return deployer_name in allowed


def _resolve_policy_identity(actor: str, review_policy: dict[str, Any], *, phase: str) -> dict[str, Any]:
    actor_name = str(actor or "").strip()
    if not actor_name:
        return {}
    if phase == "publish":
        identities = _deployer_identities(review_policy)
    else:
        identities = _reviewer_identities(review_policy)
    identity = identities.get(actor_name, {})
    return dict(identity) if isinstance(identity, dict) else {}


def _evaluate_policy_identity(
    actor: str,
    review_policy: dict[str, Any],
    *,
    phase: str,
    distinct_from: Optional[list[str]] = None,
) -> dict[str, Any]:
    actor_name = str(actor or "").strip()
    identity = _resolve_policy_identity(actor_name, review_policy, phase=phase)
    requirements = _deployer_identity_requirements(review_policy) if phase == "publish" else _reviewer_identity_requirements(review_policy)
    identities = _deployer_identities(review_policy) if phase == "publish" else _reviewer_identities(review_policy)
    require_configured = bool(identities) or _identity_requirements_configured(requirements)
    failures: list[str] = []
    roles = _coerce_reviewer_roles(identity.get("roles", [])) if identity else []
    allowed_phases = _normalize_identity_phases(identity.get("allowed_phases", [])) if identity else []
    team = str(identity.get("team", "")).strip() if identity else ""
    kind = _normalize_identity_kind(identity.get("kind", "")) if identity else ""
    authn_strength = _normalize_authn_strength(identity.get("authn_strength", "")) if identity else ""
    missing_roles = [role for role in requirements.get("required_roles", []) if role not in roles]
    if require_configured and not identity:
        failures.append("identity_not_configured")
    if identity and allowed_phases and str(phase).strip() not in allowed_phases:
        failures.append("phase_not_allowed")
    if identity and requirements.get("allowed_kinds") and kind not in requirements.get("allowed_kinds", []):
        failures.append("identity_kind_not_allowed")
    if identity and requirements.get("required_teams") and team not in requirements.get("required_teams", []):
        failures.append("identity_team_not_allowed")
    if identity and requirements.get("required_authn_strength"):
        required_strength = str(requirements.get("required_authn_strength", "")).strip()
        if _authn_strength_rank(authn_strength) < _authn_strength_rank(required_strength):
            failures.append("authn_strength_below_required")
    if missing_roles:
        failures.append("missing_required_roles")
    distinct_from_names = {str(item).strip() for item in (distinct_from or []) if str(item).strip()}
    if (
        actor_name
        and bool(requirements.get("require_distinct_from_reviewers", False))
        and actor_name in distinct_from_names
    ):
        failures.append("not_distinct_from_reviewers")
    return {
        "actor": actor_name,
        "subject": str(identity.get("subject", actor_name)).strip() if identity else actor_name,
        "configured": bool(identity),
        "phase": str(phase).strip(),
        "roles": roles,
        "team": team,
        "kind": kind,
        "authn_strength": authn_strength,
        "allowed_phases": allowed_phases,
        "missing_roles": missing_roles,
        "requirements": requirements,
        "failures": failures,
        "pass": not failures,
    }


def _required_approval_roles(review_policy: dict[str, Any]) -> list[str]:
    return _coerce_reviewer_roles(review_policy.get("required_approval_roles", []))


def _minimum_required_approvals(review_policy: dict[str, Any]) -> int:
    try:
        return max(1, int(review_policy.get("min_approvals", 1) or 1))
    except Exception:
        return 1


def _require_distinct_reviewers(review_policy: dict[str, Any]) -> bool:
    return bool(
        review_policy.get("require_distinct_reviewers", False)
        or review_policy.get("require_separation_of_duties", False)
    )


def _required_run_statuses(review_policy: dict[str, Any]) -> set[str]:
    configured = review_policy.get("required_run_statuses", [])
    if not isinstance(configured, list) or not configured:
        return {"completed"}
    return set([str(item).strip() for item in configured if str(item).strip()])


