def _required_artifact_keys(
    review_policy: dict[str, Any],
    *,
    phase: str = "approval",
    publish_environment: str = "",
) -> list[str]:
    configured = review_policy.get("required_artifacts", [])
    out = [str(item).strip() for item in configured if str(item).strip()] if isinstance(configured, list) and configured else [
        "run_report",
        "run_summary",
        "run_traceability",
        "run_subsystem_index",
    ]
    if phase == "publish":
        normalized_environment = _normalize_publish_environment(publish_environment)
        environment_policy = _publish_environment_directory(review_policy).get(normalized_environment, {}) if normalized_environment else {}
        if isinstance(environment_policy, dict):
            for item in environment_policy.get("required_artifacts", []):
                artifact_key = str(item).strip()
                if artifact_key and artifact_key not in out:
                    out.append(artifact_key)
    return out


def _normalize_publish_environment(value: Any) -> str:
    return _normalize_reviewer_role(value)


def _publish_environment_directory(review_policy: dict[str, Any]) -> dict[str, dict[str, Any]]:
    configured = review_policy.get("publish_environments", {})
    if not isinstance(configured, dict):
        return {}
    out: dict[str, dict[str, Any]] = {}
    for raw_name, raw_item in configured.items():
        environment = _normalize_publish_environment(raw_name)
        if not environment:
            continue
        item = raw_item if isinstance(raw_item, dict) else {}
        max_run_diff_metric_deltas: dict[str, int] = {}
        raw_run_diff_metric_deltas = item.get("max_run_diff_metric_deltas", {})
        if isinstance(raw_run_diff_metric_deltas, dict):
            for raw_metric_name, raw_limit in raw_run_diff_metric_deltas.items():
                metric_name = str(raw_metric_name).strip()
                if not metric_name or not str(raw_limit).strip():
                    continue
                try:
                    max_run_diff_metric_deltas[metric_name] = int(raw_limit)
                except (TypeError, ValueError):
                    continue
        predecessors = [
            predecessor
            for predecessor in [
                _normalize_publish_environment(value)
                for value in (
                    item.get("required_predecessors", item.get("requires", item.get("promote_from", [])))
                )
            ]
            if predecessor
        ]
        out[environment] = {
            "name": environment,
            "required_predecessors": predecessors,
            "max_publish_classification": normalize_data_classification(str(item.get("max_publish_classification", "")).strip())
            if str(item.get("max_publish_classification", "")).strip()
            else "",
            "required_artifacts": [str(value).strip() for value in item.get("required_artifacts", []) if str(value).strip()]
            if isinstance(item.get("required_artifacts", []), list)
            else [],
            "required_external_integrations": _normalize_identity_string_list(item.get("required_external_integrations", [])),
            "required_external_categories": _normalize_identity_string_list(item.get("required_external_categories", [])),
            "required_external_operations": _normalize_identity_string_list(item.get("required_external_operations", [])),
            "required_executed_external_operations": _normalize_identity_string_list(item.get("required_executed_external_operations", [])),
            "required_local_executed_external_operations": _normalize_identity_string_list(
                item.get("required_local_executed_external_operations", [])
            ),
            "required_remote_executed_external_operations": _normalize_identity_string_list(
                item.get("required_remote_executed_external_operations", [])
            ),
            "require_dispatch_result_pass": bool(item.get("require_dispatch_result_pass", False)),
            "require_run_diff_artifact": bool(item.get("require_run_diff_artifact", False)),
            "disallow_fact_changes": bool(item.get("disallow_fact_changes", False)),
            "disallow_architecture_changes": bool(item.get("disallow_architecture_changes", False)),
            "max_run_diff_metric_deltas": max_run_diff_metric_deltas,
            "max_self_review_issue_count": int(item.get("max_self_review_issue_count", 0))
            if str(item.get("max_self_review_issue_count", "")).strip()
            else None,
            "max_contradiction_issue_count": int(item.get("max_contradiction_issue_count", 0))
            if str(item.get("max_contradiction_issue_count", "")).strip()
            else None,
            "max_unsupported_claim_issue_count": int(item.get("max_unsupported_claim_issue_count", 0))
            if str(item.get("max_unsupported_claim_issue_count", "")).strip()
            else None,
            "max_semantically_unsupported_claims": int(item.get("max_semantically_unsupported_claims", 0))
            if str(item.get("max_semantically_unsupported_claims", "")).strip()
            else None,
        }
    return out


def _default_publish_environment(review_policy: dict[str, Any]) -> str:
    return _normalize_publish_environment(review_policy.get("default_publish_environment", ""))


def _max_publish_classification(review_policy: dict[str, Any], publish_environment: str = "") -> str:
    normalized_environment = _normalize_publish_environment(publish_environment)
    if normalized_environment:
        environment_policy = _publish_environment_directory(review_policy).get(normalized_environment, {})
        if isinstance(environment_policy, dict):
            environment_limit = str(environment_policy.get("max_publish_classification", "")).strip()
            if environment_limit:
                return normalize_data_classification(environment_limit)
    raw = str(review_policy.get("max_publish_classification", "")).strip()
    return normalize_data_classification(raw) if raw else ""


def _resolve_optional_publish_limit(
    review_policy: dict[str, Any],
    field_name: str,
    *,
    publish_environment: str = "",
) -> Optional[int]:
    normalized_environment = _normalize_publish_environment(publish_environment)
    if normalized_environment:
        environment_policy = _publish_environment_directory(review_policy).get(normalized_environment, {})
        if isinstance(environment_policy, dict) and environment_policy.get(field_name) is not None:
            try:
                return max(0, int(environment_policy.get(field_name, 0) or 0))
            except Exception:
                return None
    raw = review_policy.get(field_name, None)
    if raw is None or str(raw).strip() == "":
        return None
    try:
        return max(0, int(raw or 0))
    except Exception:
        return None


def _max_self_review_issue_count(review_policy: dict[str, Any], publish_environment: str = "") -> Optional[int]:
    return _resolve_optional_publish_limit(
        review_policy,
        "max_self_review_issue_count",
        publish_environment=publish_environment,
    )


def _max_contradiction_issue_count(review_policy: dict[str, Any], publish_environment: str = "") -> Optional[int]:
    return _resolve_optional_publish_limit(
        review_policy,
        "max_contradiction_issue_count",
        publish_environment=publish_environment,
    )


def _max_unsupported_claim_issue_count(review_policy: dict[str, Any], publish_environment: str = "") -> Optional[int]:
    return _resolve_optional_publish_limit(
        review_policy,
        "max_unsupported_claim_issue_count",
        publish_environment=publish_environment,
    )


def _max_semantically_unsupported_claims(review_policy: dict[str, Any], publish_environment: str = "") -> Optional[int]:
    return _resolve_optional_publish_limit(
        review_policy,
        "max_semantically_unsupported_claims",
        publish_environment=publish_environment,
    )


def _load_publish_manifests_for_run(publish_root: str, run_id: str) -> list[dict[str, Any]]:
    root = os.path.abspath(os.path.expanduser(str(publish_root or "").strip()))
    normalized_run_id = str(run_id or "").strip()
    if not root or not normalized_run_id or not os.path.isdir(root):
        return []
    manifests: list[dict[str, Any]] = []
    for current_root, _, files in os.walk(root):
        if RUN_PUBLISH_MANIFEST_FILENAME not in files:
            continue
        path = os.path.join(current_root, RUN_PUBLISH_MANIFEST_FILENAME)
        payload = read_json_file(path)
        if not isinstance(payload, dict):
            continue
        if str(payload.get("run_id", "")).strip() != normalized_run_id:
            continue
        item = dict(payload)
        item["_manifest_path"] = path
        manifests.append(item)
    manifests.sort(key=lambda item: str(item.get("published_at", "")).strip())
    return manifests


def _evaluate_publish_environment_policy(
    review_policy: dict[str, Any],
    *,
    publish_root: str,
    run_id: str,
    publish_environment: str,
    external_integrations_audit: Optional[dict[str, Any]] = None,
    external_integration_dispatch_results: Optional[dict[str, Any]] = None,
    self_review_summary: Optional[dict[str, Any]] = None,
    contradiction_summary: Optional[dict[str, Any]] = None,
    unsupported_claim_summary: Optional[dict[str, Any]] = None,
    run_diff_summary: Optional[dict[str, Any]] = None,
    enforce_executed_operations: bool = True,
) -> dict[str, Any]:
    requested_environment = _normalize_publish_environment(publish_environment)
    environment_directory = _publish_environment_directory(review_policy)
    default_environment = _default_publish_environment(review_policy)
    configured = bool(environment_directory)
    normalized_environment = requested_environment
    if configured and not normalized_environment and default_environment and default_environment in environment_directory:
        normalized_environment = default_environment
    failures: list[str] = []
    if configured and not normalized_environment:
        failures.append("publish_environment_required")
    if requested_environment and configured and normalized_environment not in environment_directory:
        failures.append("publish_environment_not_configured")
    environment_policy = environment_directory.get(normalized_environment, {}) if normalized_environment else {}
    required_predecessors = (
        [str(item).strip() for item in environment_policy.get("required_predecessors", []) if str(item).strip()]
        if isinstance(environment_policy, dict)
        else []
    )
    prior_manifests = _load_publish_manifests_for_run(publish_root, run_id)
    prior_environments = sorted(
        {
            _normalize_publish_environment(item.get("publish_environment", ""))
            for item in prior_manifests
            if _normalize_publish_environment(item.get("publish_environment", ""))
        }
    )
    missing_predecessors = [env for env in required_predecessors if env not in prior_environments]
    if missing_predecessors:
        failures.append("missing_required_predecessor_environments")
    required_external_integrations = (
        [str(item).strip() for item in environment_policy.get("required_external_integrations", []) if str(item).strip()]
        if isinstance(environment_policy, dict)
        else []
    )
    required_external_categories = (
        [str(item).strip() for item in environment_policy.get("required_external_categories", []) if str(item).strip()]
        if isinstance(environment_policy, dict)
        else []
    )
    required_external_operations = (
        [str(item).strip() for item in environment_policy.get("required_external_operations", []) if str(item).strip()]
        if isinstance(environment_policy, dict)
        else []
    )
    required_executed_external_operations = (
        [str(item).strip() for item in environment_policy.get("required_executed_external_operations", []) if str(item).strip()]
        if isinstance(environment_policy, dict)
        else []
    )
    required_local_executed_external_operations = (
        [
            str(item).strip()
            for item in environment_policy.get("required_local_executed_external_operations", [])
            if str(item).strip()
        ]
        if isinstance(environment_policy, dict)
        else []
    )
    required_remote_executed_external_operations = (
        [
            str(item).strip()
            for item in environment_policy.get("required_remote_executed_external_operations", [])
            if str(item).strip()
        ]
        if isinstance(environment_policy, dict)
        else []
    )
    require_dispatch_result_pass = bool(environment_policy.get("require_dispatch_result_pass", False)) if isinstance(environment_policy, dict) else False
    require_run_diff_artifact = bool(environment_policy.get("require_run_diff_artifact", False)) if isinstance(environment_policy, dict) else False
    disallow_fact_changes = bool(environment_policy.get("disallow_fact_changes", False)) if isinstance(environment_policy, dict) else False
    disallow_architecture_changes = bool(environment_policy.get("disallow_architecture_changes", False)) if isinstance(environment_policy, dict) else False
    max_run_diff_metric_deltas = (
        dict(environment_policy.get("max_run_diff_metric_deltas", {}))
        if isinstance(environment_policy, dict) and isinstance(environment_policy.get("max_run_diff_metric_deltas", {}), dict)
        else {}
    )
    max_self_review_issue_count = _max_self_review_issue_count(review_policy, publish_environment=normalized_environment)
    max_contradiction_issue_count = _max_contradiction_issue_count(review_policy, publish_environment=normalized_environment)
    max_unsupported_claim_issue_count = _max_unsupported_claim_issue_count(review_policy, publish_environment=normalized_environment)
    max_semantically_unsupported_claims = _max_semantically_unsupported_claims(review_policy, publish_environment=normalized_environment)
    self_review_payload = self_review_summary if isinstance(self_review_summary, dict) else {}
    contradiction_payload = contradiction_summary if isinstance(contradiction_summary, dict) else {}
    unsupported_payload = unsupported_claim_summary if isinstance(unsupported_claim_summary, dict) else {}
    run_diff_payload = run_diff_summary if isinstance(run_diff_summary, dict) else {}
    self_review_issue_count = max(0, int(self_review_payload.get("issue_count", 0) or 0))
    contradiction_issue_count = max(0, int(contradiction_payload.get("issue_count", 0) or 0))
    unsupported_claim_issue_count = max(0, int(unsupported_payload.get("issue_count", 0) or 0))
    semantically_unsupported_claim_count = max(
        0,
        int(
            unsupported_payload.get(
                "claims_semantically_unsupported",
                unsupported_payload.get("issue_count", 0),
            )
            or 0
        ),
    )
    run_diff_present = bool(run_diff_payload.get("present", False))
    run_diff_metric_deltas = (
        {
            str(name).strip(): int(value or 0)
            for name, value in run_diff_payload.get("metric_deltas", {}).items()
            if str(name).strip()
        }
        if isinstance(run_diff_payload.get("metric_deltas", {}), dict)
        else {}
    )
    fact_changes_detected = bool(run_diff_payload.get("fact_changes_detected", False))
    architecture_changes_detected = bool(run_diff_payload.get("architecture_changes_detected", False))
    run_diff_metric_limit_exceeded: list[str] = []
    for metric_name, max_delta in max_run_diff_metric_deltas.items():
        if abs(int(run_diff_metric_deltas.get(metric_name, 0) or 0)) > int(max_delta):
            run_diff_metric_limit_exceeded.append(metric_name)
    missing_required_external_integrations: list[str] = []
    unready_required_external_integrations: list[str] = []
    missing_required_external_categories: list[str] = []
    unready_required_external_categories: list[str] = []
    missing_required_external_operations: list[str] = []
    unready_required_external_operations: list[str] = []
    unexecuted_required_external_operations: list[str] = []
    unexecuted_required_local_external_operations: list[str] = []
    unexecuted_required_remote_external_operations: list[str] = []
    dispatch_result_payload = (
        external_integration_dispatch_results
        if isinstance(external_integration_dispatch_results, dict)
        else {}
    )
    dispatch_result_items = (
        dispatch_result_payload.get("results", [])
        if isinstance(dispatch_result_payload.get("results", []), list)
        else []
    )
    dispatch_result_count = max(0, int(dispatch_result_payload.get("result_count", 0) or 0)) if dispatch_result_payload else 0
    dispatch_result_pass = bool(dispatch_result_payload.get("pass", False)) if dispatch_result_payload else False
    blocking_dispatch_result_failure_count = (
        max(0, int(dispatch_result_payload.get("blocking_result_failure_count", 0) or 0))
        if dispatch_result_payload
        else 0
    )
    failing_required_dispatch_results = [
        item
        for item in dispatch_result_items
        if isinstance(item, dict)
        and bool(item.get("required_for_phase", False))
        and not bool(item.get("pass", False))
    ]
    failing_required_dispatch_integrations = sorted(
        {
            str(item.get("name", "")).strip()
            for item in failing_required_dispatch_results
            if str(item.get("name", "")).strip()
        }
    )
    failing_required_dispatch_operations = sorted(
        {
            str(item.get("operation", "")).strip()
            for item in failing_required_dispatch_results
            if str(item.get("operation", "")).strip()
        }
    )
    failing_required_dispatch_transports = sorted(
        {
            str(item.get("transport", "")).strip()
            for item in failing_required_dispatch_results
            if str(item.get("transport", "")).strip()
        }
    )
    dispatch_result_failure_kinds = (
        [str(item).strip() for item in dispatch_result_payload.get("failure_kinds", []) if str(item).strip()]
        if dispatch_result_payload and isinstance(dispatch_result_payload.get("failure_kinds", []), list)
        else []
    )
    local_executed_external_operations = sorted(
        {
            str(item.get("operation", "")).strip()
            for item in dispatch_result_items
            if isinstance(item, dict)
            and bool(item.get("pass", False))
            and str(item.get("mode", "")).strip() == "local_execution"
            and str(item.get("operation", "")).strip()
        }
    )
    remote_executed_external_operations = sorted(
        {
            str(item.get("operation", "")).strip()
            for item in dispatch_result_items
            if isinstance(item, dict)
            and bool(item.get("pass", False))
            and str(item.get("mode", "")).strip() == "remote_execution"
            and str(item.get("operation", "")).strip()
        }
    )
    executed_external_operations = sorted(set(local_executed_external_operations + remote_executed_external_operations))
    integrations = (
        external_integrations_audit.get("integrations", [])
        if isinstance(external_integrations_audit, dict) and isinstance(external_integrations_audit.get("integrations", []), list)
        else []
    )
    if required_external_integrations or required_external_categories or required_external_operations:
        integration_by_name = {
            str(item.get("name", "")).strip(): item
            for item in integrations
            if isinstance(item, dict) and str(item.get("name", "")).strip()
        }
        integrations_by_category: dict[str, list[dict[str, Any]]] = {}
        integrations_by_operation: dict[str, list[dict[str, Any]]] = {}
        for item in integrations:
            if not isinstance(item, dict):
                continue
            category = str(item.get("category", "")).strip()
            if not category:
                continue
            integrations_by_category.setdefault(category, []).append(item)
            for operation in item.get("supported_operations", []):
                normalized_operation = str(operation).strip()
                if normalized_operation:
                    integrations_by_operation.setdefault(normalized_operation, []).append(item)
        missing_required_external_integrations = [
            name for name in required_external_integrations if name not in integration_by_name
        ]
        unready_required_external_integrations = [
            name
            for name in required_external_integrations
            if name in integration_by_name and not bool(integration_by_name[name].get("ready", False))
        ]
        missing_required_external_categories = [
            category for category in required_external_categories if category not in integrations_by_category
        ]
        unready_required_external_categories = [
            category
            for category in required_external_categories
            if category in integrations_by_category
            and not any(bool(item.get("ready", False)) for item in integrations_by_category[category])
        ]
        missing_required_external_operations = [
            operation for operation in required_external_operations if operation not in integrations_by_operation
        ]
        unready_required_external_operations = [
            operation
            for operation in required_external_operations
            if operation in integrations_by_operation
            and not any(bool(item.get("ready", False)) for item in integrations_by_operation[operation])
        ]
        if missing_required_external_integrations:
            failures.append("missing_required_external_integrations")
        if unready_required_external_integrations:
            failures.append("unready_required_external_integrations")
        if missing_required_external_categories:
            failures.append("missing_required_external_categories")
        if unready_required_external_categories:
            failures.append("unready_required_external_categories")
        if missing_required_external_operations:
            failures.append("missing_required_external_operations")
        if unready_required_external_operations:
            failures.append("unready_required_external_operations")
    if required_executed_external_operations and enforce_executed_operations:
        executed_external_operation_set = set(executed_external_operations)
        unexecuted_required_external_operations = [
            operation
            for operation in required_executed_external_operations
            if operation not in executed_external_operation_set
        ]
        if unexecuted_required_external_operations:
            failures.append("unexecuted_required_external_operations")
    if required_local_executed_external_operations and enforce_executed_operations:
        local_executed_external_operation_set = set(local_executed_external_operations)
        unexecuted_required_local_external_operations = [
            operation
            for operation in required_local_executed_external_operations
            if operation not in local_executed_external_operation_set
        ]
        if unexecuted_required_local_external_operations:
            failures.append("unexecuted_required_local_external_operations")
    if required_remote_executed_external_operations and enforce_executed_operations:
        remote_executed_external_operation_set = set(remote_executed_external_operations)
        unexecuted_required_remote_external_operations = [
            operation
            for operation in required_remote_executed_external_operations
            if operation not in remote_executed_external_operation_set
        ]
        if unexecuted_required_remote_external_operations:
            failures.append("unexecuted_required_remote_external_operations")
    if require_dispatch_result_pass:
        if dispatch_result_count <= 0:
            failures.append("missing_external_integration_dispatch_results")
        elif not dispatch_result_pass:
            failures.append("failing_external_integration_dispatch_results")
    if max_self_review_issue_count is not None and self_review_issue_count > max_self_review_issue_count:
        failures.append("self_review_issue_count_exceeds_max")
    if max_contradiction_issue_count is not None and contradiction_issue_count > max_contradiction_issue_count:
        failures.append("contradiction_issue_count_exceeds_max")
    if max_unsupported_claim_issue_count is not None and unsupported_claim_issue_count > max_unsupported_claim_issue_count:
        failures.append("unsupported_claim_issue_count_exceeds_max")
    if max_semantically_unsupported_claims is not None and semantically_unsupported_claim_count > max_semantically_unsupported_claims:
        failures.append("semantically_unsupported_claim_count_exceeds_max")
    if require_run_diff_artifact and not run_diff_present:
        failures.append("missing_run_diff_artifact")
    if disallow_fact_changes and fact_changes_detected:
        failures.append("run_diff_fact_changes_detected")
    if disallow_architecture_changes and architecture_changes_detected:
        failures.append("run_diff_architecture_changes_detected")
    if run_diff_metric_limit_exceeded:
        failures.append("run_diff_metric_delta_exceeds_max")
    return {
        "configured": configured,
        "default_environment": default_environment,
        "environment": normalized_environment,
        "failures": failures,
        "pass": not failures,
        "required_predecessors": required_predecessors,
        "satisfied_predecessors": [env for env in required_predecessors if env in prior_environments],
        "missing_predecessors": missing_predecessors,
        "required_artifacts": [str(item).strip() for item in environment_policy.get("required_artifacts", []) if str(item).strip()]
        if isinstance(environment_policy, dict)
        else [],
        "required_external_integrations": required_external_integrations,
        "required_external_categories": required_external_categories,
        "required_external_operations": required_external_operations,
        "required_executed_external_operations": required_executed_external_operations,
        "required_local_executed_external_operations": required_local_executed_external_operations,
        "required_remote_executed_external_operations": required_remote_executed_external_operations,
        "require_dispatch_result_pass": require_dispatch_result_pass,
        "require_run_diff_artifact": require_run_diff_artifact,
        "disallow_fact_changes": disallow_fact_changes,
        "disallow_architecture_changes": disallow_architecture_changes,
        "max_run_diff_metric_deltas": max_run_diff_metric_deltas,
        "missing_required_external_integrations": missing_required_external_integrations,
        "unready_required_external_integrations": unready_required_external_integrations,
        "missing_required_external_categories": missing_required_external_categories,
        "unready_required_external_categories": unready_required_external_categories,
        "missing_required_external_operations": missing_required_external_operations,
        "unready_required_external_operations": unready_required_external_operations,
        "local_executed_external_operations": local_executed_external_operations,
        "remote_executed_external_operations": remote_executed_external_operations,
        "executed_external_operations": executed_external_operations,
        "unexecuted_required_external_operations": unexecuted_required_external_operations,
        "unexecuted_required_local_external_operations": unexecuted_required_local_external_operations,
        "unexecuted_required_remote_external_operations": unexecuted_required_remote_external_operations,
        "dispatch_result_pass": dispatch_result_pass,
        "dispatch_result_count": dispatch_result_count,
        "blocking_dispatch_result_failure_count": blocking_dispatch_result_failure_count,
        "failing_required_dispatch_integrations": failing_required_dispatch_integrations,
        "failing_required_dispatch_operations": failing_required_dispatch_operations,
        "failing_required_dispatch_transports": failing_required_dispatch_transports,
        "dispatch_result_failure_kinds": dispatch_result_failure_kinds,
        "self_review_issue_count": self_review_issue_count,
        "contradiction_issue_count": contradiction_issue_count,
        "unsupported_claim_issue_count": unsupported_claim_issue_count,
        "semantically_unsupported_claim_count": semantically_unsupported_claim_count,
        "max_self_review_issue_count": max_self_review_issue_count,
        "max_contradiction_issue_count": max_contradiction_issue_count,
        "max_unsupported_claim_issue_count": max_unsupported_claim_issue_count,
        "max_semantically_unsupported_claims": max_semantically_unsupported_claims,
        "run_diff_present": run_diff_present,
        "run_diff_metric_deltas": run_diff_metric_deltas,
        "run_diff_metric_limit_exceeded": run_diff_metric_limit_exceeded,
        "fact_changes_detected": fact_changes_detected,
        "architecture_changes_detected": architecture_changes_detected,
        "prior_environments": prior_environments,
        "prior_publish_count": len(prior_manifests),
        "prior_manifest_paths": [str(item.get("_manifest_path", "")).strip() for item in prior_manifests if str(item.get("_manifest_path", "")).strip()],
    }


def _publish_environment_policy_failure_details(
    publish_environment_policy: dict[str, Any],
    *,
    requested_environment: str,
) -> list[str]:
    failures = [str(item).strip() for item in publish_environment_policy.get("failures", []) if str(item).strip()]
    details: list[str] = []
    if "publish_environment_required" in failures:
        default_environment = str(publish_environment_policy.get("default_environment", "")).strip()
        if default_environment:
            details.append(f"publish environment missing and no usable default was resolved from policy (configured default={default_environment})")
        else:
            details.append("publish environment is required by review policy")
    if "publish_environment_not_configured" in failures:
        details.append(
            f"publish environment `{requested_environment}` is not configured by review policy"
        )
    if "missing_required_predecessor_environments" in failures:
        missing_predecessors = [str(item).strip() for item in publish_environment_policy.get("missing_predecessors", []) if str(item).strip()]
        details.append(
            "missing required predecessor publish environment(s): " + ", ".join(missing_predecessors)
        )
    if "missing_required_external_integrations" in failures:
        missing_integrations = [
            str(item).strip()
            for item in publish_environment_policy.get("missing_required_external_integrations", [])
            if str(item).strip()
        ]
        details.append(
            "missing required external integration(s): " + ", ".join(missing_integrations)
        )
    if "unready_required_external_integrations" in failures:
        unready_integrations = [
            str(item).strip()
            for item in publish_environment_policy.get("unready_required_external_integrations", [])
            if str(item).strip()
        ]
        details.append(
            "required external integration(s) are not ready: " + ", ".join(unready_integrations)
        )
    if "missing_required_external_categories" in failures:
        missing_categories = [
            str(item).strip()
            for item in publish_environment_policy.get("missing_required_external_categories", [])
            if str(item).strip()
        ]
        details.append(
            "missing required external integration category or categories: " + ", ".join(missing_categories)
        )
    if "unready_required_external_categories" in failures:
        unready_categories = [
            str(item).strip()
            for item in publish_environment_policy.get("unready_required_external_categories", [])
            if str(item).strip()
        ]
        details.append(
            "required external integration category or categories are not ready: " + ", ".join(unready_categories)
        )
    if "missing_required_external_operations" in failures:
        missing_operations = [
            str(item).strip()
            for item in publish_environment_policy.get("missing_required_external_operations", [])
            if str(item).strip()
        ]
        details.append(
            "missing required external integration operation or operations: " + ", ".join(missing_operations)
        )
    if "unready_required_external_operations" in failures:
        unready_operations = [
            str(item).strip()
            for item in publish_environment_policy.get("unready_required_external_operations", [])
            if str(item).strip()
        ]
        details.append(
            "required external integration operation or operations are not ready: " + ", ".join(unready_operations)
        )
    if "unexecuted_required_external_operations" in failures:
        unexecuted_operations = [
            str(item).strip()
            for item in publish_environment_policy.get("unexecuted_required_external_operations", [])
            if str(item).strip()
        ]
        details.append(
            "required external integration operation or operations did not execute: " + ", ".join(unexecuted_operations)
        )
    if "unexecuted_required_local_external_operations" in failures:
        unexecuted_operations = [
            str(item).strip()
            for item in publish_environment_policy.get("unexecuted_required_local_external_operations", [])
            if str(item).strip()
        ]
        details.append(
            "required external integration operation or operations did not execute locally: "
            + ", ".join(unexecuted_operations)
        )
    if "unexecuted_required_remote_external_operations" in failures:
        unexecuted_operations = [
            str(item).strip()
            for item in publish_environment_policy.get("unexecuted_required_remote_external_operations", [])
            if str(item).strip()
        ]
        details.append(
            "required external integration operation or operations did not execute remotely: "
            + ", ".join(unexecuted_operations)
        )
    if "missing_external_integration_dispatch_results" in failures:
        details.append("required external integration dispatch results were not produced")
    if "failing_external_integration_dispatch_results" in failures:
        failing_operations = [
            str(item).strip()
            for item in publish_environment_policy.get("failing_required_dispatch_operations", [])
            if str(item).strip()
        ]
        failing_integrations = [
            str(item).strip()
            for item in publish_environment_policy.get("failing_required_dispatch_integrations", [])
            if str(item).strip()
        ]
        failing_transports = [
            str(item).strip()
            for item in publish_environment_policy.get("failing_required_dispatch_transports", [])
            if str(item).strip()
        ]
        dispatch_fragments: list[str] = []
        if failing_operations:
            dispatch_fragments.append("operations=" + ",".join(failing_operations))
        if failing_integrations:
            dispatch_fragments.append("integrations=" + ",".join(failing_integrations))
        if failing_transports:
            dispatch_fragments.append("transports=" + ",".join(failing_transports))
        if publish_environment_policy.get("dispatch_result_failure_kinds"):
            dispatch_fragments.append(
                "failure_kinds="
                + ",".join(
                    [
                        str(item).strip()
                        for item in publish_environment_policy.get("dispatch_result_failure_kinds", [])
                        if str(item).strip()
                    ]
                )
            )
        details.append(
            "required external integration dispatch result or results failed"
            + (": " + "; ".join(dispatch_fragments) if dispatch_fragments else "")
        )
    if "self_review_issue_count_exceeds_max" in failures:
        details.append(
            f"self review issue count {int(publish_environment_policy.get('self_review_issue_count', 0) or 0)} exceeds max "
            f"{int(publish_environment_policy.get('max_self_review_issue_count', 0) or 0)}"
        )
    if "contradiction_issue_count_exceeds_max" in failures:
        details.append(
            f"contradiction issue count {int(publish_environment_policy.get('contradiction_issue_count', 0) or 0)} exceeds max "
            f"{int(publish_environment_policy.get('max_contradiction_issue_count', 0) or 0)}"
        )
    if "unsupported_claim_issue_count_exceeds_max" in failures:
        details.append(
            f"unsupported claim issue count {int(publish_environment_policy.get('unsupported_claim_issue_count', 0) or 0)} exceeds max "
            f"{int(publish_environment_policy.get('max_unsupported_claim_issue_count', 0) or 0)}"
        )
    if "semantically_unsupported_claim_count_exceeds_max" in failures:
        details.append(
            f"semantically unsupported claim count {int(publish_environment_policy.get('semantically_unsupported_claim_count', 0) or 0)} exceeds max "
            f"{int(publish_environment_policy.get('max_semantically_unsupported_claims', 0) or 0)}"
        )
    if "missing_run_diff_artifact" in failures:
        details.append("required run diff artifact was not produced for this run")
    if "run_diff_fact_changes_detected" in failures:
        details.append("run diff detected fact changes and policy disallows fact drift")
    if "run_diff_architecture_changes_detected" in failures:
        details.append("run diff detected architecture changes and policy disallows architecture drift")
    if "run_diff_metric_delta_exceeds_max" in failures:
        exceeded_metrics = [
            str(item).strip()
            for item in publish_environment_policy.get("run_diff_metric_limit_exceeded", [])
            if str(item).strip()
        ]
        details.append(
            "run diff metric delta exceeds configured max"
            + (": " + ", ".join(exceeded_metrics) if exceeded_metrics else "")
        )
    return details


def _cleanup_partial_publish_path(publish_path: str) -> None:
    resolved = os.path.abspath(os.path.expanduser(str(publish_path or "").strip()))
    if resolved and os.path.exists(resolved):
        shutil.rmtree(resolved, ignore_errors=True)


def load_run_fact_index(run_path: str, state: Optional[dict[str, Any]] = None) -> Optional[dict[str, Any]]:
    candidate = ""
    if isinstance(state, dict):
        candidate = str(state.get("artifacts", {}).get("run_fact_index", "")).strip()
    if candidate and os.path.isfile(candidate):
        loaded = read_json_file(candidate)
        return loaded if isinstance(loaded, dict) else None
    fallback = os.path.join(run_path, "fact_index.json")
    loaded = read_json_file(fallback)
    return loaded if isinstance(loaded, dict) else None


def load_run_diff_summary(run_path: str, state: Optional[dict[str, Any]] = None) -> dict[str, Any]:
    candidate = ""
    if isinstance(state, dict):
        candidate = str(state.get("artifacts", {}).get("run_diff_json", "")).strip()
    resolved_path = ""
    payload: Optional[dict[str, Any]] = None
    if candidate and os.path.isfile(candidate):
        resolved_path = os.path.abspath(os.path.expanduser(candidate))
        loaded = read_json_file(resolved_path)
        if isinstance(loaded, dict):
            payload = loaded
    if payload is None:
        fallback = os.path.join(run_path, "run_diff.json")
        if os.path.isfile(fallback):
            resolved_path = fallback
            loaded = read_json_file(fallback)
            if isinstance(loaded, dict):
                payload = loaded
    if not isinstance(payload, dict):
        return {
            "present": False,
            "path": resolved_path,
            "metric_deltas": {},
            "fact_changes_detected": False,
            "architecture_changes_detected": False,
            "architecture_metric_deltas": {},
        }
    comparison = payload.get("comparison", {}) if isinstance(payload.get("comparison", {}), dict) else {}
    comparison_metrics = comparison.get("metrics", {}) if isinstance(comparison.get("metrics", {}), dict) else {}
    metric_deltas: dict[str, int] = {}
    for raw_name, raw_metric in comparison_metrics.items():
        if not isinstance(raw_metric, dict):
            continue
        metric_name = str(raw_name).strip()
        if not metric_name:
            continue
        metric_deltas[metric_name] = int(raw_metric.get("delta", 0) or 0)
    architecture = payload.get("architecture", {}) if isinstance(payload.get("architecture", {}), dict) else {}
    architecture_metrics_payload = architecture.get("metrics", {}) if isinstance(architecture.get("metrics", {}), dict) else {}
    architecture_metric_deltas: dict[str, int] = {}
    for raw_name, raw_metric in architecture_metrics_payload.items():
        if not isinstance(raw_metric, dict):
            continue
        metric_name = str(raw_name).strip()
        if not metric_name:
            continue
        architecture_metric_deltas[metric_name] = int(raw_metric.get("delta", 0) or 0)
    return {
        "present": True,
        "path": resolved_path,
        "metric_deltas": metric_deltas,
        "fact_changes_detected": any(delta != 0 for delta in metric_deltas.values()),
        "architecture_changes_detected": bool(architecture.get("changed", False))
        or any(delta != 0 for delta in architecture_metric_deltas.values()),
        "architecture_metric_deltas": architecture_metric_deltas,
    }


def load_run_classification_summary(run_path: str, state: Optional[dict[str, Any]] = None) -> dict[str, Any]:
    fact_index = load_run_fact_index(run_path, state=state)
    if not isinstance(fact_index, dict):
        return _empty_classification_summary()
    summary = fact_index.get("classification_summary", {})
    if not isinstance(summary, dict):
        return _empty_classification_summary()
    merged = _empty_classification_summary()
    merged.update(summary)
    return merged


def classification_within_review_policy(
    classification_summary: Optional[dict[str, Any]],
    review_policy: Optional[dict[str, Any]],
    *,
    publish_environment: str = "",
) -> tuple[bool, str]:
    summary = classification_summary if isinstance(classification_summary, dict) else _empty_classification_summary()
    policy = review_policy if isinstance(review_policy, dict) else {}
    max_allowed = _max_publish_classification(policy, publish_environment=publish_environment)
    highest = normalize_data_classification(summary.get("highest_classification", "unclassified"))
    if not max_allowed:
        return True, "Review policy does not cap publish classification."
    if not is_known_data_classification(max_allowed):
        return False, f"Review policy max_publish_classification `{max_allowed}` is not recognized."
    allowed = classification_rank(highest) <= classification_rank(max_allowed)
    return (
        allowed,
        f"Run highest classification `{highest}` must be <= `{max_allowed}` for publish.",
    )


def _artifact_exists(path: str) -> bool:
    return bool(path) and os.path.exists(path)


def approval_records_dir(run_path: str) -> str:
    return os.path.join(run_path, RUN_APPROVALS_DIRNAME)


def approval_record_filename(reviewer: str) -> str:
    return f"{sanitize_queue_scope_name(str(reviewer or '').strip(), default='reviewer')}.json"


def _approval_sort_key(payload: dict[str, Any]) -> tuple[str, str]:
    return (
        str(payload.get("approved_at", "")).strip(),
        str(payload.get("approved_by", "")).strip(),
    )


def load_run_approval_records(run_path: str, state: Optional[dict[str, Any]] = None) -> list[dict[str, Any]]:
    directories: list[str] = []
    if isinstance(state, dict):
        candidate = str(state.get("artifacts", {}).get("run_approvals_dir", "")).strip()
        if candidate:
            directories.append(candidate)
    directories.append(approval_records_dir(run_path))
    seen_paths: set[str] = set()
    out: list[dict[str, Any]] = []
    for directory in directories:
        if not directory or not os.path.isdir(directory):
            continue
        for name in sorted(os.listdir(directory)):
            if not name.endswith(".json"):
                continue
            path = os.path.join(directory, name)
            if path in seen_paths or not os.path.isfile(path):
                continue
            seen_paths.add(path)
            payload = read_json_file(path)
            if isinstance(payload, dict):
                out.append(payload)
        if out:
            out.sort(key=_approval_sort_key)
            return out

    summary_candidates: list[str] = []
    if isinstance(state, dict):
        candidate = str(state.get("artifacts", {}).get("run_approval", "")).strip()
        if candidate:
            summary_candidates.append(candidate)
    summary_candidates.append(os.path.join(run_path, RUN_APPROVAL_FILENAME))
    for path in summary_candidates:
        if not path or not os.path.isfile(path):
            continue
        payload = read_json_file(path)
        if not isinstance(payload, dict):
            continue
        approvals = payload.get("approvals", [])
        if isinstance(approvals, list) and approvals:
            out = [item for item in approvals if isinstance(item, dict)]
            out.sort(key=_approval_sort_key)
            return out
        reviewer = str(payload.get("approved_by", "")).strip()
        if reviewer:
            return [payload]
    return []


def _approval_identity_subject(approval: dict[str, Any]) -> str:
    if not isinstance(approval, dict):
        return ""
    identity = approval.get("reviewer_identity", {}) if isinstance(approval.get("reviewer_identity", {}), dict) else {}
    subject = str(identity.get("subject", "")).strip()
    if subject:
        return subject
    return str(approval.get("approved_by", "")).strip()


def _required_roles_assignable_to_distinct_reviewers(
    approvals: list[dict[str, Any]],
    required_roles: list[str],
) -> bool:
    normalized_roles = [role for role in _coerce_reviewer_roles(required_roles) if role]
    if not normalized_roles:
        return True
    reviewer_roles: list[tuple[str, set[str]]] = []
    for approval in approvals:
        reviewer = _approval_identity_subject(approval)
        roles = set(_coerce_reviewer_roles(approval.get("reviewer_roles", [])))
        if reviewer and roles:
            reviewer_roles.append((reviewer, roles))
    if not reviewer_roles:
        return False
    role_order = sorted(
        normalized_roles,
        key=lambda role: sum(1 for _reviewer, roles in reviewer_roles if role in roles),
    )

    def assign(index: int, used_reviewers: set[str]) -> bool:
        if index >= len(role_order):
            return True
        role = role_order[index]
        for reviewer, roles in reviewer_roles:
            if reviewer in used_reviewers or role not in roles:
                continue
            used_reviewers.add(reviewer)
            if assign(index + 1, used_reviewers):
                return True
            used_reviewers.remove(reviewer)
        return False

    return assign(0, set())


def summarize_approval_records(
    approval_records: list[dict[str, Any]],
    review_policy: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    policy = review_policy if isinstance(review_policy, dict) else {}
    reviewer_identity_directory = _reviewer_identities(policy)
    approvals: list[dict[str, Any]] = []
    for record in approval_records:
        if not isinstance(record, dict):
            continue
        reviewer = str(record.get("approved_by", "")).strip()
        if not reviewer:
            continue
        entry = dict(record)
        entry["approved_by"] = reviewer
        entry["approved_at"] = str(record.get("approved_at", "")).strip()
        entry["approval_notes"] = str(record.get("approval_notes", "")).strip()
        identity_check = _evaluate_policy_identity(reviewer, policy, phase="approval")
        entry["reviewer_identity"] = identity_check
        entry["reviewer_roles"] = _coerce_reviewer_roles(record.get("reviewer_roles", []) or identity_check.get("roles", []))
        approvals.append(entry)
    approvals.sort(key=_approval_sort_key)
    latest = approvals[-1] if approvals else {}
    distinct_reviewers = sorted({_approval_identity_subject(item) for item in approvals if _approval_identity_subject(item)})
    satisfied_roles = sorted({role for item in approvals for role in _coerce_reviewer_roles(item.get("reviewer_roles", []))})
    required_roles = _required_approval_roles(policy)
    missing_roles = [role for role in required_roles if role not in satisfied_roles]
    min_approvals = _minimum_required_approvals(policy)
    require_distinct = _require_distinct_reviewers(policy)
    approval_count = len(approvals)
    distinct_reviewer_count = len(distinct_reviewers)
    reviewer_identity_checks = [
        item.get("reviewer_identity", {})
        for item in approvals
        if isinstance(item.get("reviewer_identity", {}), dict)
    ]
    reviewer_identity_failures = [
        {
            "approved_by": str(item.get("approved_by", "")).strip(),
            "subject": str(item.get("reviewer_identity", {}).get("subject", "")).strip(),
            "failures": item.get("reviewer_identity", {}).get("failures", []),
        }
        for item in approvals
        if isinstance(item.get("reviewer_identity", {}), dict) and not bool(item.get("reviewer_identity", {}).get("pass", False))
    ]
    reviewer_identity_subjects = sorted(
        {
            str(item.get("subject", "")).strip()
            for item in reviewer_identity_checks
            if str(item.get("subject", "")).strip()
        }
    )
    reviewer_identity_requirements_met = bool(approvals) and not reviewer_identity_failures
    role_separation_satisfied = (
        _required_roles_assignable_to_distinct_reviewers(approvals, required_roles)
        if require_distinct and required_roles
        else True
    )
    approval_requirements_met = bool(approvals) and approval_count >= min_approvals and not missing_roles
    if require_distinct:
        approval_requirements_met = (
            approval_requirements_met
            and distinct_reviewer_count >= min_approvals
            and role_separation_satisfied
        )
    approval_requirements_met = approval_requirements_met and reviewer_identity_requirements_met
    summary: dict[str, Any] = {
        "approved_at": str(latest.get("approved_at", "")).strip(),
        "approved_by": str(latest.get("approved_by", "")).strip(),
        "approval_notes": str(latest.get("approval_notes", "")).strip(),
        "approval_count": approval_count,
        "distinct_reviewer_count": distinct_reviewer_count,
        "reviewers": distinct_reviewers,
        "approvals": approvals,
        "reviewer_identity_count": len(reviewer_identity_subjects),
        "reviewer_identity_subjects": reviewer_identity_subjects,
        "reviewer_identity_requirements_met": reviewer_identity_requirements_met,
        "reviewer_identity_failure_count": len(reviewer_identity_failures),
        "reviewer_identity_failures": reviewer_identity_failures,
        "required_approval_roles": required_roles,
        "satisfied_approval_roles": satisfied_roles,
        "missing_approval_roles": missing_roles,
        "min_approvals": min_approvals,
        "require_distinct_reviewers": require_distinct,
        "role_separation_satisfied": role_separation_satisfied,
        "approval_requirements_met": approval_requirements_met,
    }
    if reviewer_identity_directory:
        summary["reviewer_identity_directory"] = sorted(reviewer_identity_directory.keys())
    for key in [
        "review_policy_path",
        "run_id",
        "run_path",
        "repo_path",
        "run_status",
        "required_run_statuses",
        "required_artifacts",
        "classification_summary",
        "endpoint_quality_summary",
        "max_publish_classification",
        "artifact_hashes",
    ]:
        if key in latest:
            summary[key] = latest[key]
    summary["signature"] = sign_audit_payload(summary)
    return summary


def approval_within_review_policy(
    approval_summary: Optional[dict[str, Any]],
    review_policy: Optional[dict[str, Any]],
) -> tuple[bool, str]:
    policy = review_policy if isinstance(review_policy, dict) else {}
    summary = approval_summary if isinstance(approval_summary, dict) else {}
    approval_count = max(0, int(summary.get("approval_count", 0) or 0))
    if approval_count <= 0:
        return False, "Publish requires at least one reviewer approval."
    if bool(summary.get("approval_requirements_met", False)):
        return True, "Approval requirements satisfied."
    details: list[str] = []
    min_approvals = _minimum_required_approvals(policy)
    if approval_count < min_approvals:
        details.append(f"need at least {min_approvals} approval(s), found {approval_count}")
    missing_roles = [str(item).strip() for item in summary.get("missing_approval_roles", []) if str(item).strip()]
    if missing_roles:
        details.append(f"missing required approval roles: {', '.join(missing_roles)}")
    if _require_distinct_reviewers(policy):
        distinct_count = max(0, int(summary.get("distinct_reviewer_count", 0) or 0))
        if distinct_count < min_approvals:
            details.append(f"need {min_approvals} distinct reviewer(s), found {distinct_count}")
        if _required_approval_roles(policy) and not bool(summary.get("role_separation_satisfied", False)):
            details.append("required approval roles are not covered by distinct reviewers")
    if not bool(summary.get("reviewer_identity_requirements_met", True)):
        details.append("reviewer identity requirements are not satisfied")
    if not details:
        details.append("approval requirements are not satisfied")
    return False, "; ".join(details)


def _artifact_hash_entry(key: str, path: str) -> dict[str, Any]:
    absolute = os.path.abspath(os.path.expanduser(path))
    payload = {
        "artifact_key": key,
        "path": absolute,
        "exists": os.path.exists(absolute),
        "kind": "directory" if os.path.isdir(absolute) else "file",
    }
    if os.path.isfile(absolute):
        payload["sha256"] = sha256_file(absolute)
        payload["size_bytes"] = os.path.getsize(absolute)
    elif os.path.isdir(absolute):
        child_entries: list[dict[str, Any]] = []
        for root, _, files in os.walk(absolute):
            for name in sorted(files):
                file_path = os.path.join(root, name)
                child_entries.append(
                    {
                        "relative_path": os.path.relpath(file_path, absolute).replace("\\", "/"),
                        "sha256": sha256_file(file_path),
                        "size_bytes": os.path.getsize(file_path),
                    }
                )
        payload["children"] = child_entries
    return payload


def _copy_publish_artifact(source: str, destination: str) -> None:
    if os.path.isdir(source):
        shutil.copytree(source, destination)
        return
    parent = os.path.dirname(destination)
    if parent:
        os.makedirs(parent, exist_ok=True)
    shutil.copyfile(source, destination)


def write_repo_report_shortcuts(report_home_dir: str, run_path: str, summary_path: str, report_path: str) -> dict[str, str]:
    root = os.path.abspath(os.path.expanduser(str(report_home_dir or "").strip()))
    if not root:
        return {}
    os.makedirs(root, exist_ok=True)
    artifacts: dict[str, str] = {}

    if os.path.isfile(summary_path):
        summary_target = os.path.join(root, "SUMMARY.md")
        _copy_publish_artifact(summary_path, summary_target)
        artifacts["repo_summary"] = summary_target

    if os.path.isfile(report_path):
        report_target = os.path.join(root, "LATEST_REPORT.md")
        _copy_publish_artifact(report_path, report_target)
        artifacts["repo_report"] = report_target

    traceability_md = os.path.join(run_path, "traceability.md")
    if os.path.isfile(traceability_md):
        traceability_target = os.path.join(root, "LATEST_TRACEABILITY.md")
        _copy_publish_artifact(traceability_md, traceability_target)
        artifacts["repo_traceability"] = traceability_target

    architecture_png = os.path.join(run_path, "architecture_clean.png")
    if os.path.isfile(architecture_png):
        architecture_target = os.path.join(root, "LATEST_ARCHITECTURE.png")
        _copy_publish_artifact(architecture_png, architecture_target)
        artifacts["repo_architecture_png"] = architecture_target

    note_path = os.path.join(root, "README.txt")
    note_lines = [
        "Code Analyzer output bundle",
        "",
        f"Repo label: {os.path.basename(root)}",
        f"Latest run folder: {run_path}",
        f"Run artifacts folder: {os.path.join(root, DEFAULT_REPO_REPORTS_DIRNAME)}",
    ]
    if os.path.isfile(summary_path):
        note_lines.append("Quick summary: SUMMARY.md")
    if os.path.isfile(report_path):
        note_lines.append("Latest report: LATEST_REPORT.md")
    if os.path.isfile(architecture_png):
        note_lines.append("Latest architecture image: LATEST_ARCHITECTURE.png")
    write_text_atomic(note_path, "\n".join(note_lines) + "\n")
    artifacts["repo_bundle_note"] = note_path
    return artifacts


def resolve_llm_output_policy(value: str = "") -> str:
    normalized = str(value or "").strip().lower() or DEFAULT_LLM_OUTPUT_POLICY
    return normalized if normalized in {"strict_gate", "best_effort"} else "best_effort"


def llm_best_effort_enabled(value: str = "") -> bool:
    return resolve_llm_output_policy(value) == "best_effort"


def write_llm_iteration_draft(run_path: str, iteration: int, text: str) -> str:
    path = os.path.join(run_path, f"llm_iteration_{max(1, int(iteration or 1))}_draft.md")
    write_text_atomic(path, text)
    return path


def llm_candidate_rank(validation: dict[str, Any], gate: dict[str, Any], draft: str) -> tuple[Any, ...]:
    claims_without_evidence = int(validation.get("claims_without_evidence", 10**9) or 0)
    unsupported = int(validation.get("claims_semantically_unsupported", 10**9) or 0)
    invalid_tokens = int(validation.get("invalid_evidence_tokens_count", 10**9) or 0)
    factual_bullets = int(validation.get("factual_bullet_count", 0) or 0)
    coverage = float(gate.get("coverage", 0.0) or 0.0)
    semantic_coverage = float(gate.get("semantic_coverage", 0.0) or 0.0)
    semantic_pass = 1 if gate.get("semantic_pass", False) else 0
    traceability_pass = 1 if gate.get("strict_traceability_pass", True) else 0
    return (
        1 if gate.get("pass", False) else 0,
        semantic_pass,
        traceability_pass,
        -claims_without_evidence,
        -unsupported,
        -invalid_tokens,
        semantic_coverage,
        coverage,
        factual_bullets,
        len(str(draft or "")),
    )


def choose_best_llm_candidate(candidates: list[dict[str, Any]]) -> Optional[dict[str, Any]]:
    if not candidates:
        return None
    return max(candidates, key=lambda item: llm_candidate_rank(item.get("validation", {}), item.get("gate", {}), item.get("draft", "")))


def sanitize_queue_scope_name(value: str, default: str = "") -> str:
    text = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(value or "").strip()).strip("._-")
    return text or default


def resolve_queue_name(queue_name: str = "", queue_class: str = "") -> str:
    explicit = sanitize_queue_scope_name(queue_name)
    if explicit:
        return explicit
    return sanitize_queue_scope_name(queue_class)


def resolve_queue_class(queue_class: str = "") -> str:
    return sanitize_queue_scope_name(queue_class)


def queue_namespace_root(queue_dir: str) -> str:
    return os.path.join(resolve_queue_dir(queue_dir), QUEUE_NAMESPACE_DIRNAME)


def queue_scope_descriptor(queue_dir: str, queue_name: str = "", queue_class: str = "") -> dict[str, str]:
    queue_root_dir = resolve_queue_dir(queue_dir)
    resolved_queue_name = resolve_queue_name(queue_name, queue_class)
    resolved_queue_class = resolve_queue_class(queue_class)
    queue_scope = resolved_queue_name or QUEUE_ROOT_SCOPE_NAME
    queue_label = resolved_queue_name or QUEUE_ROOT_SCOPE_LABEL
    actual_queue_dir = queue_root_dir if not resolved_queue_name else os.path.join(queue_namespace_root(queue_root_dir), resolved_queue_name)
    return {
        "queue_root_dir": queue_root_dir,
        "queue_dir": actual_queue_dir,
        "queue_name": resolved_queue_name,
        "queue_class": resolved_queue_class,
        "queue_scope": queue_scope,
        "queue_label": queue_label,
        "is_named": bool(resolved_queue_name),
    }


def resolve_queue_scope_dir(queue_dir: str, queue_name: str = "", queue_class: str = "") -> str:
    return queue_scope_descriptor(queue_dir, queue_name, queue_class)["queue_dir"]


def describe_queue_scope_from_dir(queue_dir: str) -> dict[str, str]:
    resolved = resolve_queue_dir(queue_dir)
    parent = os.path.dirname(resolved)
    if os.path.basename(parent) == QUEUE_NAMESPACE_DIRNAME:
        queue_root_dir = os.path.dirname(parent)
        queue_name = os.path.basename(resolved)
        return {
            "queue_root_dir": queue_root_dir,
            "queue_dir": resolved,
            "queue_name": queue_name,
            "queue_class": "",
            "queue_scope": queue_name,
            "queue_label": queue_name,
            "is_named": True,
        }
    return {
        "queue_root_dir": resolved,
        "queue_dir": resolved,
        "queue_name": "",
        "queue_class": "",
        "queue_scope": QUEUE_ROOT_SCOPE_NAME,
        "queue_label": QUEUE_ROOT_SCOPE_LABEL,
        "is_named": False,
    }


def list_queue_scope_descriptors(queue_dir: str) -> list[dict[str, str]]:
    queue_root_dir = resolve_queue_dir(queue_dir)
    descriptors = [queue_scope_descriptor(queue_root_dir)]
    namespace_dir = queue_namespace_root(queue_root_dir)
    if os.path.isdir(namespace_dir):
        for name in sorted(os.listdir(namespace_dir)):
            path = os.path.join(namespace_dir, name)
            if not os.path.isdir(path):
                continue
            descriptors.append(
                {
                    "queue_root_dir": queue_root_dir,
                    "queue_dir": path,
                    "queue_name": name,
                    "queue_class": "",
                    "queue_scope": name,
                    "queue_label": name,
                    "is_named": True,
                }
            )
    return descriptors


def queue_dir_paths(queue_dir: str) -> dict[str, str]:
    root = resolve_queue_dir(queue_dir)
    return {
        "root": root,
        "pending": os.path.join(root, QUEUE_PENDING_DIRNAME),
        "running": os.path.join(root, QUEUE_RUNNING_DIRNAME),
        "completed": os.path.join(root, QUEUE_COMPLETED_DIRNAME),
        "failed": os.path.join(root, QUEUE_FAILED_DIRNAME),
        "workers": os.path.join(root, QUEUE_WORKERS_DIRNAME),
        "metrics": os.path.join(root, QUEUE_METRICS_FILENAME),
    }


def ensure_queue_dirs(queue_dir: str) -> dict[str, str]:
    paths = queue_dir_paths(queue_dir)
    for key in ["root", "pending", "running", "completed", "failed", "workers"]:
        ensure_dir(paths[key])
    return paths


def make_queue_job_id() -> str:
    return f"job_{time.strftime('%Y%m%d_%H%M%S', time.localtime())}_{os.getpid()}"


def _queue_job_priority(job: dict[str, Any]) -> int:
    try:
        return int(job.get("priority", QUEUE_DEFAULT_JOB_PRIORITY))
    except Exception:
        return QUEUE_DEFAULT_JOB_PRIORITY


def _queue_job_max_attempts(job: dict[str, Any]) -> int:
    try:
        parsed = int(job.get("max_attempts", QUEUE_DEFAULT_MAX_ATTEMPTS))
    except Exception:
        return QUEUE_DEFAULT_MAX_ATTEMPTS
    return max(1, parsed)


def _queue_job_retry_backoff_seconds(job: dict[str, Any]) -> float:
    return coerce_positive_float(job.get("retry_backoff_seconds", QUEUE_DEFAULT_RETRY_BACKOFF_SECONDS), QUEUE_DEFAULT_RETRY_BACKOFF_SECONDS)


def _queue_job_retry_backoff_multiplier(job: dict[str, Any]) -> float:
    return coerce_positive_float(
        job.get("retry_backoff_multiplier", QUEUE_DEFAULT_RETRY_BACKOFF_MULTIPLIER),
        QUEUE_DEFAULT_RETRY_BACKOFF_MULTIPLIER,
    )


def _queue_job_next_attempt_ts(job: dict[str, Any]) -> Optional[float]:
    return _parse_iso_timestamp(str(job.get("next_attempt_at", "")).strip())


def _queue_job_retry_delay_seconds(job: dict[str, Any], attempt_count: Optional[int] = None) -> float:
    attempts = int(attempt_count if attempt_count is not None else job.get("attempt_count", 0) or 0)
    base = _queue_job_retry_backoff_seconds(job)
    multiplier = _queue_job_retry_backoff_multiplier(job)
    return max(0.0, base * (multiplier ** max(0, attempts - 1)))


def _queue_job_ready(job: dict[str, Any], now_ts: Optional[float] = None) -> bool:
    next_attempt_ts = _queue_job_next_attempt_ts(job)
    if next_attempt_ts is None:
        return True
    current_ts = time.time() if now_ts is None else now_ts
    return next_attempt_ts <= current_ts


def _queue_job_queued_ts(job: dict[str, Any], path: str = "") -> float:
    queued_ts = _parse_iso_timestamp(str(job.get("queued_at", "")).strip())
    if queued_ts is not None:
        return queued_ts
    if path:
        try:
            return os.path.getmtime(path)
        except Exception:
            pass
    return 0.0


def _queue_job_sort_key(path: str, payload: dict[str, Any]) -> tuple[int, float, str]:
    return (-_queue_job_priority(payload), _queue_job_queued_ts(payload, path), os.path.basename(path))


def _queue_job_should_retry(job: dict[str, Any], result: dict[str, Any]) -> bool:
    status = str(result.get("status", "")).strip()
    if status not in QUEUE_RETRYABLE_RESULT_STATUSES:
        return False
    try:
        exit_code = int(result.get("exit_code", 1))
    except Exception:
        exit_code = 1
    if exit_code == 0:
        return False
    return int(job.get("attempt_count", 0) or 0) < _queue_job_max_attempts(job)


def _queue_retry_timestamp(delay_seconds: float) -> str:
    return time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(time.time() + max(0.0, float(delay_seconds))))


def schedule_queue_job_retry(queue_dir: str, current_path: str, payload: dict[str, Any], result: dict[str, Any]) -> str:
    paths = ensure_queue_dirs(queue_dir)
    delay_seconds = _queue_job_retry_delay_seconds(payload)
    run_path = str(result.get("run_path", "")).strip()
    payload["status"] = "pending"
    payload["worker_id"] = ""
    payload["active_run_path"] = ""
    payload["run_stage"] = ""
    payload["started_at"] = ""
    payload["finished_at"] = ""
    payload["last_failure_at"] = utc_now_iso()
    payload["last_status"] = str(result.get("status", "")).strip()
    try:
        payload["last_exit_code"] = int(result.get("exit_code", 1))
    except Exception:
        payload["last_exit_code"] = 1
    payload["last_run_path"] = run_path
    payload["next_attempt_at"] = _queue_retry_timestamp(delay_seconds)
    payload["last_retry_delay_seconds"] = delay_seconds
    payload["retry_count"] = int(payload.get("retry_count", 0) or 0) + 1
    if run_path and result.get("resumable"):
        payload["resume_run"] = run_path
    write_json_atomic(current_path, payload)
    pending_path = os.path.join(paths["pending"], os.path.basename(current_path))
    os.replace(current_path, pending_path)
    write_queue_metrics(queue_dir)
    return pending_path


def enqueue_queue_job(queue_dir: str, payload: dict[str, Any]) -> str:
    paths = ensure_queue_dirs(queue_dir)
    job_id = str(payload.get("job_id", "")).strip() or make_queue_job_id()
    payload["job_id"] = job_id
    payload["status"] = "pending"
    payload["queued_at"] = utc_now_iso()
    payload["priority"] = _queue_job_priority(payload)
    payload["max_attempts"] = _queue_job_max_attempts(payload)
    payload["retry_backoff_seconds"] = _queue_job_retry_backoff_seconds(payload)
    payload["retry_backoff_multiplier"] = _queue_job_retry_backoff_multiplier(payload)
    payload.setdefault("attempt_count", 0)
    payload.setdefault("retry_count", 0)
    payload.setdefault("reclaim_count", 0)
    payload.setdefault("next_attempt_at", "")
    path = os.path.join(paths["pending"], f"{job_id}.json")
    idx = 1
    while os.path.exists(path):
        job_id = f"{payload['job_id']}_{idx}"
        payload["job_id"] = job_id
        path = os.path.join(paths["pending"], f"{job_id}.json")
        idx += 1
    write_json_atomic(path, payload)
    write_queue_metrics(queue_dir)
    return path


def worker_heartbeat_path(queue_dir: str, worker_id: str) -> str:
    paths = ensure_queue_dirs(queue_dir)
    safe_worker_id = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(worker_id or "").strip()) or "worker"
    return os.path.join(paths["workers"], f"{safe_worker_id}.json")


def write_worker_heartbeat(
    queue_dir: str,
    worker_id: str,
    *,
    status: str,
    processed_count: int,
    current_job_id: str = "",
    current_run_path: str = "",
) -> str:
    path = worker_heartbeat_path(queue_dir, worker_id)
    payload = {
        "ts": utc_now_iso(),
        "worker_id": str(worker_id or "").strip(),
        "pid": os.getpid(),
        "status": str(status or "").strip(),
        "processed_count": int(processed_count),
        "current_job_id": str(current_job_id or "").strip(),
        "current_run_path": str(current_run_path or "").strip(),
    }
    write_json_atomic(path, payload)
    return path


def load_worker_heartbeat(queue_dir: str, worker_id: str) -> Optional[dict[str, Any]]:
    return read_json_file(worker_heartbeat_path(queue_dir, worker_id))


def remove_worker_heartbeat(queue_dir: str, worker_id: str) -> None:
    path = worker_heartbeat_path(queue_dir, worker_id)
    try:
        if os.path.exists(path):
            os.remove(path)
    except Exception:
        pass


def _queue_worker_heartbeat_is_stale(
    heartbeat: Optional[dict[str, Any]],
    stale_seconds: float = QUEUE_WORKER_HEARTBEAT_STALE_SECONDS,
) -> bool:
    if not isinstance(heartbeat, dict):
        return True
    ts = _parse_iso_timestamp(str(heartbeat.get("ts", "")).strip())
    if ts is None:
        return True
    return (time.time() - ts) > stale_seconds


def _queue_job_started_at(job: dict[str, Any]) -> Optional[float]:
    if not isinstance(job, dict):
        return None
    for key in ["started_at", "queued_at"]:
        ts = _parse_iso_timestamp(str(job.get(key, "")).strip())
        if ts is not None:
            return ts
    return None


def _load_run_state_heartbeat_for_job(job: dict[str, Any]) -> tuple[Optional[dict[str, Any]], Optional[dict[str, Any]]]:
    if not isinstance(job, dict):
        return None, None
    run_path = (
        str(job.get("active_run_path", "")).strip()
        or str(job.get("resume_run", "")).strip()
        or str(job.get("last_run_path", "")).strip()
    )
    if not run_path or not os.path.isdir(run_path):
        return None, None
    return load_run_state(run_path), load_run_heartbeat(run_path)


def _summarize_queue_job(path: str, payload: dict[str, Any]) -> dict[str, Any]:
    run_state, run_heartbeat = _load_run_state_heartbeat_for_job(payload)
    run_status = str(run_state.get("status", "")).strip() if isinstance(run_state, dict) else ""
    now_ts = time.time()
    next_attempt_ts = _queue_job_next_attempt_ts(payload)
    retry_in_seconds = None
    if next_attempt_ts is not None:
        retry_in_seconds = max(0, int(next_attempt_ts - now_ts))
    updated_at = ""
    try:
        updated_at = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(os.path.getmtime(path)))
    except Exception:
        updated_at = ""
    return {
        "job_id": str(payload.get("job_id", "")).strip(),
        "status": str(payload.get("status", "")).strip(),
        "repo_path": str(payload.get("repo_path", "")).strip(),
        "worker_id": str(payload.get("worker_id", "")).strip(),
        "priority": _queue_job_priority(payload),
        "attempt_count": int(payload.get("attempt_count", 0) or 0),
        "max_attempts": _queue_job_max_attempts(payload),
        "retry_count": int(payload.get("retry_count", 0) or 0),
        "reclaim_count": int(payload.get("reclaim_count", 0) or 0),
        "resume_run": str(payload.get("resume_run", "")).strip(),
        "active_run_path": str(payload.get("active_run_path", "")).strip(),
        "next_attempt_at": str(payload.get("next_attempt_at", "")).strip(),
        "ready": _queue_job_ready(payload, now_ts=now_ts),
        "retry_in_seconds": retry_in_seconds,
        "last_retry_delay_seconds": float(payload.get("last_retry_delay_seconds", 0) or 0),
        "last_status": str(payload.get("last_status", "")).strip(),
        "last_exit_code": int(payload.get("last_exit_code", 0) or 0) if str(payload.get("last_exit_code", "")).strip() else None,
        "run_status": run_status,
        "run_heartbeat_stale": _heartbeat_is_stale(run_heartbeat) if isinstance(run_heartbeat, dict) else None,
        "updated_at": updated_at,
        "path": path,
    }


def build_queue_metrics(queue_dir: str) -> dict[str, Any]:
    paths = ensure_queue_dirs(queue_dir)
    descriptor = describe_queue_scope_from_dir(queue_dir)
    queue_counts: dict[str, int] = {}
    recent_jobs: list[dict[str, Any]] = []
    stale_running_jobs = 0
    pending_ready = 0
    pending_delayed = 0
    for state_key in ["pending", "running", "completed", "failed"]:
        state_dir = paths[state_key]
        job_paths = sorted(
            [
                os.path.join(state_dir, name)
                for name in os.listdir(state_dir)
                if name.endswith(".json")
            ],
            key=lambda p: os.path.getmtime(p),
            reverse=True,
        )
        queue_counts[state_key] = len(job_paths)
        for path in job_paths[:STATUS_RECENT_LIMIT]:
            payload = read_json_file(path) or {}
            summary = _summarize_queue_job(path, payload)
            summary["queue_scope"] = descriptor["queue_scope"]
            summary["queue_name"] = descriptor["queue_name"]
            summary["queue_label"] = descriptor["queue_label"]
            if state_key == "pending":
                if summary["ready"]:
                    pending_ready += 1
                else:
                    pending_delayed += 1
            if state_key == "running":
                worker_heartbeat = load_worker_heartbeat(queue_dir, summary["worker_id"]) if summary["worker_id"] else None
                run_state, run_heartbeat = _load_run_state_heartbeat_for_job(payload)
                started_at = _queue_job_started_at(payload)
                is_stale = False
                if isinstance(run_heartbeat, dict) and not _heartbeat_is_stale(run_heartbeat):
                    is_stale = False
                elif isinstance(worker_heartbeat, dict) and not _queue_worker_heartbeat_is_stale(worker_heartbeat):
                    is_stale = False
                elif started_at is not None and (time.time() - started_at) > QUEUE_JOB_STALE_SECONDS:
                    is_stale = True
                summary["stale"] = is_stale
                summary["worker_heartbeat_stale"] = _queue_worker_heartbeat_is_stale(worker_heartbeat) if isinstance(worker_heartbeat, dict) else None
                if is_stale:
                    stale_running_jobs += 1
            recent_jobs.append(summary)

    if queue_counts.get("pending", 0) > len([job for job in recent_jobs if job.get("status") == "pending"]):
        pending_paths = [
            os.path.join(paths["pending"], name)
            for name in os.listdir(paths["pending"])
            if name.endswith(".json")
        ]
        pending_ready = 0
        pending_delayed = 0
        now_ts = time.time()
        for path in pending_paths:
            payload = read_json_file(path) or {}
            if _queue_job_ready(payload, now_ts=now_ts):
                pending_ready += 1
            else:
                pending_delayed += 1
    queue_counts["pending_ready"] = pending_ready
    queue_counts["pending_delayed"] = pending_delayed

    worker_paths = sorted(
        [
            os.path.join(paths["workers"], name)
            for name in os.listdir(paths["workers"])
            if name.endswith(".json")
        ],
        key=lambda p: os.path.getmtime(p),
        reverse=True,
    )
    worker_summaries: list[dict[str, Any]] = []
    active_workers = 0
    stale_workers = 0
    for path in worker_paths:
        payload = read_json_file(path) or {}
        stale = _queue_worker_heartbeat_is_stale(payload)
        if stale:
            stale_workers += 1
        else:
            active_workers += 1
        worker_summaries.append(
            {
                "worker_id": str(payload.get("worker_id", "")).strip(),
                "status": str(payload.get("status", "")).strip(),
                "processed_count": int(payload.get("processed_count", 0) or 0),
                "current_job_id": str(payload.get("current_job_id", "")).strip(),
                "current_run_path": str(payload.get("current_run_path", "")).strip(),
                "stale": stale,
                "ts": str(payload.get("ts", "")).strip(),
            }
        )

    return {
        "generated_at": utc_now_iso(),
        "queue_root_dir": descriptor["queue_root_dir"],
        "queue_dir": resolve_queue_dir(queue_dir),
        "queue_name": descriptor["queue_name"],
        "queue_class": descriptor["queue_class"],
        "queue_scope": descriptor["queue_scope"],
        "queue_label": descriptor["queue_label"],
        "counts": queue_counts,
        "workers": {
            "active": active_workers,
            "stale": stale_workers,
            "items": worker_summaries[:STATUS_RECENT_LIMIT],
        },
        "running_jobs": {
            "stale": stale_running_jobs,
        },
        "recent_jobs": recent_jobs[:STATUS_RECENT_LIMIT],
    }


def write_queue_metrics(queue_dir: str) -> str:
    paths = ensure_queue_dirs(queue_dir)
    metrics = build_queue_metrics(queue_dir)
    write_json_atomic(paths["metrics"], metrics)
    return paths["metrics"]


def aggregate_queue_metrics(queue_root_dir: str, queue_metrics_items: list[dict[str, Any]], limit: int = STATUS_RECENT_LIMIT) -> dict[str, Any]:
    aggregate_counts = {
        "pending": 0,
        "pending_ready": 0,
        "pending_delayed": 0,
        "running": 0,
        "completed": 0,
        "failed": 0,
    }
    active_workers = 0
    stale_workers = 0
    stale_running_jobs = 0
    worker_items: list[dict[str, Any]] = []
    recent_jobs: list[dict[str, Any]] = []

    for item in queue_metrics_items:
        metrics = item.get("metrics", {}) if isinstance(item, dict) else {}
        counts = metrics.get("counts", {}) if isinstance(metrics, dict) else {}
        for key in aggregate_counts:
            aggregate_counts[key] += int(counts.get(key, 0) or 0)
        workers = metrics.get("workers", {}) if isinstance(metrics, dict) else {}
        active_workers += int(workers.get("active", 0) or 0)
        stale_workers += int(workers.get("stale", 0) or 0)
        for worker in workers.get("items", []) if isinstance(workers, dict) else []:
            if not isinstance(worker, dict):
                continue
            annotated_worker = dict(worker)
            annotated_worker["queue_scope"] = str(item.get("queue_scope", "")).strip()
            annotated_worker["queue_label"] = str(item.get("queue_label", "")).strip()
            worker_items.append(annotated_worker)
        running_jobs = metrics.get("running_jobs", {}) if isinstance(metrics, dict) else {}
        stale_running_jobs += int(running_jobs.get("stale", 0) or 0)
        for job in metrics.get("recent_jobs", []) if isinstance(metrics, dict) else []:
            if not isinstance(job, dict):
                continue
            annotated_job = dict(job)
            annotated_job["queue_scope"] = str(item.get("queue_scope", "")).strip()
            annotated_job["queue_name"] = str(item.get("queue_name", "")).strip()
            annotated_job["queue_label"] = str(item.get("queue_label", "")).strip()
            recent_jobs.append(annotated_job)

    worker_items.sort(key=lambda item: _parse_iso_timestamp(str(item.get("ts", "")).strip()) or 0, reverse=True)
    recent_jobs.sort(key=lambda item: _parse_iso_timestamp(str(item.get("updated_at", "")).strip()) or 0, reverse=True)
    return {
        "generated_at": utc_now_iso(),
        "queue_root_dir": resolve_queue_dir(queue_root_dir),
        "queue_dir": resolve_queue_dir(queue_root_dir),
        "queue_name": "",
        "queue_class": "",
        "queue_scope": "all",
        "queue_label": "all",
        "counts": aggregate_counts,
        "workers": {
            "active": active_workers,
            "stale": stale_workers,
            "items": worker_items[: max(1, int(limit or STATUS_RECENT_LIMIT))],
        },
        "running_jobs": {
            "stale": stale_running_jobs,
        },
        "recent_jobs": recent_jobs[: max(1, int(limit or STATUS_RECENT_LIMIT))],
    }


def reclaim_stale_queue_jobs(queue_dir: str) -> dict[str, int]:
    paths = ensure_queue_dirs(queue_dir)
    reclaimed_to_pending = 0
    finalized_completed = 0
    finalized_failed = 0
    running_paths = sorted(
        [
            os.path.join(paths["running"], name)
            for name in os.listdir(paths["running"])
            if name.endswith(".json")
        ]
    )
    for current_path in running_paths:
        payload = read_json_file(current_path)
        if not isinstance(payload, dict):
            continue
        worker_id = str(payload.get("worker_id", "")).strip()
        worker_heartbeat = load_worker_heartbeat(queue_dir, worker_id) if worker_id else None
        run_state, run_heartbeat = _load_run_state_heartbeat_for_job(payload)
        started_at = _queue_job_started_at(payload)
        active_run_path = str(payload.get("active_run_path", "")).strip()
        run_status = str(run_state.get("status", "")).strip() if isinstance(run_state, dict) else ""

        if isinstance(run_heartbeat, dict) and not _heartbeat_is_stale(run_heartbeat):
            continue
        if isinstance(worker_heartbeat, dict) and not _queue_worker_heartbeat_is_stale(worker_heartbeat):
            continue
        if started_at is not None and (time.time() - started_at) <= QUEUE_JOB_STALE_SECONDS and not run_status:
            continue

        payload["stale_reclaimed_at"] = utc_now_iso()
        payload["stale_reclaimed"] = True
        payload["previous_worker_id"] = worker_id

        if run_status == "completed":
            payload["last_run_path"] = active_run_path or str(payload.get("resume_run", "")).strip()
            payload["last_status"] = run_status
            payload["last_exit_code"] = 0
            target = move_queue_job(queue_dir, current_path, "completed", payload)
            finalized_completed += 1
            continue

        if run_status in {"failed_gate", "failed_security_policy"}:
            payload["last_run_path"] = active_run_path or str(payload.get("resume_run", "")).strip()
            payload["last_status"] = run_status
            payload["last_exit_code"] = 2 if run_status == "failed_gate" else 1
            target = move_queue_job(queue_dir, current_path, "failed", payload)
            finalized_failed += 1
            continue

        if run_status == "error":
            retry_path = ""
            retry_result = {
                "exit_code": 1,
                "status": "error",
                "run_path": active_run_path or str(payload.get("resume_run", "")).strip(),
                "resumable": bool(active_run_path or str(payload.get("resume_run", "")).strip()),
            }
            if _queue_job_should_retry(payload, retry_result):
                retry_path = schedule_queue_job_retry(queue_dir, current_path, payload, retry_result)
                if retry_path:
                    reclaimed_to_pending += 1
                    continue
            payload["last_run_path"] = retry_result["run_path"]
            payload["last_status"] = "error"
            payload["last_exit_code"] = 1
            target = move_queue_job(queue_dir, current_path, "failed", payload)
            finalized_failed += 1
            continue

        payload["status"] = "pending"
        payload["worker_id"] = ""
        payload["active_run_path"] = ""
        if active_run_path:
            payload["resume_run"] = active_run_path
        payload["reclaim_count"] = int(payload.get("reclaim_count", 0) or 0) + 1
        write_json_atomic(current_path, payload)
        pending_path = os.path.join(paths["pending"], os.path.basename(current_path))
        try:
            os.replace(current_path, pending_path)
        except FileNotFoundError:
            continue
        reclaimed_to_pending += 1

    write_queue_metrics(queue_dir)
    return {
        "reclaimed_to_pending": reclaimed_to_pending,
        "finalized_completed": finalized_completed,
        "finalized_failed": finalized_failed,
    }


def claim_next_queue_job(
    queue_dir: str,
    worker_id: str,
) -> tuple[Optional[str], Optional[dict[str, Any]]]:
    paths = ensure_queue_dirs(queue_dir)
    candidate_items: list[tuple[tuple[int, float, str], str]] = []
    now_ts = time.time()
    for name in os.listdir(paths["pending"]):
        if not name.endswith(".json"):
            continue
        pending_path = os.path.join(paths["pending"], name)
        payload = read_json_file(pending_path) or {}
        if not _queue_job_ready(payload, now_ts=now_ts):
            continue
        candidate_items.append((_queue_job_sort_key(pending_path, payload), pending_path))
    for _, pending_path in sorted(candidate_items, key=lambda item: item[0]):
        basename = os.path.basename(pending_path)
        running_path = os.path.join(paths["running"], basename)
        try:
            os.replace(pending_path, running_path)
        except FileNotFoundError:
            continue
        payload = read_json_file(running_path) or {}
        payload["status"] = "running"
        payload["worker_id"] = worker_id
        payload["started_at"] = utc_now_iso()
        payload["priority"] = _queue_job_priority(payload)
        payload["max_attempts"] = _queue_job_max_attempts(payload)
        payload["retry_backoff_seconds"] = _queue_job_retry_backoff_seconds(payload)
        payload["retry_backoff_multiplier"] = _queue_job_retry_backoff_multiplier(payload)
        payload["next_attempt_at"] = ""
        payload["attempt_count"] = int(payload.get("attempt_count", 0) or 0) + 1
        write_json_atomic(running_path, payload)
        write_queue_metrics(queue_dir)
        return running_path, payload
    return None, None


def move_queue_job(queue_dir: str, current_path: str, target_state: str, payload: dict[str, Any]) -> str:
    paths = ensure_queue_dirs(queue_dir)
    target_dir = paths[target_state]
    target_path = os.path.join(target_dir, os.path.basename(current_path))
    payload["status"] = target_state
    payload["finished_at"] = utc_now_iso()
    write_json_atomic(current_path, payload)
    os.replace(current_path, target_path)
    write_queue_metrics(queue_dir)
    return target_path

def _compact_fact_items(
    items: Any,
    max_items: int,
    fields: Optional[list[str]] = None,
) -> tuple[list[dict[str, Any]], int]:
    if not isinstance(items, list):
        return [], 0
    out: list[dict[str, Any]] = []
    for item in items[:max_items]:
        if not isinstance(item, dict):
            continue
        if fields is None:
            out.append(item)
        else:
            trimmed = {}
            for field in fields:
                if field in item:
                    trimmed[field] = item[field]
            out.append(trimmed)
    return out, len(items)

def build_subsystem_prompt_summaries(fact_index: dict, max_subsystems: int = PROMPT_SUBSYSTEM_LIMIT) -> list[dict[str, Any]]:
    grouped: dict[str, dict[str, Any]] = {}

    def ensure_group(name: str) -> dict[str, Any]:
        return grouped.setdefault(
            name,
            {
                "name": name,
                "file_count": 0,
                "languages": {},
                "sample_files": [],
                "endpoints": [],
                "dependencies": [],
                "scripts": [],
                "sql_entities": [],
                "sql_queries": [],
                "language_symbols": [],
            },
        )

    for item in fact_index.get("files", []):
        path = str(item.get("path", "")).replace("\\", "/")
        if not path:
            continue
        group = ensure_group(derive_subsystem_name(path))
        group["file_count"] += 1
        lang = infer_language(path)
        group["languages"][lang] = group["languages"].get(lang, 0) + 1
        if len(group["sample_files"]) < PROMPT_SUBSYSTEM_SAMPLE_LIMIT:
            group["sample_files"].append(path)

    def add_items(kind: str, items: list[dict], text_builder) -> None:
        for item in items:
            path = str(item.get("file", "")).replace("\\", "/")
            if not path:
                continue
            group = ensure_group(derive_subsystem_name(path))
            if len(group[kind]) >= PROMPT_SUBSYSTEM_SAMPLE_LIMIT:
                continue
            text = text_builder(item)
            if text and text not in group[kind]:
                group[kind].append(text)

    add_items(
        "endpoints",
        fact_index.get("api_endpoints", []),
        lambda item: f"{str(item.get('method', 'GET')).upper()} {str(item.get('route', '/')).strip()}",
    )
    add_items(
        "dependencies",
        fact_index.get("dependencies", []),
        lambda item: str(item.get("name", "")).strip(),
    )
    add_items(
        "scripts",
        fact_index.get("scripts", []),
        lambda item: str(item.get("name", "")).strip(),
    )
    add_items(
        "sql_entities",
        fact_index.get("sql_entities", []),
        lambda item: f"{str(item.get('kind', '')).strip()} {str(item.get('name', '')).strip()}".strip(),
    )
    add_items(
        "sql_queries",
        fact_index.get("sql_queries", []),
        lambda item: f"{str(item.get('kind', '')).strip()} {str(item.get('target', '')).strip()}".strip(),
    )
    add_items(
        "language_symbols",
        fact_index.get("language_symbols", []),
        lambda item: f"{str(item.get('language', '')).strip()} {str(item.get('kind', '')).strip()} {str(item.get('qualname', '')).strip()}".strip(),
    )

    summaries = list(grouped.values())
    summaries.sort(key=lambda item: (-int(item.get("file_count", 0)), str(item.get("name", ""))))
    return summaries[:max_subsystems]


def subsystem_doc_slug(name: str) -> str:
    text = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(name or "").strip()).strip("._-")
    return text or "subsystem"


def subsystem_primary_evidence(subsystem: dict[str, Any]) -> str:
    sample_files = subsystem.get("sample_files", [])
    if isinstance(sample_files, list):
        for path in sample_files:
            normalized = str(path or "").replace("\\", "/").strip()
            if normalized:
                return f"{normalized}#L1"
    for key in ["endpoints", "dependencies", "scripts", "sql_entities", "sql_queries", "language_symbols"]:
        items = subsystem.get(key, [])
        if not isinstance(items, list):
            continue
        for item in items:
            if isinstance(item, dict):
                evidence = str(item.get("evidence", "")).strip()
                if evidence:
                    return evidence
    return "none"


def _subsystem_summary_line(label: str, value: str, evidence: str) -> str:
    if evidence and evidence != "none":
        return f"- {label}: {value} [Evidence: {evidence}]"
    return f"- {label}: {value}"


def write_subsystem_docs(run_path: str, fact_index: dict[str, Any]) -> dict[str, Any]:
    subsystem_dir = os.path.join(run_path, "subsystems")
    ensure_dir(subsystem_dir)
    summaries = build_subsystem_prompt_summaries(fact_index, max_subsystems=max(8, int(PROMPT_SUBSYSTEM_LIMIT or 8)))
    written_docs: list[dict[str, str]] = []
    seen_slugs: set[str] = set()
    for subsystem in summaries:
        name = str(subsystem.get("name", "")).strip() or "subsystem"
        slug = subsystem_doc_slug(name)
        original_slug = slug
        suffix = 2
        while slug in seen_slugs:
            slug = f"{original_slug}_{suffix}"
            suffix += 1
        seen_slugs.add(slug)
        doc_path = os.path.join(subsystem_dir, f"{slug}.md")
        evidence = subsystem_primary_evidence(subsystem)
        languages = subsystem.get("languages", {}) if isinstance(subsystem.get("languages", {}), dict) else {}
        language_summary = ", ".join(
            [f"{lang}:{int(count or 0)}" for lang, count in sorted(languages.items(), key=lambda item: (-int(item[1] or 0), str(item[0])))]
        ) or "unknown"
        lines = [
            f"# Subsystem: {name}",
            "",
            _subsystem_summary_line("Files", str(int(subsystem.get("file_count", 0) or 0)), evidence),
            _subsystem_summary_line("Languages", language_summary, evidence),
        ]
        sample_files = [str(item).replace("\\", "/").strip() for item in subsystem.get("sample_files", []) if str(item).strip()]
        if sample_files:
            lines.extend(["", "## Representative Files"])
            for path in sample_files:
                lines.append(_subsystem_summary_line("File", f"`{path}`", f"{path}#L1"))
        section_specs = [
            ("Endpoints", "endpoints"),
            ("Dependencies", "dependencies"),
            ("Scripts", "scripts"),
            ("SQL Entities", "sql_entities"),
            ("SQL Queries", "sql_queries"),
            ("Language Symbols", "language_symbols"),
        ]
        for heading, key in section_specs:
            values = [str(item).strip() for item in subsystem.get(key, []) if str(item).strip()]
            if not values:
                continue
            lines.extend(["", f"## {heading}"])
            for value in values:
                lines.append(_subsystem_summary_line(heading[:-1] if heading.endswith("s") else heading, value, evidence))
        write_text_atomic(doc_path, "\n".join(lines).rstrip() + "\n")
        written_docs.append({"name": name, "slug": slug, "path": doc_path, "evidence": evidence, "file_count": str(int(subsystem.get("file_count", 0) or 0))})

    readme_lines = ["# Subsystems", ""]
    if not written_docs:
        readme_lines.append("No subsystem-level groupings were generated for this run.")
    else:
        readme_lines.extend(
            [
                "| Subsystem | Files | Entry Doc |",
                "| --- | ---: | --- |",
            ]
        )
        for item in written_docs:
            readme_lines.append(
                f"| {item['name']} | {item['file_count']} | [{item['slug']}.md]({item['slug']}.md) |"
            )
    index_path = os.path.join(subsystem_dir, "README.md")
    write_text_atomic(index_path, "\n".join(readme_lines).rstrip() + "\n")
    return {
        "subsystem_count": len(written_docs),
        "run_subsystem_dir": subsystem_dir,
        "run_subsystem_index": index_path,
    }

def build_model_safe_fact_index(fact_index: dict) -> dict:
    safe = sanitize_fact_structure(fact_index)
    safe = refresh_architecture_views(safe)

    files, files_total = _compact_fact_items(
        safe.get("files", []),
        PROMPT_FACT_FILE_LIMIT,
        ["path", "line_count"],
    )
    entrypoints, entrypoints_total = _compact_fact_items(
        safe.get("entrypoints", []),
        PROMPT_FACT_ITEM_LIMIT,
        ["kind", "file", "line", "evidence"],
    )
    imports, imports_total = _compact_fact_items(
        safe.get("imports", []),
        PROMPT_FACT_ITEM_LIMIT,
        ["package", "file", "line", "evidence"],
    )
    dependencies, dependencies_total = _compact_fact_items(
        safe.get("dependencies", []),
        PROMPT_FACT_ITEM_LIMIT,
        ["name", "version", "file", "line", "evidence"],
    )
    api_endpoints, api_endpoints_total = _compact_fact_items(
        safe.get("api_endpoints", []),
        PROMPT_FACT_ITEM_LIMIT,
        ["method", "route", "framework", "file", "line", "evidence"],
    )
    scripts, scripts_total = _compact_fact_items(
        safe.get("scripts", []),
        PROMPT_FACT_ITEM_LIMIT,
        ["name", "command", "file", "line", "evidence"],
    )
    run_hints, run_hints_total = _compact_fact_items(
        safe.get("run_hints", []),
        PROMPT_FACT_SIGNAL_LIMIT,
        ["command", "file", "line", "evidence"],
    )
