    parser.add_argument(
        "--queue-dir",
        default="",
        help="File-backed queue directory for enqueue/worker mode. Defaults to outputs/job_queue.",
    )
    parser.add_argument(
        "--queue-name",
        default="",
        help="Optional named queue under --queue-dir/queues/<name> for enqueue/worker/status isolation.",
    )
    parser.add_argument(
        "--queue-class",
        default="",
        help="Optional queue class label. When --queue-name is omitted, it routes to a same-named queue scope.",
    )
    parser.add_argument(
        "--job-priority",
        type=int,
        default=QUEUE_DEFAULT_JOB_PRIORITY,
        help="Queue priority for --enqueue-job. Higher numbers are claimed first.",
    )
    parser.add_argument(
        "--max-job-attempts",
        type=int,
        default=QUEUE_DEFAULT_MAX_ATTEMPTS,
        help="Maximum worker attempts per queue job before it is moved to failed.",
    )
    parser.add_argument(
        "--retry-backoff-seconds",
        type=float,
        default=QUEUE_DEFAULT_RETRY_BACKOFF_SECONDS,
        help="Base retry delay for retryable queue job failures.",
    )
    parser.add_argument(
        "--retry-backoff-multiplier",
        type=float,
        default=QUEUE_DEFAULT_RETRY_BACKOFF_MULTIPLIER,
        help="Multiplier applied to retry backoff after each failed attempt.",
    )
    parser.add_argument(
        "--status",
        action=argparse.BooleanOptionalAction,
        default=False,
        help="Show operator status for the queue and recent standalone runs.",
    )
    parser.add_argument(
        "--status-json",
        default="",
        help="Optional path to save operator status as JSON.",
    )
    parser.add_argument(
        "--recent-limit",
        type=int,
        default=STATUS_RECENT_LIMIT,
        help="Number of recent jobs/runs to include in status output.",
    )
    parser.add_argument(
        "--all-queues",
        action=argparse.BooleanOptionalAction,
        default=False,
        help="For --status, aggregate the root queue and all named queues under --queue-dir.",
    )
    parser.add_argument(
        "--evaluate-manifest",
        default="",
        help="Run the evaluation harness on a manifest JSON instead of a direct repo analysis.",
    )
    parser.add_argument(
        "--evaluation-json",
        default="",
        help="Optional path to save evaluation JSON. Defaults next to --evaluate-manifest.",
    )
    parser.add_argument(
        "--evaluation-md",
        default="",
        help="Optional path to save evaluation Markdown. Defaults next to --evaluate-manifest.",
    )
    parser.add_argument(
        "--benchmark-md",
        default="",
        help="Optional path to save a presentation-ready Markdown benchmark table.",
    )
    parser.add_argument(
        "--benchmark-csv",
        default="",
        help="Optional path to save a presentation-ready CSV benchmark table.",
    )
    parser.add_argument(
        "--approve-run",
        default="",
        help="Approve a completed run by run directory path or run id inside --runs-dir.",
    )
    parser.add_argument(
        "--approved-by",
        default="",
        help="Reviewer identity for --approve-run or publish audit metadata.",
    )
    parser.add_argument(
        "--published-by",
        default="",
        help="Publisher or deployer identity for --publish-run. Falls back to --approved-by or the latest approval when omitted.",
    )
    parser.add_argument(
        "--approval-notes",
        default="",
        help="Optional reviewer notes stored in the approval artifact.",
    )
    parser.add_argument(
        "--approval-policy",
        default="",
        help="Optional review/publish policy JSON with authorized reviewers and required artifacts.",
    )
    parser.add_argument(
        "--publish-run",
        default="",
        help="Publish an approved run by run directory path or run id inside --runs-dir.",
    )
    parser.add_argument(
        "--publish-dir",
        default="",
        help="Directory for published artifact bundles. Defaults to outputs/published.",
    )
    parser.add_argument(
        "--publish-label",
        default="",
        help="Optional published bundle name. Defaults to the run id.",
    )
    parser.add_argument(
        "--publish-environment",
        default="",
        help="Optional publish environment such as staging or prod. Required when the review policy defines environment promotion rules without a default.",
    )
    parser.add_argument(
        "--allow-remote-external-dispatch",
        action=argparse.BooleanOptionalAction,
        default=False,
        help="Allow non-loopback external integration dispatch execution during publish. Disabled by default to preserve local-only behavior.",
    )
    parser.add_argument(
        "--require-approval",
        action=argparse.BooleanOptionalAction,
        default=True,
        help="Require an approval artifact before publishing.",
    )
    parser.add_argument(
        "--force-publish",
        action=argparse.BooleanOptionalAction,
        default=False,
        help="Overwrite an existing published bundle directory for the same label.",
    )
    parser.add_argument(
        "--enqueue-job",
        action=argparse.BooleanOptionalAction,
        default=False,
        help="Queue this analysis job instead of executing it immediately.",
    )
    parser.add_argument(
        "--worker",
        action=argparse.BooleanOptionalAction,
        default=False,
        help="Run a file-backed queue worker instead of a direct analysis run.",
    )
    parser.add_argument(
        "--worker-once",
        action=argparse.BooleanOptionalAction,
        default=True,
        help="When in worker mode, stop after the current backlog is drained.",
    )
    parser.add_argument(
        "--max-jobs",
        type=int,
        default=0,
        help="Maximum jobs to execute in worker mode before exiting. Use 0 for unlimited.",
    )
    parser.add_argument(
        "--poll-interval-seconds",
        type=float,
        default=2.0,
        help="Worker polling interval when --no-worker-once is used.",
    )
    args = parser.parse_args(argv)
    args.grounding_profile_explicit = grounding_profile_explicit
    return args

