def write_run_architecture_exports(run_path: str, report_markdown: str, fact_index: dict, write_root_outputs: bool) -> dict[str, str]:
    fact_index = refresh_architecture_views(fact_index)
    architecture_model = fact_index.get("architecture_model", {})
    mermaid_text = extract_code_block(report_markdown, ["mermaid"]) or build_mermaid_from_fact_index(fact_index)
    dot_text = extract_code_block(report_markdown, ["dot", "graphviz"]) or build_dot_from_fact_index(fact_index)
    likec4_text = extract_code_block(report_markdown, ["likec4", "c4"]) or build_likec4_from_fact_index(fact_index)

    run_architecture_model_path = os.path.join(run_path, "architecture_model.json")
    run_mermaid_path = os.path.join(run_path, "architecture.mmd")
    run_dot_path = os.path.join(run_path, "architecture.dot")
    run_likec4_path = os.path.join(run_path, "architecture.likec4")
    run_svg_path = os.path.join(run_path, "architecture_clean.svg")
    run_png_path = os.path.join(run_path, "architecture_clean.png")
    write_json_atomic(run_architecture_model_path, architecture_model if isinstance(architecture_model, dict) else {"version": 1, "summary": {}, "nodes": [], "edges": []})
    write_text_atomic(run_mermaid_path, mermaid_text.strip() + "\n")
    write_text_atomic(run_dot_path, dot_text.strip() + "\n")
    write_text_atomic(run_likec4_path, likec4_text.strip() + "\n")
    render_graphviz_images(run_dot_path, run_svg_path, run_png_path)

    if write_root_outputs:
        write_json_atomic(ARCHITECTURE_MODEL_FILE, architecture_model if isinstance(architecture_model, dict) else {"version": 1, "summary": {}, "nodes": [], "edges": []})
        write_text_atomic(GRAPHVIZ_FILE, dot_text.strip() + "\n")
        write_text_atomic(LIKEC4_FILE, likec4_text.strip() + "\n")
        render_graphviz_images(GRAPHVIZ_FILE, GRAPHVIZ_CLEAN_SVG_FILE, GRAPHVIZ_CLEAN_PNG_FILE)

    return {
        "run_architecture_model": run_architecture_model_path,
        "run_mermaid": run_mermaid_path,
        "run_dot": run_dot_path,
        "run_likec4": run_likec4_path,
        "run_svg": run_svg_path,
        "run_png": run_png_path,
        "root_architecture_model": ARCHITECTURE_MODEL_FILE if write_root_outputs else "",
        "root_dot": GRAPHVIZ_FILE if write_root_outputs else "",
        "root_likec4": LIKEC4_FILE if write_root_outputs else "",
        "root_svg": GRAPHVIZ_CLEAN_SVG_FILE if write_root_outputs else "",
        "root_png": GRAPHVIZ_CLEAN_PNG_FILE if write_root_outputs else "",
    }


def write_analysis_run_summary(
    run_path: str,
    *,
    run_id: str,
    repo_path: str,
    requested_mode: str,
    effective_mode: str,
    state: dict[str, Any],
    redaction_stats: dict[str, Any],
    fact_index: dict[str, Any],
    fact_index_cache_stats: dict[str, Any],
    validation: dict[str, Any],
    gate: dict[str, Any],
    source: str,
    run_report_path: str,
    timings: dict[str, Any],
) -> str:
    llm_enhancements = state.get("llm_enhancements", {}) if isinstance(state.get("llm_enhancements", {}), dict) else {}
    accepted_llm_sections = llm_enhancements.get("accepted_section_headings", []) if isinstance(llm_enhancements, dict) else []
    rejected_llm_sections = llm_enhancements.get("rejected_section_headings", []) if isinstance(llm_enhancements, dict) else []
    safe_repo_path = display_safe_path(repo_path)
    repo_context = str(redaction_stats.get("repo_path", "")).strip() or repo_path
    classification_summary = fact_index.get("classification_summary", {}) if isinstance(fact_index.get("classification_summary", {}), dict) else {}
    endpoint_verification = _runtime_endpoint_verification_counts(fact_index)
    endpoint_quality = summarize_endpoint_quality_for_endpoints(fact_index.get("api_endpoints", []))
    service_verification = _runtime_service_verification_counts(fact_index)
    contradiction_audit = state.get("contradiction_audit", {}) if isinstance(state.get("contradiction_audit", {}), dict) else {}
    self_review_audit = state.get("self_review_audit", {}) if isinstance(state.get("self_review_audit", {}), dict) else {}
    external_integrations_audit = state.get("external_integrations_audit", {}) if isinstance(state.get("external_integrations_audit", {}), dict) else {}
    external_integration_plan = state.get("external_integration_plan", {}) if isinstance(state.get("external_integration_plan", {}), dict) else {}
    external_integration_dispatch_results = (
        state.get("external_integration_dispatch_results", {})
        if isinstance(state.get("external_integration_dispatch_results", {}), dict)
        else {}
    )
    lines = [
        "# Analyzer Run Summary",
        "",
        f"- Run ID: `{run_id}`",
        f"- Repo Path: `{safe_repo_path}`",
        f"- Attempt Count: `{state.get('attempt_count', 1)}`",
        f"- Resume Count: `{state.get('resume_count', 0)}`",
        f"- Requested Mode: `{requested_mode}`",
        f"- Effective Mode: `{effective_mode}`",
        f"- Backend: `{LLM_BACKEND}`",
        f"- Model: `{state.get('model', '')}`",
        f"- LLM Output Policy: `{state.get('llm_output_policy', resolve_llm_output_policy(''))}`",
        f"- Report Source: `{source}`",
        f"- Best Effort Accepted: `{state.get('best_effort_accepted', False)}`",
        f"- LLM Enhancement Sections Accepted: `{len(accepted_llm_sections)}`",
        f"- LLM Enhancement Sections Rejected: `{len(rejected_llm_sections)}`",
        f"- Gate Pass: `{gate.get('pass', False)}`",
        f"- Evidence Coverage: `{gate.get('coverage', 0.0):.2%}`",
        f"- Semantic Claim Coverage: `{gate.get('semantic_coverage', 1.0):.2%}`",
        f"- Semantic Validation Pass: `{gate.get('semantic_pass', True)}`",
        f"- Files Missing Evidence: `{validation.get('files_missing_evidence_count', 0)}`",
        f"- Semantically Unsupported Claims: `{validation.get('claims_semantically_unsupported', 0)}`",
        f"- Report Artifact: `{os.path.basename(run_report_path)}`",
        "",
        "## Key Metrics",
        f"- Files: `{len(fact_index.get('files', []))}`",
        f"- Endpoints: `{len(fact_index.get('api_endpoints', []))}`",
        f"- Runtime Services: `{service_verification.get('total', 0)}`",
        f"- Services With Verified Endpoints: `{service_verification.get('with_verified_endpoints', 0)}`",
        f"- Runtime-Verified Endpoints: `{endpoint_verification.get('verified', 0)}`",
        f"- Static-Only Endpoints: `{endpoint_verification.get('static_only', 0)}`",
        f"- Verified Endpoint Rate: `{float(endpoint_quality.get('verified_endpoint_rate', 0.0)):.2%}`",
        f"- High-Confidence Endpoints: `{endpoint_quality.get('high_confidence_endpoints', 0)}`",
        f"- High-Confidence Endpoint Rate: `{float(endpoint_quality.get('high_confidence_endpoint_rate', 0.0)):.2%}`",
        f"- Cross-file Inference Endpoints: `{endpoint_quality.get('cross_file_inference_endpoints', 0)}`",
        f"- Runtime Observation Endpoints: `{endpoint_quality.get('runtime_observation_endpoints', 0)}`",
        f"- Contract Spec Endpoints: `{endpoint_quality.get('contract_spec_endpoints', 0)}`",
        f"- Linked Contract Spec Endpoints: `{endpoint_quality.get('linked_contract_spec_endpoints', 0)}`",
        f"- Contract-backed Endpoints: `{endpoint_quality.get('contract_backed_endpoints', 0)}`",
        f"- Contract Link Rate: `{float(endpoint_quality.get('contract_link_rate', 0.0)):.2%}`",
        f"- Contradiction Issues: `{int(contradiction_audit.get('issue_count', 0) or 0)}`",
        f"- Duplicate Endpoint Signatures: `{int(contradiction_audit.get('duplicate_endpoint_signature_count', 0) or 0)}`",
        f"- Verification Conflicts: `{int(contradiction_audit.get('endpoint_verification_conflict_count', 0) or 0)}`",
        f"- Unsupported Claim Audit Issues: `{int((state.get('unsupported_claim_audit', {}) or {}).get('issue_count', 0) or 0)}`",
        f"- Self Review Issues: `{int(self_review_audit.get('issue_count', 0) or 0)}`",
        f"- Self Review Pass: `{bool(self_review_audit.get('pass', False))}`",
        f"- External Integrations Configured: `{int(external_integrations_audit.get('configured_count', 0) or 0)}`",
        f"- External Integration Blocking Failures: `{int(external_integrations_audit.get('blocking_failure_count', 0) or 0)}`",
        f"- External Integration Plans: `{int(external_integration_plan.get('plan_count', 0) or 0)}`",
        f"- External Integration Plan Failures: `{int(external_integration_plan.get('failing_plan_count', 0) or 0)}`",
        f"- External Integration Blocking Plan Failures: `{int(external_integration_plan.get('blocking_plan_failure_count', 0) or 0)}`",
        f"- External Integration Dispatch Specs: `{int((state.get('external_integration_dispatch_specs', {}) or {}).get('spec_count', 0) or 0)}`",
        f"- External Integration Blocking Dispatch Specs: `{int((state.get('external_integration_dispatch_specs', {}) or {}).get('blocking_spec_failure_count', 0) or 0)}`",
        f"- External Integration Dispatch Results: `{int(external_integration_dispatch_results.get('result_count', 0) or 0)}`",
        f"- External Integration Blocking Dispatch Results: `{int(external_integration_dispatch_results.get('blocking_result_failure_count', 0) or 0)}`",
        f"- External Integration Local Executed Results: `{int(external_integration_dispatch_results.get('local_execution_result_count', 0) or 0)}`",
        f"- External Integration Remote Executed Results: `{int(external_integration_dispatch_results.get('remote_execution_result_count', 0) or 0)}`",
        f"- External Integration Total Executed Results: `{int(external_integration_dispatch_results.get('executed_result_count', 0) or 0)}`",
        f"- Dependencies: `{len(fact_index.get('dependencies', []))}`",
        f"- Scripts: `{len(fact_index.get('scripts', []))}`",
        f"- Runtime Observations: `{len(fact_index.get('runtime_observations', []))}`",
        f"- Highest Data Classification: `{classification_summary.get('highest_classification', 'unclassified')}`",
        f"- Classified Files: `{classification_summary.get('classified_files', 0)}`",
        f"- Files Matched By Classification Rules: `{classification_summary.get('matched_files', 0)}`",
        f"- Redactions Applied: `{redaction_stats.get('total_redactions', 0)}`",
        f"- Files Scanned: `{redaction_stats.get('files_read', 0)}`",
        f"- Characters Scanned: `{redaction_stats.get('chars_scanned', 0)}`",
        f"- Skipped Large Files: `{redaction_stats.get('skipped_by_size_count', 0)}`",
        f"- Fact Index Cache Hits: `{fact_index_cache_stats.get('cache_hits', 0)}`",
        f"- Fact Index Cache Misses: `{fact_index_cache_stats.get('cache_misses', 0)}`",
        f"- Gather Time Sec: `{float(timings.get('gather_sec', 0.0)):.3f}`",
        f"- Synthesize Time Sec: `{float(timings.get('synthesize_sec', 0.0)):.3f}`",
        f"- Total Time Sec: `{float(timings.get('total_sec', 0.0)):.3f}`",
    ]
    if accepted_llm_sections:
        lines.append(f"- Accepted LLM Section Headings: `{'; '.join(str(item) for item in accepted_llm_sections)}`")
    if rejected_llm_sections:
        lines.append(f"- Rejected LLM Section Headings: `{'; '.join(str(item) for item in rejected_llm_sections)}`")
    scan_cfg_path = display_safe_path(str(redaction_stats.get("scan_config_path", "")).strip(), repo_path=repo_context)
    if scan_cfg_path:
        lines.append(f"- Scan Config: `{scan_cfg_path}`")
    redaction_policy_path = display_safe_path(str(redaction_stats.get("redaction_policy_path", "")).strip(), repo_path=repo_context)
    if redaction_policy_path:
        lines.append(f"- Redaction Policy: `{redaction_policy_path}`")
    security_policy_name = str(redaction_stats.get("security_policy_name", "")).strip()
    if security_policy_name:
        lines.append(f"- Security Policy: `{security_policy_name}`")
    security_policy_path = display_safe_path(str(redaction_stats.get("security_policy_path", "")).strip(), repo_path=repo_context)
    if security_policy_path:
        lines.append(f"- Security Policy File: `{security_policy_path}`")
    policy_packs = [str(item).strip() for item in redaction_stats.get("policy_packs", []) if str(item).strip()]
    if policy_packs:
        lines.append(f"- Policy Packs: `{', '.join(policy_packs)}`")
    classification_counts = classification_summary.get("classification_counts", {})
    if isinstance(classification_counts, dict) and classification_counts:
        lines.append(f"- Classification Counts: `{json.dumps(classification_counts, ensure_ascii=True, sort_keys=True)}`")
    lines.append(
        f"- Endpoint Provenance Counts: `{json.dumps(endpoint_quality.get('provenance_counts', {}), ensure_ascii=True, sort_keys=True)}`"
    )
    lines.append(
        f"- Endpoint Confidence Counts: `{json.dumps(endpoint_quality.get('confidence_counts', {}), ensure_ascii=True, sort_keys=True)}`"
    )
    lines.append(
        f"- API Contract Links: `{len(fact_index.get('api_contract_links', []))}`"
    )
    heartbeat_artifact = state.get("artifacts", {}).get("run_heartbeat", "")
    if heartbeat_artifact:
        lines.append(f"- Heartbeat Artifact: `{os.path.basename(heartbeat_artifact)}`")
    lines.append("- Lock Lifecycle: `run.lock.json` is held during execution and removed on exit.")
    for artifact_key in [
        "run_llm_backend_status",
        "run_security_policy_audit",
        "run_gather_checkpoint",
        "run_synthesis_checkpoint",
        "run_runtime_observations",
        "run_llm_enhancements",
        "run_traceability",
        "run_inference_audit",
        "run_contradiction_audit",
        "run_contradiction_audit_markdown",
        "run_unsupported_claim_audit",
        "run_unsupported_claim_audit_markdown",
        "run_self_review_audit",
        "run_self_review_audit_markdown",
        "run_external_integrations_audit",
        "run_external_integrations_audit_markdown",
        "run_external_integration_plan",
        "run_external_integration_plan_markdown",
        "run_external_integration_dispatch_specs",
        "run_external_integration_dispatch_specs_markdown",
        "run_external_integration_dispatch_results",
        "run_external_integration_dispatch_results_markdown",
        "run_review_audit",
        "run_review_audit_sarif",
        "run_architecture_model",
        "run_subsystem_index",
        "run_architecture_diff_markdown",
        "run_architecture_diff_json",
        "run_diff_markdown",
        "run_diff_json",
    ]:
        artifact_path = state.get("artifacts", {}).get(artifact_key, "")
        if artifact_path:
            lines.append(f"- {artifact_key}: `{os.path.basename(artifact_path)}`")
    summary_path = os.path.join(run_path, "run_summary.md")
    write_text_atomic(summary_path, "\n".join(lines) + "\n")
    return summary_path


def build_analysis_prompt(
    *,
    redaction_stats: dict[str, Any],
    allowed_files_text: str,
    allowed_evidence_text: str,
    prompt_fact_index_json: str,
) -> str:
    return f"""
You are a senior software engineer.
Reply in ENGLISH only. Use clear headings and bullet points.

Task:
1) Explain what this repo does in 5 bullets.
2) Give an architecture diagram in Mermaid (graph TD) using the required template.
3) List the key folders and files and what each does.
4) Give step-by-step instructions to run locally.
5) Give 10 smart questions to understand the codebase deeply.
6) Provide a Graphviz DOT architecture diagram in a fenced ```dot``` block.
7) Provide a LikeC4 architecture snippet in a fenced ```likec4``` block.

Grounding and anti-hallucination rules:
- Every factual bullet MUST end with [Evidence: path#Lline].
- Use only line-level evidence from Allowed Evidence Targets.
- If evidence is missing, write exactly: Unknown from provided code. [Evidence: none]
- Do not invent components, files, behavior, or APIs.
- Do not generalize beyond explicit facts in the model-safe index.
- If a relationship is not directly supported by evidence, mark it unknown.

Security context:
- Source snippets were pre-redacted for likely secrets.
- Redaction summary: {summarize_redaction_stats(redaction_stats)}

Allowed Source and Runtime Artifact Paths:
{allowed_files_text}

Allowed Evidence Targets:
{allowed_evidence_text}

Retrieval-Oriented Deterministic Prompt Context (single source of truth for LLM synthesis):
{prompt_fact_index_json}
"""


LLM_SECTION_ENHANCEMENT_SPECS = [
    {
        "key": "executive_summary",
        "heading": "## Executive Summary (LLM Enhanced)",
        "source_heading": "## 1) High-level Repository Overview",
        "purpose": (
            "Write a polished reviewer-facing summary of what the repository does, "
            "its architectural shape, and the strongest grounded implementation signals."
        ),
    },
    {
        "key": "repo_walkthrough",
        "heading": "## Repo Walkthrough (LLM Enhanced)",
        "source_heading": "## 2) Summaries for Major Folders and Modules",
        "purpose": (
            "Explain how a reviewer should navigate the repository, which folders or modules "
            "matter first, and why they matter."
        ),
    },
    {
        "key": "runbook_notes",
        "heading": "## Runbook Notes (LLM Enhanced)",
        "source_heading": "## 6) Setup and Run Instructions (Inferred)",
        "purpose": (
            "Rewrite the setup and execution guidance into clearer reviewer-friendly runbook notes "
            "without inventing new commands or deployment behavior."
        ),
    },
]
LLM_SECTION_ITEM_COUNT = 3
LLM_SECTION_SUPPORT_SNIPPET_RADIUS = 2
LLM_SECTION_SUPPORT_SNIPPET_LIMIT = 10
LLM_SECTION_SUPPORT_CONTEXT_CHARS = 3600


def extract_markdown_section(markdown: str, heading: str) -> str:
    pattern = re.compile(rf"(?ms)^{re.escape(heading)}\s*\n(.*?)(?=^##\s|\Z)")
    match = pattern.search(str(markdown or ""))
    if not match:
        return ""
    body = match.group(1).strip()
    if not body:
        return heading + "\n"
    return heading + "\n" + body + "\n"


def normalize_llm_section_output(text: str, expected_heading: str) -> str:
    raw = str(text or "").replace("\r\n", "\n").strip()
    if not raw:
        return expected_heading + "\n"

    raw = re.sub(r"^\s*```[a-zA-Z0-9_-]*\s*", "", raw)
    raw = re.sub(r"\s*```\s*$", "", raw)
    if expected_heading in raw:
        raw = raw.split(expected_heading, 1)[1]

    body_lines: list[str] = []
    numbered_index = 1
    for line in raw.splitlines():
        stripped = line.strip()
        if not stripped:
            continue
        if stripped.startswith("## "):
            if body_lines:
                break
            continue
        if re.match(r"^\d+\.\s+", stripped):
            if numbered_index > LLM_SECTION_ITEM_COUNT:
                break
            body_lines.append(f"{numbered_index}. " + re.sub(r"^\d+\.\s+", "", stripped))
            numbered_index += 1
            continue
        if stripped.startswith("- ") or stripped.startswith("* "):
            if numbered_index > LLM_SECTION_ITEM_COUNT:
                break
            body_lines.append(f"{numbered_index}. " + stripped[2:].strip())
            numbered_index += 1
            continue
        if body_lines:
            body_lines[-1] = body_lines[-1].rstrip() + " " + stripped
            continue
        if numbered_index > LLM_SECTION_ITEM_COUNT:
            break
        body_lines.append(f"{numbered_index}. " + stripped)
        numbered_index += 1

    body = "\n".join(body_lines).strip()
    if not body:
        return expected_heading + "\n"
    return expected_heading + "\n" + body + "\n"


def evaluate_llm_section_gate(
    section_markdown: str,
    allowed_line_counts: Optional[dict[str, int]] = None,
    claim_support_index: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    text = str(section_markdown or "").replace("\r\n", "\n").strip()
    lines = [line.rstrip() for line in text.splitlines()]
    heading_lines = [line for line in lines if line.strip().startswith("## ")]
    body_lines = [line.strip() for line in lines[1:] if line.strip()]
    numbered_lines = [line for line in body_lines if re.match(r"^\d+\.\s+", line)]
    prose_lines = [line for line in body_lines if not re.match(r"^\d+\.\s+", line)]
    body_text = "\n".join(body_lines).strip()
    items_with_evidence = 0
    semantically_supported_items = 0
    invalid_evidence_tokens: list[str] = []
    unsupported_claims: list[str] = []
    for line in numbered_lines:
        token_groups = extract_evidence_token_strings(line)
        if not token_groups:
            continue
        item_valid = True
        normalized_evidence_tokens: list[str] = []
        for token in token_groups:
            path, line_no, has_line = parse_evidence_token(token)
            if path == "none" or not has_line or line_no is None:
                item_valid = False
                invalid_evidence_tokens.append(token.strip())
                continue
            if allowed_line_counts is not None:
                max_line = allowed_line_counts.get(path)
                if max_line is None or line_no < 1 or line_no > max_line:
                    item_valid = False
                    invalid_evidence_tokens.append(token.strip())
                    continue
            normalized_evidence_tokens.append(make_evidence(path, line_no))
        if item_valid:
            items_with_evidence += 1
            if claim_support_index:
                claim_text = strip_evidence_tags(line)
                claim_text = re.sub(r"^\d+\.\s*", "", claim_text).strip()
                support_texts = _candidate_support_texts(
                    claim_text,
                    _semantic_tokens(claim_text),
                    normalized_evidence_tokens,
                    claim_support_index,
                )
                score, _basis = _score_claim_against_support(claim_text, support_texts)
                if score >= effective_min_claim_support_score():
                    semantically_supported_items += 1
                elif len(unsupported_claims) < 10:
                    unsupported_claims.append(claim_text[:160])
            else:
                semantically_supported_items += 1
    passed = (
        len(heading_lines) == 1
        and bool(body_text)
        and "```" not in text
        and len(body_text) >= 160
        and len(body_text) <= 2600
        and len(body_lines) == LLM_SECTION_ITEM_COUNT
        and len(numbered_lines) == LLM_SECTION_ITEM_COUNT
        and not prose_lines
        and items_with_evidence == LLM_SECTION_ITEM_COUNT
        and semantically_supported_items == LLM_SECTION_ITEM_COUNT
        and not invalid_evidence_tokens
    )
    return {
        "pass": passed,
        "body_chars": len(body_text),
        "line_count": len(body_lines),
        "numbered_lines": len(numbered_lines),
        "contains_code_fence": "```" in text,
        "items_with_evidence": items_with_evidence,
        "semantically_supported_items": semantically_supported_items,
        "invalid_evidence_tokens_count": len(invalid_evidence_tokens),
        "invalid_evidence_tokens": invalid_evidence_tokens[:20],
        "unsupported_claims_sample": unsupported_claims,
    }


def llm_section_best_effort_acceptable(gate: dict[str, Any]) -> bool:
    return bool(gate.get("pass", False)) or (
        not bool(gate.get("contains_code_fence", False))
        and int(gate.get("body_chars", 0)) >= 160
        and int(gate.get("numbered_lines", 0)) == LLM_SECTION_ITEM_COUNT
        and int(gate.get("items_with_evidence", 0)) == LLM_SECTION_ITEM_COUNT
        and int(gate.get("semantically_supported_items", 0)) == LLM_SECTION_ITEM_COUNT
        and int(gate.get("invalid_evidence_tokens_count", 0)) == 0
    )


def score_llm_section_candidate(candidate: dict[str, Any]) -> tuple[Any, ...]:
    gate = candidate.get("gate", {})
    return (
        1 if gate.get("pass", False) else 0,
        int(gate.get("semantically_supported_items", 0)),
        int(gate.get("items_with_evidence", 0)),
        -int(gate.get("invalid_evidence_tokens_count", 0)),
        int(gate.get("numbered_lines", 0)),
        int(gate.get("line_count", 0)),
        int(gate.get("body_chars", 0)),
    )


def build_llm_section_feedback(spec: dict[str, str], gate: dict[str, Any]) -> str:
    lines = [
        f"Previous draft for {spec['heading']} failed the overlay format rules. Fix these issues:",
        f"- Body characters observed: {gate.get('body_chars', 0)}",
        f"- Non-empty line count observed: {gate.get('line_count', 0)}",
        f"- Numbered lines observed: {gate.get('numbered_lines', 0)}",
        f"- Numbered items with valid evidence: {gate.get('items_with_evidence', 0)}",
        f"- Semantically supported numbered items: {gate.get('semantically_supported_items', 0)}",
        f"- Invalid evidence tokens: {gate.get('invalid_evidence_tokens_count', 0)}",
        f"- Contains code fence: {gate.get('contains_code_fence', False)}",
        "- Output exactly one section with the requested heading.",
        "- After the heading, write exactly 3 numbered items using `1.`, `2.`, `3.`.",
        "- Every numbered item must end with one or more valid `[Evidence: path#Lline]` tags.",
        "- Every numbered item must also be semantically supported by the deterministic facts behind those evidence tags.",
        "- Do not use bullet points, extra headings, code fences, tables, or diagrams.",
        "- Stay strictly within the facts already present in the deterministic base section.",
    ]
    unsupported = gate.get("unsupported_claims_sample", [])[:5]
    if unsupported:
        lines.append(f"- Sample semantically unsupported claims: {' | '.join(map(str, unsupported))}")
    return "\n".join(lines)


def collect_section_allowed_line_counts(base_section: str, line_counts: dict[str, int]) -> dict[str, int]:
    narrowed: dict[str, int] = {}
    for path, _line, has_line in extract_evidence_tokens(base_section):
        if path == "none" or not has_line:
            continue
        max_line = line_counts.get(path)
        if max_line is not None:
            narrowed[path] = int(max_line)
    if not narrowed:
        for path in sorted(line_counts.keys())[:20]:
            narrowed[path] = int(line_counts[path])
    return narrowed


def collect_section_preferred_evidence(base_section: str, line_counts: dict[str, int]) -> list[str]:
    preferred: list[str] = []
    seen: set[str] = set()
    for path, line_no, has_line in extract_evidence_tokens(base_section):
        if path == "none" or not has_line or line_no is None:
            continue
        max_line = line_counts.get(path)
        if max_line is None or line_no < 1 or line_no > max_line:
            continue
        token = make_evidence(path, line_no)
        if token in seen:
            continue
        seen.add(token)
        preferred.append(token)
        if len(preferred) >= LLM_SECTION_SUPPORT_SNIPPET_LIMIT:
            break
    return preferred


def build_section_allowed_evidence_text(base_section: str, line_counts: dict[str, int]) -> str:
    narrowed = collect_section_allowed_line_counts(base_section, line_counts)
    preferred = collect_section_preferred_evidence(base_section, line_counts)
    parts: list[str] = []
    if preferred:
        parts.append(
            "Preferred Exact Evidence Tokens:\n" + "\n".join([f"- {token}" for token in preferred])
        )
    parts.append(
        "Allowed File Ranges:\n"
        + format_allowed_evidence_for_prompt(narrowed, max_items=min(len(narrowed), 40) or 20)
    )
    return "\n\n".join([part.strip() for part in parts if part.strip()])


def trim_section_fact_context(fact_context_json: str, max_chars: int = 2500) -> str:
    text = str(fact_context_json or "").strip()
    if len(text) <= max_chars:
        return text
    return text[:max_chars].rstrip() + "\n... [truncated deterministic context]"


def _compact_section_line(text: str, max_chars: int = 220) -> str:
    collapsed = re.sub(r"\s+", " ", str(text or "").strip())
    if len(collapsed) <= max_chars:
        return collapsed
    return collapsed[: max_chars - 3].rstrip() + "..."


def _load_repo_evidence_snippet(
    repo_path: str,
    evidence_token: str,
    radius: int = LLM_SECTION_SUPPORT_SNIPPET_RADIUS,
) -> str:
    path, line_no, has_line = parse_evidence_token(evidence_token)
    if path == "none" or not has_line or line_no is None:
        return ""
    absolute = os.path.join(repo_path, path)
    if not repo_path or not os.path.isfile(absolute):
        return ""
    try:
        with open(absolute, "r", encoding="utf-8", errors="ignore") as fh:
            lines = fh.read().splitlines()
    except Exception:
        return ""
    if line_no < 1 or line_no > len(lines):
        return ""
    start = max(1, line_no - radius)
    end = min(len(lines), line_no + radius)
    snippet_lines = [f"{evidence_token}"]
    for idx in range(start, end + 1):
        snippet_lines.append(f"{idx}: {_compact_section_line(lines[idx - 1], max_chars=180)}")
    return "\n".join(snippet_lines)


def build_section_support_context(
    repo_path: str,
    base_section: str,
    fact_context_json: str,
    line_counts: dict[str, int],
) -> str:
    parts: list[str] = []
    base_facts: list[str] = []
    for line in str(base_section or "").splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith("## "):
            continue
        base_facts.append(f"- {_compact_section_line(stripped, max_chars=240)}")
        if len(base_facts) >= 8:
            break
    if base_facts:
        parts.append("Section Facts:\n" + "\n".join(base_facts))

    preferred = collect_section_preferred_evidence(base_section, line_counts)
    snippet_blocks = []
    for token in preferred[:LLM_SECTION_SUPPORT_SNIPPET_LIMIT]:
        snippet = _load_repo_evidence_snippet(repo_path, token)
        if snippet:
            snippet_blocks.append(snippet)
    if snippet_blocks:
        parts.append("Exact Supporting Snippets:\n" + "\n\n".join(snippet_blocks))

    compact_context = trim_section_fact_context(fact_context_json, max_chars=1200)
    if compact_context.strip():
        parts.append("Compact Deterministic Context:\n" + compact_context)

    merged = "\n\n".join([part.strip() for part in parts if part.strip()]).strip()
    if len(merged) <= LLM_SECTION_SUPPORT_CONTEXT_CHARS:
        return merged
    return merged[:LLM_SECTION_SUPPORT_CONTEXT_CHARS].rstrip() + "\n... [truncated section context]"


def build_llm_section_prompt(
    spec: dict[str, str],
    *,
    base_section: str,
    allowed_evidence_text: str,
    support_context_text: str,
    feedback_text: str,
) -> str:
    feedback_block = f"\nFeedback To Fix:\n{feedback_text}\n" if feedback_text.strip() else ""
    return f"""
You are polishing a deterministic repository report for readability.
Reply in ENGLISH only.

Task:
- Output ONLY one markdown section with this exact heading:
  {spec["heading"]}
- After the heading, write exactly 3 numbered items using `1.`, `2.`, `3.`.
- Every numbered item MUST end with one or more `[Evidence: path#Lline]` tags.
- Use only facts that are directly supported by the deterministic base section and retrieval context.
- Reuse the exact evidence tokens shown below whenever possible.
- Prefer synthesis, prioritization, and clearer explanations over repeating raw inventory.
- Do not output code fences, diagrams, tables, bullet lists, or any extra headings.
- Do not mention quality metrics, validation, or grounding policy in the final section text.
- Mention concrete modules, routes, files, or subsystems instead of vague phrases when the support context provides them.
- If a sentence cannot be supported by the deterministic base section, replace it with a different supported sentence.
- Do not invent new evidence tokens or change line numbers.

Section purpose:
- {spec["purpose"]}

Deterministic base section to improve:
{base_section}

Allowed Evidence Targets:
{allowed_evidence_text}

Supplemental deterministic context:
{support_context_text}
{feedback_block}
"""


def insert_sections_after_title(report: str, section_blocks: list[str]) -> str:
    blocks = [str(item).strip() for item in section_blocks if str(item or "").strip()]
    if not blocks:
        return report
    text = str(report or "").replace("\r\n", "\n").strip()
    if not text:
        return "\n\n".join(blocks) + "\n"

    lines = text.splitlines()
    title = lines[0].rstrip()
    remainder = "\n".join(lines[1:]).lstrip("\n")
    merged = title + "\n\n" + "\n\n".join(blocks)
    if remainder:
        merged += "\n\n" + remainder
    return merged.rstrip() + "\n"


def maybe_translate_to_english(text: str) -> str:
    if not has_cjk(text):
        return text

    translate_prompt = f"""
Translate the following text to ENGLISH.
Rules:
* Output ONLY English.
* Keep headings, bullet formatting, and code blocks unchanged where possible.
* Do not include any Chinese characters.

TEXT:
{text}
"""
    return ollama_chat_with_retry(
        model=active_model(),
        system="Output ENGLISH only. No Chinese characters.",
        user=translate_prompt,
        temperature=0.0,
    )


def synthesize_hybrid_report(
    *,
    repo_path: str,
    effective_mode: str,
    llm_output_policy: str,
    fact_index: dict[str, Any],
    redaction_stats: dict[str, Any],
    included_files: set[str],
    line_counts: dict[str, int],
    fact_context_json: str,
    max_iterations: int,
    claim_support_index: Optional[dict[str, Any]] = None,
) -> dict[str, Any]:
    base_report = build_deterministic_report(fact_index, redaction_stats)
    base_report = sanitize_all_mermaid(base_report)
    base_validation = validate_report_grounding(
        base_report,
        included_files,
        line_counts,
        claim_support_index=claim_support_index,
    )
    base_gate = evaluate_grounding_gate(base_validation)

    final_text = base_report
    final_validation = base_validation
    final_gate = base_gate
    source = "deterministic_initial" if effective_mode == "deterministic" else "deterministic_base_only"
    enhancement_records: list[dict[str, Any]] = []
    applied_sections: list[dict[str, Any]] = []

    if effective_mode != "agent":
        return {
            "report": final_text,
            "validation": final_validation,
            "gate": final_gate,
            "source": source,
            "llm_enhancements": {
                "requested": False,
                "base_gate_pass": bool(base_gate.get("pass", False)),
                "accepted_sections_count": 0,
                "accepted_section_headings": [],
                "rejected_section_headings": [],
                "sections": [],
                "applied_sections": [],
            },
        }

    record_map: dict[str, dict[str, Any]] = {}
    candidate_sections: list[dict[str, Any]] = []
    system_prompt = (
        "You MUST reply in ENGLISH only. "
        "If you see Chinese, translate it internally and output only English. "
        "Do not output any Chinese characters."
    )
    for spec in LLM_SECTION_ENHANCEMENT_SPECS:
        record = {
            "key": spec["key"],
            "heading": spec["heading"],
            "source_heading": spec["source_heading"],
            "status": "pending",
            "accepted_policy": "",
            "attempt_count": 0,
            "error": "",
        }
        enhancement_records.append(record)
        record_map[spec["key"]] = record

        base_section = extract_markdown_section(base_report, spec["source_heading"])
        if not base_section.strip():
            record["status"] = "skipped_missing_source_section"
            continue
        section_allowed_evidence_text = build_section_allowed_evidence_text(base_section, line_counts)
        section_support_context = build_section_support_context(
            repo_path,
            base_section,
            fact_context_json,
            line_counts,
        )

        feedback_text = ""
        best_candidate: Optional[dict[str, Any]] = None
        accepted_candidate: Optional[dict[str, Any]] = None
        for iteration in range(1, max(1, int(max_iterations or 1)) + 1):
            record["attempt_count"] = iteration
            try:
                prompt = build_llm_section_prompt(
                    spec,
                    base_section=base_section,
                    allowed_evidence_text=section_allowed_evidence_text,
                    support_context_text=section_support_context,
                    feedback_text=feedback_text,
                )
                draft = ollama_chat_with_retry(
                    model=active_model(),
                    system=system_prompt,
                    user=prompt,
                    temperature=0.2,
                )
                normalized = normalize_llm_section_output(maybe_translate_to_english(draft), spec["heading"])
                gate = evaluate_llm_section_gate(
                    normalized,
                    allowed_line_counts=line_counts,
                    claim_support_index=claim_support_index,
                )
                candidate = {
                    "key": spec["key"],
                    "heading": spec["heading"],
                    "iteration": iteration,
                    "markdown": normalized,
                    "gate": gate,
                }
                if best_candidate is None or score_llm_section_candidate(candidate) > score_llm_section_candidate(best_candidate):
                    best_candidate = candidate

                record["last_fragment_gate"] = {
                    "pass": gate.get("pass", False),
                    "body_chars": gate.get("body_chars", 0),
                    "line_count": gate.get("line_count", 0),
                    "numbered_lines": gate.get("numbered_lines", 0),
                    "items_with_evidence": gate.get("items_with_evidence", 0),
                    "invalid_evidence_tokens_count": gate.get("invalid_evidence_tokens_count", 0),
                    "contains_code_fence": gate.get("contains_code_fence", False),
                }
                if gate.get("pass", False):
                    accepted_candidate = candidate
                    record["status"] = "accepted_fragment"
                    record["accepted_policy"] = "strict_gate"
                    break
                feedback_text = build_llm_section_feedback(spec, gate)
            except Exception as e:
                record["error"] = str(e)
                feedback_text = f"Previous attempt failed with runtime error: {e}"

        if accepted_candidate is None and llm_best_effort_enabled(llm_output_policy) and best_candidate:
            best_gate = dict(best_candidate.get("gate", {}))
            if llm_section_best_effort_acceptable(best_gate):
                accepted_candidate = best_candidate
                record["status"] = "accepted_fragment"
                record["accepted_policy"] = "best_effort"

        if accepted_candidate is None:
            if record["status"] == "pending":
                record["status"] = "rejected_fragment"
            continue

        candidate_sections.append(accepted_candidate)
        record["accepted_iteration"] = int(accepted_candidate.get("iteration", 0) or 0)

    applied_blocks: list[str] = []
    for candidate in candidate_sections:
        trial_report = insert_sections_after_title(base_report, applied_blocks + [str(candidate.get("markdown", "")).strip()])
        trial_report = sanitize_all_mermaid(trial_report)
        trial_validation = validate_report_grounding(
            trial_report,
            included_files,
            line_counts,
            claim_support_index=claim_support_index,
        )
        trial_gate = evaluate_grounding_gate(trial_validation)
        record = record_map.get(str(candidate.get("key", "")), {})
        if trial_gate.get("pass", False):
            applied_blocks.append(str(candidate.get("markdown", "")).strip())
            applied_sections.append(
                {
                    "key": str(candidate.get("key", "")),
                    "heading": str(candidate.get("heading", "")),
                    "iteration": int(candidate.get("iteration", 0) or 0),
                    "accepted_policy": str(record.get("accepted_policy", "")).strip(),
                    "markdown": str(candidate.get("markdown", "")).strip(),
                }
            )
            record["status"] = "applied"
            final_text = trial_report
            final_validation = trial_validation
            final_gate = trial_gate
        else:
            record["status"] = "rejected_full_report_gate"
            record["full_report_gate"] = {
                "pass": trial_gate.get("pass", False),
                "coverage": trial_gate.get("coverage", 0.0),
                "semantic_coverage": trial_gate.get("semantic_coverage", 1.0),
            }

    accepted_headings = [item.get("heading", "") for item in applied_sections if str(item.get("heading", "")).strip()]
    rejected_headings = [
        item.get("heading", "")
        for item in enhancement_records
        if item.get("status") not in {"applied"}
    ]
    if applied_sections:
        source = "deterministic_with_llm_sections"

    return {
        "report": final_text,
        "validation": final_validation,
        "gate": final_gate,
        "source": source,
        "llm_enhancements": {
            "requested": True,
            "base_gate_pass": bool(base_gate.get("pass", False)),
            "accepted_sections_count": len(accepted_headings),
            "accepted_section_headings": accepted_headings,
            "rejected_section_headings": rejected_headings,
            "sections": enhancement_records,
            "applied_sections": applied_sections,
        },
    }


def _resolve_cli_repo_path(args: argparse.Namespace, *, allow_prompt: bool) -> str:
    cli_repo = (args.repo or args.repo_path or "").strip()
    if cli_repo:
        return os.path.abspath(os.path.expanduser(cli_repo))
    if not allow_prompt:
        return ""
    while True:
        repo_path = input("Enter repo path: ").strip()
        if repo_path:
            return os.path.abspath(os.path.expanduser(repo_path))
        print("❌ Repo path cannot be empty. Example: ./deepwiki-open")


def run_repository_analysis(
    args: argparse.Namespace,
    repo_path: str,
    on_run_update: Optional[Any] = None,
) -> dict[str, Any]:
    repo_path = os.path.abspath(os.path.expanduser(repo_path))
    if not os.path.isdir(repo_path):
        print(f"❌ Path is not a folder: {repo_path}")
        return {"exit_code": 1, "status": "invalid_repo", "run_path": "", "resumable": False}

    previous_grounding_profile_override = _ACTIVE_GROUNDING_PROFILE_OVERRIDE
    requested_grounding_profile = str(getattr(args, "grounding_profile", "")).strip()
    runs_dir = resolve_runs_dir(args.runs_dir, repo_path=repo_path)
    report_home_dir = default_repo_report_home(repo_path) if not str(args.runs_dir or "").strip() else ""
    if args.write_root_outputs:
        os.makedirs(OUTPUT_DIR, exist_ok=True)
    overall_t0 = time.perf_counter()

    scan_config = load_repo_scan_config(repo_path)
    scan_config = apply_policy_packs_to_scan_config(
        scan_config,
        getattr(args, "policy_pack", []),
        source="cli",
    )
    effective_grounding_profile = requested_grounding_profile
    if not bool(getattr(args, "grounding_profile_explicit", False)):
        recommended_grounding_profile = normalize_grounding_profile(scan_config.get("recommended_grounding_profile", ""))
        if recommended_grounding_profile:
            effective_grounding_profile = recommended_grounding_profile
    if effective_grounding_profile:
        set_active_grounding_profile_override(effective_grounding_profile)
    else:
        clear_active_grounding_profile_override()
    runtime_config = merge_runtime_probe_config(
        repo_path,
        scan_config,
        enabled=args.runtime_probe,
        commands=args.runtime_command,
        timeout_seconds=args.runtime_timeout_seconds,
        max_output_chars=args.runtime_max_output_chars,
    )
    effective_scan_config = apply_runtime_config_to_scan_config(scan_config, runtime_config)
    requested_mode = args.mode
    effective_mode = requested_mode
    llm_output_policy = resolve_llm_output_policy(getattr(args, "llm_output_policy", ""))
    analysis_review_policy_path = os.path.abspath(os.path.expanduser(str(getattr(args, "approval_policy", "")).strip())) if str(getattr(args, "approval_policy", "")).strip() else ""
    analysis_review_policy = load_review_policy(analysis_review_policy_path) if analysis_review_policy_path else {}
    if requested_mode == "agent" and llm_best_effort_enabled(llm_output_policy):
        args.require_llm = True
    clear_active_model_override()
    backend_status: dict[str, Any] = {
        "backend": LLM_BACKEND,
        "healthy": False,
        "primary_model": active_model(),
        "candidate_models": model_candidates(),
        "available_models": [],
        "selected_model": "",
        "requested_mode": requested_mode,
        "effective_mode": requested_mode,
        "llm_output_policy": llm_output_policy,
        "grounding_profile": active_grounding_profile(),
        "require_llm": bool(args.require_llm),
        "error": "",
    }
    llm_setup_error = ""
    if requested_mode == "agent":
        backend_status = probe_llm_backend()
        backend_status["requested_mode"] = requested_mode
        backend_status["require_llm"] = bool(args.require_llm)
        backend_status["grounding_profile"] = active_grounding_profile()
        if backend_status.get("healthy") and str(backend_status.get("selected_model", "")).strip():
            set_active_model_override(str(backend_status.get("selected_model", "")).strip())
        else:
            llm_setup_error = str(backend_status.get("error", "")).strip() or "LLM backend health check failed."
        if llm_setup_error:
            backend_status["error"] = llm_setup_error
            if args.require_llm:
                print(f"❌ {llm_setup_error}")
                return {"exit_code": 1, "status": "llm_unavailable", "run_path": "", "resumable": False}
            effective_mode = "deterministic"
            print(f"[WARN] Agent mode requested but local LLM is unavailable. Falling back to deterministic mode: {llm_setup_error}")
    backend_status["effective_mode"] = effective_mode

    resume_run_path = resolve_resume_run_path(runs_dir, args.resume_run)
    resuming = bool(resume_run_path)
    if resuming:
        run_path = resume_run_path
        state = load_run_state(run_path)
        if not isinstance(state, dict):
            print(f"❌ Resume run is missing {RUN_STATE_FILENAME}: {run_path}")
            return {"exit_code": 1, "status": "resume_missing_state", "run_path": run_path, "resumable": False}
        prior_repo_path = normalize_repo_path_value(str(state.get("repo_path", "")).strip()) if str(state.get("repo_path", "")).strip() else ""
        if prior_repo_path and prior_repo_path != normalize_repo_path_value(repo_path):
            print(f"❌ Resume run repo mismatch. Existing run repo={prior_repo_path} current repo={normalize_repo_path_value(repo_path)}")
            return {"exit_code": 1, "status": "resume_repo_mismatch", "run_path": run_path, "resumable": False}
        if str(state.get("status", "")).strip() == "completed":
            print(f"❌ Run is already completed and does not need resume: {run_path}")
            return {"exit_code": 1, "status": "already_completed", "run_path": run_path, "resumable": False}
        run_id = str(state.get("run_id", "")).strip() or os.path.basename(run_path.rstrip("/\\"))
        state = ensure_run_state_defaults(state, repo_path=repo_path, requested_mode=requested_mode, effective_mode=effective_mode)
        state["run_id"] = run_id
        state["repo_path"] = repo_path
        state["requested_mode"] = requested_mode
        state["mode"] = effective_mode
        state["llm_output_policy"] = llm_output_policy
        state["grounding_profile"] = active_grounding_profile()
        state["review_policy_path"] = analysis_review_policy_path
        state["status"] = "running"
        state["completed_at"] = None
        state["attempt_count"] = int(state.get("attempt_count", 1) or 1) + 1
        state["resume_count"] = int(state.get("resume_count", 0) or 0) + 1
        state["current_stage"] = "resume"
        state["backend"] = LLM_BACKEND
        state["model"] = active_model() if effective_mode == "agent" else "deterministic_only"
        state.pop("error", None)
        clear_run_failure_artifact(run_path)
        add_run_event(state, "resume", "Resuming prior standalone run from saved checkpoints.", data={"run_path": run_path})
    else:
        run_id, run_path = make_run_dir(runs_dir)
        state = {
            "run_id": run_id,
            "started_at": utc_now_iso(),
            "completed_at": None,
            "status": "running",
            "requested_mode": requested_mode,
            "mode": effective_mode,
            "repo_path": repo_path,
            "backend": LLM_BACKEND,
            "model": active_model() if effective_mode == "agent" else "deterministic_only",
            "llm_output_policy": llm_output_policy,
            "grounding_profile": active_grounding_profile(),
            "events": [],
            "artifacts": {},
            "attempt_count": 1,
            "resume_count": 0,
            "current_stage": "plan",
            "review_policy_path": analysis_review_policy_path,
        }

    run_lock_path = os.path.join(run_path, RUN_LOCK_FILENAME)
    run_heartbeat_path = os.path.join(run_path, RUN_HEARTBEAT_FILENAME)
    run_llm_backend_status_path = os.path.join(run_path, "llm_backend_status.json")
    run_security_policy_audit_path = os.path.join(run_path, "security_policy_audit.json")
    effective_scan_config = augment_scan_config_with_repo_artifact_exclusions(
        repo_path,
        effective_scan_config,
        [runs_dir, run_path, OUTPUT_DIR],
    )
    state["artifacts"]["run_lock"] = run_lock_path
    state["artifacts"]["run_heartbeat"] = run_heartbeat_path
    state["artifacts"]["run_llm_backend_status"] = run_llm_backend_status_path
    state["artifacts"]["run_security_policy_audit"] = run_security_policy_audit_path

    security_policy_audit = build_security_policy_audit(
        effective_scan_config,
        runtime_config,
        requested_mode=requested_mode,
        effective_mode=effective_mode,
    )

    lock_acquired = False
    previous_signal_handlers: dict[int, Any] = {}
    current_stage = "plan"
    def _notify_run_update(status: str) -> None:
        if callable(on_run_update):
            try:
                on_run_update(
                    {
                        "run_path": run_path,
                        "run_id": state.get("run_id", ""),
                        "status": status,
                        "current_stage": state.get("current_stage", ""),
                    }
                )
            except Exception:
                pass

    try:
        lock_info = acquire_run_lock(run_path, run_id=state["run_id"], attempt_count=int(state.get("attempt_count", 1) or 1))
        lock_acquired = True
        if lock_info.get("stale_reclaimed"):
            add_run_event(state, "resume" if resuming else "plan", "Reclaimed stale run lock before continuing.")
            print(f"[WARN] Reclaimed stale run lock for {run_path}")
        write_json_atomic(run_llm_backend_status_path, backend_status)
        write_json_atomic(run_security_policy_audit_path, security_policy_audit)
        if args.write_root_outputs:
            save_fact_index(LLM_BACKEND_STATUS_FILE, backend_status)
            save_fact_index(SECURITY_POLICY_AUDIT_FILE, security_policy_audit)
            state["artifacts"]["root_llm_backend_status"] = LLM_BACKEND_STATUS_FILE
            state["artifacts"]["root_security_policy_audit"] = SECURITY_POLICY_AUDIT_FILE
        add_run_event(state, "plan", "Created standalone analyzer run plan.")
        save_run_state(run_path, state)
        _notify_run_update("running")
        reset_shutdown_context()
        previous_signal_handlers = install_runtime_signal_handlers()

        print("[INFO] repo_path =", repo_path)
        print("[INFO] exists?  ", os.path.exists(repo_path))
        if args.write_root_outputs:
            print("[INFO] output_dir =", os.path.abspath(OUTPUT_DIR))
        if report_home_dir:
            print("[INFO] desktop_report_home =", report_home_dir)
        print(f"[INFO] run_id={state['run_id']}")
        print(f"[INFO] run_path={run_path}")
        print(f"[INFO] attempt_count={state.get('attempt_count', 1)}")
        print(f"[INFO] requested_mode={requested_mode}")
        print(f"[INFO] effective_mode={effective_mode}")
        print(f"[INFO] runtime_probe={bool(runtime_config.get('enabled', False))}")
        print(f"[INFO] runtime_commands={len(runtime_config.get('commands', []))}")
        print(f"[INFO] security_policy={summarize_security_policy(effective_scan_config.get('security_policy', {}))}")
        if backend_status.get("selected_model"):
            print(f"[INFO] selected_model={backend_status.get('selected_model')}")
        if backend_status.get("error"):
            print(f"[INFO] llm_backend_status_error={backend_status.get('error')}")

        if not security_policy_audit.get("pass", False):
            state["status"] = "failed_security_policy"
            state["current_stage"] = "plan"
            state["completed_at"] = utc_now_iso()
            failure_path = write_run_failure_artifact(
                run_path,
                run_id=state["run_id"],
                repo_path=repo_path,
                stage="plan",
                status="failed_security_policy",
                error="; ".join(security_policy_audit.get("violations", [])[:3]),
                resumable=False,
            )
            state["artifacts"]["run_failure"] = failure_path
            save_error = safe_save_run_state(run_path, state)
            _notify_run_update("failed_security_policy")
            if save_error:
                print(f"[WARN] Failed to persist state after security policy block: {save_error}")
            print(f"❌ Security policy blocked execution: {'; '.join(security_policy_audit.get('violations', [])[:3])}")
            print(f"[SAVED] {failure_path}")
            return {"exit_code": 1, "status": "failed_security_policy", "run_path": run_path, "resumable": False}

        current_stage = "gather"
        state["current_stage"] = current_stage
        add_run_event(state, "gather", "Reading repository and building deterministic fact inventory.")
        save_run_state(run_path, state)
        gather_t0 = time.perf_counter()
        reused_gather_checkpoint = False
        resume_gather = load_gather_resume_context(run_path) if resuming else None

        if resume_gather:
            _code, resume_redaction_stats = read_files(
                repo_path,
                max_chars=MAX_CHARS,
                collect_text=False,
                scan_config=effective_scan_config,
            )
            resume_included_files = set([p.replace("\\", "/") for p in resume_redaction_stats.get("included_files", [])])
            resume_line_counts = {
                p.replace("\\", "/"): int(n)
                for p, n in resume_redaction_stats.get("line_counts", {}).items()
            }
            current_fingerprint = compute_repo_fingerprint(resume_included_files, resume_line_counts) if resume_included_files else ""
            if current_fingerprint and current_fingerprint == str(resume_gather.get("repo_fingerprint", "")).strip():
                reused_gather_checkpoint = True
                redaction_stats = resume_gather["redaction_stats"]
                included_files = resume_gather["included_files"]
                line_counts = resume_gather["line_counts"]
                repo_fingerprint = str(resume_gather.get("repo_fingerprint", "")).strip()
                fact_index_cache_stats = resume_gather["fact_index_cache_stats"]
                fact_index = resume_gather["fact_index"]
                model_safe_fact_index = resume_gather["model_safe_fact_index"]
                prompt_fact_context = resume_gather["prompt_fact_context"]
                claim_support_index = resume_gather["claim_support_index"]
                runtime_config = resolve_runtime_probe_config(fact_index, resume_gather.get("runtime_config", runtime_config))
                security_policy_audit = build_security_policy_audit(
                    effective_scan_config,
                    runtime_config,
                    requested_mode=requested_mode,
                    effective_mode=effective_mode,
                    redaction_stats=redaction_stats,
                )
                write_json_atomic(run_security_policy_audit_path, security_policy_audit)
                if args.write_root_outputs:
                    save_fact_index(SECURITY_POLICY_AUDIT_FILE, security_policy_audit)
                if not security_policy_audit.get("pass", False):
                    raise RuntimeError(
                        f"Security policy blocked execution after resume verification: {'; '.join(security_policy_audit.get('violations', [])[:3])}"
                    )
                state["artifacts"]["run_gather_checkpoint"] = os.path.join(run_path, RUN_GATHER_CHECKPOINT_FILENAME)
                add_run_event(state, "resume", "Reused gather checkpoint after fingerprint verification.")
            else:
                add_run_event(state, "resume", "Gather checkpoint invalidated because repository fingerprint changed.")

        if not reused_gather_checkpoint:
            _code, redaction_stats = read_files(
                repo_path,
                max_chars=MAX_CHARS,
                collect_text=False,
                scan_config=effective_scan_config,
            )
            included_files = set([p.replace("\\", "/") for p in redaction_stats.get("included_files", [])])
            line_counts = {
                p.replace("\\", "/"): int(n)
                for p, n in redaction_stats.get("line_counts", {}).items()
            }
            if not included_files:
                raise RuntimeError("No files were collected. Check include extensions, skip rules, and max file size settings.")
            repo_fingerprint = compute_repo_fingerprint(included_files, line_counts)
            state["repo_fingerprint"] = repo_fingerprint
            fact_index, fact_index_cache_stats = build_local_fact_index_incremental(
                repo_path=repo_path,
                included_files=sorted(list(included_files)),
                line_counts=line_counts,
                use_cache=True,
            )
            runtime_config = resolve_runtime_probe_config(fact_index, runtime_config)
            security_policy_audit = build_security_policy_audit(
                effective_scan_config,
                runtime_config,
                requested_mode=requested_mode,
                effective_mode=effective_mode,
                redaction_stats=redaction_stats,
            )
            write_json_atomic(run_security_policy_audit_path, security_policy_audit)
            if args.write_root_outputs:
                save_fact_index(SECURITY_POLICY_AUDIT_FILE, security_policy_audit)
            if not security_policy_audit.get("pass", False):
                raise RuntimeError(
                    f"Security policy blocked execution after scan: {'; '.join(security_policy_audit.get('violations', [])[:3])}"
                )

            run_runtime_observations_path = os.path.join(run_path, "runtime_observations.md")
            runtime_data = collect_runtime_observations(
                repo_path=repo_path,
                fact_index=fact_index,
                runtime_config=runtime_config,
                artifact_path=run_runtime_observations_path,
            )
            fact_index = apply_runtime_observations_to_fact_index(fact_index, runtime_data)
            fact_index = refresh_architecture_views(fact_index)
            extra_evidence_targets: dict[str, int] = {}
            if runtime_data.get("artifact_path") and int(runtime_data.get("line_count", 0) or 0) > 0:
                extra_evidence_targets[str(runtime_data.get("artifact_path"))] = int(runtime_data.get("line_count", 0) or 0)
                state["artifacts"]["run_runtime_observations"] = run_runtime_observations_path
                if args.write_root_outputs:
                    shutil.copyfile(run_runtime_observations_path, RUNTIME_OBSERVATIONS_FILE)
                    state["artifacts"]["root_runtime_observations"] = RUNTIME_OBSERVATIONS_FILE
            included_files, line_counts = merge_extra_evidence_targets(included_files, line_counts, extra_evidence_targets)
            model_safe_fact_index = build_model_safe_fact_index(fact_index)
            prompt_fact_context = build_prompt_fact_context(fact_index)
            claim_support_index = build_claim_support_index(fact_index, redaction_stats=redaction_stats)

            run_fact_path = os.path.join(run_path, "fact_index.json")
            run_model_safe_fact_path = os.path.join(run_path, "model_safe_fact_index.json")
            run_prompt_fact_context_path = os.path.join(run_path, "prompt_fact_context.json")
            run_claim_support_index_path = os.path.join(run_path, "claim_support_index.json")
            save_fact_index(run_fact_path, fact_index)
            save_fact_index(run_model_safe_fact_path, model_safe_fact_index)
            save_fact_index(run_prompt_fact_context_path, prompt_fact_context)
            save_fact_index(run_claim_support_index_path, claim_support_index)
            state["artifacts"]["run_fact_index"] = run_fact_path
            state["artifacts"]["run_model_safe_fact_index"] = run_model_safe_fact_path
            state["artifacts"]["run_prompt_fact_context"] = run_prompt_fact_context_path
            state["artifacts"]["run_claim_support_index"] = run_claim_support_index_path
            if args.write_root_outputs:
                save_fact_index(FACT_INDEX_FILE, fact_index)
                save_fact_index(MODEL_SAFE_FACT_INDEX_FILE, model_safe_fact_index)
                save_fact_index(PROMPT_FACT_CONTEXT_FILE, prompt_fact_context)
                save_fact_index(CLAIM_SUPPORT_INDEX_FILE, claim_support_index)
                save_fact_index(LLM_BACKEND_STATUS_FILE, backend_status)
                state["artifacts"]["root_fact_index"] = FACT_INDEX_FILE
                state["artifacts"]["root_model_safe_fact_index"] = MODEL_SAFE_FACT_INDEX_FILE
                state["artifacts"]["root_prompt_fact_context"] = PROMPT_FACT_CONTEXT_FILE
                state["artifacts"]["root_claim_support_index"] = CLAIM_SUPPORT_INDEX_FILE
                state["artifacts"]["root_llm_backend_status"] = LLM_BACKEND_STATUS_FILE
            checkpoint_path = save_run_gather_checkpoint(
                run_path,
                {
                    "repo_fingerprint": repo_fingerprint,
                    "included_files": sorted(list(included_files)),
                    "line_counts": line_counts,
                    "redaction_stats": redaction_stats,
                    "fact_index_cache_stats": fact_index_cache_stats,
                    "runtime_config": runtime_config,
                    "artifacts": {
                        "run_fact_index": run_fact_path,
                        "run_model_safe_fact_index": run_model_safe_fact_path,
                        "run_prompt_fact_context": run_prompt_fact_context_path,
                        "run_claim_support_index": run_claim_support_index_path,
                    },
                },
            )
            state["artifacts"]["run_gather_checkpoint"] = checkpoint_path
            save_run_state(run_path, state)
        elif args.write_root_outputs:
            save_fact_index(FACT_INDEX_FILE, fact_index)
            save_fact_index(MODEL_SAFE_FACT_INDEX_FILE, model_safe_fact_index)
            save_fact_index(PROMPT_FACT_CONTEXT_FILE, prompt_fact_context)
            save_fact_index(CLAIM_SUPPORT_INDEX_FILE, claim_support_index)
            save_fact_index(LLM_BACKEND_STATUS_FILE, backend_status)
            state["artifacts"]["root_fact_index"] = FACT_INDEX_FILE
            state["artifacts"]["root_model_safe_fact_index"] = MODEL_SAFE_FACT_INDEX_FILE
            state["artifacts"]["root_prompt_fact_context"] = PROMPT_FACT_CONTEXT_FILE
            state["artifacts"]["root_claim_support_index"] = CLAIM_SUPPORT_INDEX_FILE
            state["artifacts"]["root_llm_backend_status"] = LLM_BACKEND_STATUS_FILE

        state["repo_fingerprint"] = repo_fingerprint
        prompt_fact_index_json = json.dumps(prompt_fact_context, ensure_ascii=True, indent=2)
        allowed_files_text = format_allowed_files_for_prompt(list(included_files))
        allowed_evidence_text = format_allowed_evidence_for_prompt(line_counts)

        current_stage = "synthesize"
        state["current_stage"] = current_stage
        add_run_event(state, "synthesize", "Starting standalone documentation synthesis.")
        save_run_state(run_path, state)
        synth_t0 = time.perf_counter()

        final_text = ""
        final_validation: dict[str, Any] = {}
        final_gate: dict[str, Any] = {"pass": False, "coverage": 0.0}
        source = "none"
        llm_enhancements: dict[str, Any] = {
            "requested": effective_mode == "agent",
            "base_gate_pass": False,
            "accepted_sections_count": 0,
            "accepted_section_headings": [],
            "rejected_section_headings": [],
            "sections": [],
            "applied_sections": [],
        }
        resumed_synthesis = load_synthesis_resume_context(run_path) if resuming else None

        if resumed_synthesis:
            final_text = str(resumed_synthesis.get("final_text", ""))
            final_validation = resumed_synthesis.get("final_validation", {})
            final_gate = resumed_synthesis.get("final_gate", {})
            source = str(resumed_synthesis.get("source", "checkpoint")).strip() or "checkpoint"
            if isinstance(resumed_synthesis.get("llm_enhancements", {}), dict):
                llm_enhancements = resumed_synthesis.get("llm_enhancements", {})
                state["llm_enhancements"] = llm_enhancements
            add_run_event(state, "resume", "Reused synthesis checkpoint and skipped report regeneration.")
        else:
            hybrid_result = synthesize_hybrid_report(
                repo_path=repo_path,
                effective_mode=effective_mode,
                llm_output_policy=llm_output_policy,
                fact_index=fact_index,
                redaction_stats=redaction_stats,
                included_files=included_files,
                line_counts=line_counts,
                fact_context_json=prompt_fact_index_json,
                max_iterations=getattr(args, "max_iterations", 2),
                claim_support_index=claim_support_index,
            )
            final_text = str(hybrid_result.get("report", ""))
            final_validation = hybrid_result.get("validation", {})
            final_gate = hybrid_result.get("gate", {})
            source = str(hybrid_result.get("source", "none")).strip() or "none"
            llm_enhancements = hybrid_result.get("llm_enhancements", {}) if isinstance(hybrid_result.get("llm_enhancements", {}), dict) else llm_enhancements
            state["llm_enhancements"] = llm_enhancements
            add_run_event(
                state,
                "synthesize",
                "Built deterministic-first report and applied validated LLM enhancement sections.",
                data={
                    "source": source,
                    "llm_sections_applied": int(llm_enhancements.get("accepted_sections_count", 0) or 0),
                    "llm_sections_rejected": len(llm_enhancements.get("rejected_section_headings", [])),
                },
            )
            if effective_mode == "deterministic":
                add_run_event(state, "synthesize", "Built deterministic report in deterministic mode.")

            checkpoint_path = save_run_synthesis_checkpoint(
                run_path,
                {
                    "llm_output_policy": llm_output_policy,
                    "fallback_used": source.startswith("deterministic"),
                    "accepted_iteration": "",
                    "source": source,
                    "final_text": final_text,
                    "final_validation": final_validation,
                    "final_gate": final_gate,
                    "llm_enhancements": llm_enhancements,
                    "iterations": [],
                    "iteration_errors": [],
                },
            )
            state["artifacts"]["run_synthesis_checkpoint"] = checkpoint_path
            save_run_state(run_path, state)

        current_stage = "finalize"
        state["current_stage"] = current_stage
        save_run_state(run_path, state)

        traceability = {
            "scanned_files_count": int(final_validation.get("scanned_files_count", len(included_files))),
            "valid_evidence_paths_count": int(final_validation.get("valid_evidence_paths", 0)),
            "evidence_file_coverage": float(final_validation.get("file_evidence_coverage", 0.0)),
            "files_missing_evidence_count": int(final_validation.get("files_missing_evidence_count", 0)),
            "files_missing_evidence_sample": final_validation.get("files_missing_evidence_sample", []),
            "strict_traceability_enabled": bool(final_gate.get("strict_traceability_enabled", False)),
            "strict_traceability_pass": bool(final_gate.get("strict_traceability_pass", True)),
        }
        run_traceability_path = os.path.join(run_path, "traceability.json")
        run_inference_audit_path = os.path.join(run_path, "inference_audit.json")
        run_contradiction_audit_path = os.path.join(run_path, "contradiction_audit.json")
        run_contradiction_audit_md_path = os.path.join(run_path, "contradiction_audit.md")
        run_unsupported_claim_audit_path = os.path.join(run_path, RUN_UNSUPPORTED_CLAIM_AUDIT_FILENAME)
        run_unsupported_claim_audit_md_path = os.path.join(run_path, RUN_UNSUPPORTED_CLAIM_AUDIT_MARKDOWN_FILENAME)
        run_self_review_audit_path = os.path.join(run_path, RUN_SELF_REVIEW_AUDIT_FILENAME)
        run_self_review_audit_md_path = os.path.join(run_path, RUN_SELF_REVIEW_AUDIT_MARKDOWN_FILENAME)
        run_external_integrations_audit_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATIONS_AUDIT_FILENAME)
        run_external_integrations_audit_md_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATIONS_AUDIT_MARKDOWN_FILENAME)
        run_external_integration_plan_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATION_PLAN_FILENAME)
        run_external_integration_plan_md_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATION_PLAN_MARKDOWN_FILENAME)
        run_external_integration_dispatch_specs_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATION_DISPATCH_SPECS_FILENAME)
        run_external_integration_dispatch_specs_md_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATION_DISPATCH_SPECS_MARKDOWN_FILENAME)
        run_external_integration_dispatch_results_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATION_DISPATCH_RESULTS_FILENAME)
        run_external_integration_dispatch_results_md_path = os.path.join(run_path, RUN_EXTERNAL_INTEGRATION_DISPATCH_RESULTS_MARKDOWN_FILENAME)
        contradiction_audit = build_contradiction_audit(fact_index)
        unsupported_claim_audit = build_unsupported_claim_audit(final_validation)
        endpoint_quality_summary = summarize_endpoint_quality_for_endpoints(fact_index.get("api_endpoints", []))
        self_review_audit = build_self_review_audit(
            validation_stats=final_validation,
            gate=final_gate,
            contradiction_summary=contradiction_audit,
            unsupported_claim_summary=unsupported_claim_audit,
            endpoint_quality_summary=endpoint_quality_summary,
            traceability_summary=traceability,
        )
        external_integrations_audit = build_external_integrations_audit(analysis_review_policy, phase="analysis")
        external_integration_plan = build_external_integration_execution_plan(external_integrations_audit)
        external_integration_dispatch_specs = build_external_integration_dispatch_specs(external_integrations_audit)
        external_integration_dispatch_results = build_external_integration_dispatch_results(external_integration_dispatch_specs)
        write_json_atomic(run_traceability_path, traceability)
        inference_records = build_reasoned_inference_records(fact_index)
        write_json_atomic(
            run_inference_audit_path,
            {"record_count": len(inference_records), "records": inference_records},
        )
        write_json_atomic(run_contradiction_audit_path, contradiction_audit)
        write_text_atomic(run_contradiction_audit_md_path, render_contradiction_audit_markdown(contradiction_audit))
        write_json_atomic(run_unsupported_claim_audit_path, unsupported_claim_audit)
        write_text_atomic(run_unsupported_claim_audit_md_path, render_unsupported_claim_audit_markdown(unsupported_claim_audit))
        write_json_atomic(run_self_review_audit_path, self_review_audit)
        write_text_atomic(run_self_review_audit_md_path, render_self_review_audit_markdown(self_review_audit))
        write_json_atomic(run_external_integrations_audit_path, external_integrations_audit)
        write_text_atomic(run_external_integrations_audit_md_path, render_external_integrations_audit_markdown(external_integrations_audit))
        write_json_atomic(run_external_integration_plan_path, external_integration_plan)
        write_text_atomic(run_external_integration_plan_md_path, render_external_integration_execution_plan_markdown(external_integration_plan))
        write_json_atomic(run_external_integration_dispatch_specs_path, external_integration_dispatch_specs)
        write_text_atomic(
            run_external_integration_dispatch_specs_md_path,
            render_external_integration_dispatch_specs_markdown(external_integration_dispatch_specs),
        )
        write_json_atomic(run_external_integration_dispatch_results_path, external_integration_dispatch_results)
        write_text_atomic(
            run_external_integration_dispatch_results_md_path,
            render_external_integration_dispatch_results_markdown(external_integration_dispatch_results),
        )
        state["artifacts"]["run_traceability"] = run_traceability_path
        state["artifacts"]["run_inference_audit"] = run_inference_audit_path
        state["artifacts"]["run_contradiction_audit"] = run_contradiction_audit_path
        state["artifacts"]["run_contradiction_audit_markdown"] = run_contradiction_audit_md_path
        state["artifacts"]["run_unsupported_claim_audit"] = run_unsupported_claim_audit_path
        state["artifacts"]["run_unsupported_claim_audit_markdown"] = run_unsupported_claim_audit_md_path
        state["artifacts"]["run_self_review_audit"] = run_self_review_audit_path
        state["artifacts"]["run_self_review_audit_markdown"] = run_self_review_audit_md_path
        state["artifacts"]["run_external_integrations_audit"] = run_external_integrations_audit_path
        state["artifacts"]["run_external_integrations_audit_markdown"] = run_external_integrations_audit_md_path
        state["artifacts"]["run_external_integration_plan"] = run_external_integration_plan_path
        state["artifacts"]["run_external_integration_plan_markdown"] = run_external_integration_plan_md_path
        state["artifacts"]["run_external_integration_dispatch_specs"] = run_external_integration_dispatch_specs_path
        state["artifacts"]["run_external_integration_dispatch_specs_markdown"] = run_external_integration_dispatch_specs_md_path
        state["artifacts"]["run_external_integration_dispatch_results"] = run_external_integration_dispatch_results_path
        state["artifacts"]["run_external_integration_dispatch_results_markdown"] = run_external_integration_dispatch_results_md_path
        state["contradiction_audit"] = contradiction_audit
        state["unsupported_claim_audit"] = unsupported_claim_audit
        state["self_review_audit"] = self_review_audit
        state["external_integrations_audit"] = external_integrations_audit
        state["external_integration_plan"] = external_integration_plan
        state["external_integration_dispatch_specs"] = external_integration_dispatch_specs
        state["external_integration_dispatch_results"] = external_integration_dispatch_results
        if effective_mode == "agent":
            run_llm_enhancements_path = os.path.join(run_path, "llm_enhancements.json")
            write_json_atomic(run_llm_enhancements_path, llm_enhancements)
            state["artifacts"]["run_llm_enhancements"] = run_llm_enhancements_path

        final_validation["classification_summary"] = fact_index.get("classification_summary", {})
        final_text = append_quality_metrics(final_text, final_validation, redaction_stats, final_gate)
        best_effort_report = source.startswith("llm_best_effort")
        accepted_report = bool(final_gate.get("pass", False)) or best_effort_report
        run_report_path = os.path.join(run_path, "report.md" if accepted_report else "report_rejected.md")
        write_text_atomic(run_report_path, final_text)
        state["artifacts"]["run_report"] = run_report_path
        state["report_source"] = source
        state["llm_output_policy"] = llm_output_policy
        state["best_effort_accepted"] = best_effort_report
        state["llm_enhancements"] = llm_enhancements
        state["gate"] = final_gate
        state["validation"] = final_validation
        if args.write_root_outputs:
            if accepted_report:
                write_text_atomic(OUTPUT_FILE, final_text)
                state["artifacts"]["root_report"] = OUTPUT_FILE
            else:
                write_text_atomic(REJECTED_REPORT_FILE, final_text)
                state["artifacts"]["root_report_rejected"] = REJECTED_REPORT_FILE

        state["artifacts"].update(write_run_architecture_exports(run_path, final_text, fact_index, bool(args.write_root_outputs)))
        subsystem_stats = write_subsystem_docs(run_path, fact_index)
        state["artifacts"]["run_subsystem_dir"] = subsystem_stats.get("run_subsystem_dir", "")
        state["artifacts"]["run_subsystem_index"] = subsystem_stats.get("run_subsystem_index", "")
        review_artifact_hashes: list[dict[str, Any]] = []
        for key in [
            "run_report",
            "run_fact_index",
            "run_claim_support_index",
            "run_traceability",
            "run_inference_audit",
            "run_contradiction_audit",
            "run_contradiction_audit_markdown",
            "run_unsupported_claim_audit",
            "run_unsupported_claim_audit_markdown",
            "run_self_review_audit",
            "run_self_review_audit_markdown",
            "run_external_integrations_audit",
            "run_external_integrations_audit_markdown",
            "run_external_integration_plan",
            "run_external_integration_plan_markdown",
            "run_external_integration_dispatch_specs",
            "run_external_integration_dispatch_specs_markdown",
            "run_external_integration_dispatch_results",
            "run_external_integration_dispatch_results_markdown",
            "run_architecture_model",
            "run_subsystem_index",
        ]:
            path = str(state.get("artifacts", {}).get(key, "")).strip()
            if path and os.path.exists(path):
                review_artifact_hashes.append(_artifact_hash_entry(key, path))
        review_audit_bundle = build_review_audit_bundle(
            phase="analysis",
            run_path=run_path,
            state=state,
            review_policy_path="",
            classification_summary=fact_index.get("classification_summary", {}) if isinstance(fact_index.get("classification_summary", {}), dict) else {},
            endpoint_quality_summary=endpoint_quality_summary,
            grounding_summary={
                "gate_pass": bool(final_gate.get("pass", False)),
                "evidence_coverage": float(final_gate.get("coverage", 0.0) or 0.0),
                "semantic_coverage": float(final_gate.get("semantic_coverage", 1.0) or 1.0),
                "files_missing_evidence_count": int(final_validation.get("files_missing_evidence_count", 0) or 0),
                "claims_semantically_unsupported": int(final_validation.get("claims_semantically_unsupported", 0) or 0),
            },
            contradiction_summary=contradiction_audit,
            unsupported_claim_summary=unsupported_claim_audit,
            self_review_summary=self_review_audit,
            external_integrations_summary=external_integrations_audit,
            external_integration_dispatch_specs_summary=external_integration_dispatch_specs,
            external_integration_dispatch_results_summary=external_integration_dispatch_results,
            artifact_hashes=review_artifact_hashes,
        )
        run_review_audit_path = os.path.join(run_path, RUN_REVIEW_AUDIT_FILENAME)
        run_review_audit_sarif_path = os.path.join(run_path, RUN_REVIEW_AUDIT_SARIF_FILENAME)
        write_json_atomic(run_review_audit_path, review_audit_bundle)
        write_json_atomic(run_review_audit_sarif_path, build_review_audit_sarif(review_audit_bundle))
        state["artifacts"]["run_review_audit"] = run_review_audit_path
        state["artifacts"]["run_review_audit_sarif"] = run_review_audit_sarif_path
        add_run_event(
            state,
            "subsystems",
            "Generated subsystem-level documentation artifacts.",
            data={"subsystem_count": int(subsystem_stats.get("subsystem_count", 0) or 0)},
        )
        previous = find_previous_run_for_repo(runs_dir, run_path, repo_path, current_state=state)
        if previous:
            try:
                import agent

                diff_obj = agent.compare_run_dirs(previous["run_dir"], run_path)
                run_diff_md_path = os.path.join(run_path, "run_diff.md")
                run_diff_json_path = os.path.join(run_path, "run_diff.json")
                run_architecture_diff_md_path = os.path.join(run_path, "architecture_diff.md")
                run_architecture_diff_json_path = os.path.join(run_path, "architecture_diff.json")
                write_text_atomic(run_diff_md_path, agent.render_run_diff_markdown(diff_obj))
                write_json_atomic(run_diff_json_path, diff_obj)
                write_text_atomic(
                    run_architecture_diff_md_path,
                    agent.render_architecture_diff_markdown(
                        diff_obj.get("architecture", {}),
                        base_run_id=diff_obj.get("base_run_id", ""),
                        head_run_id=diff_obj.get("head_run_id", ""),
                    ),
                )
                write_json_atomic(
                    run_architecture_diff_json_path,
                    diff_obj.get("architecture", {}) if isinstance(diff_obj.get("architecture", {}), dict) else {},
                )
                state["artifacts"]["run_diff_markdown"] = run_diff_md_path
                state["artifacts"]["run_diff_json"] = run_diff_json_path
                state["artifacts"]["run_architecture_diff_markdown"] = run_architecture_diff_md_path
                state["artifacts"]["run_architecture_diff_json"] = run_architecture_diff_json_path
                state["previous_run_id"] = previous.get("run_id", "")
                add_run_event(
                    state,
                    "compare",
                    "Computed run to run delta against previous repository run.",
                    data={"previous_run_id": previous.get("run_id", "")},
                )
            except Exception as e:
                add_run_event(
                    state,
                    "compare",
                    "Run comparison skipped due to comparison error.",
                    data={"error": str(e)},
                )
        else:
            add_run_event(state, "compare", "No previous comparable run found for this repository.")
        gather_sec = time.perf_counter() - gather_t0
        synth_sec = time.perf_counter() - synth_t0
        total_sec = time.perf_counter() - overall_t0
        timings = {
            "gather_sec": round(gather_sec, 3),
            "synthesize_sec": round(synth_sec, 3),
            "total_sec": round(total_sec, 3),
        }
        summary_path = write_analysis_run_summary(
            run_path,
            run_id=state["run_id"],
            repo_path=repo_path,
            requested_mode=requested_mode,
            effective_mode=effective_mode,
            state=state,
            redaction_stats=redaction_stats,
            fact_index=fact_index,
            fact_index_cache_stats=fact_index_cache_stats,
            validation=final_validation,
            gate=final_gate,
            source=source,
            run_report_path=run_report_path,
            timings=timings,
        )
        state["artifacts"]["run_summary"] = summary_path
        if report_home_dir:
            state["artifacts"].update(write_repo_report_shortcuts(report_home_dir, run_path, summary_path, run_report_path))
        state["completed_at"] = utc_now_iso()
        state["status"] = "completed" if accepted_report else "failed_gate"
        state["current_stage"] = state["status"]
        clear_run_failure_artifact(run_path)
        save_run_state(run_path, state)
        _notify_run_update(state["status"])

        print(f"[SAVED] {run_report_path}")
        print(f"[SAVED] {summary_path}")
        if state.get("artifacts", {}).get("run_self_review_audit"):
            print(f"[SAVED] {state['artifacts']['run_self_review_audit']}")
        if state.get("artifacts", {}).get("run_self_review_audit_markdown"):
            print(f"[SAVED] {state['artifacts']['run_self_review_audit_markdown']}")
        if state.get("artifacts", {}).get("run_external_integrations_audit"):
            print(f"[SAVED] {state['artifacts']['run_external_integrations_audit']}")
        if state.get("artifacts", {}).get("run_external_integrations_audit_markdown"):
            print(f"[SAVED] {state['artifacts']['run_external_integrations_audit_markdown']}")
        if state.get("artifacts", {}).get("run_external_integration_plan"):
            print(f"[SAVED] {state['artifacts']['run_external_integration_plan']}")
        if state.get("artifacts", {}).get("run_external_integration_plan_markdown"):
            print(f"[SAVED] {state['artifacts']['run_external_integration_plan_markdown']}")
        if state.get("artifacts", {}).get("run_external_integration_dispatch_specs"):
            print(f"[SAVED] {state['artifacts']['run_external_integration_dispatch_specs']}")
        if state.get("artifacts", {}).get("run_external_integration_dispatch_specs_markdown"):
            print(f"[SAVED] {state['artifacts']['run_external_integration_dispatch_specs_markdown']}")
        if state.get("artifacts", {}).get("run_external_integration_dispatch_results"):
            print(f"[SAVED] {state['artifacts']['run_external_integration_dispatch_results']}")
        if state.get("artifacts", {}).get("run_external_integration_dispatch_results_markdown"):
            print(f"[SAVED] {state['artifacts']['run_external_integration_dispatch_results_markdown']}")
        if state.get("artifacts", {}).get("run_unsupported_claim_audit"):
            print(f"[SAVED] {state['artifacts']['run_unsupported_claim_audit']}")
        if state.get("artifacts", {}).get("run_unsupported_claim_audit_markdown"):
            print(f"[SAVED] {state['artifacts']['run_unsupported_claim_audit_markdown']}")
        print(f"[SAVED] {os.path.join(run_path, RUN_STATE_FILENAME)}")
        if args.write_root_outputs and accepted_report:
            print(f"[SAVED] {OUTPUT_FILE}")
            print(final_text)
        if args.write_root_outputs and not accepted_report:
            print(f"[SAVED] {REJECTED_REPORT_FILE}")
        return {
            "exit_code": 0 if accepted_report else 2,
            "status": state["status"],
            "run_path": run_path,
            "resumable": False,
        }
    except ShutdownRequested as e:
        state["completed_at"] = utc_now_iso()
        state["status"] = "interrupted"
        state["current_stage"] = current_stage
        state["error"] = str(e)
        add_run_event(state, "shutdown", "Graceful shutdown requested.", data={"signal": _SHUTDOWN_CONTEXT.get("signal", "")})
        failure_path = write_run_failure_artifact(
            run_path,
            run_id=state["run_id"],
            repo_path=repo_path,
            stage=current_stage,
            status="interrupted",
            error=str(e),
            resumable=current_stage in {"gather", "synthesize", "finalize"},
        )
        state["artifacts"]["run_failure"] = failure_path
        save_error = safe_save_run_state(run_path, state)
        _notify_run_update("interrupted")
        if save_error:
            print(f"[WARN] Failed to persist interrupted state: {save_error}")
        print(f"[WARN] {e}")
        print(f"[SAVED] {failure_path}")
        return {"exit_code": 130, "status": "interrupted", "run_path": run_path, "resumable": True}
    except Timeout:
        state["completed_at"] = utc_now_iso()
        state["status"] = "error"
        state["current_stage"] = current_stage
        state["error"] = f"Timeout: model took too long (> {TIMEOUT_SECONDS}s)."
        failure_path = write_run_failure_artifact(
            run_path,
            run_id=state["run_id"],
            repo_path=repo_path,
            stage=current_stage,
            status="error",
            error=state["error"],
            resumable=current_stage in {"gather", "synthesize", "finalize"},
        )
        state["artifacts"]["run_failure"] = failure_path
        save_error = safe_save_run_state(run_path, state)
        _notify_run_update("error")
        if save_error:
            print(f"[WARN] Failed to persist timeout state: {save_error}")
        print(f"❌ {state['error']}")
        print(f"[SAVED] {failure_path}")
        return {"exit_code": 1, "status": "error", "run_path": run_path, "resumable": True}
    except Exception as e:
        state["completed_at"] = utc_now_iso()
        state["status"] = "error"
        state["current_stage"] = current_stage
        state["error"] = str(e)
        add_run_event(state, "error", "Unhandled error during standalone analysis.", data={"error": str(e)})
        failure_path = write_run_failure_artifact(
            run_path,
            run_id=state["run_id"],
            repo_path=repo_path,
            stage=current_stage,
            status="error",
            error=str(e),
            resumable=current_stage in {"gather", "synthesize", "finalize"},
        )
        state["artifacts"]["run_failure"] = failure_path
        save_error = safe_save_run_state(run_path, state)
        _notify_run_update("error")
        if save_error:
            print(f"[WARN] Failed to persist error state: {save_error}")
        print(f"❌ Error: {e}")
        print(f"[SAVED] {failure_path}")
        return {"exit_code": 1, "status": "error", "run_path": run_path, "resumable": True}
    finally:
        if previous_signal_handlers:
            restore_runtime_signal_handlers(previous_signal_handlers)
        if lock_acquired:
            release_run_lock(run_path)
        if previous_grounding_profile_override:
            set_active_grounding_profile_override(previous_grounding_profile_override)
        else:
            clear_active_grounding_profile_override()


def build_queue_job_payload(args: argparse.Namespace, repo_path: str) -> dict[str, Any]:
    queue_meta = queue_scope_descriptor(args.queue_dir, getattr(args, "queue_name", ""), getattr(args, "queue_class", ""))
    return {
        "job_id": make_queue_job_id(),
        "repo_path": repo_path,
        "mode": args.mode,
        "grounding_profile": str(getattr(args, "grounding_profile", active_grounding_profile())).strip() or active_grounding_profile(),
        "grounding_profile_explicit": bool(getattr(args, "grounding_profile_explicit", False)),
        "policy_pack": list(getattr(args, "policy_pack", []) or []),
        "runtime_probe": args.runtime_probe,
        "runtime_command": list(args.runtime_command),
        "runtime_timeout_seconds": args.runtime_timeout_seconds,
        "runtime_max_output_chars": args.runtime_max_output_chars,
        "require_llm": bool(args.require_llm),
        "runs_dir": resolve_runs_dir(args.runs_dir),
        "resume_run": str(args.resume_run or "").strip(),
        "queue_name": queue_meta["queue_name"],
        "queue_class": queue_meta["queue_class"],
        "queue_scope": queue_meta["queue_scope"],
        "priority": int(args.job_priority),
        "max_attempts": max(1, int(args.max_job_attempts or QUEUE_DEFAULT_MAX_ATTEMPTS)),
        "retry_backoff_seconds": coerce_positive_float(args.retry_backoff_seconds, QUEUE_DEFAULT_RETRY_BACKOFF_SECONDS),
        "retry_backoff_multiplier": coerce_positive_float(
            args.retry_backoff_multiplier,
            QUEUE_DEFAULT_RETRY_BACKOFF_MULTIPLIER,
        ),
        # Queue workers keep artifacts inside run directories to avoid root output collisions.
        "write_root_outputs": False,
    }


def build_args_from_queue_job(job: dict[str, Any]) -> argparse.Namespace:
    return argparse.Namespace(
        repo=str(job.get("repo_path", "")).strip(),
        repo_path="",
        mode=str(job.get("mode", "agent")).strip() or "agent",
        grounding_profile=str(job.get("grounding_profile", active_grounding_profile())).strip() or active_grounding_profile(),
        grounding_profile_explicit=bool(job.get("grounding_profile_explicit", False)),
        policy_pack=list(job.get("policy_pack", []) or []),
        runtime_probe=job.get("runtime_probe", None),
        runtime_command=list(job.get("runtime_command", []) or []),
        runtime_timeout_seconds=job.get("runtime_timeout_seconds", None),
        runtime_max_output_chars=job.get("runtime_max_output_chars", None),
        require_llm=bool(job.get("require_llm", False)),
        runs_dir=str(job.get("runs_dir", "")).strip(),
        resume_run=str(job.get("resume_run", "")).strip(),
        write_root_outputs=bool(job.get("write_root_outputs", False)),
        queue_dir="",
        queue_name=str(job.get("queue_name", "")).strip(),
        queue_class=str(job.get("queue_class", "")).strip(),
        job_priority=_queue_job_priority(job),
        max_job_attempts=_queue_job_max_attempts(job),
        retry_backoff_seconds=_queue_job_retry_backoff_seconds(job),
        retry_backoff_multiplier=_queue_job_retry_backoff_multiplier(job),
        status=False,
        status_json="",
        recent_limit=STATUS_RECENT_LIMIT,
        all_queues=False,
        enqueue_job=False,
        worker=False,
        worker_once=True,
        max_jobs=0,
        poll_interval_seconds=2.0,
    )


def resolve_queue_scope_from_args(args: argparse.Namespace) -> dict[str, Any]:
    return queue_scope_descriptor(
        getattr(args, "queue_dir", ""),
        getattr(args, "queue_name", ""),
        getattr(args, "queue_class", ""),
    )


def run_queue_worker(args: argparse.Namespace) -> int:
    queue_meta = resolve_queue_scope_from_args(args)
    queue_dir = str(queue_meta.get("queue_dir", "")).strip()
    ensure_queue_dirs(queue_dir)
    worker_id = f"worker_{os.getpid()}"
    processed = 0
    print(f"[INFO] queue_dir={queue_dir}")
    if queue_meta.get("queue_name"):
        print(f"[INFO] queue_name={queue_meta.get('queue_name', '')}")
    if queue_meta.get("queue_class"):
        print(f"[INFO] queue_class={queue_meta.get('queue_class', '')}")
    print(f"[INFO] worker_id={worker_id}")
    write_worker_heartbeat(queue_dir, worker_id, status="idle", processed_count=processed)
    write_queue_metrics(queue_dir)
    try:
        while True:
            if args.max_jobs and processed >= int(args.max_jobs):
                write_worker_heartbeat(queue_dir, worker_id, status="stopping", processed_count=processed)
                write_queue_metrics(queue_dir)
                return 0
            reclaim_stats = reclaim_stale_queue_jobs(queue_dir)
            if any(int(reclaim_stats.get(key, 0) or 0) > 0 for key in reclaim_stats):
                print(
                    "[WARN] reclaimed_stale_jobs "
                    f"pending={reclaim_stats.get('reclaimed_to_pending', 0)} "
                    f"completed={reclaim_stats.get('finalized_completed', 0)} "
                    f"failed={reclaim_stats.get('finalized_failed', 0)}"
                )
            write_worker_heartbeat(queue_dir, worker_id, status="idle", processed_count=processed)
            job_path, job = claim_next_queue_job(queue_dir, worker_id)
            if not job_path or not isinstance(job, dict):
                if args.worker_once:
                    write_worker_heartbeat(queue_dir, worker_id, status="idle", processed_count=processed)
                    write_queue_metrics(queue_dir)
                    return 0
                time.sleep(max(0.2, float(args.poll_interval_seconds or 2.0)))
                continue

            repo_path = str(job.get("repo_path", "")).strip()
            current_job_id = str(job.get("job_id", "")).strip()
            active_run_path = str(job.get("resume_run", "")).strip()
            write_worker_heartbeat(
                queue_dir,
                worker_id,
                status="running",
                processed_count=processed,
                current_job_id=current_job_id,
                current_run_path=active_run_path,
            )

            def _job_update(update: dict[str, Any]) -> None:
                latest = read_json_file(job_path)
                if not isinstance(latest, dict):
                    return
                latest["active_run_path"] = str(update.get("run_path", "")).strip()
                latest["active_run_id"] = str(update.get("run_id", "")).strip()
                latest["run_status"] = str(update.get("status", "")).strip()
                latest["run_stage"] = str(update.get("current_stage", "")).strip()
                write_json_atomic(job_path, latest)
                write_worker_heartbeat(
                    queue_dir,
                    worker_id,
                    status="running",
                    processed_count=processed,
                    current_job_id=current_job_id,
                    current_run_path=str(update.get("run_path", "")).strip(),
                )

            print(f"[INFO] processing_job={current_job_id} repo={repo_path}")
            result = run_repository_analysis(build_args_from_queue_job(job), repo_path, on_run_update=_job_update)
            processed += 1
            latest_job = read_json_file(job_path) or job
            latest_job["last_run_path"] = result.get("run_path", "")
            latest_job["last_exit_code"] = int(result.get("exit_code", 1))
            latest_job["last_status"] = str(result.get("status", "unknown"))
            latest_job["active_run_path"] = ""
            latest_job["run_stage"] = ""
            write_worker_heartbeat(queue_dir, worker_id, status="idle", processed_count=processed)
            if result.get("exit_code") == 0:
                target = move_queue_job(queue_dir, job_path, "completed", latest_job)
                print(f"[SAVED] {target}")
            elif result.get("exit_code") == 130 and result.get("run_path"):
                latest_job["resume_run"] = str(result.get("run_path", "")).strip()
                latest_job["status"] = "pending"
                latest_job["requeued_for_resume"] = True
                latest_job["next_attempt_at"] = ""
                write_json_atomic(job_path, latest_job)
                pending_path = os.path.join(queue_dir_paths(queue_dir)["pending"], os.path.basename(job_path))
                os.replace(job_path, pending_path)
                write_queue_metrics(queue_dir)
                print(f"[WARN] Job requeued for resume: {pending_path}")
                return 130
            else:
                if result.get("resumable") and result.get("run_path"):
                    latest_job["resume_run"] = str(result.get("run_path", "")).strip()
                if _queue_job_should_retry(latest_job, result):
                    retry_path = schedule_queue_job_retry(queue_dir, job_path, latest_job, result)
                    print(f"[WARN] Job retry scheduled: {retry_path}")
                    continue
                target = move_queue_job(queue_dir, job_path, "failed", latest_job)
                print(f"[SAVED] {target}")
    finally:
        remove_worker_heartbeat(queue_dir, worker_id)
        write_queue_metrics(queue_dir)


def recent_run_summaries(runs_dir: str, limit: int = STATUS_RECENT_LIMIT) -> list[dict[str, Any]]:
    root = resolve_runs_dir(runs_dir)
    if not os.path.isdir(root):
        return []
    candidates: list[tuple[float, str]] = []
    for name in os.listdir(root):
        run_path = os.path.join(root, name)
        state_path = os.path.join(run_path, RUN_STATE_FILENAME)
        if os.path.isdir(run_path) and os.path.isfile(state_path):
            try:
                candidates.append((os.path.getmtime(state_path), run_path))
            except Exception:
                continue
    candidates.sort(key=lambda item: item[0], reverse=True)
    out: list[dict[str, Any]] = []
    for _, run_path in candidates[: max(1, int(limit or STATUS_RECENT_LIMIT))]:
        state = load_run_state(run_path) or {}
        artifacts = state.get("artifacts", {}) if isinstance(state.get("artifacts", {}), dict) else {}
        approval_summary = load_run_approval(run_path, state=state)
        out.append(
            {
                "run_id": str(state.get("run_id", os.path.basename(run_path))).strip(),
                "status": str(state.get("status", "")).strip(),
                "repo_path": str(state.get("repo_path", "")).strip(),
                "requested_mode": str(state.get("requested_mode", "")).strip(),
                "effective_mode": str(state.get("mode", "")).strip(),
                "attempt_count": int(state.get("attempt_count", 0) or 0),
                "resume_count": int(state.get("resume_count", 0) or 0),
                "current_stage": str(state.get("current_stage", "")).strip(),
                "completed_at": str(state.get("completed_at", "")).strip(),
                "approved": bool(approval_summary.get("approval_requirements_met", False)) if isinstance(approval_summary, dict) else False,
                "published": _artifact_exists(str(artifacts.get("run_publish_manifest", "")).strip()),
                "run_path": run_path,
            }
        )
    return out


def build_operator_status(
    queue_dir: str,
    runs_dir: str,
    limit: int = STATUS_RECENT_LIMIT,
    *,
    queue_name: str = "",
    queue_class: str = "",
    all_queues: bool = False,
) -> dict[str, Any]:
    selection = queue_scope_descriptor(queue_dir, queue_name, queue_class)
    selection_payload = {
        "queue_root_dir": selection["queue_root_dir"],
        "queue_dir": selection["queue_dir"],
        "queue_name": selection["queue_name"],
        "queue_class": selection["queue_class"],
        "queue_scope": selection["queue_scope"],
        "queue_label": selection["queue_label"],
        "all_queues": bool(all_queues),
    }
    queue_summaries: list[dict[str, Any]] = []
    if all_queues:
        selection_payload["queue_dir"] = selection["queue_root_dir"]
        selection_payload["queue_scope"] = "all"
        selection_payload["queue_label"] = "all"
        for descriptor in list_queue_scope_descriptors(queue_dir):
            queue_summaries.append(
                {
                    **descriptor,
                    "metrics": build_queue_metrics(descriptor["queue_dir"]),
                }
            )
        queue_metrics = aggregate_queue_metrics(queue_dir, queue_summaries, limit=limit)
    else:
        queue_metrics = build_queue_metrics(selection["queue_dir"])
    return {
        "generated_at": utc_now_iso(),
        "selection": selection_payload,
        "queue": queue_metrics,
        "queues": queue_summaries,
        "runs": {
            "runs_dir": resolve_runs_dir(runs_dir),
            "recent": recent_run_summaries(runs_dir, limit=max(1, int(limit or STATUS_RECENT_LIMIT))),
        },
    }


def render_operator_status_text(status: dict[str, Any]) -> str:
    queue = status.get("queue", {}) if isinstance(status, dict) else {}
    counts = queue.get("counts", {}) if isinstance(queue, dict) else {}
    workers = queue.get("workers", {}) if isinstance(queue, dict) else {}
    running = queue.get("running_jobs", {}) if isinstance(queue, dict) else {}
    selection = status.get("selection", {}) if isinstance(status, dict) else {}
    lines = [
        "# Operator Status",
        "",
        f"- Generated At: `{status.get('generated_at', '')}`",
        f"- Queue Root Dir: `{selection.get('queue_root_dir', queue.get('queue_root_dir', queue.get('queue_dir', '')) )}`",
        f"- Queue Scope: `{selection.get('queue_scope', queue.get('queue_scope', QUEUE_ROOT_SCOPE_NAME))}`",
        f"- Queue Dir: `{selection.get('queue_dir', queue.get('queue_dir', ''))}`",
        f"- Pending Jobs: `{counts.get('pending', 0)}`",
        f"- Ready Pending Jobs: `{counts.get('pending_ready', counts.get('pending', 0))}`",
        f"- Delayed Pending Jobs: `{counts.get('pending_delayed', 0)}`",
        f"- Running Jobs: `{counts.get('running', 0)}`",
        f"- Completed Jobs: `{counts.get('completed', 0)}`",
        f"- Failed Jobs: `{counts.get('failed', 0)}`",
        f"- Active Workers: `{workers.get('active', 0)}`",
        f"- Stale Workers: `{workers.get('stale', 0)}`",
        f"- Stale Running Jobs: `{running.get('stale', 0)}`",
    ]
    queue_groups = status.get("queues", []) if isinstance(status, dict) else []
    if queue_groups:
        lines.extend(["", "## Queues"])
        for item in queue_groups:
            metrics = item.get("metrics", {}) if isinstance(item, dict) else {}
            group_counts = metrics.get("counts", {}) if isinstance(metrics, dict) else {}
            lines.append(
                f"- `{item.get('queue_scope', '')}` pending=`{group_counts.get('pending', 0)}` "
                f"running=`{group_counts.get('running', 0)}` completed=`{group_counts.get('completed', 0)}` "
                f"failed=`{group_counts.get('failed', 0)}` dir=`{item.get('queue_dir', '')}`"
            )

    lines.extend(["", "## Recent Jobs"])
    recent_jobs = queue.get("recent_jobs", []) if isinstance(queue, dict) else []
    if recent_jobs:
        for job in recent_jobs:
            retry_suffix = ""
            if job.get("status") == "pending" and job.get("next_attempt_at") and not job.get("ready", True):
                retry_suffix = f" next=`{job.get('next_attempt_at', '')}`"
            queue_suffix = ""
            if job.get("queue_scope"):
                queue_suffix = f" queue=`{job.get('queue_scope', '')}`"
            lines.append(
                f"- `{job.get('job_id', '')}` status=`{job.get('status', '')}` priority=`{job.get('priority', 0)}` "
                f"attempts=`{job.get('attempt_count', 0)}/{job.get('max_attempts', 0)}` worker=`{job.get('worker_id', '') or 'none'}` "
                f"repo=`{job.get('repo_path', '')}` run_status=`{job.get('run_status', '') or 'unknown'}`{queue_suffix}{retry_suffix}"
            )
    else:
        lines.append("- None")

    lines.extend(["", "## Recent Runs"])
    recent_runs = status.get("runs", {}).get("recent", []) if isinstance(status.get("runs", {}), dict) else []
    if recent_runs:
        for run in recent_runs:
            lines.append(
                f"- `{run.get('run_id', '')}` status=`{run.get('status', '')}` mode=`{run.get('effective_mode', '')}` "
                f"attempts=`{run.get('attempt_count', 0)}` approved=`{run.get('approved', False)}` "
                f"published=`{run.get('published', False)}` repo=`{run.get('repo_path', '')}`"
            )
    else:
        lines.append("- None")
    lines.append("")
    return "\n".join(lines)


def load_run_approval(
    run_path: str,
    state: Optional[dict[str, Any]] = None,
    review_policy: Optional[dict[str, Any]] = None,
) -> Optional[dict[str, Any]]:
    approval_records = load_run_approval_records(run_path, state=state)
    if approval_records:
        return summarize_approval_records(approval_records, review_policy=review_policy)
    candidate = ""
    if isinstance(state, dict):
        candidate = str(state.get("artifacts", {}).get("run_approval", "")).strip()
    if candidate and os.path.isfile(candidate):
        loaded = read_json_file(candidate)
        if isinstance(loaded, dict):
            reviewer = str(loaded.get("approved_by", "")).strip()
            if reviewer:
                return summarize_approval_records([loaded], review_policy=review_policy)
            return loaded
    fallback = os.path.join(run_path, RUN_APPROVAL_FILENAME)
    loaded = read_json_file(fallback)
    if isinstance(loaded, dict):
        reviewer = str(loaded.get("approved_by", "")).strip()
        if reviewer:
            return summarize_approval_records([loaded], review_policy=review_policy)
        return loaded
    return None


def run_approval_cli(args: argparse.Namespace) -> int:
    run_path = resolve_run_reference(args.runs_dir, str(args.approve_run or "").strip())
    if not run_path:
        print(f"❌ Run not found: {args.approve_run}")
        return 1
    state = load_run_state(run_path)
    if not isinstance(state, dict):
        print(f"❌ Missing state.json in run: {run_path}")
        return 1
    reviewer = str(args.approved_by or "").strip()
    if not reviewer:
        print("❌ --approved-by is required.")
        return 1
    review_policy = load_review_policy(getattr(args, "approval_policy", ""))
    external_integrations_audit = build_external_integrations_audit(review_policy, phase="approval")
    if not bool(external_integrations_audit.get("pass", False)):
        blocking = [
            str(item.get("name", "")).strip()
            for item in external_integrations_audit.get("integrations", [])
            if isinstance(item, dict) and bool(item.get("required_for_phase", False)) and not bool(item.get("ready", False))
        ]
        print("❌ Review policy blocked approval: external integration requirements failed: " + ", ".join([item for item in blocking if item]))
        return 1
    if not _authorized_reviewer(reviewer, review_policy):
        print(f"❌ Reviewer is not authorized by policy: {reviewer}")
        return 1
    reviewer_identity = _evaluate_policy_identity(reviewer, review_policy, phase="approval")
    if not bool(reviewer_identity.get("pass", False)):
        print(
            "❌ Review policy blocked approval: reviewer identity requirements failed: "
            + ", ".join([str(item) for item in reviewer_identity.get("failures", []) if str(item).strip()])
        )
        return 1
    required_statuses = _required_run_statuses(review_policy)
    run_status = str(state.get("status", "")).strip()
    if run_status not in required_statuses:
        print(f"❌ Run status `{run_status}` is not approvable. Allowed: {', '.join(sorted(required_statuses))}")
        return 1
    artifacts = state.get("artifacts", {}) if isinstance(state.get("artifacts", {}), dict) else {}
    missing_artifacts = [key for key in _required_artifact_keys(review_policy, phase="approval") if not _artifact_exists(str(artifacts.get(key, "")).strip())]
    if missing_artifacts:
        print(f"❌ Run is missing required artifacts for approval: {', '.join(missing_artifacts)}")
        return 1
    classification_summary = load_run_classification_summary(run_path, state=state)
    classification_ok, classification_detail = classification_within_review_policy(classification_summary, review_policy)
    if not classification_ok:
        print(f"❌ Review policy blocked approval: {classification_detail}")
        return 1
    fact_index = load_run_fact_index(run_path, state=state)
    endpoint_quality_summary = summarize_endpoint_quality_for_endpoints(
        fact_index.get("api_endpoints", []) if isinstance(fact_index, dict) else []
    )
    self_review_summary = state.get("self_review_audit", {}) if isinstance(state.get("self_review_audit", {}), dict) else build_self_review_audit(
        validation_stats=state.get("validation", {}) if isinstance(state.get("validation", {}), dict) else {},
        gate=state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {},
        contradiction_summary=state.get("contradiction_audit", {}) if isinstance(state.get("contradiction_audit", {}), dict) else {},
        unsupported_claim_summary=build_unsupported_claim_audit(state.get("validation", {})),
        endpoint_quality_summary=endpoint_quality_summary,
        traceability_summary=read_json_file(str(state.get("artifacts", {}).get("run_traceability", "")).strip()) or {},
    )
    artifact_hashes = []
    for key in sorted(set(_required_artifact_keys(review_policy, phase="approval") + ["run_report", "run_summary", "run_traceability"])):
        path = str(artifacts.get(key, "")).strip()
        if _artifact_exists(path):
            artifact_hashes.append(_artifact_hash_entry(key, path))
    payload = {
        "approved_at": utc_now_iso(),
        "approved_by": reviewer,
        "approval_notes": str(args.approval_notes or "").strip(),
        "reviewer_roles": reviewer_identity.get("roles", []) or _reviewer_roles(reviewer, review_policy),
        "reviewer_identity": reviewer_identity,
        "review_policy_path": os.path.abspath(os.path.expanduser(str(args.approval_policy or "").strip())) if str(args.approval_policy or "").strip() else "",
        "run_id": str(state.get("run_id", os.path.basename(run_path))).strip(),
        "run_path": run_path,
        "repo_path": str(state.get("repo_path", "")).strip(),
        "run_status": run_status,
        "required_run_statuses": sorted(list(required_statuses)),
        "required_artifacts": _required_artifact_keys(review_policy, phase="approval"),
        "self_review_summary": self_review_summary,
        "external_integrations_summary": external_integrations_audit,
        "classification_summary": classification_summary,
        "endpoint_quality_summary": endpoint_quality_summary,
        "max_publish_classification": _max_publish_classification(review_policy),
        "artifact_hashes": artifact_hashes,
    }
    payload["signature"] = sign_audit_payload(payload)
    approvals_dir_path = approval_records_dir(run_path)
    os.makedirs(approvals_dir_path, exist_ok=True)
    approval_record_path = os.path.join(approvals_dir_path, approval_record_filename(reviewer))
    write_json_atomic(approval_record_path, payload)
    approval_summary = summarize_approval_records(load_run_approval_records(run_path), review_policy=review_policy)
    approval_path = os.path.join(run_path, RUN_APPROVAL_FILENAME)
    write_json_atomic(approval_path, approval_summary)
    review_audit_bundle = build_review_audit_bundle(
        phase="approval",
        run_path=run_path,
        state=state,
        review_policy_path=approval_summary.get("review_policy_path", payload["review_policy_path"]),
        classification_summary=classification_summary,
        endpoint_quality_summary=endpoint_quality_summary,
        grounding_summary={
            "gate_pass": bool((state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {}).get("pass", False)),
            "evidence_coverage": float((state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {}).get("coverage", 0.0) or 0.0),
            "semantic_coverage": float((state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {}).get("semantic_coverage", 1.0) or 1.0),
            "files_missing_evidence_count": int((state.get("validation", {}) if isinstance(state.get("validation", {}), dict) else {}).get("files_missing_evidence_count", 0) or 0),
            "claims_semantically_unsupported": int((state.get("validation", {}) if isinstance(state.get("validation", {}), dict) else {}).get("claims_semantically_unsupported", 0) or 0),
        },
        contradiction_summary=state.get("contradiction_audit", {}) if isinstance(state.get("contradiction_audit", {}), dict) else {},
        unsupported_claim_summary=build_unsupported_claim_audit(state.get("validation", {})),
        self_review_summary=self_review_summary,
        external_integrations_summary=external_integrations_audit,
        artifact_hashes=artifact_hashes,
        approval=approval_summary,
    )
    review_audit_path = os.path.join(run_path, RUN_REVIEW_AUDIT_FILENAME)
    write_json_atomic(review_audit_path, review_audit_bundle)
    review_audit_sarif = build_review_audit_sarif(review_audit_bundle)
    review_audit_sarif_path = os.path.join(run_path, RUN_REVIEW_AUDIT_SARIF_FILENAME)
    write_json_atomic(review_audit_sarif_path, review_audit_sarif)
    state.setdefault("artifacts", {})
    state["artifacts"]["run_approvals_dir"] = approvals_dir_path
    state["artifacts"]["run_approval"] = approval_path
    state["artifacts"]["run_review_audit"] = review_audit_path
    state["artifacts"]["run_review_audit_sarif"] = review_audit_sarif_path
    state["approved_by"] = str(approval_summary.get("approved_by", reviewer)).strip()
    state["approved_at"] = str(approval_summary.get("approved_at", payload["approved_at"])).strip()
    add_run_event(
        state,
        "approve",
        "Recorded reviewer approval for publish workflow.",
        data={
            "approved_by": reviewer,
            "approval_count": approval_summary.get("approval_count", 0),
            "approval_requirements_met": approval_summary.get("approval_requirements_met", False),
        },
    )
    save_run_state(run_path, state)
    print(f"[SAVED] {approval_path}")
    return 0


def run_publish_cli(args: argparse.Namespace) -> int:
    run_path = resolve_run_reference(args.runs_dir, str(args.publish_run or "").strip())
    if not run_path:
        print(f"❌ Run not found: {args.publish_run}")
        return 1
    state = load_run_state(run_path)
    if not isinstance(state, dict):
        print(f"❌ Missing state.json in run: {run_path}")
        return 1
    review_policy = load_review_policy(getattr(args, "approval_policy", ""))
    external_integrations_audit = build_external_integrations_audit(review_policy, phase="publish")
    external_integration_dispatch_specs = build_external_integration_dispatch_specs(external_integrations_audit)
    external_integration_dispatch_results = build_external_integration_dispatch_results(external_integration_dispatch_specs)
    if not bool(external_integrations_audit.get("pass", False)):
        blocking = [
            str(item.get("name", "")).strip()
            for item in external_integrations_audit.get("integrations", [])
            if isinstance(item, dict) and bool(item.get("required_for_phase", False)) and not bool(item.get("ready", False))
        ]
        print("❌ Review policy blocked publish: external integration requirements failed: " + ", ".join([item for item in blocking if item]))
        return 1
    required_statuses = _required_run_statuses(review_policy)
    run_status = str(state.get("status", "")).strip()
    if run_status not in required_statuses:
        print(f"❌ Run status `{run_status}` is not publishable. Allowed: {', '.join(sorted(required_statuses))}")
        return 1
    approval = load_run_approval(run_path, state=state, review_policy=review_policy)
    require_approval = bool(getattr(args, "require_approval", True)) and not bool(review_policy.get("allow_publish_without_approval", False))
    if require_approval and not isinstance(approval, dict):
        print("❌ Publish requires an approval artifact. Run --approve-run first or use policy to allow publish without approval.")
        return 1
    if require_approval:
        approval_ok, approval_detail = approval_within_review_policy(approval, review_policy)
        if not approval_ok:
            print(f"❌ Review policy blocked publish: {approval_detail}")
            return 1
    publisher = str(
        getattr(args, "published_by", "")
        or getattr(args, "approved_by", "")
        or (approval.get("approved_by", "") if isinstance(approval, dict) else "")
    ).strip()
    deployer_identities = _deployer_identities(review_policy)
    deployer_requirements = _deployer_identity_requirements(review_policy)
    if (deployer_identities or _identity_requirements_configured(deployer_requirements)) and not publisher:
        print("❌ Review policy blocked publish: --published-by is required for deployer identity checks.")
        return 1
    if publisher and not _authorized_deployer(publisher, review_policy):
        print(f"❌ Deployer is not authorized by policy: {publisher}")
        return 1
    distinct_reviewer_subjects: list[str] = []
    if isinstance(approval, dict):
        distinct_reviewer_subjects = [
            _approval_identity_subject(item)
            for item in (approval.get("approvals", []) if isinstance(approval.get("approvals", []), list) else [])
            if isinstance(item, dict) and _approval_identity_subject(item)
        ]
    publisher_identity = _evaluate_policy_identity(
        publisher,
        review_policy,
        phase="publish",
        distinct_from=distinct_reviewer_subjects,
    ) if publisher else _evaluate_policy_identity("", review_policy, phase="publish")
    if publisher and not bool(publisher_identity.get("pass", False)):
        print(
            "❌ Review policy blocked publish: deployer identity requirements failed: "
            + ", ".join([str(item) for item in publisher_identity.get("failures", []) if str(item).strip()])
        )
        return 1
    artifacts = state.get("artifacts", {}) if isinstance(state.get("artifacts", {}), dict) else {}
    publish_root = resolve_published_dir(args.publish_dir)
    publish_environment = _normalize_publish_environment(getattr(args, "publish_environment", ""))
    allow_remote_external_dispatch = _remote_external_dispatch_enabled(
        review_policy=review_policy,
        args=args,
    )
    contradiction_summary = state.get("contradiction_audit", {}) if isinstance(state.get("contradiction_audit", {}), dict) else {}
    unsupported_claim_summary = build_unsupported_claim_audit(state.get("validation", {}))
    run_diff_summary = load_run_diff_summary(run_path, state=state)
    fact_index = load_run_fact_index(run_path, state=state)
    endpoint_quality_summary = summarize_endpoint_quality_for_endpoints(
        fact_index.get("api_endpoints", []) if isinstance(fact_index, dict) else []
    )
    self_review_summary = state.get("self_review_audit", {}) if isinstance(state.get("self_review_audit", {}), dict) else build_self_review_audit(
        validation_stats=state.get("validation", {}) if isinstance(state.get("validation", {}), dict) else {},
        gate=state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {},
        contradiction_summary=contradiction_summary,
        unsupported_claim_summary=unsupported_claim_summary,
        endpoint_quality_summary=endpoint_quality_summary,
        traceability_summary=read_json_file(str(state.get("artifacts", {}).get("run_traceability", "")).strip()) or {},
    )
    publish_environment_policy = _evaluate_publish_environment_policy(
        review_policy,
        publish_root=publish_root,
        run_id=str(state.get("run_id", os.path.basename(run_path))).strip(),
        publish_environment=publish_environment,
        external_integrations_audit=external_integrations_audit,
        external_integration_dispatch_results=external_integration_dispatch_results,
        self_review_summary=self_review_summary,
        contradiction_summary=contradiction_summary,
        unsupported_claim_summary=unsupported_claim_summary,
        run_diff_summary=run_diff_summary,
        enforce_executed_operations=False,
    )
    if not bool(publish_environment_policy.get("pass", False)):
        details = _publish_environment_policy_failure_details(
            publish_environment_policy,
            requested_environment=publish_environment,
        )
        print("❌ Review policy blocked publish: " + "; ".join([item for item in details if item]))
        return 1
    resolved_publish_environment = str(
        publish_environment_policy.get("environment", publish_environment)
    ).strip()
    missing_artifacts = [
        key
        for key in _required_artifact_keys(review_policy, phase="publish", publish_environment=resolved_publish_environment)
        if not _artifact_exists(str(artifacts.get(key, "")).strip())
    ]
    if missing_artifacts:
        print(f"❌ Run is missing required artifacts for publish: {', '.join(missing_artifacts)}")
        return 1
    classification_summary = load_run_classification_summary(run_path, state=state)
    classification_ok, classification_detail = classification_within_review_policy(
        classification_summary,
        review_policy,
        publish_environment=resolved_publish_environment,
    )
    if not classification_ok:
        print(f"❌ Review policy blocked publish: {classification_detail}")
        return 1
    publish_label_default = str(state.get("run_id", os.path.basename(run_path))).strip()
    if resolved_publish_environment:
        publish_label_default = f"{publish_label_default}-{resolved_publish_environment}"
    publish_label = sanitize_queue_scope_name(str(args.publish_label or "").strip(), default=publish_label_default)
    publish_path = os.path.join(publish_root, publish_label)
    if os.path.exists(publish_path):
        if not bool(getattr(args, "force_publish", False)):
            print(f"❌ Publish target already exists: {publish_path}")
            return 1
        shutil.rmtree(publish_path)
    os.makedirs(publish_path, exist_ok=True)
    publish_entries: list[dict[str, Any]] = []
    for key in _publish_artifact_keys(review_policy):
        source = str(artifacts.get(key, "")).strip()
        if not _artifact_exists(source):
            continue
        destination = os.path.join(publish_path, os.path.basename(source))
        _copy_publish_artifact(source, destination)
        entry = _artifact_hash_entry(key, destination)
        entry["source_path"] = os.path.abspath(os.path.expanduser(source))
        entry["published_path"] = destination
        publish_entries.append(entry)
    if isinstance(approval, dict) and not any(item.get("artifact_key") == "run_approval" for item in publish_entries):
        approval_source = str(state.get("artifacts", {}).get("run_approval", "")).strip() or os.path.join(run_path, RUN_APPROVAL_FILENAME)
        if _artifact_exists(approval_source):
            destination = os.path.join(publish_path, os.path.basename(approval_source))
            _copy_publish_artifact(approval_source, destination)
            entry = _artifact_hash_entry("run_approval", destination)
            entry["source_path"] = os.path.abspath(os.path.expanduser(approval_source))
            entry["published_path"] = destination
            publish_entries.append(entry)
    approvals_dir_source = str(state.get("artifacts", {}).get("run_approvals_dir", "")).strip() or approval_records_dir(run_path)
    if os.path.isdir(approvals_dir_source) and not any(item.get("artifact_key") == "run_approvals_dir" for item in publish_entries):
        destination = os.path.join(publish_path, os.path.basename(approvals_dir_source.rstrip("/\\")))
        _copy_publish_artifact(approvals_dir_source, destination)
        entry = _artifact_hash_entry("run_approvals_dir", destination)
        entry["source_path"] = os.path.abspath(os.path.expanduser(approvals_dir_source))
        entry["published_path"] = destination
        publish_entries.append(entry)
    published_external_integration_dispatch_specs_path = os.path.join(
        publish_path, RUN_PUBLISH_EXTERNAL_INTEGRATION_DISPATCH_SPECS_FILENAME
    )
    write_json_atomic(published_external_integration_dispatch_specs_path, external_integration_dispatch_specs)
    published_external_integration_dispatch_specs_md_path = os.path.join(
        publish_path, RUN_PUBLISH_EXTERNAL_INTEGRATION_DISPATCH_SPECS_MARKDOWN_FILENAME
    )
    write_text_atomic(
        published_external_integration_dispatch_specs_md_path,
        render_external_integration_dispatch_specs_markdown(external_integration_dispatch_specs),
    )
    publish_entries.append(_artifact_hash_entry("published_external_integration_dispatch_specs", published_external_integration_dispatch_specs_path))
    publish_entries.append(_artifact_hash_entry("published_external_integration_dispatch_specs_markdown", published_external_integration_dispatch_specs_md_path))
    external_integration_dispatch_results = execute_external_integration_dispatch_results(
        external_integration_dispatch_results,
        publish_source_path=publish_path,
        publish_label=publish_label,
        allow_remote_execution=allow_remote_external_dispatch,
    )
    publish_environment_policy = _evaluate_publish_environment_policy(
        review_policy,
        publish_root=publish_root,
        run_id=str(state.get("run_id", os.path.basename(run_path))).strip(),
        publish_environment=resolved_publish_environment,
        external_integrations_audit=external_integrations_audit,
        external_integration_dispatch_results=external_integration_dispatch_results,
        self_review_summary=self_review_summary,
        contradiction_summary=contradiction_summary,
        unsupported_claim_summary=unsupported_claim_summary,
        run_diff_summary=run_diff_summary,
    )
    if not bool(publish_environment_policy.get("pass", False)):
        details = _publish_environment_policy_failure_details(
            publish_environment_policy,
            requested_environment=resolved_publish_environment or publish_environment,
        )
        _cleanup_partial_publish_path(publish_path)
        print("❌ Review policy blocked publish: " + "; ".join([item for item in details if item]))
        return 1
    published_external_integration_dispatch_results_path = os.path.join(
        publish_path, RUN_PUBLISH_EXTERNAL_INTEGRATION_DISPATCH_RESULTS_FILENAME
    )
    write_json_atomic(published_external_integration_dispatch_results_path, external_integration_dispatch_results)
    published_external_integration_dispatch_results_md_path = os.path.join(
        publish_path, RUN_PUBLISH_EXTERNAL_INTEGRATION_DISPATCH_RESULTS_MARKDOWN_FILENAME
    )
    write_text_atomic(
        published_external_integration_dispatch_results_md_path,
        render_external_integration_dispatch_results_markdown(external_integration_dispatch_results),
    )
    publish_entries.append(_artifact_hash_entry("published_external_integration_dispatch_results", published_external_integration_dispatch_results_path))
    publish_entries.append(_artifact_hash_entry("published_external_integration_dispatch_results_markdown", published_external_integration_dispatch_results_md_path))
    manifest_payload = {
        "published_at": utc_now_iso(),
        "published_by": publisher,
        "publish_label": publish_label,
        "publish_environment": resolved_publish_environment,
        "publish_environment_policy": publish_environment_policy,
        "remote_external_dispatch_enabled": allow_remote_external_dispatch,
        "publish_dir": publish_path,
        "run_id": str(state.get("run_id", os.path.basename(run_path))).strip(),
        "run_path": run_path,
        "repo_path": str(state.get("repo_path", "")).strip(),
        "run_status": run_status,
        "requested_mode": str(state.get("requested_mode", "")).strip(),
        "effective_mode": str(state.get("mode", "")).strip(),
        "approval_required": require_approval,
        "approval_artifact": str(state.get("artifacts", {}).get("run_approval", "")).strip(),
        "approval_artifacts_dir": approvals_dir_source if os.path.isdir(approvals_dir_source) else "",
        "approval_present": isinstance(approval, dict),
        "approval_count": max(0, int(approval.get("approval_count", 0) or 0)) if isinstance(approval, dict) else 0,
        "approval_requirements_met": bool(approval.get("approval_requirements_met", False)) if isinstance(approval, dict) else False,
        "required_approval_roles": approval.get("required_approval_roles", []) if isinstance(approval, dict) else [],
        "satisfied_approval_roles": approval.get("satisfied_approval_roles", []) if isinstance(approval, dict) else [],
        "missing_approval_roles": approval.get("missing_approval_roles", []) if isinstance(approval, dict) else [],
        "reviewer_identity_requirements_met": bool(approval.get("reviewer_identity_requirements_met", False)) if isinstance(approval, dict) else False,
        "reviewer_identity_count": int(approval.get("reviewer_identity_count", 0) or 0) if isinstance(approval, dict) else 0,
        "review_policy_path": os.path.abspath(os.path.expanduser(str(args.approval_policy or "").strip())) if str(args.approval_policy or "").strip() else "",
        "classification_summary": classification_summary,
        "endpoint_quality_summary": endpoint_quality_summary,
        "self_review_summary": self_review_summary,
        "contradiction_summary": contradiction_summary,
        "unsupported_claim_summary": unsupported_claim_summary,
        "run_diff_summary": run_diff_summary,
        "external_integrations_summary": external_integrations_audit,
        "external_integration_dispatch_specs_summary": external_integration_dispatch_specs,
        "external_integration_dispatch_results_summary": external_integration_dispatch_results,
        "max_publish_classification": _max_publish_classification(review_policy, publish_environment=resolved_publish_environment),
        "require_run_diff_artifact": publish_environment_policy.get("require_run_diff_artifact"),
        "disallow_fact_changes": publish_environment_policy.get("disallow_fact_changes"),
        "disallow_architecture_changes": publish_environment_policy.get("disallow_architecture_changes"),
        "max_run_diff_metric_deltas": publish_environment_policy.get("max_run_diff_metric_deltas"),
        "max_self_review_issue_count": publish_environment_policy.get("max_self_review_issue_count"),
        "max_contradiction_issue_count": publish_environment_policy.get("max_contradiction_issue_count"),
        "max_unsupported_claim_issue_count": publish_environment_policy.get("max_unsupported_claim_issue_count"),
        "max_semantically_unsupported_claims": publish_environment_policy.get("max_semantically_unsupported_claims"),
        "publisher_identity": publisher_identity,
        "publisher_identity_requirements_met": bool(publisher_identity.get("pass", False)),
        "publisher_identity_failure_count": len(publisher_identity.get("failures", [])) if isinstance(publisher_identity.get("failures", []), list) else 0,
        "publisher_identity_failures": publisher_identity.get("failures", []),
        "publisher_distinct_from_approvers": "not_distinct_from_reviewers" not in (
            publisher_identity.get("failures", []) if isinstance(publisher_identity.get("failures", []), list) else []
        ),
        "artifacts": publish_entries,
    }
    ledger_path = _publish_audit_ledger_path(publish_root)
    try:
        ledger_result = append_publish_audit_ledger(
            ledger_path,
            {
                "event": "publish",
                "run_id": manifest_payload["run_id"],
                "publish_label": publish_label,
                "publish_environment": resolved_publish_environment,
                "published_by": publisher,
                "publish_dir": publish_path,
                "approval_count": manifest_payload["approval_count"],
                "approval_requirements_met": manifest_payload["approval_requirements_met"],
                "artifact_count": len(publish_entries),
            },
        )
    except Exception as e:
        print(f"❌ Review policy blocked publish: publish audit ledger append failed: {e}")
        return 1
    ledger_entry = ledger_result.get("entry", {}) if isinstance(ledger_result.get("entry", {}), dict) else {}
    ledger_summary = {
        "path": str(ledger_result.get("path", "")).strip(),
        "sequence": int(ledger_entry.get("sequence", 0) or 0),
        "entry_hash": str(ledger_entry.get("entry_hash", "")).strip(),
        "previous_hash": str(ledger_entry.get("previous_hash", "")).strip(),
        "prior_entry_count": int(ledger_result.get("prior_entry_count", 0) or 0),
        "chain_valid": bool(ledger_result.get("chain_valid", False)),
    }
    manifest_payload["publish_audit_ledger"] = ledger_summary
    manifest_payload["signature"] = sign_audit_payload(manifest_payload)
    publish_manifest_path = os.path.join(publish_path, RUN_PUBLISH_MANIFEST_FILENAME)
    write_json_atomic(publish_manifest_path, manifest_payload)
    publish_audit_ledger_entry_path = os.path.join(publish_path, RUN_PUBLISH_AUDIT_LEDGER_ENTRY_FILENAME)
    write_json_atomic(
        publish_audit_ledger_entry_path,
        {
            "published_at": manifest_payload["published_at"],
            "run_id": manifest_payload["run_id"],
            "publish_label": publish_label,
            "publish_environment": resolved_publish_environment,
            "ledger": ledger_summary,
            "entry": ledger_entry,
        },
    )
    review_audit_bundle = build_review_audit_bundle(
        phase="publish",
        run_path=run_path,
        state=state,
        review_policy_path=manifest_payload["review_policy_path"],
        classification_summary=classification_summary,
        endpoint_quality_summary=endpoint_quality_summary,
        grounding_summary={
            "gate_pass": bool((state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {}).get("pass", False)),
            "evidence_coverage": float((state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {}).get("coverage", 0.0) or 0.0),
            "semantic_coverage": float((state.get("gate", {}) if isinstance(state.get("gate", {}), dict) else {}).get("semantic_coverage", 1.0) or 1.0),
            "files_missing_evidence_count": int((state.get("validation", {}) if isinstance(state.get("validation", {}), dict) else {}).get("files_missing_evidence_count", 0) or 0),
            "claims_semantically_unsupported": int((state.get("validation", {}) if isinstance(state.get("validation", {}), dict) else {}).get("claims_semantically_unsupported", 0) or 0),
        },
        contradiction_summary=state.get("contradiction_audit", {}) if isinstance(state.get("contradiction_audit", {}), dict) else {},
        unsupported_claim_summary=build_unsupported_claim_audit(state.get("validation", {})),
        self_review_summary=self_review_summary,
        external_integrations_summary=external_integrations_audit,
        external_integration_dispatch_specs_summary=external_integration_dispatch_specs,
        external_integration_dispatch_results_summary=external_integration_dispatch_results,
        approval=approval if isinstance(approval, dict) else None,
        manifest=manifest_payload,
        published_artifacts=publish_entries,
    )
    published_review_audit_path = os.path.join(publish_path, RUN_REVIEW_AUDIT_FILENAME)
    write_json_atomic(published_review_audit_path, review_audit_bundle)
    published_review_audit_sarif = build_review_audit_sarif(review_audit_bundle)
    published_review_audit_sarif_path = os.path.join(publish_path, RUN_REVIEW_AUDIT_SARIF_FILENAME)
    write_json_atomic(published_review_audit_sarif_path, published_review_audit_sarif)
    for item in external_integration_dispatch_results.get("results", []) if isinstance(external_integration_dispatch_results.get("results", []), list) else []:
        if not isinstance(item, dict):
            continue
        if str(item.get("transport", "")).strip() != "file_copy":
            continue
        executed_target_path = str(item.get("executed_target_path", "")).strip()
        if not executed_target_path or not os.path.isdir(executed_target_path):
            continue
        for relative_name in [
            RUN_PUBLISH_EXTERNAL_INTEGRATION_DISPATCH_RESULTS_FILENAME,
            RUN_PUBLISH_EXTERNAL_INTEGRATION_DISPATCH_RESULTS_MARKDOWN_FILENAME,
            RUN_PUBLISH_MANIFEST_FILENAME,
            RUN_PUBLISH_AUDIT_LEDGER_ENTRY_FILENAME,
            RUN_REVIEW_AUDIT_FILENAME,
            RUN_REVIEW_AUDIT_SARIF_FILENAME,
        ]:
            source_file = os.path.join(publish_path, relative_name)
            if not os.path.isfile(source_file):
                continue
            target_file = os.path.join(executed_target_path, relative_name)
            _copy_publish_artifact(source_file, target_file)
    state.setdefault("artifacts", {})
    state["artifacts"]["run_publish_manifest"] = publish_manifest_path
    state["artifacts"]["root_publish_audit_ledger"] = ledger_path
    state["artifacts"]["published_publish_audit_ledger_entry"] = publish_audit_ledger_entry_path
    state["artifacts"]["published_external_integration_dispatch_specs"] = published_external_integration_dispatch_specs_path
    state["artifacts"]["published_external_integration_dispatch_specs_markdown"] = published_external_integration_dispatch_specs_md_path
    state["artifacts"]["published_external_integration_dispatch_results"] = published_external_integration_dispatch_results_path
    state["artifacts"]["published_external_integration_dispatch_results_markdown"] = published_external_integration_dispatch_results_md_path
    state["artifacts"]["published_review_audit"] = published_review_audit_path
    state["artifacts"]["published_review_audit_sarif"] = published_review_audit_sarif_path
    state["published_at"] = manifest_payload["published_at"]
    state["published_dir"] = publish_path
    if resolved_publish_environment:
        published_environments = [
            str(item).strip()
            for item in state.get("published_environments", [])
            if str(item).strip()
        ] if isinstance(state.get("published_environments", []), list) else []
        if resolved_publish_environment not in published_environments:
            published_environments.append(resolved_publish_environment)
        state["published_environments"] = published_environments
    published_history = state.get("published_history", [])
    if not isinstance(published_history, list):
        published_history = []
    published_history.append(
        {
            "published_at": manifest_payload["published_at"],
            "published_dir": publish_path,
            "publish_label": publish_label,
            "publish_environment": resolved_publish_environment,
            "publish_audit_ledger_sequence": ledger_summary["sequence"],
            "publish_audit_ledger_hash": ledger_summary["entry_hash"],
        }
    )
    state["published_history"] = published_history
    add_run_event(
        state,
        "publish",
        "Published approved run artifacts.",
        data={
            "publish_dir": publish_path,
            "publish_environment": resolved_publish_environment,
            "approval_count": manifest_payload["approval_count"],
            "approval_requirements_met": manifest_payload["approval_requirements_met"],
        },
    )
    save_run_state(run_path, state)
    print(f"[SAVED] {publish_manifest_path}")
    return 0


def run_status_cli(args: argparse.Namespace) -> int:
    if bool(getattr(args, "all_queues", False)):
        for descriptor in list_queue_scope_descriptors(args.queue_dir):
            write_queue_metrics(descriptor["queue_dir"])
    else:
        write_queue_metrics(resolve_queue_scope_from_args(args)["queue_dir"])
    status = build_operator_status(
        args.queue_dir,
        args.runs_dir,
        limit=max(1, int(args.recent_limit or STATUS_RECENT_LIMIT)),
        queue_name=getattr(args, "queue_name", ""),
        queue_class=getattr(args, "queue_class", ""),
        all_queues=bool(getattr(args, "all_queues", False)),
    )
    if str(args.status_json or "").strip():
        write_json_atomic(os.path.abspath(os.path.expanduser(args.status_json.strip())), status)
        print(f"[SAVED] {os.path.abspath(os.path.expanduser(args.status_json.strip()))}")
    print(render_operator_status_text(status))
    return 0


def run_evaluation_cli(args: argparse.Namespace) -> int:
    import evaluation_harness

    manifest_path = os.path.abspath(os.path.expanduser(str(args.evaluate_manifest or "").strip()))
    if not manifest_path:
        print("❌ --evaluate-manifest requires a manifest path.")
        return 1
    manifest = evaluation_harness.load_manifest(manifest_path)
    result = evaluation_harness.evaluate_manifest_config(manifest, manifest_path=manifest_path)
    out_json, out_md = evaluation_harness.default_output_paths(manifest_path)
    benchmark_md, benchmark_csv = evaluation_harness.default_benchmark_output_paths(manifest_path)
    if str(args.evaluation_json or "").strip():
        out_json = os.path.abspath(os.path.expanduser(args.evaluation_json.strip()))
    if str(args.evaluation_md or "").strip():
        out_md = os.path.abspath(os.path.expanduser(args.evaluation_md.strip()))
    if str(args.benchmark_md or "").strip():
        benchmark_md = os.path.abspath(os.path.expanduser(args.benchmark_md.strip()))
    if str(args.benchmark_csv or "").strip():
        benchmark_csv = os.path.abspath(os.path.expanduser(args.benchmark_csv.strip()))
    write_json_atomic(out_json, result)
    write_text_atomic(out_md, evaluation_harness.render_evaluation_markdown(result))
    write_text_atomic(benchmark_md, evaluation_harness.render_benchmark_table_markdown(result))
    write_text_atomic(benchmark_csv, evaluation_harness.render_benchmark_csv(result))
    print(f"[SAVED] {out_json}")
    print(f"[SAVED] {out_md}")
    print(f"[SAVED] {benchmark_md}")
    print(f"[SAVED] {benchmark_csv}")
    quality_gates = result.get("quality_gates", {}) if isinstance(result, dict) else {}
    if isinstance(quality_gates, dict) and bool(quality_gates.get("configured", False)) and not bool(quality_gates.get("pass", False)):
        print(
            "❌ Evaluation quality gates failed: "
            f"{int(quality_gates.get('failure_count', 0) or 0)} check(s) did not meet the configured thresholds."
        )
        return 2
    return 0


def main(argv: Optional[list[str]] = None) -> int:
    args = parse_cli_args(sys.argv[1:] if argv is None else argv)

    if sum(
        [
            int(bool(args.worker)),
            int(bool(args.enqueue_job)),
            int(bool(args.status)),
            int(bool(args.evaluate_manifest)),
            int(bool(args.approve_run)),
            int(bool(args.publish_run)),
        ]
    ) > 1:
        print("❌ Choose only one of --worker, --enqueue-job, --status, --evaluate-manifest, --approve-run, or --publish-run.")
        return 1

    if args.status:
        return run_status_cli(args)

    if args.evaluate_manifest:
        return run_evaluation_cli(args)

    if args.approve_run:
        return run_approval_cli(args)

    if args.publish_run:
        return run_publish_cli(args)

    if args.worker:
        return run_queue_worker(args)

    repo_path = _resolve_cli_repo_path(args, allow_prompt=not args.enqueue_job)
    if not repo_path:
        print("❌ Repository path is required.")
        return 1

    if args.enqueue_job:
        job_path = enqueue_queue_job(resolve_queue_scope_from_args(args)["queue_dir"], build_queue_job_payload(args, repo_path))
        print(f"[SAVED] {job_path}")
        return 0

    result = run_repository_analysis(args, repo_path)
    return int(result.get("exit_code", 1))


if __name__ == "__main__":
    sys.exit(main())
